// translationsSpellDescriptions.js

Object.assign(translations.de, {
        // Zauber: Beschreibungen
        "acidSplashD": "Du erzeugst eine Säureblase an einem Punkt in Reichweite, wo sie in einer Sphäre mit einem Radius von 1.5 m explodiert. Jede Kreatur in dieser Sphäre muss einen Geschicklichkeitsrettungswurf bestehen oder 1W6 Säureschaden erleiden.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W6, wenn du Stufe 5 (2W6), 11 (3W6) und 17 (4W6) erreichst.",
        "bladeWardD": "Immer wenn eine Kreatur einen Angriffswurf gegen dich macht, bevor der Zauber endet, zieht der Angreifer 1W4 vom Angriffswurf ab.",
        "chillTouchD": "Du kanalisierst die Kälte des Grabes und machst einen Nahkampf-Zauberangriff gegen ein Ziel in Reichweite. Bei einem Treffer erleidet das Ziel 1W10 nekrotischen Schaden und kann bis zum Ende deines nächsten Zuges keine Trefferpunkte zurückgewinnen.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W10, wenn du Stufe 5 (2W10), 11 (3W10) und 17 (4W10) erreichst.",
        "dancingLightsD": "Du erschaffst bis zu vier fackelgroße Lichter in Reichweite, die als Fackeln, Laternen oder schwebende Kugeln für die Dauer des Zaubers erscheinen. Alternativ kannst du die vier Lichter zu einer leuchtenden, vage menschenähnlichen Gestalt mittlerer Größe kombinieren. Welche Form du auch wählst, jedes Licht wirft dämmriges Licht in einem Radius von 3 m.<br><br>Als Bonusaktion kannst du die Lichter bis zu 18 m an einen Ort in Reichweite bewegen. Ein Licht muss sich innerhalb von 6 m eines anderen durch diesen Zauber erschaffenen Lichts befinden, und ein Licht erlischt, wenn es die Reichweite des Zaubers überschreitet.<br><br><b>Material:</b> Ein wenig Phosphor.",
        "druidcraftD": "Du flüsterst den Geistern der Natur zu und erzeugst einen der folgenden Effekte in Reichweite:<ul><li><b>Wetter-Sensor:</b> Du erzeugst einen winzigen, harmlosen sensorischen Effekt, der das Wetter an deinem Standort für die nächsten 24 Stunden vorhersagt. Der Effekt könnte sich als goldene Kugel für klaren Himmel, eine Wolke für Regen, fallende Schneeflocken für Schnee usw. manifestieren. Dieser Effekt hält 1 Runde an.</li><li><b>Blüte:</b> Du bringst sofort eine Blume zum Blühen, eine Samenkapsel zum Öffnen oder eine Blattknospe zum Aufbrechen.</li><li><b>Sensorischer Effekt:</b> Du erzeugst einen harmlosen sensorischen Effekt, wie fallende Blätter, spektral tanzende Feen, eine sanfte Brise, den Klang eines Tieres oder den schwachen Geruch eines Stinktiers. Der Effekt muss in einen 1.5-m-Würfel passen.</li><li><b>Feuerspiel:</b> Du entzündest oder löschst eine Kerze, eine Fackel oder ein Lagerfeuer.</li></ul>",
        "eldritchBlastD": "Du schleuderst einen Strahl knisternder Energie. Mache einen Fernkampf-Zauberangriff gegen eine Kreatur oder ein Objekt in Reichweite. Bei einem Treffer erleidet das Ziel 1W10 Energieschaden.<br><br><b>Zaubertrick-Upgrade:</b> Der Zauber erzeugt zwei Strahlen auf Stufe 5, drei Strahlen auf Stufe 11 und vier Strahlen auf Stufe 17. Du kannst die Strahlen auf dasselbe Ziel oder auf verschiedene richten. Mache für jeden Strahl einen separaten Angriffswurf.",
        "elementalismD": "Du übst Kontrolle über die Elemente aus und erzeugst einen der folgenden Effekte in Reichweite:<ul><li><b>Luft herbeirufen:</b> Du erzeugst eine Brise, die stark genug ist, um Stoff zu kräuseln, Staub aufzuwirbeln, Blätter rascheln zu lassen und offene Türen und Fensterläden in einem 1.5-m-Würfel zu schließen. Türen und Fensterläden, die von jemandem oder etwas offengehalten werden, sind nicht betroffen.</li><li><b>Erde herbeirufen:</b> Du erzeugst eine dünne Schicht aus Staub oder Sand, die Oberflächen in einem 1.5-m-Quadrat bedeckt, oder du lässt ein einzelnes Wort in deiner Handschrift in einem Fleck Erde oder Sand erscheinen.</li><li><b>Feuer herbeirufen:</b> Du erzeugst eine dünne Wolke aus harmlosen Funken und farbigem, duftendem Rauch in einem 1.5-m-Würfel. Du wählst die Farbe und den Duft, und die Funken können Kerzen, Fackeln oder Lampen in diesem Bereich entzünden. Der Duft des Rauches hält 1 Minute an.</li><li><b>Wasser herbeirufen:</b> Du erzeugst einen Sprühnebel aus kühlem Dunst, der Kreaturen und Objekte in einem 1.5-m-Würfel leicht anfeuchtet. Alternativ erzeugst du 1 Tasse sauberes Wasser entweder in einem offenen Behälter oder auf einer Oberfläche, und das Wasser verdunstet in 1 Minute.</li><li><b>Element formen:</b> Du bringst Erde, Sand, Feuer, Rauch, Nebel oder Wasser, das in einen 30-cm-Würfel passt, dazu, 1 Stunde lang eine grobe Form (wie die einer Kreatur) anzunehmen.</li></ul>",
        "fireBoltD": "Du schleuderst einen Funken Feuer auf eine Kreatur oder ein Objekt in Reichweite. Mache einen Fernkampf-Zauberangriff gegen das Ziel. Bei einem Treffer erleidet das Ziel 1W10 Feuerschaden. Ein brennbarer Gegenstand, der von diesem Zauber getroffen wird, fängt Feuer, wenn er nicht getragen oder gehalten wird.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W10, wenn du Stufe 5 (2W10), 11 (3W10) und 17 (4W10) erreichst.",
        "friendsD": "Du strahlst magisch ein Gefühl der Freundschaft auf eine Kreatur aus, die du in Reichweite sehen kannst. Das Ziel muss einen Weisheitsrettungswurf bestehen oder wird für die Dauer des Zaubers bezaubert. Das Ziel besteht automatisch, wenn es kein Humanoid ist, wenn du gegen es kämpfst oder wenn du diesen Zauber in den letzten 24 Stunden auf es gewirkt hast.<br><br>Der Zauber endet vorzeitig, wenn das Ziel Schaden erleidet oder wenn du einen Angriffswurf machst, Schaden verursachst oder jemanden zu einem Rettungswurf zwingst. Wenn der Zauber endet, weiß das Ziel, dass es von dir bezaubert wurde.<br><br><b>Material:</b> Etwas Make-up.",
        "guidanceD": "Du berührst eine willige Kreatur und wählst eine Fertigkeit. Bis der Zauber endet, addiert die Kreatur 1W4 zu jedem Fähigkeitswurf, der diese Fertigkeit verwendet.",
        "lightD": "Du berührst ein großes oder kleineres Objekt, das nicht von jemand anderem getragen oder gehalten wird. Bis der Zauber endet, wirft das Objekt helles Licht in einem Radius von 6 m und dämmriges Licht für zusätzliche 6 m. Das Licht kann nach Belieben gefärbt sein.<br><br>Das Abdecken des Objekts mit etwas Undurchsichtigem blockiert das Licht. Der Zauber endet, wenn du ihn erneut wirkst.<br><br><b>Material:</b> Ein Glühwürmchen oder phosphoreszierendes Moos.",
        "mageHandD": "Eine spektrale, schwebende Hand erscheint an einem von dir gewählten Punkt in Reichweite. Die Hand bleibt für die Dauer des Zaubers bestehen. Die Hand verschwindet, wenn sie jemals mehr als 9 m von dir entfernt ist oder wenn du diesen Zauber erneut wirkst.<br><br>Wenn du den Zauber wirkst, kannst du die Hand benutzen, um einen Gegenstand zu manipulieren, eine unverschlossene Tür oder einen Behälter zu öffnen, einen Gegenstand aus einem offenen Behälter zu verstauen oder zu entnehmen oder den Inhalt aus einer Phiole zu gießen.<br><br>Als Magie-Aktion in deinen späteren Zügen kannst du die Hand erneut so steuern. Als Teil dieser Aktion kannst du die Hand bis zu 9 m bewegen.<br><br>Die Hand kann nicht angreifen, magische Gegenstände aktivieren oder mehr als 5 kg tragen.",
        "mendingD": "Dieser Zauber repariert einen einzelnen Bruch oder Riss in einem Objekt, das du berührst, wie ein gebrochenes Kettenglied, zwei Hälften eines zerbrochenen Schlüssels, ein zerrissener Umhang oder ein undichter Weinschlauch. Solange der Bruch oder Riss nicht größer als 30 cm in irgendeiner Dimension ist, besserst du ihn aus, ohne eine Spur des früheren Schadens zu hinterlassen.<br><br>Dieser Zauber kann einen magischen Gegenstand physisch reparieren, aber er kann die Magie eines solchen Gegenstands nicht wiederherstellen.<br><br><b>Material:</b> Zwei Magnetsteine.",
        "messageD": "Du zeigst auf eine Kreatur in Reichweite und flüsterst eine Nachricht. Das Ziel (und nur das Ziel) hört die Nachricht und kann eine kurze Nachricht zurückflüstern, die nur du hörst.<br><br>Du kannst diesen Zauber durch feste Objekte wirken, wenn du mit dem Ziel vertraut bist und weißt, dass es sich hinter dem Hindernis befindet. Eine 30 cm dicke Schicht aus Stein, 2.5 cm aus gewöhnlichem Metall oder eine dünne Bleiplatte blockieren den Zauber.<br><br><b>Material:</b> Ein Kupferdraht.",
        "mindSliverD": "Du versuchst, den Verstand einer Kreatur, die du in Reichweite sehen kannst, vorübergehend zu zersplittern. Das Ziel muss einen Intelligenzrettungswurf bestehen oder 1W6 psychischen Schaden erleiden und 1W4 vom nächsten Rettungswurf abziehen, den es vor dem Ende deines nächsten Zuges macht.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W6, wenn du Stufe 5 (2W6), 11 (3W6) und 17 (4W6) erreichst.",
        "minorIllusionD": "Du erzeugst einen Ton oder ein Bild eines Objekts in Reichweite, das für die Dauer des Zaubers anhält. Die Illusion endet, wenn du diesen Zauber erneut wirkst.<br><br>Wenn eine Kreatur eine Studier-Aktion durchführt, um den Ton oder das Bild zu untersuchen, kann sie mit einem erfolgreichen Intelligenz (Nachforschung)-Wurf gegen deinen Zauberrettungs-SG feststellen, dass es sich um eine Illusion handelt. Wenn eine Kreatur die Illusion als das erkennt, was sie ist, wird die Illusion für sie schwach.<br><br><ul><li><b>Ton:</b> Wenn du einen Ton erzeugst, kann seine Lautstärke von einem Flüstern bis zu einem Schrei reichen. Es kann deine Stimme, die Stimme eines anderen, das Brüllen eines Löwen, Trommelschläge oder jeder andere Ton sein, den du wählst. Der Ton dauert während der gesamten Dauer ununterbrochen an, oder du kannst zu verschiedenen Zeiten diskrete Geräusche machen, bevor der Zauber endet.</li><li><b>Bild:</b> Wenn du ein Bild eines Objekts erzeugst – wie ein Stuhl, schlammige Fußabdrücke oder eine kleine Truhe – darf es nicht größer als ein 1.5-m-Würfel sein. Das Bild kann keinen Ton, kein Licht, keinen Geruch oder einen anderen sensorischen Effekt erzeugen. Physische Interaktion mit dem Bild enthüllt es als Illusion, da Dinge hindurchgehen können.</li></ul><br><b>Material:</b> Ein Stück Vlies.",
        "poisonSprayD": "Du versprühst giftigen Nebel auf eine Kreatur in Reichweite. Mache einen Fernkampf-Zauberangriff gegen das Ziel. Bei einem Treffer erleidet das Ziel 1W12 Giftschaden.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W12, wenn du Stufe 5 (2W12), 11 (3W12) und 17 (4W12) erreichst.",
        "prestidigitationD": "Du erzeugst einen magischen Effekt in Reichweite. Wähle einen Effekt aus den untenstehenden Optionen. Wenn du diesen Zauber mehrmals wirkst, kannst du bis zu drei seiner nicht-augenblicklichen Effekte gleichzeitig aktiv haben.<ul><li><b>Sensorischer Effekt:</b> Du erzeugst einen augenblicklichen, harmlosen sensorischen Effekt, wie einen Funkenregen, einen Windstoß, leise musikalische Noten oder einen seltsamen Geruch.</li><li><b>Feuerspiel:</b> Du entzündest oder löschst augenblicklich eine Kerze, eine Fackel oder ein kleines Lagerfeuer.</li><li><b>Reinigen oder beschmutzen:</b> Du reinigst oder beschmutzt augenblicklich ein Objekt, das nicht größer als ein 30-cm-Würfel ist.</li><li><b>Leichte Empfindung:</b> Du kühlst, wärmst oder aromatisierst bis zu einem 30-cm-Würfel nicht lebendes Material für 1 Stunde.</li><li><b>Magisches Zeichen:</b> Du lässt eine Farbe, ein kleines Zeichen oder ein Symbol auf einem Objekt oder einer Oberfläche für 1 Stunde erscheinen.</li><li><b>Kleine Schöpfung:</b> Du erzeugst ein nichtmagisches Schmuckstück oder ein illusorisches Bild, das in deine Hand passt. Es hält bis zum Ende deines nächsten Zuges an. Ein Schmuckstück kann keinen Schaden verursachen und hat keinen Geldwert.</li></ul>",
        "produceFlameD": "Eine flackernde Flamme erscheint in deiner Hand und bleibt dort für die Dauer des Zaubers. Während sie dort ist, gibt die Flamme keine Wärme ab und entzündet nichts, und sie wirft helles Licht in einem Radius von 6 m und dämmriges Licht für zusätzliche 6 m. Der Zauber endet, wenn du ihn erneut wirkst.<br><br>Bis der Zauber endet, kannst du eine Magie-Aktion ausführen, um Feuer auf eine Kreatur oder ein Objekt in 18 m Entfernung von dir zu schleudern. Mache einen Fernkampf-Zauberangriff. Bei einem Treffer erleidet das Ziel 1W8 Feuerschaden.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W8, wenn du Stufe 5 (2W8), 11 (3W8) und 17 (4W8) erreichst.",
        "rayOfFrostD": "Ein eisiger Strahl aus blau-weißem Licht schießt auf eine Kreatur in Reichweite zu. Mache einen Fernkampf-Zauberangriff gegen das Ziel. Bei einem Treffer erleidet es 1W8 Kälteschaden, und seine Bewegungsrate wird bis zum Beginn deines nächsten Zuges um 3 m reduziert.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W8, wenn du Stufe 5 (2W8), 11 (3W8) und 17 (4W8) erreichst.",
        "resistanceD": "Du berührst eine willige Kreatur und wählst eine Schadensart: Kälte, Blitz, Feuer, Gift, Hieb, Nekrotisch, Säure, Schall, Stich, Strahlend oder Wucht. Wenn die Kreatur vor dem Ende des Zaubers Schaden der gewählten Art erleidet, reduziert sie den erlittenen Gesamtschaden um 1W4. Eine Kreatur kann von diesem Zauber nur einmal pro Zug profitieren.",
        "sacredFlameD": "Flammenähnliche Strahlung senkt sich auf eine Kreatur herab, die du in Reichweite sehen kannst. Das Ziel muss einen Geschicklichkeitsrettungswurf bestehen oder 1W8 Strahlungsschaden erleiden. Das Ziel erhält für diesen Rettungswurf keinen Vorteil durch halbe oder dreiviertel Deckung.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W8, wenn du Stufe 5 (2W8), 11 (3W8) und 17 (4W8) erreichst.",
        "shillelaghD": "Ein Knüppel oder Kampfstab, den du hältst, wird mit der Macht der Natur durchdrungen. Für die Dauer des Zaubers kannst du deine Zauberfähigkeit anstelle von Stärke für die Angriffs- und Schadenswürfe von Nahkampfangriffen mit dieser Waffe verwenden, und der Schadenswürfel der Waffe wird zu einem W8. Wenn der Angriff Schaden verursacht, kann es sich um Energieschaden oder den normalen Schadenstyp der Waffe handeln (deine Wahl).<br><br>Der Zauber endet vorzeitig, wenn du ihn erneut wirkst oder die Waffe loslässt.<br><br><b>Zaubertrick-Upgrade:</b> Der Schadenswürfel ändert sich, wenn du Stufe 5 (W10), 11 (W12) und 17 (2W6) erreichst.<br><br><b>Material:</b> Mistelzweig",
        "shockingGraspD": "Ein Blitz springt von dir auf eine Kreatur über, die du zu berühren versuchst. Mache einen Nahkampf-Zauberangriff gegen das Ziel. Bei einem Treffer erleidet das Ziel 1W8 Blitzschaden und kann bis zum Beginn seines nächsten Zuges keine Gelegenheitsangriffe ausführen.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W8, wenn du Stufe 5 (2W8), 11 (3W8) und 17 (4W8) erreichst.",
        "sorcerousBurstD": "Du schleuderst magische Energie auf eine Kreatur oder ein Objekt in Reichweite. Mache einen Fernkampfangriffswurf gegen das Ziel. Bei einem Treffer erleidet das Ziel 1W8 Schaden einer von dir gewählten Art: Blitz, Eis, Feuer, Gift, Psionisch, Säure oder Schall.<br><br>Wenn du bei diesem Zauber eine 8 auf einem W8 würfelst, kannst du einen weiteren W8 würfeln und ihn zum Schaden hinzufügen. Wenn du diesen Zauber wirkst, entspricht die maximale Anzahl dieser W8, die du zum Schaden des Zaubers hinzufügen kannst, deinem Modifikator für die Zauberfähigkeit.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W8, wenn du Stufe 5 (2W8), 11 (3W8) und 17 (4W8) erreichst.",
        "spareTheDyingD": "Wähle eine Kreatur in Reichweite, die 0 Trefferpunkte hat und nicht tot ist. Die Kreatur wird stabilisiert.<br><br><b>Zaubertrick-Upgrade:</b> Die Reichweite verdoppelt sich, wenn du Stufe 5 (9 m), 11 (18 m) und 17 (36 m) erreichst.",
        "starryWispD": "Du schleuderst einen Lichtfunken auf eine Kreatur oder ein Objekt in Reichweite. Mache einen Fernkampf-Zauberangriff gegen das Ziel. Bei einem Treffer erleidet das Ziel 1W8 Strahlungsschaden und strahlt bis zum Ende deines nächsten Zuges dämmriges Licht in einem Radius von 3 m aus und kann nicht vom Zustand 'Unsichtbar' profitieren.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W8, wenn du Stufe 5 (2W8), 11 (3W8) und 17 (4W8) erreichst.",
        "thaumaturgyD": "Du manifestierst ein kleines Wunder in Reichweite. Du erzeugst einen der folgenden Effekte in Reichweite. Wenn du diesen Zauber mehrmals wirkst, kannst du bis zu drei seiner 1-Minuten-Effekte gleichzeitig aktiv haben.<br><ul><li><b>Veränderte Augen:</b> Du veränderst das Aussehen deiner Augen für 1 Minute.</li><li><b>Dröhnende Stimme:</b> Deine Stimme dröhnt für 1 Minute bis zu dreimal lauter als normal. Für die Dauer hast du Vorteil bei Charisma (Einschüchterung)-Würfen.</li><li><b>Feuerspiel:</b> Du lässt Flammen für 1 Minute flackern, aufleuchten, dimmen oder ihre Farbe ändern.</li><li><b>Unsichtbare Hand:</b> Du lässt eine unverschlossene Tür oder ein Fenster augenblicklich auffliegen oder zuschlagen.</li><li><b>Phantomgeräusch:</b> Du erzeugst ein augenblickliches Geräusch, das von einem Punkt deiner Wahl in Reichweite ausgeht, wie das Grollen von Donner, der Schrei eines Raben oder unheilvolles Flüstern.</li><li><b>Erschütterungen:</b> Du verursachst für 1 Minute harmlose Erschütterungen im Boden.</li></ul>",
        "thornWhipD": "Du erschaffst eine rankenartige, mit Dornen besetzte Peitsche, die auf deinen Befehl hin auf eine Kreatur in Reichweite zuschlägt. Mache einen Nahkampf-Zauberangriff gegen das Ziel. Bei einem Treffer erleidet das Ziel 1W6 Stichschaden, und wenn es groß oder kleiner ist, kannst du es bis zu 3 m näher zu dir ziehen.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W6, wenn du Stufe 5 (2W6), 11 (3W6) und 17 (4W6) erreichst.<br><br><b>Material:</b> Der Stängel einer Pflanze mit Dornen",
        "thunderclapD": "Jede Kreatur in einer 1.5-m-Emanation, die von dir ausgeht, muss einen Konstitutionsrettungswurf bestehen oder 1W6 Schallschaden erleiden. Der donnernde Klang des Zaubers ist bis zu 30 m weit zu hören.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W6, wenn du Stufe 5 (2W6), 11 (3W6) und 17 (4W6) erreichst.",
        "tollTheDeadD": "Du zeigst auf eine Kreatur, die du in Reichweite sehen kannst, und das einzelne Läuten einer schmerzvollen Glocke ist im Umkreis von 3 m um das Ziel hörbar. Das Ziel muss einen Weisheitsrettungswurf bestehen oder 1W8 nekrotischen Schaden erleiden. Wenn dem Ziel Trefferpunkte fehlen, erleidet es stattdessen 1W12 nekrotischen Schaden.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um einen Würfel, wenn du Stufe 5 (2W8 oder 2W12), 11 (3W8 oder 3W12) und 17 (4W8 oder 4W12) erreichst.",
        "trueStrikeD": "Geleitet von einem Blitz magischer Einsicht machst du einen Angriff mit der Waffe, die beim Wirken des Zaubers verwendet wurde. Der Angriff verwendet deine Zauberfähigkeit für die Angriffs- und Schadenswürfe anstelle von Stärke oder Geschicklichkeit. Wenn der Angriff Schaden verursacht, kann es sich um Strahlungsschaden oder den normalen Schadenstyp der Waffe handeln (deine Wahl).<br><br><b>Zaubertrick-Upgrade:</b> Unabhängig davon, ob du Strahlungsschaden oder den normalen Schadenstyp der Waffe verursachst, verursacht der Angriff zusätzlichen Strahlungsschaden, wenn du Stufe 5 (1W6), 11 (2W6) und 17 (3W6) erreichst.<br><br><b>Material:</b> Eine Waffe, mit der du geübt bist und die 1+ KM wert ist",
        "viciousMockeryD": "Du entfesselst eine Reihe von Beleidigungen, die mit subtilen Verzauberungen gespickt sind, auf eine Kreatur, die du in Reichweite sehen oder hören kannst. Das Ziel muss einen Weisheitsrettungswurf bestehen oder 1W6 psychischen Schaden erleiden und hat Nachteil beim nächsten Angriffswurf, den es vor dem Ende seines nächsten Zuges macht.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W6, wenn du Stufe 5 (2W6), 11 (3W6) und 17 (4W6) erreichst.",
        "wordOfRadianceD": "Brennende Strahlung bricht in einer 1.5-m-Emanation von dir aus. Jede Kreatur deiner Wahl, die du darin sehen kannst, muss einen Konstitutionsrettungswurf bestehen oder 1W6 Strahlungsschaden erleiden.<br><br><b>Zaubertrick-Upgrade:</b> Der Schaden erhöht sich um 1W6, wenn du Stufe 5 (2W6), 11 (3W6) und 17 (4W6) erreichst.<br><br><b>Material:</b> Ein Sonnenstrahlen-Symbol",
        "alarmD": "Du stellst einen Alarm gegen Eindringlinge auf. Wähle eine Tür, ein Fenster oder einen Bereich in Reichweite, der nicht größer als ein 6-m-Würfel ist. Bis der Zauber endet, alarmiert dich ein Alarm, wann immer eine Kreatur den geschützten Bereich berührt oder betritt. Wenn du den Zauber wirkst, kannst du Kreaturen bestimmen, die den Alarm nicht auslösen. Du wählst auch, ob der Alarm hörbar oder mental ist:<ul><li><b>Hörbarer Alarm:</b> Der Alarm erzeugt für 10 Sekunden den Klang einer Handglocke im Umkreis von 18 m um den geschützten Bereich.</li><li><b>Mentaler Alarm:</b> Du wirst durch ein mentales Signal alarmiert, wenn du dich innerhalb von 1.6 km des geschützten Bereichs befindest. Dieses Signal weckt dich auf, wenn du schläfst.</li></ul><br><b>Material:</b> Eine Glocke und Silberdraht",
        "animalFriendshipD": "Ziele auf ein Tier, das du in Reichweite sehen kannst. Das Ziel muss einen Weisheitsrettungswarf bestehen oder erhält für die Dauer den Zustand 'Bezaubert'. Wenn du oder einer deiner Verbündeten dem Ziel Schaden zufügt, endet der Zauber.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 1 ein zusätzliches Tier als Ziel wählen.<br><br><b>Material:</b> Ein Bissen Futter",
        "armorOfAgathysD": "Schützender magischer Frost umgibt dich. Du erhältst 5 temporäre Trefferpunkte. Wenn eine Kreatur dich mit einem Nahkampfangriff trifft, bevor der Zauber endet, erleidet die Kreatur 5 Kälteschaden. Der Zauber endet vorzeitig, wenn du keine temporären Trefferpunkte mehr hast.<br><br><b>Höhere Zaubergrade:</b> Die temporären Trefferpunkte und der Kälteschaden erhöhen sich beide um 5 für jeden Zaubergard über 1.<br><br><b>Material:</b> Ein Splitter aus blauem Glas",
        "armsOfHadarD": "Indem du Hadar anrufst, lässt du Tentakel aus dir hervorbrechen. Jede Kreatur in einer 3-m-Emanation, die von dir ausgeht, macht einen Stärkerettungswurf. Bei einem misslungenen Rettungswurf erleidet ein Ziel 2W6 nekrotischen Schaden und kann bis zum Beginn seines nächsten Zuges keine Reaktionen ausführen. Bei einem erfolgreichen Rettungwuf erleidet ein Ziel nur halb so viel Schaden.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W6 für jeden Zaubergrad über 1.",
        "baneD": "Bis zu drei Kreaturen deiner Wahl, die du in Reichweite sehen kannst, müssen jeweils einen Charismarettungswurf machen. Wann immer ein Ziel, das diesen Rettungswurf nicht besteht, einen Angriffswurf oder einen Rettungswurf macht, bevor der Zauber endet, muss das Ziel 1W4 vom Angriffs- oder Rettungswurf abziehen.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 1 eine zusätzliche Kreatur als Ziel wählen.<br><br><b>Material:</b> Ein Tropfen Blut",
        "blessD": "Du segnest bis zu drei Kreaturen in Reichweite. Wann immer ein Ziel einen Angriffswurf oder einen Rettungswurf macht, bevor der Zauber endet, addiert das Ziel 1W4 zum Angriffs- oder Rettungswurf.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 1 eine zusätzliche Kreatur als Ziel wählen.<br><br><b>Material:</b> Ein heiliges Symbol im Wert von 5+ GM",
        "burningHandsD": "Ein dünner Vorhang aus Flammen schießt von dir aus. Jede Kreatur in einem 4.5-m-Kegel macht einen Geschicklichkeitsrettungswurf, erleidet bei einem misslungenen Rettungswurf 3W6 Feuerschaden oder bei einem erfolgreichen halb so viel Schaden.<br><br>Entflammbare Objekte im Kegel, die nicht getragen oder gehalten werden, fangen Feuer.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W6 für jeden Zaubergrad über 1.",
        "charmPersonD": "Ein Humanoid, den du in Reichweite sehen kannst, macht einen Weisheitsrettungswurf. Er tut dies mit Vorteil, wenn du oder deine Verbündeten gegen ihn kämpfen. Bei einem misslungenen Rettungswurf hat das Ziel den Zustand 'Bezaubert', bis der Zauber endet oder bis du oder deine Verbündeten ihm Schaden zufügen. Die bezauberte Kreatur ist dir gegenüber freundlich. Wenn der Zauber endet, weiß das Ziel, dass es von dir bezaubert wurde.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 1 eine zusätzliche Kreatur als Ziel wählen.",
        "chromaticOrbD": "Du schleuderst eine Energiekugel auf ein Ziel in Reichweite. Wähle Kälte, Blitz, Feuer, Gift, Säure oder Schall für die Art der Kugel, die du erschaffst, und mache dann einen Fernkampf-Zauberangriff gegen das Ziel. Bei einem Treffer erleidet das Ziel 3W8 Schaden des gewählten Typs.<br><br>Wenn du bei zwei oder mehr der W8 dieselbe Zahl würfelst, springt die Kugel auf ein anderes Ziel deiner Wahl inner-halb von 9 m des Ziels über. Mache einen Angriffswurf gegen das neue Ziel und einen neuen Schadenswurf. Die Kugel kann nicht erneut springen, es sei denn, du wirkst den Zauber mit einem Zauberplatz des 2. oder höheren Grades.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 1. Die Kugel kann maximal so oft springen, wie der Grad des verbrauchten Zauberplatzes, und eine Kreatur kann nur einmal pro Wirkung dieses Zaubers als Ziel gewählt werden.<br><br><b>Material:</b> Ein Diamant im Wert von 50+ GM",
        "colorSprayD": "Du schleuderst eine blendende Anordnung aus blitzendem, farbenfrohem Licht. Jede Kreatur in einem 4.5-m-Kegel, der von dir ausgeht, muss einen Konstitutionsrettungswurf bestehen oder erhält bis zum Ende deines nächsten Zuges den Zustand 'Blind'.<br><br><b>Material:</b> Eine Prise bunten Sandes",
        "commandD": "Du sprichst einen Ein-Wort-Befehl an eine Kreatur aus, die du in Reichweite sehen kannst. Das Ziel muss einen Weisheitsrettungswurf bestehen oder den Befehl in seinem nächsten Zug befolgen. Wähle den Befehl aus diesen Optionen:<ul><li><b>Nähern:</b> Das Ziel bewegt sich auf dem kürzesten und direktesten Weg auf dich zu und beendet seinen Zug, wenn es sich innerhalb von 1.5 m von dir befindet.</li><li><b>Fallen lassen:</b> Das Ziel lässt alles fallen, was es hält, und beendet dann seinen Zug.</li><li><b>Fliehen:</b> Das Ziel verbringt seinen Zug damit, sich auf dem schnellsten verfügbaren Weg von dir wegzubewegen.</li><li><b>Kriechen:</b> Das Ziel erhält den Zustand 'Liegend' und beendet dann seinen Zug.</li><li><b>Anhalten:</b> In seinem Zug bewegt sich das Ziel nicht und führt keine Aktion oder Bonusaktion aus.</li></ul><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 1 eine zusätzliche Kreatur beeinflussen.",
        "compelledDuelD": "Du versuchst, eine Kreatur zu einem Duell zu zwingen. Eine Kreatur, die du in Reichweite sehen kannst, macht einen Weisheitsrettungswurf. Bei einem misslungenen Rettungswurf hat das Ziel Nachteil bei Angriffswürfen gegen andere Kreaturen als dich, und es kann sich nicht freiwillig in einen Raum bewegen, der mehr als 9 m von dir entfernt ist.<br><br>Der Zauber endet, wenn du einen Angriffswurf gegen eine andere Kreatur als das Ziel machst, wenn du einen Zauber auf einen anderen Feind als das Ziel wirkst, wenn ein Verbündeter von dir das Ziel beschädigt oder wenn du deinen Zug mehr als 9 m vom Ziel entfernt beendest.",
        "comprehendLanguagesD": "Für die Dauer des Zaubers verstehst du die wörtliche Bedeutung jeder Sprache, die du hörst oder in Gebärdensprache siehst. Du verstehst auch jede geschriebene Sprache, die du siehst, aber du musst die Oberfläche berühren, auf der die Worte geschrieben sind. Es dauert etwa 1 Minute, eine Seite Text zu lesen. Dieser Zauber entschlüsselt keine Symbole oder geheimen Botschaften.<br><br><b>Material:</b> Eine Prise Ruß und Salz",
        "createOrDestroyWaterD": "Du tust eines der folgenden Dinge:<ul><li><b>Wasser erschaffen:</b> Du erschaffst bis zu 40 Liter sauberes Wasser in Reichweite in einem offenen Behälter. Alternativ fällt das Wasser als Regen in einem 9-m-Würfel in Reichweite und löscht dort offene Flammen.</li><li><b>Wasser zerstören:</b> Du zerstörst bis zu 40 Liter Wasser in einem offenen Behälter in Reichweite. Alternativ zerstörst du Nebel in einem 9-m-Würfel in Reichweite.</li></ul><br><b>Höhere Zaubergrade:</b> Du erschaffst oder zerstörst 40 zusätzliche Liter Wasser, oder die Größe des Würfels erhöht sich um 1.5 m, für jeden Zaubergrad über 1.<br><br><b>Material:</b> Eine Mischung aus Wasser und Sand",
        "cureWoundsD": "Eine Kreatur, die du berührst, gewinnt eine Anzahl von Trefferpunkten zurück, die 2W8 plus deinem Modifikator für die Zauberfähigkeit entspricht.<br><br><b>Höhere Zaubergrade:</b> Die Heilung erhöht sich um 2W8 für jeden Zaubergrad über 1.",
        "detectEvilAndGoodD": "Für die Dauer des Zaubers spürst du den Standort jeder Aberration, jedes Celestials, Elementars, Fey, Fiends oder Untoten innerhalb von 9 m von dir. Du spürst auch, ob der Zauber 'Weihen' dort aktiv ist und, wenn ja, wo.<br><br>Der Zauber wird durch 30 cm Stein, Erde oder Holz; 2.5 cm Metall; oder eine dünne Bleiplatte blockiert.",
"detectMagicD": "Für die Dauer des Zaubers spürst du die Anwesenheit von magischen Effekten innerhalb von 9 m um dich herum. Wenn du solche Effekte spürst, kannst du die Magie-Aktion nutzen, um eine schwache Aura um jede sichtbare Kreatur oder jeden sichtbaren Gegenstand in dem Bereich zu sehen, der Magie trägt. Wenn ein Effekt durch einen Zauber erzeugt wurde, erfährst du die Magieschule des Zaubers.<br><br>Der Zauber wird durch 30 cm Stein, Erde oder Holz; 2.5 cm Metall; oder eine dünne Bleiplatte blockiert.",
        "detectPoisonAndDiseaseD": "Für die Dauer des Zaubers spürst du den Standort von Giften, giftigen oder venomösen Kreaturen und magischen Seuchen innerhalb von 9 m um dich herum. Du spürst in jedem Fall die Art des Giftes, der Kreatur oder der Seuche.<br><br>Der Zauber wird durch 30 cm Stein, Erde oder Holz; 2.5 cm Metall; oder eine dünne Bleiplatte blockiert.<br><br><b>Material:</b> Ein Eibenblatt.",
        "disguiseSelfD": "Du lässt dich selbst – einschließlich deiner Kleidung, Rüstung, Waffen und anderer Gegenstände an deiner Person – bis zum Ende des Zaubers anders aussehen. Du kannst 30 cm kleiner oder größer erscheinen und schwerer oder leichter wirken. Du musst eine Form annehmen, die dieselbe grundlegende Anordnung von Gliedmaßen hat wie du. Ansonsten liegt das Ausmaß der Illusion bei dir.<br><br>Die durch diesen Zauber bewirkten Veränderungen halten einer physischen Untersuchung nicht stand. Wenn du diesen Zauber beispielsweise nutzt, um einen Hut zu deinem Outfit hinzuzufügen, dringen Gegenstände durch den Hut hindurch, und jeder, der ihn berührt, würde nichts fühlen.<br><br>Um zu erkennen, dass du verkleidet bist, muss eine Kreatur die Studieren-Aktion nutzen, um dein Aussehen zu inspizieren und einen Intelligenz (Nachforschung)-Wurf gegen deinen Zauberrettungs-SG bestehen.",
        "dissonantWhispersD": "Eine Kreatur deiner Wahl, die du in Reichweite sehen kannst, hört eine disharmonische Melodie in ihrem Geist. Das Ziel muss einen Weisheitsrettungswurf machen. Bei einem misslungenen Rettungswurf erleidet es 3W6 psychischen Schaden und muss sofort seine Reaktion verwenden, falls verfügbar, um sich so weit wie möglich von dir wegzubewegen, wobei es die sicherste Route nutzt. Bei einem erfolgreichen Rettungswurf erleidet das Ziel nur halb so viel Schaden.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W6 für jeden Zaubergrad über 1.",
        "divineFavorD": "Bis der Zauber endet, verursachen deine Angriffe mit Waffen bei einem Treffer zusätzlich 1W4 Strahlungsschaden.",
        "divineSmiteD": "Das Ziel erleidet durch den Angriff zusätzlich 2W8 Strahlungsschaden. Der Schaden erhöht sich um 1W8, wenn das Ziel ein Unhold oder ein Untoter ist.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 1.<br><br><b>Bonusaktion:</b> Die du unmittelbar ergreifst, nachdem du ein Ziel mit einer Nahkampfwaffe oder einem unbewaffneten Schlag getroffen hast.",
        "ensnaringStrikeD": "Sobald du das Ziel triffst, erscheinen greifende Ranken an ihm, und es muss einen Stärkerettungswurf machen. Eine große oder größere Kreatur hat Vorteil bei diesem Rettungswurf. Bei einem misslungenen Rettungswurf hat das Ziel den Zustand 'Festgehalten', bis der Zauber endet. Bei einem erfolgreichen Rettungswurf verdorren die Ranken, und der Zauber endet.<br><br>Während es festgehalten ist, erleidet das Ziel zu Beginn jedes seiner Züge 1W6 Stichschaden. Das Ziel oder eine Kreatur in Reichweite kann eine Aktion aufwenden, um einen Stärke (Athletik)-Wurf gegen deinen Zauberrettungs-SG zu machen. Bei einem Erfolg endet der Zauber.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W6 für jeden Zaubergrad über 1.<br><br><b>Bonusaktion:</b> Die du unmittelbar ergreifst, nachdem du eine Kreatur mit einer Waffe getroffen hast.",
        "faerieFireD": "Gegenstände in einem 6-m-Würfel in Reichweite werden in blaues, grünes oder violettes Licht (deiner Wahl) gehüllt. Jede Kreatur im Würfel wird ebenfalls eingehüllt, wenn ihr ein <b>Geschicklichkeitsrettungswurf</b> misslingt. Für die Dauer des Zaubers strahlen Gegenstände und betroffene Kreaturen <b>dämmriges Licht</b> in einem Radius von 3 m aus und können nicht vom Zustand <b>'Unsichtbar'</b> profitieren.<br><br>Angriffswürfe gegen eine betroffene Kreatur oder einen betroffenen Gegenstand haben <b>Vorteil</b>, wenn der Angreifer sie sehen kann.",
        "falseLifeD": "Du erhältst 2W4 + 4 temporäre Trefferpunkte.<br><br><b>Höhere Zaubergrade:</b> Du erhältst 5 zusätzliche temporäre Trefferpunkte für jeden Zaubergrad über 1.<br><br><b>Material:</b> Ein Tropfen Alkohol.",
        "featherFallD": "Wähle bis zu fünf fallende Kreaturen in Reichweite. Die Fallgeschwindigkeit einer fallenden Kreatur verlangsamt sich auf 18 m pro Runde, bis der Zauber endet. Wenn eine Kreatur landet, bevor der Zauber endet, erleidet sie keinen Fallschaden, und der Zauber endet für diese Kreatur.<br><br><b>Reaktion:</b> Die du ergreifst, wenn du oder eine Kreatur, die du sehen kannst, innerhalb von 18 m von dir fällt.<br><br><b>Material:</b> Eine kleine Feder oder Daune.",
        "findFamiliarD": "Du erhältst den Dienst eines Vertrauten, eines Geistes, der eine Tierform deiner Wahl annimmt: Fledermaus, Katze, Kröte, Falke, Eidechse, Oktopus, Eule, Ratte, Rabe, Spinne, Wiesel oder ein anderes Tier mit einem Herausforderungsgrad von 0. Der Vertraute erscheint auf einem unbesetzten Platz in Reichweite und hat die Spielwerte der gewählten Form, ist jedoch ein Celestial, Fey oder Fiend (deine Wahl) anstelle eines Tiers. Dein Vertrauter handelt unabhängig von dir, aber er gehorcht deinen Befehlen.<br><br><b>Telepathische Verbindung:</b> Solange sich dein Vertrauter innerhalb von 30 m von dir befindet, kannst du telepathisch mit ihm kommunizieren. Zusätzlich kannst du als Bonusaktion durch die Augen des Vertrauten sehen und hören, was er hört, bis zum Beginn deines nächsten Zuges, und erhältst die Vorteile aller besonderen Sinne, die er hat.<br><br><b>Zauber übermitteln:</b> Wenn du einen Zauber mit einer Reichweite von Berührung wirkst, kann dein Vertrauter die Berührung übermitteln. Dein Vertrauter muss sich innerhalb von 30 m von dir befinden und seine Reaktion verwenden, um die Berührung zu übermitteln, wenn du den Zauber wirkst.<br><br><b>Kampf:</b> Der Vertraute ist ein Verbündeter für dich und deine Verbündeten. Er würfelt seine eigene Initiative und handelt in seinem eigenen Zug. Ein Vertrauter kann nicht angreifen, aber er kann andere Aktionen wie gewohnt ausführen.<br><br><b>Verschwinden des Vertrauten:</b> Wenn der Vertraute auf 0 Trefferpunkte fällt, verschwindet er. Er erscheint wieder, nachdem du diesen Zauber erneut gewirkt hast. Als Magie-Aktion kannst du den Vertrauten vorübergehend in eine Taschendimension entlassen. Alternativ kannst du ihn für immer entlassen. Als Magie-Aktion, während er vorübergehend entlassen ist, kannst du ihn auf einem unbesetzten Platz innerhalb von 9 m von dir wieder erscheinen lassen. Immer wenn der Vertraute auf 0 Trefferpunkte fällt oder in die Taschendimension verschwindet, lässt er alles, was er trug oder bei sich hatte, an seinem Platz zurück.<br><br><b>Nur ein Vertrauter:</b> Du kannst nicht mehr als einen Vertrauten gleichzeitig haben. Wenn du diesen Zauber wirkst, während du bereits einen Vertrauten hast, lässt du ihn stattdessen eine neue geeignete Form annehmen.<br><br><b>Material:</b> Brennendes Räucherwerk im Wert von 10+ GM, das der Zauber verbraucht.",
        "frogCloudD": "Du erzeugst eine Nebelsphäre mit einem Radius von 6 m, zentriert auf einen Punkt in Reichweite. Die Sphäre ist stark verdunkelt. Sie hält für die Dauer an oder bis ein starker Wind (wie einer, der durch *Windstoß* erzeugt wird) sie vertreibt.<br><br><b>Höhere Zaubergrade:</b> Der Radius des Nebels erhöht sich um 6 m für jeden Zaubergrad über 1.",
        "goodberryD": "Zehn Beeren erscheinen in deiner Hand und sind für die Dauer des Zaubers mit Magie durchdrungen. Eine Kreatur kann eine Bonusaktion verwenden, um eine Beere zu essen. Das Essen einer Beere stellt 1 Trefferpunkt wieder her, und die Beere bietet genug Nahrung, um eine Kreatur für einen Tag zu versorgen.<br><br>Nicht gegessene Beeren verschwinden, wenn der Zauber endet.<br><br><b>Material:</b> Ein Mistelzweig.",
        "greaseD": "Nicht brennbares Fett bedeckt den Boden in einem 3-m-Quadrat, zentriert auf einen Punkt in Reichweite, und verwandelt es für die Dauer in schwieriges Gelände.<br><br>Wenn das Fett erscheint, muss jede Kreatur, die in seinem Bereich steht, einen Geschicklichkeitsrettungswurf bestehen oder erhält den Zustand 'Liegend'. Eine Kreatur, die den Bereich betritt oder ihren Zug dort beendet, muss ebenfalls diesen Rettungswurf bestehen oder stürzt zu Boden.<br><br><b>Material:</b> Ein Stück Schweineschwarte oder Butter.",
        "guidingBoltD": "Du schleuderst einen Lichtblitz auf eine Kreatur in Reichweite. Mache einen Fernkampf-Zauberangriff gegen das Ziel. Bei einem Treffer erleidet es 4W6 Strahlungsschaden, und der nächste Angriffswurf, der vor dem Ende deines nächsten Zuges gegen es gemacht wird, hat Vorteil.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W6 für jeden Zaubergrad über 1.",
        "hailOfThornsD": "Sobald du die Kreatur triffst, erzeugt dieser Zauber einen Regen aus Dornen, der aus deiner Fernkampfwaffe oder Munition sprießt. Das Ziel des Angriffs und jede Kreatur innerhalb von 1.5 m davon müssen einen Geschicklichkeitsrettungswurf machen. Bei einem misslungenen Rettungswurf erleiden sie 1W10 Stichschaden, bei einem erfolgreichen halb so viel Schaden.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W10 für jeden Zaubergrad über 1.<br><br><b>Bonusaktion:</b> Die du unmittelbar ergreifst, nachdem du eine Kreatur mit einer Fernkampfwaffe getroffen hast.",
        "healingWordD": "Eine Kreatur deiner Wahl, die du in Reichweite sehen kannst, erhält Trefferpunkte in Höhe von 2W4 plus deinem Modifikator für die Zauberfähigkeit zurück.<br><br><b>Höhere Zaubergrade:</b> Die Heilung erhöht sich um 2W4 für jeden Zaubergrad über 1.",
        "hellishRebukeD": "Die Kreatur, die dich verletzt hat, wird kurzzeitig von grünen Flammen umhüllt. Sie muss einen Geschicklichkeitsrettungswurf machen. Bei einem misslungenen Rettungswurf erleidet sie 2W10 Feuerschaden, bei einem erfolgreichen halb so viel Schaden.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W10 für jeden Zaubergrad über 1.<br><br><b>Reaktion:</b> Die du als Antwort darauf ergreifst, dass du Schaden von einer Kreatur nimmst, die du innerhalb von 18 m von dir sehen kannst.",
        "heroismD": "Eine willige Kreatur, die du berührst, wird mit Tapferkeit erfüllt. Bis der Zauber endet, ist die Kreatur immun gegen den Zustand 'Verängstigt' und erhält zu Beginn jedes ihrer Züge temporäre Trefferpunkte in Höhe deines Modifikators für die Zauberfähigkeit.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 1 eine zusätzliche Kreatur als Ziel wählen.",
        "hexD": "Du belegst eine Kreatur, die du in Reichweite sehen kannst, mit einem Fluch. Bis der Zauber endet, verursachst du dem Ziel zusätzlich 1W6 nekrotischen Schaden, wenn du es mit einem Angriffswurf triffst. Wähle außerdem beim Wirken des Zaubers ein Attribut. Das Ziel hat Nachteil bei Attributswürfen, die mit dem gewählten Attribut gemacht werden.<br><br>Wenn das Ziel auf 0 Trefferpunkte fällt, bevor dieser Zauber endet, kannst du in einem späteren Zug eine Bonusaktion verwenden, um eine neue Kreatur zu verfluchen.<br><br><b>Höhere Zaubergrade:</b> Deine Konzentration kann mit einem Zauberplatz des Levels 2 (bis zu 4 Stunden), 3–4 (bis zu 8 Stunden) oder 5+ (24 Stunden) länger anhalten.<br><br><b>Material:</b> Das versteinerte Auge eines Molchs.",
        "huntersMarkD": "Du markierst eine Kreatur, die du in Reichweite sehen kannst, magisch als deine Beute. Bis der Zauber endet, verursachst du dem Ziel zusätzlich 1W6 Energieschaden, wenn du es mit einem Angriffswurf triffst. Du hast auch Vorteil bei jedem Weisheit (Wahrnehmung oder Überleben)-Wurf, den du machst, um es zu finden.<br><br>Wenn das Ziel auf 0 Trefferpunkte fällt, bevor dieser Zauber endet, kannst du eine Bonusaktion verwenden, um die Markierung auf eine neue Kreatur zu verschieben, die du in Reichweite sehen kannst.<br><br><b>Höhere Zaubergrade:</b> Deine Konzentration kann mit einem Zauberplatz des Levels 3–4 (bis zu 8 Stunden) oder 5+ (bis zu 24 Stunden) länger anhalten.",
        "iceKnifeD": "Du erschaffst einen Eissplitter und schleuderst ihn auf eine Kreatur in Reichweite. Mache einen Fernkampf-Zauberangriff gegen das Ziel. Bei einem Treffer erleidet das Ziel 1W10 Stichschaden. Unabhängig davon, ob du triffst oder verfehlst, explodiert der Splitter anschließend. Das Ziel und jede Kreatur innerhalb von 1.5 m davon müssen einen Geschicklichkeitsrettungswurf bestehen oder 2W6 Kälteschaden erleiden.<br><br><b>Höhere Zaubergrade:</b> Der Kälteschaden erhöht sich um 1W6 für jeden Zaubergrad über 1.<br><br><b>Material:</b> (ein Tropfen Wasser oder ein Stück Eis)",
        "identifyD": "Du berührst während des Wirkens des Zaubers einen Gegenstand. Wenn der Gegenstand ein magischer Gegenstand oder ein anderer magischer Objekt ist, erfährst du seine Eigenschaften und wie man sie benutzt, ob er Einstimmung erfordert und wie viele Ladungen er hat, falls vorhanden. Du erfährst, ob irgendwelche andauernden Zauber den Gegenstand beeinflussen und welche das sind. Wenn der Gegenstand durch einen Zauber erschaffen wurde, erfährst du den Namen dieses Zaubers.<br><br>Wenn du stattdessen während des Wirkens eine Kreatur berührst, erfährst du, welche andauernden Zauber, falls vorhanden, sie derzeit beeinflussen.<br><br><b>Material:</b> Eine Perle im Wert von 100+ GM.",
        "illusoryScriptD": "Du schreibst auf Pergament, Papier oder ein anderes geeignetes Material und versiehst es mit einer Illusion, die für die Dauer anhält. Für dich und alle Kreaturen, die du beim Wirken des Zaubers bestimmst, erscheint die Schrift normal, scheint in deiner Handschrift geschrieben zu sein und vermittelt die Bedeutung, die du beim Schreiben des Textes beabsichtigt hast. Für alle anderen erscheint die Schrift wie in einer unbekannten oder magischen Schrift geschrieben, die unverständlich ist. Alternativ kann die Illusion die Bedeutung, Handschrift und Sprache des Textes ändern, obwohl die Sprache eine sein muss, die du kennst.<br><br>Wenn der Zauber gebannt wird, verschwinden sowohl die Originalschrift als auch die Illusion.<br><br>Eine Kreatur mit *Wahrer Blick* kann die versteckte Nachricht lesen.<br><br><b>Material:</b> Tinte im Wert von 10+ GM, die der Zauber verbraucht.",
        "inflictWoundsD": "Eine Kreatur, die du berührst, muss einen Konstitutionsrettungswurf machen. Bei einem misslungenen Rettungswurf erleidet sie 2W10 nekrotischen Schaden, bei einem erfolgreichen halb so viel Schaden.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W10 für jeden Zaubergrad über 1.",
        "jumpD": "Du berührst eine willige Kreatur. Einmal in jedem ihrer Züge bis zum Ende des Zaubers kann diese Kreatur bis zu 9 m weit springen, indem sie 3 m ihrer Bewegung aufwendet.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 1 eine zusätzliche Kreatur als Ziel wählen.<br><br><b>Material:</b> Das Hinterbein einer Heuschrecke.",
        "longstriderD": "Du berührst eine Kreatur. Die Bewegungsrate des Ziels erhöht sich um 3 m, bis der Zauber endet.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 1 eine zusätzliche Kreatur als Ziel wählen.<br><br><b>Material:</b> Eine Prise Erde.",
        "mageArmorD": "Du berührst eine willige Kreatur, die keine Rüstung trägt. Bis der Zauber endet, wird die Basis-RK des Ziels 13 + sein Geschicklichkeitsmodifikator. Der Zauber endet vorzeitig, wenn das Ziel Rüstung anlegt.<br><br><b>Material:</b> Ein Stück gehärtetes Leder.",
        "magicMissileD": "Du erschaffst drei glühende Pfeile aus magischer Energie. Jeder Pfeil trifft eine Kreatur deiner Wahl, die du in Reichweite sehen kannst. Ein Pfeil verursacht 1W4 + 1 Energieschaden bei seinem Ziel. Die Pfeile treffen alle gleichzeitig ein, und du kannst sie anweisen, eine Kreatur oder mehrere zu treffen.<br><br><b>Höhere Zaubergrade:</b> Der Zauber erzeugt einen weiteren Pfeil für jeden Zaubergrad über 1.",
        "protectionFromEvilAndGoodD": "Bis der Zauber endet, ist eine willige Kreatur, die du berührst, gegen Kreaturen geschützt, die Aberrationen, Celestials, Elementare, Fey, Fiends oder Untote sind. Der Schutz gewährt mehrere Vorteile. Kreaturen dieser Typen haben Nachteil bei Angriffswürfen gegen das Ziel. Das Ziel kann auch nicht von ihnen besessen werden oder den Zustand 'Bezaubert' oder 'Verängstigt' von ihnen erhalten. Wenn das Ziel bereits von einer solchen Kreatur besessen, bezaubert oder verängstigt ist, hat das Ziel Vorteil bei jedem neuen Rettungswurf gegen den betreffenden Effekt.<br><br><b>Material:</b> Ein Fläschchen Weihwasser im Wert von 25+ GM, das der Zauber verbraucht.",
        "purifyFoodAndDrinkD": "Du entfernst Gift und Fäulnis aus nichtmagischen Speisen und Getränken in einer Sphäre mit einem Radius von 1.5 m, zentriert auf einen Punkt in Reichweite.",
        "rayOfSicknessD": "Du schießt einen grünlichen Strahl auf eine Kreatur in Reichweite. Mache einen Fernkampf-Zauberangriff gegen das Ziel. Bei einem Treffer erleidet das Ziel 2W8 Giftschaden und hat bis zum Ende deines nächsten Zuges den Zustand 'Vergiftet'.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 1.",
        "sanctuaryD": "Du schützt eine Kreatur in Reichweite. Bis der Zauber endet, muss jede Kreatur, die die geschützte Kreatur mit einem Angriffswurf oder einem schädlichen Zauber ins Visier nimmt, einen Weisheitsrettungswurf bestehen oder entweder ein neues Ziel wählen oder den Angriff oder Zauber verlieren. Dieser Zauber schützt die geschützte Kreatur nicht vor Flächeneffekten.<br><br>Der Zauber endet, wenn die geschützte Kreatur einen Angriffswurf macht, einen Zauber wirkt oder Schaden verursacht.<br><br><b>Material:</b> Eine Glasscherbe von einem Spiegel.",
        "searingSmiteD": "Sobald du das Ziel triffst, erleidet es zusätzlich 1W6 Feuerschaden durch den Angriff. Zu Beginn jedes seiner Züge bis zum Ende des Zaubers erleidet das Ziel 1W6 Feuerschaden und macht dann einen Konstitutionsrettungswurf. Bei einem misslungenen Rettungswurf hält der Zauber an. Bei einem erfolgreichen Rettungswurf endet der Zauber.<br><br><b>Höhere Zaubergrade:</b> Der gesamte Schaden erhöht sich um 1W6 für jeden Zaubergrad über 1.<br><br><b>Bonusaktion:</b> Die du unmittelbar ergreifst, nachdem du ein Ziel mit einer Nahkampfwaffe oder einem unbewaffneten Schlag getroffen hast.",
        "shieldD": "Eine unmerkliche Barriere aus magischer Kraft schützt dich. Bis zum Beginn deines nächsten Zuges hast du einen Bonus von +5 auf die RK, auch gegen den auslösenden Angriff, und du nimmst keinen Schaden durch *Magisches Geschoss*.<br><br><b>Reaktion:</b> Die du ergreifst, wenn du von einem Angriffswurf getroffen wirst oder vom Zauber *Magisches Geschoss* anvisiert wirst.",
        "shieldOfFaithD": "Ein schimmerndes Feld umgibt eine Kreatur deiner Wahl in Reichweite und gewährt ihr für die Dauer einen Bonus von +2 auf die RK.<br><br><b>Material:</b> Eine Gebetsrolle.",
        "silentImageD": "Du erschaffst das Bild eines Objekts, einer Kreatur oder eines anderen sichtbaren Phänomens, das nicht größer als ein 4.5-m-Würfel ist. Das Bild erscheint an einem Ort in Reichweite und hält für die Dauer an. Das Bild ist rein visuell; es wird nicht von Geräuschen, Gerüchen oder anderen sensorischen Effekten begleitet.<br><br>Als Magie-Aktion kannst du das Bild an jeden Ort in Reichweite bewegen. Während das Bild seinen Standort ändert, kannst du sein Aussehen so verändern, dass seine Bewegungen für das Bild natürlich erscheinen. Wenn du beispielsweise ein Bild einer Kreatur erschaffst und es bewegst, kannst du das Bild so verändern, dass es zu laufen scheint.<br><br>Physische Interaktion mit dem Bild enthüllt es als Illusion, da Dinge hindurchgehen können. Eine Kreatur, die eine Studieren-Aktion nutzt, um das Bild zu untersuchen, kann mit einem erfolgreichen Intelligenz (Nachforschung)-Wurf gegen deinen Zauberrettungs-SG feststellen, dass es sich um eine Illusion handelt. Wenn eine Kreatur die Illusion als das erkennt, was sie ist, kann sie durch das Bild hindurchsehen.<br><br><b>Material:</b> Ein Stück Vlies.",
        "sleepD": "Jede Kreatur deiner Wahl in einer Sphäre mit 1.5-m-Radius, zentriert auf einen Punkt in Reichweite, muss einen Weisheitsrettungswurf bestehen oder erhält bis zum Ende ihres nächsten Zuges den Zustand 'Handlungsunfähig'. Zu diesem Zeitpunkt muss sie den Rettungswurf wiederholen. Wenn das Ziel den zweiten Rettungswurf nicht besteht, erhält es für die Dauer den Zustand 'Bewusstlos'. Der Zauber endet bei einem Ziel, wenn es Schaden erleidet oder jemand innerhalb von 1.5 m von ihm eine Aktion aufwendet, um es aus der Wirkung des Zaubers aufzurütteln.<br><br>Kreaturen, die nicht schlafen, wie Elfen, oder die Immunität gegen den Zustand 'Erschöpfung' haben, bestehen Rettungswürfe gegen diesen Zauber automatisch.<br><br><b>Material:</b> Eine Prise Sand oder Rosenblüten.",
        "speakWithAnimalsD": "Für die Dauer des Zaubers kannst du Tiere verstehen und verbal mit ihnen kommunizieren, und du kannst alle Fertigkeitsoptionen der Einfluss-Aktion mit ihnen nutzen.<br><br>Die meisten Tiere haben wenig zu Themen zu sagen, die nicht Überleben oder Kameradschaft betreffen, aber zumindest kann dir ein Tier Informationen über nahegelegene Orte und Monster geben, einschließlich allem, was es innerhalb des letzten Tages wahrgenommen hat.",
        "thounderousSmiteD": "Dein Schlag ertönt mit Donner, der innerhalb von 90 m von dir hörbar ist, und das Ziel erleidet zusätzlich 2W6 Schallschaden durch den Angriff. Wenn das Ziel eine Kreatur ist, muss es zusätzlich einen Stärkerettungswurf bestehen oder wird 3 m von dir weggestoßen und erhält den Zustand 'Liegend'.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W6 für jeden Zaubergrad über 1.<br><br><b>Bonusaktion:</b> Die du unmittelbar ergreifst, nachdem du ein Ziel mit einer Nahkampfwaffe oder einem unbewaffneten Schlag getroffen hast.",
        "thunderwaveD": "Du entfesselst eine Welle donnernder Energie. Jede Kreatur in einem 4.5-m-Würfel, der von dir ausgeht, muss einen Konstitutionsrettungswurf machen. Bei einem misslungenen Rettungswurf erleidet eine Kreatur 2W8 Schallschaden und wird 3 m von dir weggestoßen. Bei einem erfolgreichen Rettungswurf erleidet eine Kreatur nur halb so viel Schaden.<br><br>Zusätzlich werden ungesicherte Gegenstände, die sich vollständig innerhalb des Würfels befinden, 3 m von dir weggestoßen, und ein donnernder Knall ist innerhalb von 90 m hörbar.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 1.",
        "unseenServantD": "Dieser Zauber erschafft eine unsichtbare, geistlose, formlose, mittelgroße Kraft, die für die Dauer des Zaubers einfache Aufgaben auf deinen Befehl hin ausführt. Der Diener entsteht auf einem unbesetzten Platz auf dem Boden in Reichweite. Er hat RK 10, 1 Trefferpunkt und eine Stärke von 2 und kann nicht angreifen. Wenn er auf 0 Trefferpunkte fällt, endet der Zauber.<br><br>Einmal in jedem deiner Züge kannst du als Bonusaktion dem Diener mental befehlen, sich bis zu 4.5 m zu bewegen und mit einem Gegenstand zu interagieren. Der Diener kann einfache Aufgaben ausführen, die ein Mensch erledigen könnte, wie Dinge holen, putzen, flicken, Kleidung falten, Feuer anzünden, Essen servieren und Getränke einschenken. Sobald du den Befehl gibst, führt der Diener die Aufgabe nach bestem Vermögen aus, bis er die Aufgabe abgeschlossen hat, und wartet dann auf deinen nächsten Befehl.<br><br>Wenn du dem Diener befiehlst, eine Aufgabe auszuführen, die ihn mehr als 18 m von dir wegbewegen würde, endet der Zauber.<br><br><b>Material:</b> Ein Stück Schnur und Holz.",
        "witchBoltD": "Ein Strahl knisternder Energie schießt auf eine Kreatur in Reichweite zu und bildet einen anhaltenden Blitzbogen zwischen dir und dem Ziel. Mache einen Fernkampf-Zauberangriff gegen es. Bei einem Treffer erleidet das Ziel 2W12 Blitzschaden.<br><br>In jedem deiner folgenden Züge kannst du eine Bonusaktion verwenden, um dem Ziel automatisch 1W12 Blitzschaden zuzufügen, selbst wenn der erste Angriff verfehlt hat.<br><br>Der Zauber endet, wenn das Ziel jemals außerhalb der Reichweite des Zaubers ist oder wenn es vollständige Deckung vor dir hat.<br><br><b>Höhere Zaubergrade:</b> Der anfängliche Schaden erhöht sich um 1W12 für jeden Zaubergrad über 1.<br><br><b>Material:</b> Ein vom Blitz getroffener Zweig.",
        "wrathfulSmiteD": "Das Ziel erleidet zusätzlich 1W6 nekrotischen Schaden durch den Angriff und muss einen Weisheitsrettungswurf bestehen oder erhält bis zum Ende des Zaubers den Zustand 'Verängstigt'. Am Ende jedes seiner Züge wiederholt das verängstigte Ziel den Rettungswurf und beendet den Zauber bei einem Erfolg für sich selbst.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W6 für jeden Zaubergrad über 1.<br><br><b>Bonusaktion:</b> Die du unmittelbar ergreifst, nachdem du eine Kreatur mit einer Nahkampfwaffe oder einem unbewaffneten Schlag getroffen hast.",
        "aidD": "Wähle bis zu drei Kreaturen in Reichweite. Das Trefferpunktemaximum und die aktuellen Trefferpunkte jedes Ziels erhöhen sich für die Dauer um 5.<br><br><b>Höhere Zaubergrade:</b> Die Trefferpunkte jedes Ziels erhöhen sich um 5 für jeden Zaubergrad über 2.<br><br><b>Material:</b> Ein Streifen weißer Stoff.",
        "alterSelfD": "Du veränderst deine physische Form. Wähle eine der folgenden Optionen. Ihre Effekte halten für die Dauer an, während der du eine Magie-Aktion nutzen kannst, um die gewählte Option durch eine andere zu ersetzen.<br><ul><li><b>Aquatische Anpassung:</b> Dir sprießen Kiemen und zwischen deinen Fingern wachsen Schwimmhäute. Du kannst unter Wasser atmen und erhältst eine Schwimmgeschwindigkeit, die deiner Bewegungsrate entspricht.</li><li><b>Aussehen ändern:</b> Du veränderst dein Aussehen. Du entscheidest, wie du aussiehst, einschließlich deiner Größe, deines Gewichts, deiner Gesichtszüge, des Klangs deiner Stimme, deiner Haarlänge, deiner Färbung und anderer Unterscheidungsmerkmale. Du kannst dich als Mitglied einer anderen Spezies erscheinen lassen, obwohl sich keine deiner Spielwerte ändern. Du kannst nicht als Kreatur einer anderen Größe erscheinen, und deine Grundform bleibt dieselbe; wenn du zweibeinig bist, kannst du diesen Zauber zum Beispiel nicht nutzen, um vierbeinig zu werden. Für die Dauer kannst du eine Magie-Aktion nutzen, um dein Aussehen auf diese Weise erneut zu ändern.</li><li><b>Natürliche Waffen:</b> Dir wachsen Klauen (Hieb), Reißzähne (Stich), Hörner (Stich) oder Hufe (Wucht). Wenn du deinen unbewaffneten Schlag nutzt, um mit diesem neuen Wuchs Schaden zu verursachen, verursacht er 1W6 Schaden des in Klammern angegebenen Typs anstelle des normalen Schadens für deinen unbewaffneten Schlag, und du verwendest deinen Modifikator für die Zauberfähigkeit für die Angriffs- und Schadenswürfe anstelle von Stärke.</li></ul>",
        "animalMessnengerD": "Ein winziges Tier deiner Wahl, das du in Reichweite sehen kannst, muss einen Charisma-Rettungswurf bestehen, oder es versucht, eine Nachricht für dich zu überbringen (wenn der Herausforderungsgrad des Ziels nicht 0 ist, gelingt es automatisch). Du gibst einen Ort an, den du besucht hast, und einen Empfänger, der einer allgemeinen Beschreibung entspricht, wie „eine Person in der Uniform der Stadtwache“ oder „ein rothaariger Zwerg mit spitzem Hut“. Du übermittelst auch eine Nachricht von bis zu fünfundzwanzig Wörtern. Das Tier reist für die Dauer des Zaubers zum angegebenen Ort und legt dabei etwa 40 km pro 24 Stunden zurück, oder 80 km, wenn das Tier fliegen kann.<br><br>Wenn das Tier ankommt, überbringt es deine Nachricht der Kreatur, die du beschrieben hast, und ahmt deine Kommunikation nach. Wenn das Tier sein Ziel nicht erreicht, bevor der Zauber endet, ist die Nachricht verloren, und das Tier kehrt dorthin zurück, wo du den Zauber gewirkt hast.<br><br><b>Höhere Zaubergrade:</b> Die Dauer des Zaubers erhöht sich um 48 Stunden für jeden Zaubergrad über 2.<br><br><b>Material:</b> Ein Bissen Futter.",
        "arcaneLockD": "Du berührst eine geschlossene Tür, ein Fenster, ein Tor, einen Behälter oder eine Luke und verschließt sie magisch für die Dauer. Dieses Schloss kann nicht mit nichtmagischen Mitteln geöffnet werden. Du und alle Kreaturen, die du beim Wirken des Zaubers bestimmst, können das Objekt trotz des Schlosses öffnen und schließen. Du kannst auch ein Passwort festlegen, das, wenn es innerhalb von 1.5 m des Objekts gesprochen wird, es für 1 Minute entriegelt.<br><br><b>Material:</b> Goldstaub im Wert von 25+ GM, den der Zauber verbraucht.",
        "arcaneVigorD": "Du zapfst deine Lebenskraft an, um dich selbst zu heilen. Würfle einen oder zwei deiner unverbrauchten Trefferwürfel und gewinne eine Anzahl von Trefferpunkten zurück, die der Gesamtsumme des Wurfs plus deinem Modifikator für die Zauberfähigkeit entspricht. Diese Würfel sind dann verbraucht.<br><br><b>Höhere Zaubergrade:</b> Die Anzahl der unverbrauchten Trefferwürfel, die du würfeln kannst, erhöht sich um eins für jeden Zaubergrad über 2.",
        "auguryD": "Du erhältst ein Omen von einer außerweltlichen Entität über die Ergebnisse einer Handlung, die du innerhalb der nächsten 30 Minuten planst. Der SL wählt das Omen aus der Omen-Tabelle.<br><br><table class=\"spell-table\"><caption>Omen</caption><tr><th>Omen</th><th>Ergebnis</th></tr><tr><td>Heil</td><td>Gut</td></tr><tr><td>Unheil</td><td>Schlecht</td></tr><tr><td>Heil und Unheil</td><td>Gut und schlecht</td></tr><tr><td>Gleichgültigkeit</td><td>Weder gut noch schlecht</td></tr></table><br>Der Zauber berücksichtigt keine Umstände, wie zum Beispiel andere Zauber, die die Ergebnisse verändern könnten.<br><br>Wenn du den Zauber mehr als einmal wirkst, bevor du eine lange Rast beendest, besteht eine kumulative Chance von 25 Prozent für jeden Wurf nach dem ersten, dass du keine Antwort erhältst.<br><br><b>Material:</b> Speziell markierte Stäbchen, Knochen, Karten oder andere Weissagungs-Token im Wert von 25+ GM.",
        "barkskinD": "Du berührst eine willige Kreatur. Bis der Zauber endet, nimmt die Haut des Ziels ein rindenartiges Aussehen an, und das Ziel hat eine Rüstungsklasse (RK) von 17, falls seine RK niedriger ist.<br><br><b>Material:</b> Eine Handvoll Eichenrinde.",
        "beastSenseD": "Du berührst ein williges Tier. Für die Dauer des Zaubers kannst du sowohl durch die Sinne des Tiers als auch durch deine eigenen wahrnehmen. Wenn du durch die Sinne des Tiers wahrnimmst, profitierst du von allen besonderen Sinnen, die es hat.",
        "blindness_DeafnessD": "Eine Kreatur, die du in Reichweite sehen kannst, muss einen Konstitutionsrettungswurf bestehen, oder sie erhält für die Dauer den Zustand 'Blind' oder 'Taub' (deine Wahl). Am Ende jedes ihrer Züge wiederholt das Ziel den Rettungswurf und beendet den Zauber bei einem Erfolg für sich selbst.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 2 eine zusätzliche Kreatur als Ziel wählen.",
        "blurD": "Dein Körper wird verschwommen. Für die Dauer des Zaubers hat jede Kreatur Nachteil bei Angriffswürfen gegen dich. Ein Angreifer ist immun gegen diesen Effekt, wenn er dich mit *Blindsicht* oder *Wahrer Blick* wahrnimmt.",
        "calmEmotionsD": "Jeder Humanoid in einer Sphäre mit einem Radius von 6 m, zentriert auf einen Punkt, den du in Reichweite wählst, muss einen Charisma-Rettungswurf bestehen oder wird von einem der folgenden Effekte betroffen (wähle für jede Kreatur):<br><ul><li>Die Kreatur hat Immunität gegen die Zustände 'Bezaubert' und 'Verängstigt', bis der Zauber endet. Wenn die Kreatur bereits bezaubert oder verängstigt war, werden diese Zustände für die Dauer unterdrückt.</li><li>Die Kreatur wird gleichgültig gegenüber Kreaturen deiner Wahl, denen sie feindlich gesinnt ist. Diese Gleichgültigkeit endet, wenn das Ziel Schaden nimmt oder Zeuge wird, wie seine Verbündeten Schaden nehmen. Wenn der Zauber endet, kehrt die Einstellung der Kreatur zum Normalzustand zurück.</li></ul>",
        "cloudOfDaggersD": "Du beschwörst wirbelnde Dolche in einem 1.5-m-Würfel, zentriert auf einen Punkt in Reichweite. Jede Kreatur in diesem Bereich erleidet 4W4 Hiebschaden. Eine Kreatur erleidet diesen Schaden auch, wenn sie den Würfel betritt, ihren Zug dort beendet oder wenn sich der Würfel in ihren Bereich bewegt. Eine Kreatur erleidet diesen Schaden nur einmal pro Zug.<br><br>In deinen späteren Zügen kannst du eine Magie-Aktion nutzen, um den Würfel bis zu 9 m zu teleportieren.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 2W4 für jeden Zaubergrad über 2.<br><br><b>Material:</b> Ein Glassplitter.",
        "continualFlameD": "Eine Flamme entspringt einem Gegenstand, den du berührst. Der Effekt wirft helles Licht in einem Radius von 6 m und dämmriges Licht für zusätzliche 6 m. Sie sieht aus wie eine normale Flamme, erzeugt aber keine Wärme und verbraucht keinen Brennstoff. Die Flamme kann abgedeckt oder versteckt, aber nicht erstickt oder gelöscht werden.<br><br><b>Material:</b> Rubinstaub im Wert von 50+ GM, den der Zauber verbraucht.",
        "darknessD": "Für die Dauer des Zaubers breitet sich magische Dunkelheit von einem Punkt in Reichweite aus und füllt eine Sphäre mit einem Radius von 4.5 m. Dunkelsicht kann nicht hindurchsehen, und nichtmagisches Licht kann sie nicht erhellen.<br><br>Alternativ kannst du den Zauber auf ein Objekt wirken, das nicht getragen oder gehalten wird, wodurch die Dunkelheit eine 4.5-m-Emanation füllt, die von diesem Objekt ausgeht. Das Abdecken dieses Objekts mit etwas Undurchsichtigem, wie einer Schüssel oder einem Helm, blockiert die Dunkelheit.<br><br>Wenn sich ein Teil des Bereichs dieses Zaubers mit einem Bereich von hellem Licht oder dämmrigem Licht überschneidet, der durch einen Zauber des 2. Grades oder niedriger erzeugt wurde, wird dieser andere Zauber gebannt.<br><br><b>Material:</b> Fledermausfell und ein Stück Kohle.",
        "darkvisionD": "Für die Dauer des Zaubers hat eine willige Kreatur, die du berührst, Dunkelsicht mit einer Reichweite von 45 m.<br><br><b>Material:</b> Eine getrocknete Karotte.",
        "detectThoughtsD": "Du aktivierst einen der folgenden Effekte. Bis der Zauber endet, kannst du jeden Effekt als Magie-Aktion in deinen späteren Zügen aktivieren.<br><ul><li><b>Gedanken wahrnehmen:</b> Du spürst die Anwesenheit von Gedanken innerhalb von 9 m um dich herum, die zu Kreaturen gehören, die Sprachen kennen oder telepathisch sind. Du liest die Gedanken nicht, aber du weißt, dass eine denkende Kreatur anwesend ist. Der Zauber wird durch 30 cm Stein, Erde oder Holz; 2.5 cm Metall; oder eine dünne Bleiplatte blockiert.</li><li><b>Gedanken lesen:</b> Ziele auf eine Kreatur, die du innerhalb von 9 m von dir sehen kannst, oder auf eine Kreatur innerhalb von 9 m, die du mit der Option 'Gedanken wahrnehmen' entdeckt hast. Du erfährst, was dem Ziel gerade am meisten durch den Kopf geht. Wenn das Ziel keine Sprachen kennt und nicht telepathisch ist, erfährst du nichts.<br><br>Als Magie-Aktion in deinem nächsten Zug kannst du versuchen, tiefer in den Geist des Ziels einzudringen. Wenn du tiefer eindringst, macht das Ziel einen Weisheitsrettungswurf. Bei einem misslungenen Rettungswurf erkennst du die Argumentation, Emotionen und etwas, das dem Ziel sehr wichtig ist (wie eine Sorge, Liebe oder Hass). Bei einem erfolgreichen Rettungswurf endet der Zauber. So oder so weiß das Ziel, dass du in seinen Geist eindringst, und bis du deine Aufmerksamkeit vom Geist des Ziels abwendest, kann das Ziel in seinem Zug eine Aktion nutzen, um einen Intelligenz (Arkanes)-Wurf gegen deinen Zauberrettungs-SG zu machen, wodurch der Zauber bei einem Erfolg endet.</li></ul><br><b>Material:</b> 1 Kupfermünze.",
        "dragonsBreathD": "Du berührst eine willige Kreatur und wählst Säure, Kälte, Feuer, Blitz oder Gift. Bis der Zauber endet, kann das Ziel eine Magie-Aktion nutzen, um einen 4.5-m-Kegel auszustoßen. Jede Kreatur in diesem Bereich muss einen Geschicklichkeitsrettungswurf machen. Bei einem misslungenen Rettungswurf erleidet sie 3W6 Schaden des gewählten Typs, bei einem erfolgreichen halb so viel Schaden.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W6 für jeden Zaubergrad über 2.<br><br><b>Material:</b> Eine scharfe Paprika.",
        "enhanceAbilityD": "Du berührst eine Kreatur und wählst Stärke, Geschicklichkeit, Intelligenz, Weisheit oder Charisma. Für die Dauer des Zaubers hat das Ziel Vorteil bei Attributswürfen, die das gewählte Attribut verwenden.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 2 eine zusätzliche Kreatur als Ziel wählen. Du kannst für jedes Ziel ein anderes Attribut wählen.<br><br><b>Material:</b> Fell oder eine Feder.",
        "enlarge_ReduceD": "Für die Dauer des Zaubers vergrößert oder verkleinert der Zauber eine Kreatur oder ein Objekt, das du in Reichweite sehen kannst (siehe den gewählten Effekt unten). Ein anvisiertes Objekt darf weder getragen noch gehalten werden. Wenn das Ziel eine unwillige Kreatur ist, kann es einen Konstitutionsrettungswurf machen. Bei einem erfolgreichen Rettungswurf hat der Zauber keine Wirkung.<br><br>Alles, was eine anvisierte Kreatur trägt und hält, ändert seine Größe mit ihr. Jeder Gegenstand, den sie fallen lässt, kehrt sofort zu seiner normalen Größe zurück. Eine geworfene Waffe oder ein Stück Munition kehrt sofort zu seiner normalen Größe zurück, nachdem es ein Ziel getroffen oder verfehlt hat.<br><ul><li><b>Vergrößern:</b> Die Größe des Ziels erhöht sich um eine Kategorie – zum Beispiel von Mittel auf Groß. Das Ziel hat auch Vorteil bei Stärkewürfen und Stärkerettungswürfen. Die Angriffe des Ziels mit seinen vergrößerten Waffen oder unbewaffneten Schlägen verursachen bei einem Treffer zusätzlich 1W4 Schaden.</li><li><b>Verkleinern:</b> Die Größe des Ziels verringert sich um eine Kategorie – zum Beispiel von Mittel auf Klein. Das Ziel hat auch Nachteil bei Stärkewürfen und Stärkerettungswürfen. Die Angriffe des Ziels mit seinen verkleinerten Waffen oder unbewaffneten Schlägen verursachen bei einem Treffer 1W4 weniger Schaden (dies kann den Schaden nicht unter 1 reduzieren).</li></ul><br><b>Material:</b> Eine Prise Eisenpulver.",
        "enthrallD": "Du webst eine ablenkende Wortfolge, die Kreaturen deiner Wahl, die du in Reichweite sehen kannst, dazu veranlasst, einen Weisheitsrettungswurf zu machen. Jede Kreatur, gegen die du oder deine Gefährten kämpfen, besteht diesen Rettungswurf automatisch. Bei einem misslungenen Rettungswurf hat ein Ziel einen Malus von -10 auf Weisheit (Wahrnehmung)-Würfe und passive Wahrnehmung, bis der Zauber endet.",
        "findSteedD": "Du beschwörst ein außerweltliches Wesen, das als treues Ross auf einem unbesetzten Platz deiner Wahl in Reichweite erscheint. Diese Kreatur verwendet den 'Außerweltliches Ross'-Statistikblock. Wenn du bereits ein Ross von diesem Zauber hast, wird das Ross durch das neue ersetzt.<br><br>Das Ross ähnelt einem großen, reitbaren Tier deiner Wahl, wie einem Pferd, einem Kamel, einem Schreckenswolf oder einem Elch. Wähle jedes Mal, wenn du den Zauber wirkst, den Kreaturentyp des Rosses – Celestial, Fey oder Fiend – was bestimmte Merkmale im Statistikblock bestimmt.<br><br><b>Kampf:</b> Das Ross ist ein Verbündeter für dich und deine Verbündeten. Im Kampf teilt es deine Initiative-Zählung und fungiert als kontrolliertes Reittier, während du es reitest (wie in den Regeln zum berittenen Kampf definiert). Wenn du den Zustand 'Handlungsunfähig' hast, führt das Ross seinen Zug unmittelbar nach deinem aus und handelt unabhängig, wobei es sich darauf konzentriert, dich zu schützen.<br><br><b>Verschwinden des Rosses:</b> Das Ross verschwindet, wenn es auf 0 Trefferpunkte fällt oder wenn du stirbst. Wenn es verschwindet, lässt es alles zurück, was es trug oder bei sich hatte. Wenn du diesen Zauber erneut wirkst, entscheidest du, ob du das verschwundene Ross oder ein anderes beschwörst.<br><br><b>Höhere Zaubergrade:</b> Verwende den Grad des Zauberplatzes für den Grad des Zaubers im Statistikblock.<br><br><b>Beschwörbare Kreatur:</b> <span class=\"spell-summon-link\">Außerweltliches Ross</span>",
        "findTrapsD": "Du spürst jede Falle in Reichweite, die sich in deiner Sichtlinie befindet. Eine Falle im Sinne dieses Zaubers umfasst jeden Gegenstand oder Mechanismus, der geschaffen wurde, um Schaden oder andere Gefahren zu verursachen. Daher würde der Zauber die Zauber *Alarm* oder *Glyphe der Abwehr* oder eine mechanische Fallgrube spüren, aber er würde keine natürliche Schwäche im Boden, eine instabile Decke oder ein verstecktes Erdloch aufdecken.<br><br>Dieser Zauber enthüllt, dass eine Falle vorhanden ist, aber nicht ihren Standort. Du erfährst jedoch die allgemeine Natur der Gefahr, die von einer Falle ausgeht, die du spürst.",
        "flameBladeD": "Du rufst eine feurige Klinge in deiner freien Hand hervor. Die Klinge ähnelt in Größe und Form einem Krummsäbel und hält für die Dauer an. Wenn du die Klinge loslässt, verschwindet sie, aber du kannst sie als Bonusaktion erneut hervorrufen.<br><br>Als Magie-Aktion kannst du einen Nahkampf-Zauberangriff mit der feurigen Klinge machen. Bei einem Treffer erleidet das Ziel Feuerschaden in Höhe von 3W6 plus deinem Modifikator für die Zauberfähigkeit.<br><br>Die flammende Klinge wirft helles Licht in einem Radius von 3 m und dämmriges Licht für zusätzliche 3 m.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W6 für jeden Zaubergrad über 2.<br><br><b>Material:</b> Ein Sumachblatt.",
        "flamingSphereD": "Du erschaffst eine Feuerkugel mit einem Durchmesser von 1.5 m auf einem unbesetzten Platz auf dem Boden in Reichweite. Sie hält für die Dauer an. Jede Kreatur, die ihren Zug innerhalb von 1.5 m von der Sphäre beendet, muss einen Geschicklichkeitsrettungswurf machen. Bei einem misslungenen Rettungswurf erleidet sie 2W6 Feuerschaden, bei einem erfolgreichen halb so viel Schaden.<br><br>Als Bonusaktion kannst du die Sphäre bis zu 9 m bewegen und sie über den Boden rollen lassen. Wenn du die Sphäre in den Bereich einer Kreatur bewegst, macht diese Kreatur den Rettungswurf gegen die Sphäre, und die Sphäre stoppt ihre Bewegung für diesen Zug.<br><br>Wenn du die Sphäre bewegst, kannst du sie über Barrieren bis zu 1.5 m Höhe lenken und über Gruben bis zu 3 m Breite springen lassen. Entflammbare Objekte, die nicht getragen oder gehalten werden, fangen Feuer, wenn sie von der Sphäre berührt werden, und sie wirft helles Licht in einem Radius von 6 m und dämmriges Licht für zusätzliche 6 m.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W6 für jeden Zaubergrad über 2.<br><br><b>Material:</b> Eine Kugel aus Wachs.",
        "gentleReposeD": "Du berührst eine Leiche oder andere Überreste. Für die Dauer ist das Ziel vor Verwesung geschützt und kann nicht untot werden.<br><br>Der Zauber verlängert auch effektiv die Frist für die Wiederbelebung des Ziels von den Toten, da Tage, die unter dem Einfluss dieses Zaubers verbracht werden, nicht gegen die Frist von Zaubern wie *Tote erwecken* zählen.<br><br><b>Material:</b> 2 Kupfermünzen, die der Zauber verbraucht.",
        "gustOfWindD": "Eine Linie starken Windes, 18 m lang und 3 m breit, schießt für die Dauer des Zaubers von dir in eine von dir gewählte Richtung. Jede Kreatur in der Linie muss einen Stärkerettungswurf bestehen oder wird 4.5 m von dir weggestoßen in eine Richtung, die der Linie folgt. Eine Kreatur, die ihren Zug in der Linie beendet, muss denselben Rettungswurf machen.<br><br>Jede Kreatur in der Linie muss 2 m Bewegung für jeden 1 m aufwenden, den sie sich bewegt, wenn sie sich dir nähert.<br><br>Der Windstoß vertreibt Gas oder Dampf und löscht Kerzen und ähnliche ungeschützte Flammen in dem Bereich. Er lässt geschützte Flammen, wie die von Laternen, wild tanzen und hat eine 50-prozentige Chance, sie zu löschen.<br><br>Als Bonusaktion in deinen späteren Zügen kannst du die Richtung ändern, in die die Linie von dir aus schießt.<br><br><b>Material:</b> Ein Hülsenfrüchtesamen.",
        "heatMetalD": "Wähle einen hergestellten Metallgegenstand, wie eine Metallwaffe oder eine schwere oder mittlere Metallrüstung, den du in Reichweite sehen kannst. Du lässt das Objekt rotglühend werden. Jede Kreatur, die in physischem Kontakt mit dem Objekt steht, erleidet 2W8 Feuerschaden, wenn du den Zauber wirkst. Bis der Zauber endet, kannst du in jedem deiner späteren Züge eine Bonusaktion nutzen, um diesen Schaden erneut zu verursachen, wenn sich das Objekt in Reichweite befindet.<br><br>Wenn eine Kreatur das Objekt hält oder trägt und den Schaden davon erleidet, muss sie einen Konstitutionsrettungswurf bestehen oder das Objekt fallen lassen, wenn sie kann. Wenn sie das Objekt nicht fallen lässt, hat sie bis zum Beginn deines nächsten Zuges Nachteil bei Angriffswürfen und Attributswürfen.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 2.<br><br><b>Material:</b> Ein Stück Eisen und eine Flamme.",
        "holdPersonD": "Wähle einen Humanoiden, den du in Reichweite sehen kannst. Das Ziel muss einen Weisheitsrettungswurf bestehen oder erhält für die Dauer den Zustand 'Gelähmt'. Am Ende jedes seiner Züge wiederholt das Ziel den Rettungswurf und beendet den Zauber bei einem Erfolg für sich selbst.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 2 einen zusätzlichen Humanoiden als Ziel wählen.<br><br><b>Material:</b> Ein gerades Stück Eisen.",
        "invisibilityD": "Eine Kreatur, die du berührst, erhält den Zustand 'Unsichtbar', bis der Zauber endet. Der Zauber endet vorzeitig, unmittelbar nachdem das Ziel einen Angriffswurf macht, Schaden verursacht oder einen Zauber wirkt.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 2 eine zusätzliche Kreatur als Ziel wählen.<br><br><b>Material:</b> Eine Wimper in Gummiarabikum.",
        "knockD": "Wähle ein Objekt, das du in Reichweite sehen kannst. Das Objekt kann eine Tür, eine Kiste, eine Truhe, ein Satz Handfesseln, ein Vorhängeschloss oder ein anderes Objekt sein, das ein gewöhnliches oder magisches Mittel enthält, das den Zugang verhindert.<br><br>Ein Ziel, das durch ein gewöhnliches Schloss verschlossen gehalten wird oder das klemmt oder verriegelt ist, wird entriegelt, gelöst oder entriegelt. Wenn das Objekt mehrere Schlösser hat, wird nur eines davon entriegelt.<br><br>Wenn das Ziel durch *Arkanes Schloss* verschlossen gehalten wird, wird dieser Zauber für 10 Minuten unterdrückt, während derer das Ziel geöffnet und geschlossen werden kann.<br><br>Wenn du den Zauber wirkst, ertönt ein lautes Klopfen vom Ziel, das bis zu 90 m weit hörbar ist.",
        "lesserRestorationD": "Du berührst eine Kreatur und beendest einen Zustand bei ihr: 'Blind', 'Taub', 'Gelähmt' oder 'Vergiftet'.",
        "LevitateD": "Eine Kreatur oder ein loser Gegenstand deiner Wahl, den du in Reichweite sehen kannst, steigt senkrecht bis zu 6 m auf und bleibt dort für die Dauer des Zaubers schweben. Der Zauber kann ein Objekt levitieren lassen, das bis zu 225 kg wiegt. Eine unwillige Kreatur, der ein Konstitutionsrettungswurf gelingt, bleibt unberührt.<br><br>Das Ziel kann sich nur bewegen, indem es sich gegen ein festes Objekt oder eine Oberfläche in Reichweite drückt oder zieht (wie eine Wand oder eine Decke), was es ihm erlaubt, sich zu bewegen, als würde es klettern. Du kannst die Höhe des Ziels in deinem Zug um bis zu 6 m in beide Richtungen ändern. Wenn du selbst das Ziel bist, kannst du dich als Teil deiner Bewegung auf oder ab bewegen. Andernfalls kannst du eine Magie-Aktion nutzen, um das Ziel zu bewegen, das innerhalb der Reichweite des Zaubers bleiben muss.<br><br>Wenn der Zauber endet, schwebt das Ziel sanft zu Boden, wenn es sich noch in der Luft befindet.<br><br><b>Material:</b> Eine Metallfeder.",
        "locateAnimalsOrPlantsD": "Beschreibe oder nenne eine bestimmte Art von Tier, Pflanzenkreatur oder nichtmagischer Pflanze. Du erfährst die Richtung und Entfernung zur nächsten Kreatur oder Pflanze dieser Art innerhalb von 8 km, falls vorhanden.<br><br><b>Material:</b> Fell von einem Bluthund.",
        "locateObjectD": "Beschreibe oder nenne ein Objekt, das dir vertraut ist. Du spürst die Richtung zum Standort des Objekts, wenn sich dieses Objekt innerhalb von 300 m von dir befindet. Wenn das Objekt in Bewegung ist, kennst du die Richtung seiner Bewegung.<br><br>Der Zauber kann ein bestimmtes Objekt lokalisieren, das dir bekannt ist, wenn du es mindestens einmal aus der Nähe – innerhalb von 9 m – gesehen hast. Alternativ kann der Zauber das nächste Objekt einer bestimmten Art lokalisieren, wie eine bestimmte Art von Kleidung, Schmuck, Möbeln, Werkzeugen oder Waffen.<br><br>Dieser Zauber kann ein Objekt nicht lokalisieren, wenn irgendeine Dicke von Blei einen direkten Pfad zwischen dir und dem Objekt blockiert.<br><br><b>Material:</b> Ein gegabelter Zweig.",
        "magicMouthD": "Du pflanzt eine Nachricht in ein Objekt in Reichweite ein – eine Nachricht, die ausgesprochen wird, wenn eine Auslösebedingung erfüllt ist. Wähle ein Objekt, das du sehen kannst und das nicht von einer anderen Kreatur getragen oder gehalten wird. Sprich dann die Nachricht, die 25 Wörter oder weniger umfassen muss, obwohl sie über einen Zeitraum von bis zu 10 Minuten übermittelt werden kann. Bestimme schließlich den Umstand, der den Zauber auslöst, um deine Nachricht zu übermitteln.<br><br>Wenn dieser Auslöser eintritt, erscheint ein magischer Mund auf dem Objekt und rezitiert die Nachricht mit deiner Stimme und in derselben Lautstärke, in der du gesprochen hast. Wenn das gewählte Objekt einen Mund oder etwas hat, das wie ein Mund aussieht (zum Beispiel der Mund einer Statue), erscheint der magische Mund dort, sodass die Worte aus dem Mund des Objekts zu kommen scheinen. Wenn du diesen Zauber wirkst, kannst du den Zauber enden lassen, nachdem er seine Nachricht übermittelt hat, oder er kann verbleiben und seine Nachricht wiederholen, wann immer der Auslöser eintritt.<br><br>Der Auslöser kann so allgemein oder so detailliert sein, wie du möchtest, muss aber auf visuellen oder hörbaren Bedingungen basieren, die innerhalb von 9 m des Objekts auftreten. Zum Beispiel könntest du den Mund anweisen zu sprechen, wenn sich eine Kreatur innerhalb von 9 m des Objekts bewegt oder wenn eine Silberglocke innerhalb von 9 m davon läutet.<br><br><b>Material:</b> Jadestaub im Wert von 10+ GM, den der Zauber verbraucht.",
        "magicWeaponD": "Du berührst eine nichtmagische Waffe. Bis der Zauber endet, wird diese Waffe zu einer magischen Waffe mit einem Bonus von +1 auf Angriffs- und Schadenswürfe. Der Zauber endet vorzeitig, wenn du ihn erneut wirkst.<br><br><b>Höhere Zaubergrade:</b> Der Bonus erhöht sich auf +2 mit einem Zauberplatz des 3.–5. Grades. Der Bonus erhöht sich auf +3 mit einem Zauberplatz des 6. Grades oder höher.",
        "mindSpikeD": "Du treibst einen Stachel psionischer Energie in den Geist einer Kreatur, die du in Reichweite sehen kannst. Das Ziel muss einen Weisheitsrettungswurf machen. Bei einem misslungenen Rettungswurf erleidet es 3W8 psychischen Schaden, bei einem erfolgreichen halb so viel Schaden. Bei einem misslungenen Rettungswurf weißt du außerdem bis zum Ende des Zaubers immer den Standort des Ziels, aber nur, solange ihr beide euch auf derselben Existenzebene befindet. Während du dieses Wissen hast, kann sich das Ziel nicht vor dir verstecken, und wenn es den Zustand 'Unsichtbar' hat, erhält es keinen Vorteil aus diesem Zustand gegen dich.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 2.",
        "mirrorImageD": "Drei illusorische Duplikate von dir erscheinen in deinem Bereich. Bis der Zauber endet, bewegen sich die Duplikate mit dir und ahmen deine Handlungen nach, wobei sie ihre Position so verändern, dass es unmöglich ist zu verfolgen, welches Abbild echt ist.<br><br>Jedes Mal, wenn eine Kreatur dich während der Dauer des Zaubers mit einem Angriffswurf trifft, würfle einen W6 für jedes deiner verbleibenden Duplikate. Wenn einer der W6 eine 3 oder höher zeigt, wird eines der Duplikate anstelle von dir getroffen, und das Duplikat wird zerstört. Die Duplikate ignorieren ansonsten allen anderen Schaden und alle anderen Effekte. Der Zauber endet, wenn alle drei Duplikate zerstört sind.<br><br>Eine Kreatur ist von diesem Zauber unberührt, wenn sie den Zustand 'Blind' hat, *Blindsicht* oder *Wahrer Blick* besitzt.",
        "mistyStepD": "Kurzzeitig von silbrigem Nebel umhüllt, teleportierst du dich bis zu 9 m an einen unbesetzten Ort, den du sehen kannst.",
        "moonbeamD": "Ein silbriger Strahl blassen Lichts scheint in einem Zylinder mit einem Radius von 1.5 m und einer Höhe von 12 m herab, zentriert auf einen Punkt in Reichweite. Bis der Zauber endet, füllt dämmriges Licht den Zylinder, und du kannst in späteren Zügen eine Magie-Aktion nutzen, um den Zylinder bis zu 18 m zu bewegen.<br><br>Wenn der Zylinder erscheint, macht jede Kreatur darin einen Konstitutionsrettungswurf. Bei einem misslungenen Rettungswurf erleidet eine Kreatur 2W10 Strahlungsschaden, und wenn die Kreatur gestaltgewandelt ist (zum Beispiel als Ergebnis des Zaubers *Verwandlung*), kehrt sie zu ihrer wahren Gestalt zurück und kann sich nicht mehr gestaltwandeln, bis sie den Zylinder verlässt. Bei einem erfolgreichen Rettungswurf erleidet eine Kreatur nur halb so viel Schaden. Eine Kreatur macht diesen Rettungswurf auch, wenn sich der Bereich des Zaubers in ihren Bereich bewegt und wenn sie den Bereich des Zaubers betritt oder ihren Zug dort beendet. Eine Kreatur macht diesen Rettungswurf nur einmal pro Zug.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W10 für jeden Zaubergrad über 2.<br><br><b>Material:</b> Ein Mondsaatblatt.",
        "passWithoutTreceD": "Du strahlst für die Dauer eine verbergende Aura in einer 9-m-Emanation aus. Während sie sich in der Aura befinden, haben du und jede Kreatur deiner Wahl einen Bonus von +10 auf Geschicklichkeit (Heimlichkeit)-Würfe und hinterlassen keine Spuren.<br><br><b>Material:</b> Asche von verbrannter Mistel.",
        "phantasmalForceD": "Du versuchst, eine Illusion im Geist einer Kreatur zu erschaffen, die du in Reichweite sehen kannst. Das Ziel muss einen Intelligenzrettungswurf machen. Bei einem misslungenen Rettungswurf erschaffst du ein phantasmales Objekt, eine Kreatur oder ein anderes Phänomen, das nicht größer als ein 3-m-Würfel ist und für die Dauer nur für das Ziel wahrnehmbar ist. Das Phantasma umfasst Geräusche, Temperatur und andere Reize.<br><br>Das Ziel kann eine Studieren-Aktion nutzen, um das Phantasma mit einem Intelligenz (Nachforschung)-Wurf gegen deinen Zauberrettungs-SG zu untersuchen. Gelingt der Wurf, erkennt das Ziel, dass das Phantasma eine Illusion ist, und der Zauber endet.<br><br>Solange es von dem Zauber betroffen ist, behandelt das Ziel das Phantasma, als ob es real wäre, und rationalisiert alle unlogischen Ergebnisse aus der Interaktion mit ihm. Wenn das Ziel beispielsweise über eine phantasmale Brücke geht und den Sturz überlebt, glaubt es, die Brücke existiere und etwas anderes habe den Sturz verursacht.<br><br>Ein betroffenes Ziel kann sogar Schaden durch die Illusion erleiden, wenn das Phantasma eine gefährliche Kreatur oder Gefahr darstellt. In jedem deiner Züge kann ein solches Phantasma dem Ziel 2W8 psychischen Schaden zufügen, wenn es sich im Bereich des Phantasmas oder innerhalb von 1.5 m davon befindet. Das Ziel nimmt den Schaden als einen Typ wahr, der zur Illusion passt.<br><br><b>Material:</b> Ein Stück Vlies.",
        "prayerOfHealingD": "Bis zu fünf Kreaturen deiner Wahl, die für die gesamte Wirkungsdauer des Zaubers in Reichweite bleiben, erhalten die Vorteile einer kurzen Rast und gewinnen zusätzlich 2W8 Trefferpunkte zurück. Eine Kreatur kann von diesem Zauber nicht erneut betroffen sein, bis sie eine lange Rast beendet hat.<br><br><b>Höhere Zaubergrade:</b> Die Heilung erhöht sich um 1W8 für jeden Zaubergrad über 2.",
        "protectionFromPoisonD": "Du berührst eine Kreatur und beendest den Zustand 'Vergiftet' bei ihr. Für die Dauer des Zaubers hat das Ziel Vorteil bei Rettungswürfen, um den Zustand 'Vergiftet' zu vermeiden oder zu beenden, und es hat Resistenz gegen Giftschaden.",
        "rayOfEnfeeblementD": "Ein Strahl schwächender Energie schießt auf eine Kreatur in Reichweite zu. Das Ziel muss einen Konstitutionsrettungswurf machen. Bei einem Erfolg hat das Ziel Nachteil auf den nächsten Angriffswurf, den es bis zum Beginn deines nächsten Zuges macht.<br><br>Bei einem misslungenen Rettungswurf hat das Ziel für die Dauer des Zaubers Nachteil auf stärkebasierte D20-Tests. Während dieser Zeit zieht es außerdem 1W8 von all seinen Schadenswürfen ab. Das Ziel wiederholt den Rettungswurf am Ende jedes seiner Züge und beendet den Zauber bei einem Erfolg.",
        "ropeTrickD": "Du berührst ein Seil. Ein Ende davon schwebt nach oben, bis das Seil senkrecht zum Boden hängt oder eine Decke erreicht. Am oberen Ende des Seils öffnet sich ein unsichtbares, 0.9 m x 1.5 m großes Portal zu einem extradimensionalen Raum, der bis zum Ende des Zaubers bestehen bleibt. Dieser Raum kann durch Klettern am Seil erreicht werden, welches in den Raum hineingezogen oder herausgelassen werden kann.<br><br>Der Raum bietet Platz für bis zu acht mittelgroße oder kleinere Kreaturen. Angriffe, Zauber und andere Effekte können nicht in den Raum hinein oder aus ihm heraus gelangen, aber Kreaturen im Inneren können durch das Portal nach draußen sehen. Alles im Inneren fällt heraus, wenn der Zauber endet.<br><br><b>Material:</b> Ein Stück Seil.",
        "scorchingRayD": "Du schleuderst drei feurige Strahlen. Du kannst sie auf ein Ziel in Reichweite oder auf mehrere richten. Mache für jeden Strahl einen Fernkampf-Zauberangriff. Bei einem Treffer erleidet das Ziel 2W6 Feuerschaden.<br><br><b>Höhere Zaubergrade:</b> Du erzeugst einen zusätzlichen Strahl für jeden Zaubergrad über 2.",
        "seeInvisibilityD": "Für die Dauer des Zaubers siehst du Kreaturen und Objekte, die den Zustand 'Unsichtbar' haben, als wären sie sichtbar, und du kannst in die Ätherebene blicken. Kreaturen und Objekte dort erscheinen geisterhaft.<br><br><b>Material:</b> Eine Prise Talkpuder.",
        "shatterD": "Ein lautes Geräusch bricht an einem Punkt deiner Wahl in Reichweite aus. Jede Kreatur in einer Sphäre mit 3-m-Radius, die dort zentriert ist, macht einen Konstitutionsrettungswurf. Sie erleidet 3W8 Schallschaden bei einem misslungenen Rettungswurf oder halb so viel Schaden bei einem erfolgreichen. Ein Konstrukt hat Nachteil bei diesem Rettungswurf.<br><br>Ein nichtmagischer Gegenstand, der nicht getragen oder gehalten wird, erleidet ebenfalls den Schaden, wenn er sich im Bereich des Zaubers befindet.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 2.<br><br><b>Material:</b> Ein Glimmersplitter.",
        "silenceD": "Für die Dauer des Zaubers kann kein Geräusch innerhalb einer Sphäre mit 6-m-Radius entstehen oder diese durchdringen, die auf einen Punkt deiner Wahl in Reichweite zentriert ist. Jede Kreatur und jeder Gegenstand, der sich vollständig innerhalb der Sphäre befindet, ist immun gegen Schallschaden, und Kreaturen haben den Zustand 'Taub', solange sie sich darin befinden. Das Wirken eines Zaubers, der eine verbale Komponente enthält, ist dort unmöglich.",
        "spiderClimbD": "Bis der Zauber endet, erhält eine willige Kreatur, die du berührst, die Fähigkeit, sich an vertikalen Flächen und an Decken auf- und abwärts sowie quer zu bewegen, während sie die Hände frei hat. Das Ziel erhält außerdem eine Klettergeschwindigkeit, die seiner Bewegungsrate entspricht.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 2 eine zusätzliche Kreatur als Ziel wählen.<br><br><b>Material:</b> Ein Tropfen Bitumen und eine Spinne.",
        "spikeGrowthD": "Der Boden in einer Sphäre mit 6-m-Radius, zentriert auf einen Punkt in Reichweite, lässt harte Stacheln und Dornen sprießen. Der Bereich wird für die Dauer zu schwierigem Gelände. Wenn sich eine Kreatur in den Bereich hinein oder darin bewegt, erleidet sie 2W4 Stichschaden für alle 1.5 m, die sie zurücklegt.<br><br>Die Verwandlung des Bodens ist so getarnt, dass sie natürlich aussieht. Jede Kreatur, die den Bereich beim Wirken des Zaubers nicht sehen kann, muss eine Suchen-Aktion aufwenden und einen Weisheit (Wahrnehmung oder Überleben)-Wurf gegen deinen Zauberrettungs-SG bestehen, um das Gelände als gefährlich zu erkennen, bevor sie es betritt.<br><br><b>Material:</b> Sieben Dornen.",
        "spiritualWeaponD": "Du erschaffst eine schwebende, spektrale Kraft, die einer Waffe deiner Wahl ähnelt und für die Dauer des Zaubers anhält. Die Kraft erscheint in Reichweite an einem Ort deiner Wahl, und du kannst sofort einen Nahkampf-Zauberangriff gegen eine Kreatur innerhalb von 1.5 m der Kraft machen. Bei einem Treffer erleidet das Ziel Energieschaden in Höhe von 1W8 plus deinem Modifikator für die Zauberfähigkeit.<br><br>Als Bonusaktion in deinen späteren Zügen kannst du die Kraft bis zu 6 m weit bewegen und den Angriff gegen eine Kreatur innerhalb von 1.5 m wiederholen.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 2.",
        "suggestionD": "Du schlägst eine Handlungsweise vor – beschrieben in höchstens 25 Wörtern – für eine Kreatur in Reichweite, die dich hören und verstehen kann. Der Vorschlag muss erreichbar klingen und darf nichts beinhalten, was dem Ziel oder seinen Verbündeten offensichtlich Schaden zufügen würde.<br><br>Das Ziel muss einen Weisheitsrettungswurf bestehen oder erhält für die Dauer den Zustand 'Bezaubert', bis du oder deine Verbündeten dem Ziel Schaden zufügen. Ein bezaubertes Ziel verfolgt den Vorschlag nach besten Kräften. Die vorgeschlagene Aktivität kann über die gesamte Dauer fortgesetzt werden; falls sie jedoch in kürzerer Zeit abgeschlossen werden kann, endet der Zauber für das Ziel mit dem Abschluss.<br><br><b>Material:</b> Ein Tropfen Honig.",
        "summonBeastD": "Du rufst einen bestialischen Geist herbei. Er manifestiert sich auf einem unbesetzten Platz in Reichweite und verwendet den 'Bestialischer Geist'-Statistikblock. Wähle beim Wirken eine Umgebung: Luft, Land oder Wasser. Die Kreatur ähnelt einem Tier deiner Wahl, das in dieser Umgebung heimisch ist. Sie verschwindet, wenn sie auf 0 Trefferpunkte fällt oder der Zauber endet.<br><br>Die Kreatur ist ein Verbündeter für dich und deine Gefährten. Im Kampf teilt sie deine Initiative, zieht aber direkt nach dir. Sie gehorcht deinen verbalen Befehlen (keine Aktion erforderlich). Ohne Befehl nutzt sie die Ausweichen-Aktion und bewegt sich aus Gefahrenzonen.<br><br><b>Höhere Zaubergrade:</b> Verwende den Grad des Zauberplatzes für den Grad des Zaubers im Statistikblock.<br><br><b>Material:</b> Eine Feder, ein Büschel Fell und ein Fischschwanz in einer vergoldeten Eichel im Wert von 200+ GM.<br><br><b>Beschwörbare Kreatur:</b> <span class=\"spell-summon-link\">Bestialischer Geist</span>",
        "wardingBondD": "Du berührst eine andere willige Kreatur und erschaffst eine mystische Verbindung. Solange das Ziel innerhalb von 18 m von dir ist, erhält es einen Bonus von +1 auf RK und Rettungswürfe und hat Resistenz gegen alle Schadensarten. Jedes Mal, wenn es Schaden erleidet, nimmst du denselben Betrag an Schaden.<br><br>Der Zauber endet, wenn du auf 0 Trefferpunkte fällst oder du und das Ziel mehr als 18 m voneinander entfernt seid.<br><br><b>Material:</b> Ein Paar Platinringe im Wert von jeweils 50+ GM, die beide für die Dauer tragen müssen.",
        "webD": "Du beschwörst eine Masse klebriger Spinnweben an einem Punkt in Reichweite. Die Weben füllen dort für die Dauer einen 6-m-Würfel. Der Bereich ist schwieriges Gelände und leicht verdunkelt.<br><br>Falls die Weben nicht zwischen zwei festen Massen (wie Wänden) verankert oder über Boden/Wand/Decke geschichtet sind, bricht das Netz in sich zusammen und der Zauber endet zu Beginn deines nächsten Zuges. Weben auf flachen Oberflächen sind 1.5 m tief.<br><br>Wenn eine Kreatur die Weben betritt oder ihren Zug dort beginnt, muss sie einen Geschicklichkeitsrettungswurf bestehen oder erhält den Zustand 'Festgehalten'. Eine Kreatur kann eine Aktion nutzen, um einen Stärke (Athletik)-Wurf gegen deinen Zauberrettungs-SG zu machen, um sich zu befreien.<br><br>Die Weben sind brennbar. Ein 1.5-m-Würfel brennt in 1 Runde weg und fügt Kreaturen darin 2W4 Feuerschaden zu.<br><br><b>Material:</b> Ein Stück Spinnennetz.",
        "zoneOfTruthD": "Du erschaffst eine magische Zone gegen Täuschung in einer Sphäre mit 4.5-m-Radius. Eine Kreatur, die den Bereich betritt oder ihren Zug dort beginnt, macht einen Charismarettungswurf. Bei einem Misserfolg kann sie innerhalb des Radius keine bewusste Lüge aussprechen. Du weißt, ob eine Kreatur den Wurf besteht oder nicht.<br><br>Betroffene Kreaturen sind sich des Zaubers bewusst und können Antworten vermeiden, die normalerweise eine Lüge erfordern würden. Sie können ausweichend reagieren, müssen aber wahrheitsgemäß bleiben.",
        "animateDeadD": "Wähle einen Knochenhaufen oder eine Leiche eines mittelgroßen oder kleinen Humanoiden in Reichweite. Das Ziel wird zu einem Untoten: ein Skelett (bei Knochen) oder ein Zombie (bei einer Leiche).<br><br>In jedem deiner Züge kannst du als Bonusaktion alle mit diesem Zauber erschaffenen Kreaturen mental befehligen, sofern sie innerhalb von 18 m sind. Du entscheidest über ihre Aktion und Bewegung. Ohne Befehl nutzen sie die Ausweichen-Aktion. Der Befehl gilt, bis die Aufgabe erledigt ist.<br><br>Die Kreatur steht 24 Stunden unter deiner Kontrolle. Um die Kontrolle zu verlängern, musst du den Zauber erneut wirken. Dies festigt die Kontrolle über bis zu vier Kreaturen, anstatt eine neue zu beleben.<br><br><b>Höhere Zaubergrade:</b> Du belebst oder kontrollierst zwei zusätzliche Untote für jeden Zaubergrad über 3.<br><br><b>Material:</b> Ein Tropfen Blut, ein Stück Fleisch und eine Prise Knochenstaub.",
        "auraOfVitalityD": "Eine Aura strahlt in einer 9-m-Emanation von dir aus. Wenn du die Aura erschaffst und zu Beginn jedes deiner Züge, kannst du bei einer Kreatur darin 2W6 Trefferpunkte wiederherstellen.",
        "beaconOfHopeD": "Wähle eine beliebige Anzahl von Kreaturen in Reichweite. Für die Dauer hat jedes Ziel Vorteil bei Weisheits- und Todesrettungswürfen und erhält bei jeder Heilung die maximal mögliche Anzahl an Trefferpunkten.",
        "bestowCurseD": "Du berührst eine Kreatur, der ein Weisheitsrettungswurf misslingen muss, oder sie wird verflucht. Wähle einen Effekt:<ul><li>Nachteil auf Attributs- und Rettungswürfe eines gewählten Attributs.</li><li>Nachteil auf Angriffswürfe gegen dich.</li><li>Das Ziel muss zu Beginn jedes seiner Züge einen Weisheitsrettungswurf bestehen oder die Ausweichen-Aktion nutzen.</li><li>Deine Angriffe/Zauber fügen dem Ziel zusätzlich 1W8 nekrotischen Schaden zu.</li></ul><br><b>Höhere Zaubergrade:</b> Auf Level 4 hält die Konzentration bis zu 10 Minuten. Ab Level 5 ist keine Konzentration nötig und die Dauer steigt auf 8 Stunden (Level 5-6) oder 24 Stunden (Level 7-8). Auf Level 9 hält der Zauber, bis er gebannt wird.",
        "blindingSmiteD": "Das getroffene Ziel erleidet zusätzlich 3W8 Strahlungsschaden und erhält den Zustand 'Blind', bis der Zauber endet. Am Ende jedes seiner Züge macht das Ziel einen Konstitutionsrettungswurf, um den Effekt zu beenden.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 3.<br><br><b>Bonusaktion:</b> Die du unmittelbar ergreifst, nachdem du ein Ziel mit einer Nahkampfwaffe oder einem unbewaffneten Schlag getroffen hast.",
        "blinkD": "Würfle am Ende jedes deiner Züge 1W6. Bei einer 4-6 verschwindest du in die Ätherebene. Dort nimmst du deine Ursprungsebene nur in Graustufen und bis zu 18 m weit wahr. Du kannst nur Kreaturen auf der Ätherebene beeinflussen. Zu Beginn deines nächsten Zuges kehrst du an einen unbesetzten Platz innerhalb von 3 m deines Ursprungsortes zurück.",
        "callLightningD": "Eine Gewitterwolke erscheint über dir (Zylinder, 3 m hoch, 18 m Radius). Wähle einen Punkt unter der Wolke: Ein Blitz schlägt dort ein. Kreaturen innerhalb von 1.5 m machen einen Geschicklichkeitsrettungswurf; sie erleiden 3W10 Blitzschaden bei einem Misserfolg oder halb so viel bei einem Erfolg. Du kannst als Magie-Aktion weitere Blitze rufen. Im Freien bei einem natürlichen Sturm erhöht sich der Schaden um 1W10.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W10 für jeden Zaubergrad über 3.",
        "clairvoyanceD": "Du erschaffst einen unsichtbaren Sensor an einem vertrauten oder offensichtlichen Ort. Wähle Sehen oder Hören: Du nutzt diesen Sinn durch den Sensor. Als Bonusaktion kannst du zwischen den Sinnen wechseln. Kreaturen mit *Unsichtbarkeit sehen* oder *Wahrer Blick* sehen eine leuchtende Kugel von der Größe einer Faust.<br><br><b>Material:</b> Ein Fokus im Wert von 100+ GM (ein juwelenbesetztes Horn für Hören oder ein Glasauge für Sehen).",
        "conjureAnimalsD": "Du beschwörst Naturgeister als spektrales Rudel auf einem Platz in Reichweite. Du wählst die Tierform (z. B. Wölfe). Du hast Vorteil auf Stärkerettungswürfe innerhalb von 1.5 m zum Rudel. Du kannst das Rudel in deinem Zug bis zu 9 m weit bewegen. Kreaturen innerhalb von 3 m zum Rudel müssen einen Geschicklichkeitsrettungswurf machen oder erleiden 3W10 Hiebschaden.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W10 für jeden Zaubergrad über 3.",
        "conjureBarrageD": "Du schwingst deine Waffe und beschwörst spektrale Kopien davon (oder passende Munition), die nach vorne schnellen. Jede Kreatur deiner Wahl in einem 18-m-Kegel macht einen Geschicklichkeitsrettungswurf und erleidet 5W8 Energieschaden bei einem Misserfolg (halb so viel bei Erfolg).<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 3.<br><br><b>Material:</b> Eine Nahkampf- oder Fernkampfwaffe im Wert von mindestens 1 KM.",
        "counterspellD": "Du versuchst, das Wirken eines Zaubers zu unterbrechen. Die Kreatur macht einen Konstitutionsrettungswurf. Bei einem Misserfolg verpufft der Zauber wirkungslos. Der verbrauchte Zauberplatz geht nicht verloren.<br><br><b>Reaktion:</b> Die du ergreifst, wenn du eine Kreatur innerhalb von 18 m einen Zauber wirken siehst.",
        "createFoodAndWaterD": "Du erschaffst 20 kg Nahrung und 115 Liter frisches Wasser auf dem Boden oder in Behältern. Die Nahrung ist fad, aber nahrhaft und hält 24 Stunden.",
        "crusader'sMantleD": "Du strahlst eine Aura in einer 9-m-Emanation aus. In der Aura verursachen du und deine Verbündeten zusätzlich 1W4 Strahlungsschaden bei Treffern mit Waffen oder unbewaffneten Schlägen.",
        "daylightD": "Magisches Sonnenlicht füllt eine Sphäre mit 18-m-Radius. Der Bereich ist helles Licht (weitere 18 m dämmriges Licht). Alternativ kann ein Objekt das Licht ausstrahlen (18-m-Emanation). Das Abdecken des Objekts blockiert das Licht. Überlappt dieser Bereich mit *Dunkelheit* (Level 3 oder niedriger), wird jener Zauber gebannt.",
        "dispelMagicD": "Wähle eine Kreatur, ein Objekt oder einen Effekt. Jeder Zauber von Grad 3 oder niedriger endet. Für höhere Zauber mache einen Attributswurf mit deiner Zauberfähigkeit (SG 10 + Grad des Zaubers).<br><br><b>Höhere Zaubergrade:</b> Du bannst Zauber automatisch, deren Grad gleich oder niedriger als der verwendete Zauberplatz ist.",
        "elementalWeaponD": "Eine nichtmagische Waffe wird magisch. Wähle: Säure, Kälte, Feuer, Blitz oder Schall. Die Waffe erhält +1 auf Angriffs- und Schadenswürfe (Schaden ist der gewählte Typ).<br><br><b>Höhere Zaubergrade:</b> Mit Level 5-6 steigt der Bonus auf +2 (2W4 Schaden), ab Level 7+ auf +3 (3W4 Schaden).",
        "fearD": "Jede Kreatur in einem 9-m-Kegel muss einen Weisheitsrettungswurf bestehen oder lässt alles fallen und erhält den Zustand 'Verängstigt'. Betroffene müssen die Spurt-Aktion nutzen, um vor dir zu fliehen. Haben sie keine Sichtlinie mehr zu dir, dürfen sie den Rettungswurf wiederholen.<br><br><b>Material:</b> Eine weiße Feder.",
        "feignDeathD": "Du versetzt eine willige Kreatur in einen scheintoten Zustand. Sie erscheint tot, ist blind, handlungsunfähig und hat eine Bewegungsrate von 0. Sie hat Resistenz gegen allen Schaden (außer psychisch) und Immunität gegen 'Vergiftet'.<br><br><b>Material:</b> Eine Prise Friedhofserde.",
        "fireballD": "Ein heller Streifen schießt zu einem Punkt und explodiert in einer Sphäre mit 6-m-Radius. Jede Kreatur dort macht einen Geschicklichkeitsrettungswurf: 8W6 Feuerschaden bei Misserfolg, halb so viel bei Erfolg. Brennbare Objekte fangen Feuer.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W6 für jeden Zaubergrad über 3.<br><br><b>Material:</b> Eine Kugel aus Fledermausguano und Schwefel.",
        "flyD": "Eine willige Kreatur erhält eine Fluggeschwindigkeit von 18 m und kann schweben. Endet der Zauber in der Luft, fällt das Ziel.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 3 eine zusätzliche Kreatur als Ziel wählen.<br><br><b>Material:</b> Eine Feder.",
        "gaseousFormD": "Ein williges Ziel verwandelt sich in eine Nebelwolke. Fluggeschwindigkeit 10 m (Schweben möglich). Das Ziel hat Resistenz gegen physischen Schaden, Immunität gegen 'Liegend' und Vorteil auf körperliche Rettungswürfe. Es kann keine Aktionen, Zauber oder Angriffe ausführen.<br><br><b>Höhere Zaubergrade:</b> Ein zusätzliches Ziel für jeden Level über 3.<br><br><b>Material:</b> Ein Stück Gaze.",
        "glyphOfWardingD": "Du zeichnest eine Glyphe auf eine Fläche oder in ein Objekt (max. 3 m Durchmesser). Wird die Glyphe mehr als 3 m bewegt, bricht der Zauber. Du wählst den Auslöser und den Effekt:<ul><li><b>Explosive Rune:</b> 6-m-Radius Sphäre, 5W8 Schaden (Säure, Kälte, Feuer, Blitz oder Schall), Geschicklichkeitsrettungswurf für halben Schaden.</li><li><b>Zauberglyphe:</b> Speichert einen Zauber bis Grad 3, der beim Auslösen auf den Eindringling gewirkt wird.</li></ul><br><b>Höhere Zaubergrade:</b> Der Schaden der Rune steigt um 1W8 pro Level über 3. Bei Zauberglyphen entspricht der max. Grad dem des Zauberplatzes.<br><br><b>Material:</b> Diamantstaub im Wert von 200+ GM, den der Zauber verbraucht.",
        "hasteD": "Wähle eine willige Kreatur. Ihre Bewegungsrate verdoppelt sich, sie erhält +2 auf RK, Vorteil auf Geschicklichkeitsrettungswürfe und eine zusätzliche Aktion (nur Angriff (einmal), Spurt, Rückzug, Verstecken oder Nutzen). Endet der Zauber, ist das Ziel 1 Runde handlungsunfähig.<br><br><b>Material:</b> Eine Süßholzwurzelraspel.",
        "hungerOfHadarD": "Du öffnest ein Tor zum Fernen Reich, einer Region voller unaussprechlicher Schrecken. Eine Sphäre der Dunkelheit mit einem Radius von 6 m erscheint, zentriert auf einen Punkt in Reichweite. Die Sphäre ist schwieriges Gelände und erfüllt von seltsamem Flüstern und schlürfenden Geräuschen, die bis zu 9 m weit gehört werden können. Kein Licht, ob magisch oder anderweitig, kann den Bereich erhellen, und Kreaturen, die sich vollständig darin befinden, haben den Zustand 'Blind'.<br><br>Jede Kreatur, die ihren Zug in dem Bereich beginnt, erleidet 2W6 Kälteschaden. Jede Kreatur, die ihren Zug dort beendet, muss einen Geschicklichkeitsrettungswurf bestehen oder 2W6 Säureschaden durch außerweltliche Tentakel erleiden.<br><br><b>Höhere Zaubergrade:</b> Der Kälte- oder Säureschaden (deine Wahl) erhöht sich um 1W6 für jeden Zaubergrad über 3.<br><br><b>Material:</b> Ein eingemachter Tentakel.",
        "hypnoticPatternD": "Du erschaffst ein wirbelndes Muster aus Farben in einem 9-m-Würfel in Reichweite. Das Muster erscheint für einen Moment und verschwindet dann. Jede Kreatur in dem Bereich, die das Muster sehen kann, muss einen Weisheitsrettungswurf bestehen oder erhält für die Dauer den Zustand 'Bezaubert'. Während sie bezaubert ist, hat die Kreatur den Zustand 'Handlungsunfähig' und eine Bewegungsrate von 0.<br><br>Der Zauber endet für eine betroffene Kreatur, wenn sie Schaden erleidet oder wenn jemand anderes eine Aktion aufwendet, um die Kreatur aus ihrer Benommenheit wachzurütteln.<br><br><b>Material:</b> Eine Prise Konfetti.",
        "lightningArrowD": "Sobald dein Angriff das Ziel trifft oder verfehlt, verwandelt sich die Waffe oder Munition, die du verwendest, in einen Blitzschlag. Anstatt Schaden oder andere Effekte durch den Angriff zu erleiden, nimmt das Ziel bei einem Treffer 4W8 Blitzschaden oder bei einem Fehlschuss halb so viel Schaden. Jede Kreatur innerhalb von 3 m um das Ziel macht dann einen Geschicklichkeitsrettungswurf und erleidet 2W8 Blitzschaden bei einem misslungenen Rettungswurf oder halb so viel bei einem erfolgreichen.<br><br>Die Waffe oder Munition kehrt danach in ihre normale Form zurück.<br><br><b>Höhere Zaubergrade:</b> Der Schaden für beide Effekte des Zaubers erhöht sich um 1W8 für jeden Zaubergrad über 3.<br><br><b>Reaktion:</b> Die du unmittelbar ergreifst, nachdem du ein Ziel mit einem Fernkampfangriff unter Verwendung einer Waffe getroffen oder verfehlt hast.",
	"lightningBoltD": "Ein Blitzstrahl bildet eine 30 m lange und 1,5 m breite Linie, die in einer von dir gewählten Richtung von dir ausgeht. Jede Kreatur in der Linie muss einen <b>Geschicklichkeitsrettungswurf</b> ablegen. Bei einem misslungenen Rettungswurf erleidet sie 8W6 Blitzschaden, bei einem erfolgreichen nur halb so viel Schaden.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W6 für jeden Zaubergrad über 3.<br><br><b>Material:</b> Ein wenig Fell und ein Kristallstab.",
    	"magicCircleD": "Du erschaffst einen Zylinder aus magischer Energie mit einem Radius von 3 m und einer Höhe von 6 m, zentriert auf einen Punkt am Boden, den du in Reichweite sehen kannst. Glühende Runen erscheinen überall dort, wo der Zylinder den Boden oder eine andere Oberfläche schneidet.<br><br>Wähle eine oder mehrere der folgenden Kreaturenarten: Celestials, Elementare, Fey, Fiends oder Untote. Der Kreis beeinflusst eine Kreatur der gewählten Art auf folgende Weise:<ul><li>Die Kreatur kann den Zylinder nicht mit nichtmagischen Mitteln betreten. Versucht sie es mittels Teleportation oder interplanarer Reise, muss sie zuerst einen <b>Charismarettungswurf</b> bestehen.</li><li>Die Kreatur hat <b>Nachteil</b> bei Angriffswürfen gegen Ziele innerhalb des Zylinders.</li><li>Ziele innerhalb des Zylinders können von der Kreatur nicht besessen werden und auch nicht die Zustände <b>'Bezaubert'</b> oder <b>'Verängstigt'</b> durch sie erhalten.</li></ul><br>Jedes Mal, wenn du diesen Zauber wirkst, kannst du festlegen, dass seine Magie in umgekehrter Richtung wirkt, sodass eine Kreatur der gewählten Art den Zylinder nicht verlassen kann und Ziele außerhalb des Kreises geschützt sind.<br><br><b>Höhere Zaubergrade:</b> Die Dauer erhöht sich um 1 Stunde für jeden Zaubergrad über 3.<br><br><b>Material:</b> Salz und Silberstaub im Wert von 100+ GM, den der Zauber verbraucht.",
    	"majorImageD": "Du erschaffst das Bild eines Objekts, einer Kreatur oder eines anderen sichtbaren Phänomens, das nicht größer als ein 6-m-Würfel ist. Das Bild erscheint an einem Punkt, den du in Reichweite sehen kannst, und hält für die Dauer des Zaubers an. Es erscheint real, einschließlich Geräuschen, Gerüchen und Temperaturen, die dem dargestellten Objekt entsprechen. Die Illusion kann jedoch keinen Schaden verursachen oder Zustände hervorrufen.<br><br>Solange du dich in Reichweite der Illusion befindest, kannst du eine <b>Magie-Aktion</b> aufwenden, um das Bild an einen anderen Ort in Reichweite zu bewegen. Während das Bild seinen Standort ändert, kannst du sein Aussehen so verändern, dass die Bewegungen natürlich wirken. Wenn du zum Beispiel das Bild einer Kreatur erschaffst und es bewegst, kannst du es so verändern, dass es zu gehen scheint. Ebenso kannst du die Illusion zu verschiedenen Zeiten unterschiedliche Geräusche machen lassen oder sie sogar ein Gespräch führen lassen.<br><br>Physische Interaktion mit dem Bild enthüllt es als Illusion, da Gegenstände einfach hindurchgehen können. Eine Kreatur, die eine <b>Studieren-Aktion</b> verwendet, um das Bild zu untersuchen, kann mit einem erfolgreichen <b>Intelligenzwurf (Nachforschung)</b> gegen deinen Zauberrettungs-SG feststellen, dass es sich um eine Illusion handelt. Erkennt eine Kreatur die Illusion, kann sie durch das Bild hindurchsehen, und alle anderen sensorischen Effekte werden für sie schwach wahrnehmbar.<br><br><b>Höhere Zaubergrade:</b> Der Zauber hält an, bis er gebannt wird, und erfordert keine Konzentration, wenn er mit einem Zauberplatz der Stufe 4 oder höher gewirkt wird.<br><br><b>Material:</b> Ein Stück Vlies.",
    	"massHealingWordD": "Bis zu sechs Kreaturen deiner Wahl, die du in Reichweite sehen kannst, erhalten Trefferpunkte in Höhe von 2W4 plus deinem Modifikator für die Zauberfähigkeit zurück.<br><br><b>Höhere Zaubergrade:</b> Die Heilung erhöht sich um 1W4 für jeden Zaubergrad über 3.",
    	"meldIntoStoneD": "Du trittst in ein Steinobjekt oder eine Steinoberfläche ein, die groß genug ist, um deinen Körper vollständig aufzunehmen. Dabei verschmilzt du und deine Ausrüstung für die Dauer des Zaubers mit dem Stein. Du musst den Stein berühren, um dies zu tun. Nichts von deiner Anwesenheit bleibt sichtbar oder ist durch nichtmagische Sinne wahrnehmbar.<br><br>Während du mit dem Stein verschmolzen bist, kannst du nicht sehen, was außerhalb geschieht. Alle <b>Weisheitswürfe (Wahrnehmung)</b>, um Geräusche außerhalb zu hören, werden mit <b>Nachteil</b> abgelegt. Du bleibst dir des Zeitverlaufs bewusst und kannst Zauber auf dich selbst wirken, während du im Stein bist. Du kannst 1,5 m deiner Bewegung aufwenden, um den Stein dort zu verlassen, wo du ihn betreten hast, was den Zauber beendet. Ansonsten kannst du dich nicht bewegen.<br><br>Leichter physischer Schaden am Stein schadet dir nicht. Seine teilweise Zerstörung oder eine Veränderung seiner Form (in einem Ausmaß, dass du nicht mehr hineinpasst) stößt dich jedoch aus dem Stein aus und fügt dir 6W6 Wuchtschaden zu. Die vollständige Zerstörung des Steins (oder die Umwandlung in eine andere Substanz) stößt dich aus und fügt dir 50 Wuchtschaden zu. Wenn du ausgestoßen wirst, landest du auf dem nächstgelegenen unbesetzten Platz zu deinem Eintrittspunkt und erhältst den Zustand <b>'Liegend'</b>.",
    	"nondetectionD": "Für die Dauer des Zaubers verbirgst du ein Ziel, das du berührst, vor Erkenntniszaubern (Divination). Das Ziel kann eine willige Kreatur, ein Ort oder ein Objekt sein, das in keiner Dimension größer als 3 m ist. Das Ziel kann von keinem Erkenntniszauber anvisiert oder durch magische Ausspähsensoren wahrgenommen werden.<br><br><b>Material:</b> Eine Prise Diamantstaub im Wert von 25+ GM, den der Zauber verbraucht.",
    	"phantomSteedD": "Eine große, quasi-reale, pferdeähnliche Kreatur erscheint auf dem Boden an einem unbesetzten Platz deiner Wahl in Reichweite. Du entscheidest über das Aussehen der Kreatur, und sie ist mit Sattel, Gebiss und Zaumzeug ausgestattet. Jedes durch den Zauber erschaffene Ausrüstungsteil verschwindet in einer Rauchwolke, wenn es mehr als 3 m vom Ross entfernt wird.<br><br>Für die Dauer des Zaubers kannst du oder eine von dir gewählte Kreatur das Ross reiten. Das Ross nutzt die Spielwerte eines Reitpferdes, hat jedoch eine Bewegungsrate von 30 m und kann 20 km in einer Stunde zurücklegen. Wenn der Zauber endet, verblasst das Ross allmählich, was dem Reiter 1 Minute Zeit zum Absitzen gibt. Der Zauber endet vorzeitig, wenn das Ross Schaden erleidet.",
    	"plantGrowthD": "Dieser Zauber leitet Lebenskraft in Pflanzen. Die von dir gewählte Wirkungsdauer bestimmt, ob der Zauber den Effekt 'Wucherung' oder 'Bereicherung' hat:<ul><li><b>Wucherung:</b> Wähle einen Punkt in Reichweite. Alle normalen Pflanzen in einer Sphäre mit einem Radius von 30 m um diesen Punkt werden dicht und überwuchert. Eine Kreatur, die sich durch diesen Bereich bewegt, muss 6 m Bewegung für jeden 1,5 m Weg aufwenden. Du kannst einen oder mehrere Bereiche beliebiger Größe innerhalb des Zauberbereichs von der Wirkung ausnehmen.</li><li><b>Bereicherung:</b> Alle Pflanzen in einem Radius von 800 m um einen Punkt in Reichweite werden für 365 Tage bereichert. Die Pflanzen liefern bei der Ernte die doppelte Menge an Nahrung. Sie können nur einmal pro Jahr von 'Pflanzenwachstum' profitieren.</li></ul><br><b>Besonderes:</b> Aktion (Wucherung) oder 8 Stunden (Bereicherung).",
    	"protectionFromEnergyD": "Für die Dauer des Zaubers hat die willige Kreatur, die du berührst, <b>Resistenz</b> gegen eine Schadensart deiner Wahl: Säure, Kälte, Feuer, Blitz oder Schall.",
    	"removeCurseD": "Bei deiner Berührung enden alle Flüche, die eine Kreatur oder ein Objekt betreffen. Wenn das Objekt ein verfluchter magischer Gegenstand ist, bleibt sein Fluch bestehen, aber der Zauber bricht die <b>Einstimmung</b> des Besitzers auf den Gegenstand ab, sodass dieser entfernt oder weggeworfen werden kann.",
    	"revivifyD": "Du berührst eine Kreatur, die innerhalb der letzten Minute gestorben ist. Diese Kreatur wird mit 1 Trefferpunkt wiederbelebt. Dieser Zauber kann keine Kreatur wiederbeleben, die an Altersschwäche gestorben ist, und stellt keine fehlenden Körperteile wieder her.<br><br><b>Material:</b> Ein Diamant im Wert von 300+ GM, den der Zauber verbraucht.",
    	"sendingD": "Du sendest eine kurze Nachricht von 25 Wörtern oder weniger an eine Kreatur, die du bereits getroffen hast oder die dir von jemandem beschrieben wurde, der sie getroffen hat. Das Ziel hört die Nachricht in seinem Geist, erkennt dich als Absender, falls es dich kennt, und kann sofort auf die gleiche Weise antworten. Der Zauber ermöglicht es dem Ziel, die Bedeutung deiner Nachricht zu verstehen.<br><br>Du kannst die Nachricht über jede Distanz und sogar auf andere Existenzebenen senden. Befindet sich das Ziel auf einer anderen Ebene als du, besteht jedoch eine Chance von 5 Prozent, dass die Nachricht nicht ankommt. Du erfährst, wenn die Zustellung fehlschlägt.<br><br>Nach Erhalt deiner Nachricht kann eine Kreatur deine Fähigkeit, sie mit diesem Zauber erneut zu erreichen, für 8 Stunden blockieren. Wenn du versuchst, während dieser Zeit eine weitere Nachricht zu senden, erfährst du, dass du blockiert wurdest, und der Zauber schlägt fehl.<br><br><b>Material:</b> Ein Kupferdraht.",
    	"sleetStormD": "Bis der Zauber endet, falls Schneeregen in einem 12 m hohen Zylinder mit einem Radius von 6 m, zentriert auf einen Punkt in Reichweite. Der Bereich ist <b>stark verdunkelt</b> und offene Flammen im Bereich werden gelöscht.<br><br>Der Boden im Zylinder ist <b>schwieriges Gelände</b>. Wenn eine Kreatur den Zylinder zum ersten Mal in einem Zug betritt oder ihren Zug dort beginnt, muss sie einen <b>Geschicklichkeitsrettungswurf</b> bestehen oder erhält den Zustand <b>'Liegend'</b> und verliert ihre <b>Konzentration</b>.<br><br><b>Material:</b> Ein winziger Regenschirm.",
    	"slowD": "Du veränderst die Zeit um bis zu sechs Kreaturen deiner Wahl in einem 12-m-Würfel in Reichweite. Jedes Ziel muss einen <b>Weisheitsrettungswurf</b> bestehen oder wird für die Dauer des Zaubers von diesem betroffen.<br><br>Die Bewegungsrate eines betroffenen Ziels wird halbiert, es erhält einen Malus von -2 auf die RK und <b>Geschicklichkeitsrettungswürfe</b> und kann keine <b>Reaktionen</b> ausführen. In seinem Zug kann es entweder eine Aktion oder eine Bonusaktion ausführen, nicht beides. Es kann nur einen Angriff ausführen, wenn es die Angriffs-Aktion wählt. Wenn es einen Zauber mit einer somatischen Komponente wirkt, besteht eine Chance von 25 Prozent, dass der Zauber fehlschlägt, weil das Ziel die Gesten zu langsam ausführt.<br><br>Ein betroffenes Ziel wiederholt den Rettungswurf am Ende jedes seiner Züge und beendet den Zauber bei einem Erfolg für sich selbst.<br><br><b>Material:</b> Ein Tropfen Melasse.",
    	"speakWithDeadD": "Du verleihst einer Leiche deiner Wahl in Reichweite einen Anschein von Leben, sodass sie Fragen beantworten kann, die du ihr stellst. Die Leiche muss einen Mund haben. Dieser Zauber schlägt fehl, wenn die verstorbene Kreatur zum Zeitpunkt ihres Todes ein Untoter war. Der Zauber schlägt auch fehl, wenn die Leiche innerhalb der letzten 10 Tage bereits Ziel dieses Zaubers war.<br><br>Bis der Zauber endet, kannst du der Leiche bis zu fünf Fragen stellen. Die Leiche weiß nur das, was sie im Leben wusste, einschließlich der Sprachen, die sie beherrschte. Die Antworten sind normalerweise kurz, kryptisch oder repetitiv. Die Leiche ist nicht verpflichtet, eine wahrheitsgemäße Antwort zu geben, wenn du ihr feindselig gegenüberstehst oder sie dich als Feind erkennt. Dieser Zauber bringt nicht die Seele der Kreatur in ihren Körper zurück, sondern nur ihren belebenden Geist. Daher kann die Leiche keine neuen Informationen lernen, nichts verstehen, was seit ihrem Tod passiert ist, und nicht über zukünftige Ereignisse spekulieren.<br><br><b>Material:</b> Brennendes Räucherwerk.",
    	"speakWithPlantsD": "Du verleihst Pflanzen in einer stationären 9-m-Emanation ein begrenztes Bewusstsein und Bewegungsvermögen, was ihnen die Fähigkeit gibt, mit dir zu kommunizieren und einfachen Befehlen zu folgen. Du kannst Pflanzen nach Ereignissen befragen, die im Bereich des Zaubers innerhalb des letzten Tages stattgefunden haben, um Informationen über vorbeigekommene Kreaturen, das Wetter und andere Umstände zu erhalten.<br><br>Du kannst außerdem schwieriges Gelände, das durch Pflanzenwuchs verursacht wird (wie Dickicht und Unterholz), für die Dauer des Zaubers in normales Gelände verwandeln. Oder du kannst normales Gelände, auf dem Pflanzen vorhanden sind, für die Dauer in schwieriges Gelände verwandeln.<br><br>Der Zauber ermöglicht es Pflanzen nicht, sich zu entwurzeln und umherzubewegen, aber sie können ihre Zweige, Ranken und Stängel für dich bewegen.<br><br>Befindet sich eine Pflanzenkreatur im Bereich, kannst du mit ihr kommunizieren, als hättet ihr eine gemeinsame Sprache.",
    	"spiritGuardiansD": "Schutzgeister umschwirren dich für die Dauer in einer 4,5-m-Emanation. Wenn du gut oder neutral bist, erscheint ihre spektrale Form engelhaft oder feenhaft (deine Wahl). Wenn du böse bist, erscheinen sie teuflisch.<br><br>Wenn du diesen Zauber wirkst, kannst du Kreaturen bestimmen, die nicht von ihm betroffen sein sollen. Die Bewegungsrate jeder anderen Kreatur wird in der Emanation halbiert. Jedes Mal, wenn die Emanation in den Bereich einer Kreatur eintritt oder wenn eine Kreatur den Bereich betritt oder ihren Zug dort beendet, muss sie einen <b>Weisheitsrettungswurf</b> ablegen. Bei einem misslungenen Rettungswurf erleidet die Kreatur 3W8 Strahlungsschaden (wenn du gut oder neutral bist) oder 3W8 nekrotischen Schaden (wenn du böse bist). Bei einem erfolgreichen Rettungswurf erleidet die Kreatur nur halb so viel Schaden. Eine Kreatur macht diesen Rettungswurf nur einmal pro Zug.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 3.<br><br><b>Material:</b> Eine Gebetsrolle.",
    	"stinkingClaudD": "Du erschaffst eine Sphäre aus gelbem, übelkeitserregendem Gas mit einem Radius von 6 m, zentriert auf einen Punkt in Reichweite. Die Wolke ist <b>stark verdunkelt</b>. Das Gas verweilt für die Dauer in der Luft oder bis ein starker Wind (wie durch 'Windstoß' erzeugt) es vertreibt.<br><br>Jede Kreatur, die ihren Zug in der Sphäre beginnt, muss einen <b>Konstitutionsrettungswurf</b> bestehen oder erhält bis zum Ende des aktuellen Zuges den Zustand <b>'Vergiftet'</b>. Während sie auf diese Weise vergiftet ist, kann die Kreatur keine Aktion oder Bonusaktion ausführen.<br><br><b>Material:</b> Ein verfaultes Ei.",
    	"summonFeyD": "Du rufst einen feenhaften Geist herbei. Er manifestiert sich an einem unbesetzten Platz, den du in Reichweite sehen kannst, und verwendet den Statistikblock für 'Feengeist'. Wähle beim Wirken eine Stimmung: Zornig, Fröhlich oder Trickreich. Die Kreatur ähnelt einem von dir gewählten feenhaften Wesen, das von der gewählten Stimmung geprägt ist, was bestimmte Details im Statistikblock bestimmt. Die Kreatur verschwindet, wenn sie auf 0 Trefferpunkte fällt oder wenn der Zauber endet.<br><br>Die Kreatur ist ein Verbündeter für dich und deine Gefährten. Im Kampf teilt die Kreatur deinen Initiative-Wert, ist aber unmittelbar nach dir an der Reihe. Sie gehorcht deinen verbalen Befehlen (keine Aktion deinerseits erforderlich). Wenn du keine Befehle erteilst, nutzt sie die <b>Ausweichen-Aktion</b> und bewegt sich aus Gefahrenbereichen.<br><br><b>Höhere Zaubergrade:</b> Verwende den Level des Zauberplatzes für die Stufe des Zaubers im Statistikblock.<br><br><b>Material:</b> Eine vergoldete Blume im Wert von 300+ GM.<br><br><b>Beschwörbare Kreatur:</b> <span class=\"spell-summon-link\">Kleiner Feengeist</span>",
    	"summonUndeadD": "Du rufst einen untoten Geist herbei. Er manifestiert sich an einem unbesetzten Platz, den du in Reichweite sehen kannst, und verwendet den Statistikblock für 'Untoter Geist'. Wähle beim Wirken die Form der Kreatur: Geisterhaft, Faulig oder Skelettartig. Der Geist ähnelt einer untoten Kreatur mit der gewählten Form, was bestimmte Details im Statistikblock bestimmt. Die Kreatur verschwindet, wenn sie auf 0 Trefferpunkte fällt oder wenn der Zauber endet.<br><br>Die Kreatur ist ein Verbündeter für dich und deine Gefährten. Im Kampf teilt die Kreatur deinen Initiative-Wert, ist aber unmittelbar nach dir an der Reihe. Sie gehorcht deinen verbalen Befehlen (keine Aktion deinerseits erforderlich). Wenn du keine Befehle erteilst, nutzt sie die <b>Ausweichen-Aktion</b> und bewegt sich aus Gefahrenbereichen.<br><br><b>Höhere Zaubergrade:</b> Verwende den Level des Zauberplatzes für die Stufe des Zaubers im Statistikblock.<br><br><b>Material:</b> Ein vergoldeter Totenkopf im Wert von 300+ GM.<br><br><b>Beschwörbare Kreatur:</b> <span class=\"spell-summon-link\">Untoter Geist</span>",
    	"tonguesD": "Dieser Zauber verleiht der Kreatur, die du berührst, die Fähigkeit, jede gesprochene Sprache, die sie hört, oder jede Gebärdensprache, die sie sieht, zu verstehen. Zudem kann jede Kreatur, die mindestens eine Sprache beherrscht, das Ziel verstehen, wenn es spricht oder Gebärden verwendet.<br><br><b>Material:</b> Ein Miniatur-Zikkurat.",
    	"vampiricTouchD": "Die Berührung deiner schattenumwobenen Hand kann Lebenskraft von anderen absaugen, um deine Wunden zu heilen. Führe einen Nahkampf-Zauberangriff gegen eine Kreatur in Reichweite aus. Bei einem Treffer erleidet das Ziel 3W6 nekrotischen Schaden, und du erhältst Trefferpunkte in Höhe der Hälfte des verursachten nekrotischen Schadens zurück.<br><br>Bis der Zauber endet, kannst du den Angriff in jedem deiner Züge als <b>Magie-Aktion</b> wiederholen und dabei dasselbe oder ein anderes Ziel wählen.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W6 für jeden Zaubergrad über 3.",
    	"waterBreathingD": "Dieser Zauber verleiht bis zu zehn willigen Kreaturen deiner Wahl in Reichweite die Fähigkeit, unter Wasser zu atmen, bis der Zauber endet. Die betroffenen Kreaturen behalten zudem ihre normale Atmungsweise bei.<br><br><b>Material:</b> Ein kurzes Schilfrohr.",
    	"waterWalkD": "Dieser Zauber verleiht die Fähigkeit, sich über jede flüssige Oberfläche – wie Wasser, Säure, Schlamm, Schnee, Treibsand oder Lava – zu bewegen, als wäre es harmloser fester Boden. Bis zu zehn willige Kreaturen deiner Wahl in Reichweite erhalten diese Fähigkeit für die Dauer des Zaubers.<br><br>Ein betroffenes Ziel muss eine <b>Bonusaktion</b> aufwenden, um von der Oberfläche der Flüssigkeit in die Flüssigkeit selbst einzutauchen und umgekehrt. Wenn das Ziel jedoch in die Flüssigkeit fällt, dringt es durch die Oberfläche in die darunter liegende Flüssigkeit ein.<br><br><b>Material:</b> Ein Stück Kork.",
    	"windWallD": "Eine Wand aus starkem Wind erhebt sich an einem von dir gewählten Punkt in Reichweite vom Boden. Du kannst die Wand bis zu 15 m lang, 4,5 m hoch und 30 cm dick machen. Du kannst die Wand beliebig formen, solange sie einen zusammenhängenden Pfad auf dem Boden bildet. Die Wand hält für die Dauer des Zaubers an.<br><br>Wenn die Wand erscheint, muss jede Kreatur in ihrem Bereich einen <b>Stärkerettungswurf</b> ablegen. Bei einem misslungenen Rettungswurf erleidet die Kreatur 4W8 Wuchtschaden, bei einem erfolgreichen nur halb so viel Schaden.<br><br>Der starke Wind hält Nebel, Rauch und andere Gase fern. Kleine oder kleinere fliegende Kreaturen oder Objekte können die Wand nicht passieren. Lose, leichte Materialien, die in die Wand gelangen, werden nach oben gewirbelt. Pfeile, Bolzen und andere gewöhnliche Projektile, die auf Ziele hinter der Wand abgefeuert werden, werden nach oben abgelenkt und verfehlen automatisch. Kreaturen in Gasform können die Wand nicht passieren.<br><br><b>Material:</b> Ein Fächer und eine Feder.",
    	"arcaneEyeD": "Du erschaffst ein unsichtbares, unverwundbares Auge in Reichweite, das für die Dauer des Zaubers schwebt. Du erhältst mental visuelle Informationen von dem Auge, das in alle Richtungen sehen kann. Es besitzt zudem <b>Dunkelsicht</b> mit einer Reichweite von 9 m.<br><br>Als <b>Bonusaktion</b> kannst du das Auge bis zu 9 m in jede Richtung bewegen. Ein festes Hindernis blockiert die Bewegung des Auges, aber es kann durch Öffnungen passen, die nur 2,5 cm Durchmesser haben.<br><br><b>Material:</b> Ein wenig Fledermausfell.",
    	"auraOfLifeD": "Eine Aura strahlt in einer 9-m-Emanation von dir aus. Während sie sich in der Aura befinden, haben du und deine Verbündeten <b>Resistenz</b> gegen nekrotischen Schaden, und eure maximalen Trefferpunkte können nicht reduziert werden. Wenn ein Verbündeter mit 0 Trefferpunkten seinen Zug in der Aura beginnt, erhält er 1 Trefferpunkt zurück.",
    	"auraOfPurityD": "Eine Aura strahlt in einer 9-m-Emanation von dir aus. Während sie sich in der Aura befinden, haben du und deine Verbündeten <b>Resistenz</b> gegen Giftschaden und <b>Vorteil</b> bei Rettungswürfen, um Effekte zu vermeiden oder zu beenden, die die Zustände 'Blind', 'Bezaubert', 'Taub', 'Verängstigt', 'Gelähmt', 'Vergiftet' oder 'Betäubt' beinhalten.",
    	"banishmentD": "Eine Kreatur, die du in Reichweite sehen kannst, muss einen <b>Charismarettungswurf</b> bestehen oder wird für die Dauer des Zaubers in eine harmlose Halbebene versetzt. Während es dort ist, hat das Ziel den Zustand <b>'Handlungsunfähig'</b>. Wenn der Zauber endet, erscheint das Ziel wieder auf dem Platz, den es verlassen hat.<br><br>Wenn das Ziel eine Aberration, ein Celestial, ein Elementar, eine Fee oder ein Unhold (Fiend) ist, kehrt es nicht zurück, wenn der Zauber 1 Minute lang anhält. Stattdessen wird das Ziel an einen zufälligen Ort auf einer Ebene versetzt, die seiner Kreaturenart entspricht (Wahl des SL).<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 4 eine zusätzliche Kreatur als Ziel wählen.<br><br><b>Material:</b> Ein Pentakel.",
    	"blightD": "Eine Kreatur, die du in Reichweite sehen kannst, muss einen <b>Konstitutionsrettungswurf</b> ablegen. Bei einem misslungenen Rettungswurf erleidet sie 8W8 nekrotischen Schaden, bei einem erfolgreichen nur halb so viel Schaden. Eine Pflanzenkreatur scheitert automatisch bei diesem Rettungswurf.<br><br>Alternativ kannst du eine nichtmagische Pflanze anvisieren, die keine Kreatur ist, wie etwa einen Baum oder Strauch. Sie legt keinen Rettungswurf ab; sie verwelkt einfach und stirbt.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 4.",
    	"charmMonsterD": "Eine Kreatur, die du in Reichweite sehen kannst, muss einen <b>Weisheitsrettungswurf</b> ablegen. Sie hat <b>Vorteil</b> bei diesem Wurf, wenn du oder deine Verbündeten gegen sie kämpfen. Bei einem misslungenen Rettungswurf erhält das Ziel den Zustand <b>'Bezaubert'</b>, bis der Zauber endet oder bis du oder deine Verbündeten ihm Schaden zufügen. Die bezauberte Kreatur ist dir gegenüber freundlich gesinnt. Wenn der Zauber endet, weiß das Ziel, dass es von dir bezaubert wurde.<br><br><b>Höhere Zaubergrade:</b> Du kannst für jeden Zaubergrad über 4 eine zusätzliche Kreatur als Ziel wählen.",
    	"compulsionD": "Jede Kreatur deiner Wahl, die du in Reichweite sehen kannst, muss einen <b>Weisheitsrettungswurf</b> bestehen oder erhält bis zum Ende des Zaubers den Zustand <b>'Bezaubert'</b>.<br><br>Für die Dauer des Zaubers kannst du eine <b>Bonusaktion</b> aufwenden, um eine horizontale Richtung festzulegen. Jedes bezauberte Ziel muss so viel wie möglich von seiner Bewegung aufwenden, um sich in seinem nächsten Zug in diese Richtung zu bewegen, wobei es den sichersten Weg wählt. Nach dieser Bewegung wiederholt das Ziel den Rettungswurf und beendet den Zauber bei einem Erfolg für sich selbst.",
    	"confusionD": "Jede Kreatur in einer Sphäre mit einem Radius von 3 m, zentriert auf einen Punkt in Reichweite, muss einen <b>Weisheitsrettungswurf</b> bestehen. Bei einem Misserfolg kann das Ziel keine Bonusaktionen oder Reaktionen ausführen und muss zu Beginn jedes seiner Züge 1W10 würfeln, um sein Verhalten für diesen Zug anhand der folgenden Tabelle zu bestimmen:<br><br><table class=\"spell-table\"><caption>Verwirrung</caption><tr><th>Wurf</th><th>Verhalten</th></tr><tr><td>1</td><td>Das Ziel führt keine Aktion aus und nutzt seine gesamte Bewegung um sich in eine zufällige Richtung zu bewegen (1W4: 1 Norden; 2 Osten; 3 Süden; 4 Westen).</td></tr><tr><td>2–6</td><td>Das Ziel bewegt sich nicht und führt keine Aktionen aus.</td></tr><tr><td>7–8</td><td>Das Ziel bewegt sich nicht und führt die Angriffs-Aktion aus um einen Nahkampfangriff gegen eine zufällige Kreatur in Reichweite zu machen. Wenn niemand in Reichweite ist führt es keine Aktion aus.</td></tr><tr><td>9–10</td><td>Das Ziel wählt sein Verhalten selbst.</td></tr></table><br>Am Ende jedes seiner Züge wiederholt ein betroffenes Ziel den Rettungswurf und beendet den Zauber bei einem Erfolg für sich selbst.<br><br><b>Höhere Zaubergrade:</b> Der Radius der Sphäre erhöht sich um 1,5 m für jeden Zaubergrad über 4.<br><br><b>Material:</b> Drei Nußschalen.",
    	"conjureMinorElementalsD": "Du beschwörst Geister von den Elementarebenen, die dich für die Dauer des Zaubers in einer 4,5-m-Emanation umschwirren. Bis der Zauber endet, verursacht jeder deiner Angriffe zusätzlich 2W8 Schaden, wenn du eine Kreatur in der Emanation triffst. Dieser Schaden ist Säure, Kälte, Feuer oder Blitz (deine Wahl, wenn du den Angriff ausführst).<br><br>Zudem ist der Boden in der Emanation <b>schwieriges Gelände</b> für deine Feinde.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 2W8 für jeden Zaubergrad über 4.",
    	"conjureWoodlandBeingsD": "Du beschwörst Naturgeister, die dich für die Dauer des Zaubers in einer 3-m-Emanation umschwirren. Jedes Mal, wenn die Emanation in den Bereich einer Kreatur eintritt, die du sehen kannst, oder wenn eine Kreatur den Bereich betritt oder ihren Zug dort beendet, kannst du sie zu einem <b>Weisheitsrettungswurf</b> zwingen. Die Kreatur erleidet 5W8 Wuchtschaden bei einem misslungenen Rettungswurf oder halb so viel Schaden bei einem erfolgreichen. Eine Kreatur macht diesen Rettungswurf nur einmal pro Zug.<br><br>Zusätzlich kannst du für die Dauer des Zaubers die <b>Rückzugs-Aktion</b> als <b>Bonusaktion</b> ausführen.<br><br><b>Höhere Zaubergrade:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 4.",
    	"controlWaterD": "Bis der Zauber endet, kontrollierst du jegliches Wasser innerhalb eines von dir gewählten Würfels mit einer Seitenlänge von bis zu 30 m, wobei du einen der folgenden Effekte nutzt. Als <b>Magie-Aktion</b> in deinen späteren Zügen kannst du denselben Effekt wiederholen oder einen anderen wählen:<ul><li><b>Flut:</b> Du lässt den Wasserspiegel aller stehenden Gewässer im Bereich um bis zu 6 m ansteigen. In großen Gewässern erschaffst du stattdessen eine 6 m hohe Welle, die von einer Seite zur anderen rollt. Riesige oder kleinere Fahrzeuge im Weg der Welle werden mitgerissen; sie haben eine Chance von 25 Prozent zu kentern.</li><li><b>Wasser teilen:</b> Du teilst das Wasser im Bereich und erschaffst einen Graben. Das getrennte Wasser bildet zu beiden Seiten eine Wand. Der Graben bleibt bestehen, bis der Zauber endet oder du einen anderen Effekt wählst.</li><li><b>Strömung umleiten:</b> Du lässt fließendes Wasser im Bereich in eine von dir gewählte Richtung fließen, sogar über Hindernisse oder Wände hinauf.</li><li><b>Strudel:</b> In einem Bereich, der mindestens 15 m im Quadrat groß und 7,5 m tief ist, bildest du einen Strudel. Kreaturen im Wasser innerhalb von 7,5 m um den Strudel werden 3 m auf ihn zugezogen. Eine Kreatur, die den Strudel betritt oder ihren Zug dort beendet, muss einen <b>Stärkerettungswurf</b> bestehen oder erleidet 2W8 Wuchtschaden.</li></ul><br><b>Material:</b> Eine Mischung aus Wasser und Staub.",
    	"deathWardD": "Du berührst eine Kreatur und gewährst ihr Schutz vor dem Tod. Das erste Mal, wenn die Trefferpunkte des Ziels vor dem Ende des Zaubers auf 0 fallen würden, fallen sie stattdessen auf 1 Trefferpunkt und der Zauber endet.<br><br>Sollte das Ziel einem Effekt ausgesetzt sein, der es sofort töten würde, ohne Schaden zu verursachen, wird dieser Effekt stattdessen negiert und der Zauber endet.",
    	"dimensionDoorD": "Du teleportierst dich an einen Ort in Reichweite. Du kommst exakt an der gewünschten Stelle an. Es kann ein Ort sein, den du sehen kannst, den du dir visualisierst oder den du durch Angabe von Entfernung und Richtung beschreibst (z. B. '60 m senkrecht nach unten').<br><br>Du kannst zusätzlich eine willige Kreatur mitteleportieren. Sie muss sich innerhalb von 1,5 m von dir befinden und landet auf einem Platz innerhalb von 1,5 m deines Zielortes.<br><br>Solltest du oder die mitgeführte Kreatur an einem Platz ankommen, der bereits von einer Kreatur besetzt oder vollständig mit Objekten gefüllt ist, erleidet ihr jeweils 4W6 Wuchtschaden und die Teleportation schlägt fehl.",
    	"divinationD": "Dieser Zauber bringt dich in Kontakt mit einer Gottheit oder deren Dienern. Du stellst eine Frage zu einem bestimmten Ziel, Ereignis oder einer Aktivität, die innerhalb der nächsten 7 Tage stattfinden soll. Der SL gibt eine wahrheitsgemäße Antwort, die ein kurzer Satz oder ein kryptischer Reim sein kann. Der Zauber berücksichtigt keine Umstände, die die Antwort verändern könnten, wie etwa das Wirken anderer Zauber.<br><br>Wenn du den Zauber mehr als einmal wirkst, bevor du eine lange Rast beendest, besteht eine kumulative Chance von 25 Prozent für jedes weitere Wirken, dass du keine Antwort erhältst.<br><br><b>Material:</b> Räucherwerk im Wert von 25+ GM, den der Zauber verbraucht.",
    	"dominateBeastD": "Ein Tier, das du in Reichweite sehen kannst, muss einen <b>Weisheitsrettungswurf</b> bestehen oder erhält für die Dauer den Zustand <b>'Bezaubert'</b>. Das Ziel hat <b>Vorteil</b> bei diesem Wurf, wenn du oder deine Verbündeten gegen es kämpfen. Jedes Mal, wenn das Ziel Schaden erleidet, wiederholt es den Rettungswurf.<br><br>Du hast eine telepathische Verbindung zum Ziel, solange ihr euch auf derselben Existenzebene befindet. In deinem Zug kannst du diese Verbindung nutzen, um Befehle zu erteilen (keine Aktion erforderlich), wie 'Greif diese Kreatur an' oder 'Hol diesen Gegenstand'. Das Tier versucht, den Befehl in seinem Zug nach besten Kräften auszuführen. Ohne Befehl schützt es sich selbst.<br><br>Du kannst dem Ziel befehlen, eine <b>Reaktion</b> auszuführen, musst dafür aber deine eigene Reaktion aufwenden.<br><br><b>Höhere Zaubergrade:</b> Deine <b>Konzentration</b> kann länger anhalten: Level 5 (bis zu 10 Min.), Level 6 (bis zu 1 Std.), Level 7+ (bis zu 8 Std.).",
"fabricateD": "Du verwandelst Rohmaterialien in Produkte aus demselben Material. Zum Beispiel kannst du eine hölzerne Brücke aus einer Baumgruppe, ein Seil aus einem Hanffeld oder Kleidung aus Flachs oder Wolle herstellen.<br><br>Wähle Rohmaterialien, die du in Reichweite sehen kannst. Du kannst einen <b>großen</b> oder kleineren Gegenstand herstellen (der in einen 3-m-Würfel oder acht verbundene 1,5-m-Würfel passt), sofern eine ausreichende Menge an Material vorhanden ist. Wenn du jedoch mit Metall, Stein oder einer anderen mineralischen Substanz arbeitest, darf der hergestellte Gegenstand nicht größer als <b>mittelgroß</b> sein (passend in einen 1,5-m-Würfel). Die Qualität der hergestellten Gegenstände richtet sich nach der Qualität der Rohmaterialien.<br><br>Kreaturen und magische Gegenstände können mit diesem Zauber nicht erschaffen werden. Du kannst ihn auch nicht verwenden, um Gegenstände herzustellen, die ein hohes Maß an handwerklichem Geschick erfordern – wie Waffen und Rüstungen –, es sei denn, du besitzt <b>Übung</b> mit der Art von <b>Handwerkszeug</b>, die zur Herstellung solcher Objekte verwendet wird.",
        "fireShieldD": "Hauchzarte Flammen umhüllen deinen Körper für die Dauer des Zaubers und strahlen <b>helles Licht</b> in einem Radius von 3 m sowie <b>dämmriges Licht</b> für weitere 3 m aus.<br><br>Die Flammen bieten dir entweder einen warmen oder einen kalten Schild, ganz nach deiner Wahl. Der warme Schild gewährt dir <b>Resistenz gegen Kälteschaden</b>, und der kalte Schild gewährt dir <b>Resistenz gegen Feuerschaden</b>.<br><br>Zusätzlich bricht der Schild in Flammen aus, wann immer dich eine Kreatur innerhalb von 1,5 m mit einem Nahkampfangriff trifft. Der Angreifer erleidet 2W8 Feuerschaden durch einen warmen Schild oder 2W8 Kälteschaden durch einen kalten Schild.<br><br><b>Material:</b> Ein wenig Phosphor oder ein Glühwürmchen.",
        "fountOfMoonlightD": "Ein kühles Licht umhüllt deinen Körper für die Dauer des Zaubers und strahlt <b>helles Licht</b> in einem Radius von 6 m sowie <b>dämmriges Licht</b> für weitere 6 m aus.<br><br>Bis der Zauber endet, hast du <b>Resistenz gegen Strahlungsschaden</b>, und deine Nahkampfangriffe verursachen bei einem Treffer zusätzlich 2W6 Strahlungsschaden.<br><br>Zusätzlich kannst du, unmittelbar nachdem du Schaden von einer Kreatur erlitten hast, die du innerhalb von 18 m sehen kannst, eine <b>Reaktion</b> verwenden, um die Kreatur zu einem <b>Konstitutionsrettungswurf</b> zu zwingen. Bei einem misslungenen Rettungswurf erhält die Kreatur bis zum Ende deines nächsten Zuges den Zustand <b>'Blind'</b>.",
        "freedomOfMovementD": "Du berührst eine willige Kreatur. Für die Dauer des Zaubers wird die Bewegung des Ziels nicht durch <b>schwieriges Gelände</b> beeinflusst, und Zauber oder andere magische Effekte können weder die Bewegungsrate des Ziels reduzieren noch die Zustände <b>'Gelähmt'</b> oder <b>'Festgehalten'</b> verursachen. Das Ziel erhält zudem eine <b>Schwimmgeschwindigkeit</b>, die seiner normalen Bewegungsrate entspricht.<br><br>Zusätzlich kann das Ziel 1,5 m seiner Bewegung aufwenden, um automatisch aus nichtmagischen Fesseln wie Handschellen oder dem Zustand <b>'Gepackt'</b> zu entkommen.<br><br><b>Höhere Zaubergrad:</b> Du kannst für jeden Zaubergrad über 4 eine zusätzliche Kreatur als Ziel wählen.<br><br><b>Material:</b> Ein Lederriemen.",
        "giantInsectD": "Du beschwörst einen Riesen-Tausendfüßler, eine Riesen-Spinne oder eine Riesen-Wespe (gewählt beim Wirken des Zaubers). Die Kreatur manifestiert sich an einem unbesetzten Platz, den du in Reichweite sehen kannst, und verwendet den Statistikblock für 'Rieseninsekt'. Die gewählte Form bestimmt bestimmte Details im Statistikblock. Die Kreatur verschwindet, wenn ihre Trefferpunkte auf 0 fallen oder der Zauber endet.<br><br>Die Kreatur ist ein Verbündeter für dich und deine Gefährten. Im Kampf teilt sie deinen Initiative-Wert, ist aber unmittelbar nach dir an der Reihe. Sie gehorcht deinen verbalen Befehlen (keine Aktion erforderlich). Ohne Befehl nutzt sie die <b>Ausweichen-Aktion</b> und bewegt sich aus Gefahrenbereichen.<br><br><b>Höhere Zaubergrad:</b> Verwende den Zaubergrad für die Stufe des Zaubers im Statistikblock.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">Rieseninsekt</span>",
        "graspingVineD": "Du beschwörst eine Ranke, die aus einer Oberfläche an einem unbesetzten Platz in Reichweite sprießt. Die Ranke bleibt für die Dauer des Zaubers bestehen.<br><br>Führe einen Nahkampf-Zauberangriff gegen eine Kreatur innerhalb von 9 m um die Ranke aus. Bei einem Treffer erleidet das Ziel 4W8 Wuchtschaden und wird bis zu 9 m weit auf die Ranke zugezogen. Falls das Ziel die Größe <b>Riesig</b> oder kleiner hat, erhält es den Zustand <b>'Gepackt'</b> (Entrinnen-SG gleich deinem Zauberrettungs-SG). Die Ranke kann nur eine Kreatur gleichzeitig gepackt halten, und du kannst die Ranke anweisen, eine Kreatur freizulassen (keine Aktion erforderlich).<br><br>Als <b>Bonusaktion</b> in deinen späteren Zügen kannst du den Angriff gegen eine Kreatur innerhalb von 9 m um die Ranke wiederholen.<br><br><b>Höhere Zaubergrad:</b> Die Anzahl der Kreaturen, die die Ranke gleichzeitig gepackt halten kann, erhöht sich um eins für jeden Zaubergrad über 4.",
        "greaterInvisibilityD": "Eine Kreatur, die du berührst, erhält den Zustand <b>'Unsichtbar'</b>, bis der Zauber endet.",
        "guardianOfFaithD": "Ein <b>großer</b> spektraler Wächter erscheint für die Dauer des Zaubers an einem unbesetzten Platz in Reichweite und schwebt dort. Der Wächter besetzt diesen Platz, ist unverwundbar und erscheint in einer Form, die deiner Gottheit oder deinem Pantheon entspricht.<br><br>Jeder Feind, der sich zum ersten Mal in einem Zug auf einen Platz innerhalb von 3 m um den Wächter bewegt oder seinen Zug dort beginnt, muss einen <b>Geschicklichkeitsrettungswurf</b> ablegen. Bei einem misslungenen Rettungswurf erleidet er 20 Strahlungsschaden, bei einem erfolgreichen nur halb so viel. Der Wächter verschwindet, sobald er insgesamt 60 Schadenspunkte verursacht hat.",
        "hallucinatoryTerrainD": "Du lässt natürliches Gelände in einem 45-m-Würfel in Reichweite wie eine andere Art von natürlichem Gelände aussehen, klingen und riechen. So können offene Felder oder eine Straße wie ein Sumpf, ein Hügel, eine Spalte oder ein anderes schwieriges oder unpassierbares Gelände erscheinen. Ein Teich kann wie eine Granswiese wirken, ein Abgrund wie ein sanfter Hang oder eine felsige Schlucht wie eine breite, glatte Straße. Künstliche Strukturen, Ausrüstung und Kreaturen im Bereich werden nicht verändert.<br><br>Die taktilen Eigenschaften des Geländes bleiben unverändert, sodass Kreaturen, die den Bereich betreten, die Illusion wahrscheinlich bemerken werden. Wenn der Unterschied nicht durch Berührung offensichtlich ist, kann eine Kreatur, die die Illusion untersucht, die <b>Studieren-Aktion</b> verwenden, um einen Wurf auf <b>Intelligenz (Nachforschung)</b> gegen deinen Zauberrettungs-SG durchzuführen. Erkennt eine Kreatur das Gelände als illusionär, sieht sie ein vages Bild, das über dem realen Gelände liegt.<br><br><b>Material:</b> Ein Pilz.",
        "iceStormD": "Hagel fällt in einem Zylinder mit 6 m Radius und 12 m Höhe herab, zentriert auf einen Punkt in Reichweite. Jede Kreatur im Zylinder muss einen <b>Geschicklichkeitsrettungswurf</b> ablegen. Eine Kreatur erleidet 2W10 Wuchtschaden und 4W6 Kälteschaden bei einem misslungenen Rettungswurf oder halb so viel Schaden bei einem erfolgreichen.<br><br>Die Hagelkörner verwandeln den Boden im Zylinder bis zum Ende deines nächsten Zuges in <b>schwieriges Gelände</b>.<br><br><b>Höhere Zaubergrad:</b> Der Wuchtschaden erhöht sich um 1W10 für jeden Zaubergrad über 4.<br><br><b>Material:</b> Ein Fausthandschuh.",
        "locateCreatureD": "Beschreibe oder benenne eine Kreatur, die dir vertraut ist. Du spürst die Richtung zum Standort der Kreatur, sofern sie sich innerhalb von 300 m um dich befindet. Wenn sich die Kreatur bewegt, kennst du die Richtung ihrer Bewegung.<br><br>Der Zauber kann eine spezifische, dir bekannte Kreatur lokalisieren oder die nächstgelegene Kreatur einer bestimmten Art (wie einen Menschen oder ein Einhorn), sofern du eine solche Kreatur mindestens einmal aus der Nähe – innerhalb von 9 m – gesehen hast. Wenn die beschriebene oder benannte Kreatur in einer anderen Form vorliegt, etwa unter den Effekten von <i>Fleisch zu Stein</i> oder <i>Verwandlung</i>, kann dieser Zauber sie nicht aufspüren.<br><br>Dieser Zauber kann eine Kreatur nicht lokalisieren, wenn Blei jeglicher Dicke den direkten Pfad zwischen dir und der Kreatur blockiert.<br><br><b>Material:</b> Fell eines Bluthundes.",
        "phantasmalKillerD": "Du zapfst die Alpträume einer Kreatur an, die du in Reichweite sehen kannst, und erschaffst eine Illusion ihrer tiefsten Ängste, die nur für diese Kreatur sichtbar ist. Das Ziel muss einen <b>Weisheitsrettungswurf</b> ablegen. Bei einem misslungenen Rettungswurf erleidet das Ziel 4W10 psychischen Schaden und hat für die Dauer des Zaubers <b>Nachteil</b> bei Attributsprüfungen und Angriffswürfen. Bei einem erfolgreichen Rettungswurf erleidet das Ziel nur halb so viel Schaden und der Zauber endet.<br><br>Für die Dauer des Zaubers legt das Ziel am Ende jedes seiner Züge einen <b>Weisheitsrettungswurf</b> ab. Bei einem misslungenen Rettungswurf erleidet es erneut den psychischen Schaden. Bei einem erfolgreichen Rettungswurf endet der Zauber.<br><br><b>Höhere Zaubergrad:</b> Der Schaden erhöht sich um 1W10 für jeden Zaubergrad über 4.",
        "polymorphD": "Du versuchst, eine Kreatur in Reichweite in ein <b>Tier</b> zu verwandeln. Das Ziel muss einen <b>Weisheitsrettungswurf</b> bestehen oder verwandelt sich für die Dauer in die Tierform. Diese Form kann jedes Tier deiner Wahl sein, dessen <b>Herausforderungsgrad (HG)</b> kleiner oder gleich dem des Ziels ist (oder der Stufe des Ziels, falls es keinen HG hat). Die Spielwerte des Ziels werden durch den Statistikblock des gewählten Tieres ersetzt, aber das Ziel behält seine Gesinnung, Persönlichkeit, Kreaturenart, Trefferpunkte und Trefferwürfel.<br><br>Das Ziel erhält <b>temporäre Trefferpunkte</b> in Höhe der Trefferpunkte der Tierform. Der Zauber endet vorzeitig, wenn das Ziel keine temporären Trefferpunkte mehr hat.<br><br>Das Ziel ist in seinen Handlungen durch die Anatomie seiner neuen Form eingeschränkt und kann weder sprechen noch Zauber wirken. Die Ausrüstung des Ziels verschmilzt mit der neuen Form; die Kreatur kann diese Ausrüstung nicht verwenden oder anderweitig von ihr profitieren.<br><br><b>Material:</b> Ein Raupenkokon.",
        "staggeringSmiteD": "Das Ziel erleidet zusätzlich 4W6 psychischen Schaden durch den Angriff und muss einen <b>Weisheitsrettungswurf</b> bestehen, andernfalls erhält es bis zum Ende deines nächsten Zuges den Zustand <b>'Betäubt'</b>.<br><br><b>Höhere Zaubergrad:</b> Der zusätzliche Schaden erhöht sich um 1W6 für jeden Zaubergrad über 4.<br><br><b>Bonusaktion:</b> Die du unmittelbar ausführst, nachdem du eine Kreatur mit einer Nahkampfwaffe oder einem unbewaffneten Schlag getroffen hast.",
        "stoneShapeD": "Du berührst ein steinernes Objekt der Größe <b>Mittel</b> oder kleiner oder einen Abschnitt aus Stein, der in keiner Dimension größer als 1,5 m ist, und formst ihn nach deinen Wünschen. Du könntest zum Beispiel einen großen Felsen in eine Waffe, eine Statue oder eine Truhe verwandeln oder einen kleinen Durchgang durch eine 1,5 m dicke Wand schaffen. Du könntest auch eine Steintür oder deren Rahmen so verformen, dass die Tür versiegelt ist. Das erschaffene Objekt kann bis zu zwei Scharniere und einen Riegel haben, feinere mechanische Details sind jedoch nicht möglich.<br><br><b>Material:</b> Weicher Ton.",
        "stoneskinD": "Bis der Zauber endet, besitzt eine willige Kreatur, die du berührst, <b>Resistenz</b> gegen Wucht-, Stich- und Hiebschaden.<br><br><b>Material:</b> Diamantstaub im Wert von 100+ GM, den der Zauber verbraucht.",
        "summonAberrationD": "Du rufst einen aberrantem Geist herbei. Er manifestiert sich an einem unbesetzten Platz, den du in Reichweite sehen kannst, und verwendet den Statistikblock für 'Aberranter Geist'. Wähle beim Wirken: Betrachter-Art (Beholderkin), Gedankenschinder (Mind Flayer) oder Slaad. Die Kreatur ähnelt einer Aberration dieser Art, was bestimmte Details im Statistikblock bestimmt. Die Kreatur verschwindet, wenn ihre Trefferpunkte auf 0 fallen oder der Zauber endet.<br><br>Die Kreatur ist ein Verbündeter für dich und deine Gefährten. Im Kampf teilt sie deinen Initiative-Wert, ist aber unmittelbar nach dir an der Reihe. Sie gehorcht deinen verbalen Befehlen (keine Aktion erforderlich). Ohne Befehl nutzt sie die <b>Ausweichen-Aktion</b> und bewegt sich aus Gefahrenbereichen.<br><br><b>Höhere Zaubergrad:</b> Verwende den Zaubergrad für die Stufe des Zaubers im Statistikblock.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">Aberranter Geist</span><br><br><b>Material:</b> Ein eingelegter Tentakel und ein Augapfel in einem mit Platin verzierten Fläschchen im Wert von 400+ GM.",
        "summonConstructD": "Du rufst den Geist eines Konstrukts herbei. Er manifestiert sich an einem unbesetzten Platz, den du in Reichweite sehen kannst, und verwendet den Statistikblock für 'Konstruktgeist'. Wähle beim Wirken ein Material: Ton, Metall oder Stein. Die Kreatur ähnelt einer belebten Statue (du bestimmst das Aussehen) aus dem gewählten Material, was bestimmte Details im Statistikblock bestimmt. Die Kreatur verschwindet, wenn ihre Trefferpunkte auf 0 fallen oder der Zauber endet.<br><br>Die Kreatur ist ein Verbündeter für dich und deine Gefährten. Im Kampf teilt sie deinen Initiative-Wert, ist aber unmittelbar nach dir an der Reihe. Sie gehorcht deinen verbalen Befehlen (keine Aktion erforderlich). Ohne Befehl nutzt sie die <b>Ausweichen-Aktion</b> und bewegt sich aus Gefahrenbereichen.<br><br><b>Höhere Zaubergrad:</b> Verwende den Zaubergrad für die Stufe des Zaubers im Statistikblock.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">Konstruktgeist</span><br><br><b>Material:</b> Eine Schatulle im Wert von 400+ GM.",
        "summonElementalD": "Du rufst einen Elementargeist herbei. Er manifestiert sich an einem unbesetzten Platz, den du in Reichweite sehen kannst, und verwendet den Statistikblock für 'Elementargeist'. Wähle beim Wirken ein Element: Luft, Erde, Feuer oder Wasser. Die Kreatur ähnelt einer zweibeinigen Form, die vom gewählten Element umhüllt ist, was bestimmte Details im Statistikblock bestimmt. Die Kreatur verschwindet, wenn ihre Trefferpunkte auf 0 fallen oder der Zauber endet.<br><br>Die Kreatur ist ein Verbündeter für dich und deine Gefährten. Im Kampf teilt sie deinen Initiative-Wert, ist aber unmittelbar nach dir an der Reihe. Sie gehorcht deinen verbalen Befehlen (keine Aktion erforderlich). Ohne Befehl nutzt sie die <b>Ausweichen-Aktion</b> und bewegt sich aus Gefahrenbereichen.<br><br><b>Höhere Zaubergrad:</b> Verwende den Zaubergrad für die Stufe des Zaubers im Statistikblock.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">Elementargeist</span><br><br><b>Material:</b> Luft, ein Kieselstein, Asche und Wasser in einem mit Gold verzierten Fläschchen im Wert von 400+ GM.",
        "vitriolicSphereD": "Du zeigst auf einen Ort in Reichweite, und eine glühende Säurekugel mit 30 cm Durchmesser rast dorthin und explodiert in einer Sphäre mit 6 m Radius. Jede Kreatur in diesem Bereich muss einen <b>Geschicklichkeitsrettungswurf</b> ablegen. Bei einem misslungenen Rettungswurf erleidet eine Kreatur 10W4 Säureschaden und weitere 5W4 Säureschaden am Ende ihres nächsten Zuges. Bei einem erfolgreichen Rettungswurf erleidet eine Kreatur nur die Hälfte des Initialschadens.<br><br><b>Höhere Zaubergrad:</b> Der Initialschaden erhöht sich um 2W4 für jeden Zaubergrad über 4.<br><br><b>Material:</b> Ein Tropfen Galle.",
        "wallOfFireD": "Du erschaffst eine Feuerwand auf einer festen Oberfläche in Reichweite. Du kannst die Wand bis zu 18 m lang, 6 m hoch und 30 cm dick machen, oder eine ringförmige Wand mit bis zu 6 m Durchmesser, 6 m Höhe und 30 cm Dicke. Die Wand ist undurchsichtig und bleibt für die Dauer des Zaubers bestehen.<br><br>Wenn die Wand erscheint, legt jede Kreatur in ihrem Bereich einen <b>Geschicklichkeitsrettungswurf</b> ab und erleidet 5W8 Feuerschaden bei einem misslungenen Rettungswurf oder halb so viel Schaden bei einem erfolgreichen.<br><br>Eine Seite der Wand, die du beim Wirken auswählst, fügt jeder Kreatur, die ihren Zug innerhalb von 3 m von dieser Seite oder innerhalb der Wand beendet, 5W8 Feuerschaden zu. Eine Kreatur erleidet denselben Schaden, wenn sie die Wand zum ersten Mal in einem Zug betritt oder ihren Zug dort beendet. Die andere Seite der Wand verursacht keinen Schaden.<br><br><b>Höhere Zaubergrad:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 4.<br><br><b>Material:</b> Ein Stück Holzkohle.",
        "animateObjectsD": "Gegenstände werden auf deinen Befehl hin lebendig. Wähle eine Anzahl nichtmagischer Objekte in Reichweite, die weder getragen noch gehalten werden, nicht an einer Oberfläche fixiert sind und nicht die Größe <b>Gigantisch</b> haben. Die maximale Anzahl der Objekte entspricht deinem Modifikator für die Zauberfähigkeit; dabei zählt ein <b>mittelgroßes</b> oder kleineres Ziel als ein Objekt, ein <b>großes</b> Ziel als zwei und ein <b>riesiges</b> Ziel als drei.<br><br>Jedes Ziel wird belebt, lässt Beine sprießen und wird zu einem Konstrukt, das den Statistikblock für 'Belebtes Objekt' verwendet; diese Kreatur steht unter deiner Kontrolle, bis der Zauber endet oder sie auf 0 Trefferpunkte reduziert wird. Jede Kreatur, die du mit diesem Zauber erschaffst, ist ein Verbündeter für dich und deine Gefährten. Im Kampf teilt sie deinen Initiative-Wert und ist unmittelbar nach dir an der Reihe.<br><br>Bis der Zauber endet, kannst du eine <b>Bonusaktion</b> aufwenden, um jeder von dir erschaffenen Kreatur mental Befehle zu erteilen, sofern sie sich innerhalb von 150 m befindet. Wenn du keine Befehle erteilst, nutzt die Kreatur die <b>Ausweichen-Aktion</b>. Wenn die Kreatur auf 0 Trefferpunkte fällt, kehrt sie in ihre Objektform zurück.<br><br><b>Höhere Zaubergrad:</b> Der Ramm-Schaden (Slam) der Kreatur erhöht sich um 1W4 (Mittel oder kleiner), 1W6 (Groß) oder 1W12 (Riesig) für jeden Zaubergrad über 5.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">Belebtes Objekt</span>",
        "antilifeShellD": "Eine Aura dehnt sich in einer 3-m-Emanation von dir aus. Die Aura verhindert, dass andere Kreaturen außer Konstrukten und Untoten sie durchdringen oder hindurchgreifen. Eine betroffene Kreatur kann jedoch Zauber wirken oder Angriffe mit Fernkampf- oder Reichweitenwaffen durch die Barriere hindurch ausführen.<br><br>Wenn du dich so bewegst, dass eine betroffene Kreatur gezwungen wäre, die Barriere zu durchdringen, endet der Zauber.",
        "awakenD": "Du verbringst die Wirkungszeit damit, magische Pfade in einen kostbaren Edelstein zu zeichnen, und berührst dann das Ziel. Das Ziel muss entweder ein Tier oder eine Pflanzenkreatur mit einer Intelligenz von 3 oder weniger oder eine natürliche Pflanze sein, die keine Kreatur ist. Das Ziel erhält einen Intelligenzwert von 10 und die Fähigkeit, eine Sprache zu sprechen, die du kennst. Wenn das Ziel eine natürliche Pflanze ist, wird sie zu einer Pflanzenkreatur und erhält die Fähigkeit, ihre Gliedmaßen, Wurzeln und Ranken zu bewegen, sowie Sinne ähnlich denen eines Menschen. Der SL wählt passende Spielwerte für die erwachte Pflanze aus.<br><br>Das erwachte Ziel hat für 30 Tage den Zustand <b>'Bezaubert'</b>, oder bis du oder deine Verbündeten ihm Schaden zufügen. Wenn dieser Zustand endet, wählt die erwachte Kreatur ihre Einstellung dir gegenüber selbst.<br><br><b>Material:</b> Ein Achat im Wert von 1.000+ GM, den der Zauber verbraucht.",
        "banishingSmiteD": "Das vom Angriff getroffene Ziel erleidet zusätzlich 5W10 Energieschaden. Wenn der Angriff das Ziel auf 50 Trefferpunkte oder weniger reduziert, muss es einen <b>Charismarettungswurf</b> bestehen oder wird für die Dauer in eine harmlose Halbebene versetzt. Während es dort ist, hat das Ziel den Zustand <b>'Handlungsunfähig'</b>. Wenn der Zauber endet, erscheint das Ziel wieder auf seinem ursprünglichen Platz.<br><br><b>Bonusaktion:</b> Die du unmittelbar ausführst, nachdem du eine Kreatur mit einer Nahkampfwaffe oder einem unbewaffneten Schlag getroffen hast.",
        "circleOfPowerD": "Eine Aura strahlt in einer 9-m-Emanation von dir aus. Während sie sich in der Aura befinden, haben du und deine Verbündeten <b>Vorteil</b> bei Rettungswürfen gegen Zauber und andere magische Effekte. Wenn eine betroffene Kreatur einen Rettungswurf gegen einen Zauber oder magischen Effekt ablegt, der bei einem Erfolg nur halben Schaden zulässt, erleidet sie stattdessen gar keinen Schaden, wenn der Rettungswurf gelingt.",
        "cloudkillD": "Du erschaffst eine Sphäre aus gelbgrünem Nebel mit einem Radius von 6 m, zentriert auf einen Punkt in Reichweite. Der Nebel bleibt für die Dauer bestehen oder bis starker Wind ihn zerstreut. Der Bereich ist <b>stark verdunkelt</b>.<br><br>Jede Kreatur in der Sphäre legt einen <b>Konstitutionsrettungswurf</b> ab und erleidet 5W8 Giftschaden bei einem misslungenen Rettungswurf oder halb so viel bei einem erfolgreichen. Eine Kreatur muss diesen Rettungswurf auch ablegen, wenn sich die Sphäre in ihren Bereich bewegt, sie die Sphäre betritt oder ihren Zug dort beendet. Eine Kreatur legt diesen Rettungswurf nur einmal pro Zug ab.<br><br>Die Sphäre bewegt sich zu Beginn jedes deiner Züge 3 m von dir weg.<br><br><b>Höhere Zaubergrad:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 5.",
        "communeD": "Du nimmst Kontakt zu einer Gottheit oder einem göttlichen Stellvertreter auf und stellst bis zu drei Fragen, die mit Ja oder Nein beantwortet werden können. Du musst deine Fragen stellen, bevor der Zauber endet. Du erhältst für jede Frage eine korrekte Antwort.<br><br>Göttliche Wesen sind nicht zwangsläufig allwissend, daher erhältst du möglicherweise 'unklar' als Antwort, wenn eine Frage Informationen betrifft, die außerhalb des Wissens der Gottheit liegen. In Fällen, in denen eine Ein-Wort-Antwort irreführend wäre, kann der SL stattdessen eine kurze Phrase als Antwort geben.<br><br>Wenn du den Zauber mehr als einmal vor einer langen Rast wirkst, besteht eine kumulative Chance von 25 Prozent für jedes Wirken nach dem ersten, dass du keine Antwort erhältst.<br><br><b>Material:</b> Räucherwerk.",
        "communeWithNatureD": "Du trittst mit Naturgeistern in Kontakt und erhältst Wissen über die Umgebung. Im Freien gibt dir der Zauber Wissen über den Bereich innerhalb von 4,8 km um dich herum. In Höhlen oder anderen natürlichen unterirdischen Umgebungen ist der Radius auf 90 m begrenzt. Der Zauber funktioniert nicht dort, wo die Natur durch Bauwerke ersetzt wurde, wie in Burgen oder Siedlungen.<br><br>Wähle drei der folgenden Fakten aus; du erfährst diese in Bezug auf den Zauberbereich:<ul><li>Standorte von Siedlungen</li><li>Standorte von Portalen zu anderen Existenzebenen</li><li>Standort einer Kreatur mit HG 10+ (Wahl des SL), die ein Celestial, Elementar, Fey, Fiend oder Untoter ist</li><li>Die vorherrschende Art von Pflanzen, Mineralien oder Tieren</li><li>Standorte von Gewässern</li></ul>",
        "coneOfColdD": "Du entfesselst einen Stoß eiskalter Luft. Jede Kreatur in einem 18-m-Kegel, der von dir ausgeht, legt einen <b>Konstitutionsrettungswurf</b> ab und erleidet 8W8 Kälteschaden bei einem misslungenen Rettungswurf oder halb so viel bei einem erfolgreichen. Eine durch diesen Zauber getötete Kreatur wird zu einer gefrorenen Statue, bis sie auftaut.<br><br><b>Höhere Zaubergrad:</b> Der Schaden erhöht sich um 1W8 für jeden Zaubergrad über 5.<br><br><b>Material:</b> Ein kleiner Kristall- oder Glaskegel.",
        "conjureElementalD": "Du beschwörst einen <b>großen</b>, unstofflichen Geist von den Elementarebenen. Wähle das Element des Geistes, welches die Schadensart bestimmt: Luft (Blitz), Erde (Donner), Feuer (Feuer) oder Wasser (Kälte).<br><br>Wann immer eine Kreatur, die du sehen kannst, den Bereich des Geistes betritt oder ihren Zug innerhalb von 1,5 m um ihn beginnt, kannst du sie zu einem <b>Geschicklichkeitsrettungswurf</b> zwingen (sofern der Geist keine Kreatur <b>festgehalten</b> hat). Bei einem misslungenen Rettungswurf erleidet das Ziel 8W8 Schaden der entsprechenden Art und erhält den Zustand <b>'Festgehalten'</b>. Zu Beginn jedes seiner Züge wiederholt das festgehaltene Ziel den Rettungswurf. Bei einem Misserfolg erleidet es 4W8 Schaden, bei einem Erfolg ist es nicht länger festgehalten.<br><br><b>Höhere Zaubergrad:</b> Der Schaden erhöht sich um 2W8 für jeden Zaubergrad über 5.",
        "conjureVolleyD": "Du schwingst die Waffe, die zum Wirken des Zaubers verwendet wurde, und wählst einen Punkt in Reichweite. Hunderte ähnlicher spektraler Waffen (oder passende Munition) fallen in einer Salve herab und verschwinden dann. Jede Kreatur deiner Wahl, die du in einem Zylinder mit 12 m Radius und 6 m Höhe sehen kannst, legt einen <b>Geschicklichkeitsrettungswurf</b> ab. Eine Kreatur erleidet 8W8 Energieschaden bei einem misslungenen Rettungswurf oder halb so viel bei einem erfolgreichen.<br><br><b>Material:</b> Eine Nahkampf- oder Fernkampfwaffe im Wert von mindestens 1 KM.",
        "contactOtherPlaneD": "Du nimmst mental Kontakt zu einem Halbgott, dem Geist eines längst verstorbenen Gelehrten oder einer anderen weisen Entität von einer anderen Ebene auf. Dieser Kontakt kann deinen Verstand zerrütten. Lege beim Wirken einen Rettungswurf auf <b>Intelligenz (SG 15)</b> ab. Bei einem Erfolg kannst du der Entität bis zu fünf Fragen stellen. Der SL beantwortet jede Frage mit einem Wort wie 'Ja', 'Nein', 'Vielleicht' oder 'Unklar'.<br><br>Bei einem Misserfolg erleidest du 6W6 psychischen Schaden und erhältst den Zustand <b>'Handlungsunfähig'</b>, bis du eine lange Rast beendest. Ein Zauber wie <i>Genesung</i> beendet diesen Effekt vorzeitig.",
        "contagionD": "Deine Berührung überträgt eine magische Seuche. Das Ziel muss einen <b>Konstitutionsrettungswurf</b> bestehen oder erleidet 11W8 nekrotischen Schaden und den Zustand <b>'Vergiftet'</b>. Wähle zudem ein Attribut beim Wirken. Solange es vergiftet ist, hat das Ziel <b>Nachteil</b> bei Rettungswürfen für das gewählte Attribut.<br><br>Das Ziel wiederholt den Rettungswurf am Ende jedes seiner Züge, bis es drei Erfolge oder drei Fehlschläge angesammelt hat. Bei drei Erfolgen endet der Zauber. Bei drei Fehlschlägen hält der Zauber 7 Tage lang an.<br><br>Sollte das vergiftete Ziel einen Effekt erhalten, der den Zustand beenden würde, muss es einen <b>Konstitutionsrettungswurf</b> bestehen, andernfalls bleibt der Zustand bestehen.",
        "creationD": "Du ziehst Schattenmaterial aus dem Schattenfell, um einen Gegenstand in Reichweite zu erschaffen. Es kann sich um pflanzliches Material (Seil, Holz, Stoff) oder mineralisches Material (Stein, Metall, Kristall) handeln. Der Gegenstand darf nicht größer als ein 1,5-m-Würfel sein.<br><br>Die Dauer des Zaubers hängt vom Material ab:<br><br><table class=\"spell-table\"><caption>Schattenmaterial</caption><tr><th>Material</th><th>Dauer</th></tr><tr><td>Pflanzliches Material</td><td>24 Stunden</td></tr><tr><td>Stein oder Kristall</td><td>12 Stunden</td></tr><tr><td>Edelmetalle</td><td>1 Stunde</td></tr><tr><td>Edelsteine</td><td>10 Minuten</td></tr><tr><td>Adamant oder Mithral</td><td>1 Minute</td></tr></table><br><b>Höhere Zaubergrad:</b> Der Würfel vergrößert sich um 1,5 m für jeden Zaubergrad über 5.<br><br><b>Material:</b> Ein Pinsel.",
    "destructiveWaveD": "Zerstörerische Energie breitet sich in einer 9-m-Emanation von dir aus. Jede von dir gewählte Kreatur im Bereich muss einen <b>Konstitutionsrettungswurf</b> ablegen. Bei einem Misserfolg erleidet sie 5W6 Schallschaden sowie 5W6 Strahlungs- oder nekrotischen Schaden (deine Wahl) und erhält den Zustand <b>'Liegend'</b>. Bei einem Erfolg wird nur der halbe Schaden verursacht.",
    "dispelEvilAndGoodD": "Für die Dauer des Zaubers haben Celestials, Elementare, Fey, Fiends und Untote <b>Nachteil</b> bei Angriffswürfen gegen dich. Du kannst den Zauber vorzeitig beenden, um eine der folgenden Funktionen zu nutzen:<ul><li><b>Verzauberung brechen:</b> Als Magie-Aktion berührst du eine Kreatur, die von den oben genannten Wesen besessen, bezaubert oder verängstigt ist. Die Effekte enden sofort.</li><li><b>Vertreibung:</b> Als Magie-Aktion zielst du auf eine Kreatur der genannten Arten innerhalb von 1,5 m. Sie muss einen <b>Charismarettungswurf</b> bestehen oder wird auf ihre Heimatebene zurückgeschickt.</li></ul><br><b>Material:</b> Silber- und Eisenstaub.",
    "dominatePersonD": "Ein Humanoid in Reichweite muss einen <b>Weisheitsrettungswurf</b> bestehen oder erhält für die Dauer den Zustand <b>'Bezaubert'</b>. Das Ziel hat <b>Vorteil</b>, wenn ihr gegen es kämpft. Bei Schaden wird der Rettungswurf wiederholt. Du hast eine telepathische Verbindung zum Ziel und kannst Befehle erteilen (keine Aktion erforderlich). Das Ziel gehorcht nach besten Kräften. Du kannst eine <b>Reaktion</b> befehlen, musst dafür aber deine eigene Reaktion aufwenden.<br><br><b>Höherer Zaubergrad:</b> Konzentration hält länger: Level 6 (10 Min.), Level 7 (1 Std.), Level 8+ (8 Std.).",
    "dreamD": "Du zielst auf eine Kreatur, die du kennst. Du oder eine willige Kreatur tritt in Trance, um als Traumbote zu agieren. Der Bote ist <b>handlungsunfähig</b> und hat eine Bewegungsrate von 0. Schläft das Ziel, erscheint der Bote in seinen Träumen und kann kommunizieren. Du kannst den Boten furchteinflößend gestalten: Das Ziel muss einen <b>Weisheitsrettungswurf</b> ablegen; bei Misserfolg erhält es keine Vorteile aus der Rast und erleidet beim Aufwachen 3W6 psychischen Schaden.<br><br><b>Material:</b> Eine Handvoll Sand.",
    "flameStrikeD": "Eine Säule aus strahlendem Feuer schießt herab. Jede Kreatur in einem Zylinder (3 m Radius, 12 m Höhe) muss einen <b>Geschicklichkeitsrettungswurf</b> ablegen. Sie erleidet 5W6 Feuerschaden und 5W6 Strahlungsschaden bei einem Misserfolg (Hälfte bei Erfolg).<br><br><b>Höherer Zaubergrad:</b> Der Feuer- und Strahlungsschaden erhöht sich um jeweils 1W6 pro Zaubergrad über 5.<br><br><b>Material:</b> Eine Prise Schwefel.",
    "geasD": "Du erteilst einer Kreatur einen Befehl zu einem Dienst oder Verbot. Das Ziel muss einen <b>Weisheitsrettungswurf</b> bestehen oder wird <b>bezaubert</b>. Solange es bezaubert ist, erleidet es 5W10 psychischen Schaden, wenn es direkt gegen deinen Befehl handelt (max. einmal pro Tag). Ein Befehl zum sicheren Tod beendet den Zauber.<br><br><b>Höherer Zaubergrad:</b> Bei Level 7-8 beträgt die Dauer 365 Tage. Bei Level 9 hält der Zauber, bis er magisch aufgehoben wird.",
    "greaterRestorationD": "Du berührst eine Kreatur und entfernst magisch einen der folgenden Effekte: 1 Stufe Erschöpfung, den Zustand 'Bezaubert' oder 'Versteinert', einen Fluch (inkl. Einstimmung auf verfluchte Gegenstände), jede Reduzierung eines Attributswertes oder der maximalen Trefferpunkte.<br><br><b>Material:</b> Diamantstaub im Wert von 100+ GM, den der Zauber verbraucht.",
    "hallowD": "Du weihst einen Ort (Radius bis zu 18 m).<br><br><b>Geweihter Schutz:</b> Wähle Kreaturenarten (Aberration, Celestial, Elementar, Fey, Fiend oder Untoter). Diese können den Bereich nicht betreten. Besessenheit, Bezauberung oder Verängstigung durch solche Wesen wird unterdrückt.<br><br><b>Zusatzeffekt:</b> Wähle einen Effekt wie Mut, Dunkelheit, Tageslicht, Ewige Ruhe, Teleportations-Interferenz, Furcht, Resistenzen, Stille, Sprachen oder Verwundbarkeit.<br><br><b>Material:</b> Räucherwerk im Wert von 1.000+ GM, den der Zauber verbraucht.",
    "holdMonsterD": "Wähle eine Kreatur in Reichweite. Das Ziel muss einen <b>Weisheitsrettungswurf</b> bestehen oder erhält für die Dauer den Zustand <b>'Gelähmt'</b>. Am Ende jedes seiner Züge darf das Ziel den Rettungswurf wiederholen.<br><br><b>Höherer Zaubergrad:</b> Du kannst für jeden Zaubergrad über 5 eine zusätzliche Kreatur als Ziel wählen.<br><br><b>Material:</b> Ein gerades Stück Eisen.",
    "insectPlagueD": "Heuschreckenschwärme füllen eine Sphäre mit 6 m Radius. Der Bereich ist <b>leicht verdunkelt</b> und <b>schwieriges Gelände</b>. Jede Kreatur im Bereich muss einen <b>Konstitutionsrettungswurf</b> ablegen und erleidet 4W10 Stichschaden bei einem Misserfolg (Hälfte bei Erfolg).<br><br><b>Höherer Zaubergrad:</b> Der Schaden erhöht sich um 1W10 pro Zaubergrad über 5.<br><br><b>Material:</b> Eine Heuschrecke.",
    "jallarzisStormOfRadianceD": "Ein Sturm aus Licht und Donner entsteht in einem Zylinder (3 m Radius, 12 m Höhe). Kreaturen im Bereich sind <b>blind</b> und <b>taub</b> und können keine Zauber mit verbalen Komponenten wirken. Jede Kreatur im Sturm legt einen <b>Konstitutionsrettungswurf</b> ab und erleidet 2W10 Strahlungsschaden sowie 2W10 Schallschaden bei Misserfolg.<br><br><b>Höherer Zaubergrad:</b> Der Strahlungs- und Schallschaden erhöht sich um 1W10 pro Zaubergrad über 5.<br><br><b>Material:</b> Eine Prise Phosphor.",
    "legendLoreD": "Benenne eine berühmte Person, einen Ort oder einen Gegenstand. Der Zauber ruft eine Zusammenfassung bedeutender Sagen über dieses Thema in dein Gedächtnis. Die Informationen sind präzise, aber oft bildhaft oder poetisch. Ist das Thema nicht wirklich berühmt, schlägt der Zauber fehl.<br><br><b>Material:</b> Räucherwerk (250+ GM) und vier Elfenbeinstreifen (je 50+ GM).",
    "massCureWoundsD": "Heilende Energie breitet sich aus. Wähle bis zu sechs Kreaturen in einer Sphäre mit 9 m Radius. Jedes Ziel erhält Trefferpunkte in Höhe von 5W8 plus deinem Modifikator für die Zauberfähigkeit zurück.<br><br><b>Höherer Zaubergrad:</b> Die Heilung erhöht sich um 1W8 pro Zaubergrad über 5.",
    "misleadD": "Du wirst <b>unsichtbar</b> und ein illusorisches Double erscheint. Die Unsichtbarkeit endet bei Angriff oder Zauber. Als Magie-Aktion kannst du das Double bis zum Doppelten deiner Bewegungsrate bewegen und durch seine Sinne wahrnehmen.",
    "modifyMemoryD": "Du versuchst, die Erinnerungen einer Kreatur umzugestalten (Weisheitsrettungswurf). Bei Misserfolg ist das Ziel <b>bezaubert</b> und <b>handlungsunfähig</b>. Du kannst die Erinnerung an ein Ereignis verändern, das innerhalb der letzten 24 Stunden stattfand und max. 10 Minuten dauerte.<br><br><b>Höherer Zaubergrad:</b> Reichweite der Erinnerung: 7 Tage (Grad 6), 30 Tage (Grad 7), 365 Tage (Grad 8) oder aus der gesamten Vergangenheit (Grad 9).",
    "passwallD": "Ein Durchgang erscheint in Holz, Putz oder Stein (bis zu 1,5 m breit, 2,4 m hoch, 6 m tief). Der Durchgang verursacht keine Instabilität. Kreaturen darin werden beim Ende sicher ausgestoßen.<br><br><b>Material:</b> Eine Prise Sesamsamen.",
    "planarBindingD": "Du bindest einen Celestial, Elementar, Fey oder Fiend an deinen Dienst (Charismarettungswurf). Das Ziel muss während der 1-stündigen Wirkungszeit in Reichweite bleiben. Ein gebundenes Wesen folgt Befehlen nach besten Kräften. Ist es feindselig, versucht es diese zu verdrehen.<br><br><b>Höherer Zaubergrad:</b> Dauer: 10 Tage (Grad 6), 30 Tage (Grad 7), 180 Tage (Grad 8) oder 366 Tage (Grad 9).<br><br><b>Material:</b> Ein Juwel (1.000+ GM), das verbraucht wird.",
    "raiseDeadD": "Du belebst eine Kreatur wieder (max. 10 Tage tot). Sie kehrt mit 1 Trefferpunkt zurück, Gift wird neutralisiert und Wunden heilen (kein Ersatz für Körperteile). Das Ziel erhält einen Malus von -4 auf D20-Tests, der sich nach jeder langen Rast um 1 reduziert.<br><br><b>Material:</b> Ein Diamant (500+ GM), der verbraucht wird.",
    "rarysTelepathicBondD": "Du schmiedest ein telepathisches Band zwischen bis zu acht willigen Kreaturen. Diese können über jede Distanz kommunizieren, solange sie auf derselben Existenzebene bleiben.",
    "reincarnateD": "Du formst einen neuen Körper für einen verstorbenen Humanoiden. Die Seele tritt ein und behält Erinnerungen und Fähigkeiten, tauscht aber Volksmerkmale aus:<br><br><table class=\"spell-table\"><caption>Reinkarnation</caption><tr><th>1W10</th><th>Spezies</th></tr><tr><td>1</td><td>Aasimar</td></tr><tr><td>2</td><td>Drachenblütiger</td></tr><tr><td>3</td><td>Zwerg</td></tr><tr><td>4</td><td>Elf</td></tr><tr><td>5</td><td>Gnom</td></tr><tr><td>6</td><td>Goliath</td></tr><tr><td>7</td><td>Halfling</td></tr><tr><td>8</td><td>Mensch</td></tr><tr><td>9</td><td>Ork</td></tr><tr><td>10</td><td>Tiefling</td></tr></table><br><b>Material:</b> Seltene Öle (1.000+ GM), die verbraucht werden.",
    "scryingD": "Du kannst eine Kreatur auf derselben Ebene sehen und hören (Weisheitsrettungswurf).<br><br><table class=\"spell-table\"><caption>Kenntnisgrad</caption><tr><th>Vertrautheit</th><th>RW-Modifikator</th></tr><tr><td>Vom Hörensagen</td><td>+5</td></tr><tr><td>Persönlich getroffen</td><td>+0</td></tr><tr><td>Gut bekannt</td><td>-5</td></tr></table><br><table class=\"spell-table\"><caption>Physische Verbindung</caption><tr><th>Gegenstand</th><th>RW-Modifikator</th></tr><tr><td>Bildnis</td><td>-2</td></tr><tr><td>Besitzstück/Kleidung</td><td>-4</td></tr><tr><td>Körperteil/Haarlocke</td><td>-10</td></tr></table><br>Bei Misserfolg erscheint ein unsichtbarer Sensor innerhalb von 3 m um das Ziel.<br><br><b>Material:</b> Fokus (Kristallkugel etc.) im Wert von 1.000+ GM.",
"seemingD": "Du verleihst beliebig vielen Kreaturen in Reichweite ein illusionäres Erscheinungsbild. Ein unwilliges Ziel kann einen <b>Charismarettungswurf</b> ablegen; bei Erfolg ist es nicht betroffen. Du kannst allen dasselbe oder verschiedene Aussehen geben, inklusive Ausrüstung. Die Körpergröße kann um bis zu 30 cm variieren. Die Illusion hält einer physischen Untersuchung nicht stand. Eine Kreatur kann die Verkleidung mit der <b>Studieren-Aktion</b> und einem erfolgreichen Wurf auf <b>Intelligenz (Nachforschung)</b> gegen deinen Zauber-SG entlarven.",
    "steelWindStrikeD": "Du schwingst deine Waffe und schlägst wie der Wind zu. Wähle bis zu fünf Kreaturen in Reichweite. Führe gegen jedes Ziel einen Nahkampf-Zauberangriff aus. Bei einem Treffer erleidet das Ziel 6W10 Energieschaden. Danach teleportierst du dich auf einen freien Platz innerhalb von 1,5 m um eines der Ziele.<br><br><b>Material:</b> Eine Nahkampfwaffe im Wert von mindestens 1 SM.",
    "summonCelestialD": "Du rufst einen himmlischen Geist in engelhafter Form herbei. Er manifestiert sich an einem freien Platz in Reichweite und verwendet den Statistikblock 'Himmlischer Geist'. Wähle beim Wirken: <b>Rächer</b> oder <b>Verteidiger</b>. Die Kreatur ist ein Verbündeter, teilt deine Initiative und handelt direkt nach dir. Sie folgt deinen Befehlen oder weicht ohne Befehl aus.<br><br><b>Höherer Zaubergrad:</b> Verwende den Zaubergrad für die Stufe im Statistikblock.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">Himmlischer Geist</span><br><br><b>Material:</b> Ein Reliquienschrein im Wert von 500+ GM.",
    "summonDragonD": "Du rufst einen Drachengeist herbei. Er manifestiert sich an einem unbesetzten Platz in Reichweite und verwendet den Statistikblock 'Drachengeist'. Die Kreatur ist ein Verbündeter, teilt deine Initiative und handelt direkt nach dir. Sie folgt deinen Befehlen (keine Aktion erforderlich) oder nutzt ohne Befehl die Ausweichen-Aktion.<br><br><b>Höherer Zaubergrad:</b> Verwende den Zaubergrad für die Stufe im Statistikblock.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">Drachengeist</span><br><br><b>Material:</b> Ein Gegenstand mit eingraviertem Drachenbild im Wert von 500+ GM.",
    "swiftQuiverD": "Beim Wirken und bis der Zauber endet, kannst du als <b>Bonusaktion</b> zwei Angriffe mit einer Waffe ausführen, die Pfeile oder Bolzen verschießt. Der Zauber erschafft die Munition magisch; sie zerfällt sofort nach dem Treffer oder Fehlschuss.<br><br><b>Material:</b> Ein Köcher im Wert von 1+ GM.",
    "synapticStaticD": "Psychische Energie explodiert an einem Punkt in Reichweite. Jede Kreatur in einer Sphäre mit 6 m Radius muss einen <b>Intelligenzrettungswurf</b> ablegen oder erleidet 8W6 psychischen Schaden (Hälfte bei Erfolg). Bei Misserfolg werden die Gedanken für 1 Minute getrübt: Das Ziel zieht 1W6 von allen Angriffs- und Attributswürfen sowie Konzentrationsrettungswürfen ab. Das Ziel kann den Rettungswurf am Ende jedes seiner Züge wiederholen.",
    "telekinesisD": "Du manipulierst Kreaturen oder Objekte durch reine Gedankenkraft. In jeder Runde kannst du als <b>Magie-Aktion</b> eines der folgenden Ziele beeinflussen:<ul><li><b>Kreatur:</b> Bewege eine Kreatur (Größe Riesig oder kleiner) bis zu 9 m weit (Stärkerettungswurf). Bei Misserfolg ist sie bis zum Ende deines nächsten Zuges <b>festgehalten</b>.</li><li><b>Objekt:</b> Bewege ein Objekt (Größe Riesig oder kleiner) bis zu 9 m weit. Wird es getragen, muss die Kreatur einen Stärkerettungswurf bestehen. Du kannst das Objekt präzise steuern (Werkzeuge nutzen, Behälter öffnen etc.).</li></ul>",
    "teleportationCircleD": "Du zeichnest einen Kreis mit 1,5 m Radius auf den Boden, der ein Portal zu einem permanenten Teleportationskreis deiner Wahl öffnet. Das schimmernde Portal bleibt bis zum Ende deines nächsten Zuges offen. Kreaturen, die es betreten, erscheinen sofort am Zielort. Du kannst einen permanenten Kreis erschaffen, indem du diesen Zauber 365 Tage lang am selben Ort wirkst.<br><br><b>Material:</b> Seltene Tinten im Wert von 50+ GM, die der Zauber verbraucht.",
    "treeStrideD": "Du erhältst die Fähigkeit, in einen Baum zu treten und aus einem anderen Baum derselben Art innerhalb von 150 m wieder herauszutreten. Dies kostet 1,5 m Bewegung. Du weißt sofort, wo sich passende Bäume befinden. Du kannst diese Fähigkeit einmal pro Zug nutzen und musst deinen Zug außerhalb eines Baumes beenden.",
    "wallOfForceD": "Eine unsichtbare Kraftwand erscheint an einem Punkt in Reichweite. Sie kann als Kuppel/Kugel mit 3 m Radius oder als Fläche aus zehn 3-m-x-3-m-Paneelen gestaltet werden. In jeder Form ist sie ca. 0,6 cm dick. Nichts kann sie physisch durchdringen. Sie ist immun gegen Schaden und kann nicht gebannt werden, wird aber durch <i>Auflösung</i> zerstört. Die Wand blockiert auch Reisen durch die Ätherebene.<br><br><b>Material:</b> Eine Glasscherbe.",
    "wallOfStoneD": "Eine nichtmagische Steinwand erscheint (zehn 3-m-x-3-m-Paneele, 15 cm dick; oder 3-m-x-6-m-Paneele, 7,5 cm dick). Die Wand muss mit vorhandenem Stein verschmelzen und gestützt werden. Kreaturen im Bereich können einen <b>Geschicklichkeitsrettungswurf</b> machen, um nicht eingeschlossen zu werden. Bleibt die Konzentration über 10 Minuten bestehen, wird die Wand permanent. Jedes Paneel hat RK 15 und 30 TP pro 2,5 cm Dicke.<br><br><b>Material:</b> Ein Granitwürfel.",
    "yolandesRegalPresenceD": "Du umgibst dich mit überirdischer Majestät in einer 3-m-Emanation. Jede gewählte Kreatur im Bereich muss einen <b>Weisheitsrettungswurf</b> ablegen oder erleidet 4W6 psychischen Schaden, wird 3 m weit weggestoßen und erhält den Zustand <b>'Liegend'</b> (Hälfte Schaden bei Erfolg).<br><br><b>Material:</b> Eine Miniatur-Tiara.",
    "arcaneGateD": "Du erschaffst zwei verbundene Teleportationsportale auf dem Boden (eines in Reichweite, eines innerhalb von 3 m um dich). Die Portale sind leuchtende Ringe mit Nebel. Alles, was in die eine Seite eintritt, tritt aus der anderen Seite wieder aus. Als <b>Bonusaktion</b> kannst du die Ausrichtung der Portale ändern.",
    "bladeBarrierD": "Du erschaffst eine Wand aus wirbelnden Klingen (30 m lang oder ringförmig 18 m Durchmesser). Die Wand gewährt <b>Dreiviertel-Deckung</b> und ist <b>schwieriges Gelände</b>. Eine Kreatur, die den Bereich betritt oder dort ihren Zug beendet, muss einen <b>Geschicklichkeitsrettungswurf</b> ablegen und erleidet 6W10 Energieschaden (Hälfte bei Erfolg).",
    "chainLightningD": "Du schleuderst einen Blitz auf ein Ziel. Drei weitere Blitze springen auf bis zu drei Ziele innerhalb von 9 m um das erste Ziel über. Jedes Ziel muss einen <b>Geschicklichkeitsrettungswurf</b> ablegen und erleidet 10W8 Blitzschaden (Hälfte bei Erfolg).<br><br><b>Höherer Zaubergrad:</b> Ein zusätzlicher Blitz springt pro Zaubergrad über 6 über.<br><br><b>Material:</b> Drei Silbernadeln.",
    "circleOfDeathD": "Negative Energie breitet sich in einer Sphäre mit 18 m Radius aus. Jede Kreatur im Bereich muss einen <b>Konstitutionsrettungswurf</b> ablegen und erleidet 8W8 nekrotischen Schaden (Hälfte bei Erfolg).<br><br><b>Höherer Zaubergrad:</b> Der Schaden erhöht sich um 2W8 pro Zaubergrad über 6.<br><br><b>Material:</b> Staub einer zerstoßenen schwarzen Perle (500+ GM).",
    "conjureFeyD": "Du beschwörst einen <b>mittelgroßen</b> Geist aus dem Feenwild an einen freien Platz. Wenn der Geist erscheint, kannst du einen Nahkampf-Zauberangriff gegen eine Kreatur innerhalb von 1,5 m ausführen. Bei einem Treffer erleidet das Ziel 3W12 + Zauber-Modifikator psychischen Schaden und den Zustand <b>'Verängstigt'</b> bis zu deinem nächsten Zug. Als <b>Bonusaktion</b> kannst du den Geist 9 m weit teleportieren und den Angriff wiederholen.<br><br><b>Höherer Zaubergrad:</b> Der Schaden erhöht sich um 2W12 pro Zaubergrad über 6.",
    "contingencyD": "Wähle einen Zauber des 5. Grades oder niedriger, den du wirken kannst (Wirkungszeit 1 Aktion, Ziel: du selbst). Du wirkst diesen Zauber als Teil von <i>Vorbereitung</i> (beide Zauberplätze werden verbraucht). Der vorbereitete Zauber tritt erst in Kraft, wenn ein von dir definierter Auslöser eintritt. Er wirkt nur auf dich und endet, wenn die Materialkomponente nicht mehr bei dir ist.<br><br><b>Material:</b> Eine edelsteinbesetzte Statuette deiner selbst (1.500+ GM).",
    "createUndeadD": "Dieser Zauber kann nur nachts gewirkt werden. Verwandle bis zu drei Leichen von Humanoiden in <b>Ghoule</b> unter deiner Kontrolle. Du kannst ihnen als <b>Bonusaktion</b> Befehle erteilen. Nach 24 Stunden musst du den Zauber erneut wirken, um die Kontrolle über bis zu drei belebte Kreaturen zu behalten.<br><br><b>Höherer Zaubergrad:</b> Bei Level 7: vier Ghoule. Level 8: fünf Ghoule oder zwei Ghasts/Wichte. Level 9: sechs Ghoule, drei Ghasts/Wichte oder zwei Mumien.<br><br><b>Material:</b> Ein schwarzer Onyx (150+ GM) pro Leiche.",
    "disintegrateD": "Ein grüner Strahl trifft ein Ziel. Eine Kreatur muss einen <b>Geschicklichkeitsrettungswurf</b> ablegen und erleidet 10W6 + 40 Energieschaden. Sinkt das Ziel auf 0 Trefferpunkte, wird es mitsamt Ausrüstung zu Staub zermahlen. Nichtmagische Objekte (Größe L oder kleiner) werden automatisch aufgelöst; bei größeren Objekten wird ein 3-m-Würfel-Abschnitt aufgelöst.<br><br><b>Höherer Zaubergrad:</b> Der Schaden erhöht sich um 3W6 pro Zaubergrad über 6.<br><br><b>Material:</b> Ein Magnetstein und Staub.",
"eyebiteD": "Für die Dauer des Zaubers werden deine Augen zu einer tintenartigen Leere. Eine Kreatur deiner Wahl innerhalb von 18 m, die du sehen kannst, muss einen <b>Weisheitsrettungswurf</b> bestehen oder wird für die Dauer von einem der folgenden Effekte deiner Wahl betroffen.<br><br>In jeder deiner Runden kannst du bis zum Ende des Zaubers eine <b>Magie-Aktion</b> aufwenden, um eine andere Kreatur anzuvisieren. Du kannst eine Kreatur nicht erneut wählen, wenn ihr der Rettungswurf gegen dieses Wirken des Zaubers bereits einmal gelungen ist.<ul><li><b>Schlaf:</b> Das Ziel erhält den Zustand <b>'Bewusstlos'</b>. Es wacht auf, wenn es Schaden erleidet oder eine andere Kreatur eine Aktion verwendet, um es wachzurütteln.</li><li><b>Panik:</b> Das Ziel erhält den Zustand <b>'Verängstigt'</b>. In jedem seiner Züge muss das Ziel die <b>Spurt-Aktion</b> nutzen und sich auf dem sichersten und kürzesten Weg von dir entfernen. Der Effekt endet, wenn das Ziel mindestens 18 m von dir entfernt ist und dich nicht mehr sehen kann.</li><li><b>Übelkeit:</b> Das Ziel erhält den Zustand <b>'Vergiftet'</b>.</li></ul>",
    "findThePathD": "Du spürst magisch den direktesten physischen Weg zu einem von dir benannten Ort. Du musst mit dem Ort vertraut sein. Der Zauber schlägt fehl, wenn das Ziel auf einer anderen Existenzebene liegt, sich bewegt (wie eine fliegende Festung) oder zu ungenau beschrieben ist.<br><br>Solange du dich auf derselben Ebene wie das Ziel befindest, weißt du für die Dauer des Zaubers, wie weit es entfernt ist und in welcher Richtung es liegt. Wann immer du vor einer Weggabelung stehst, weißt du, welcher Pfad der direkteste ist.<br><br><b>Material:</b> Ein Satz Wahrsagewerkzeuge (Karten oder Runen) im Wert von 100+ GM.",
    "fleshToStoneD": "Du versuchst, eine Kreatur in Reichweite in Stein zu verwandeln. Das Ziel muss einen <b>Konstitutionsrettungswurf</b> ablegen. Bei einem Misserfolg erhält es für die Dauer den Zustand <b>'Festgehalten'</b>. Bei einem Erfolg wird seine Bewegungsrate bis zum Beginn deines nächsten Zuges auf 0 reduziert. Konstrukte bestehen den Wurf automatisch.<br><br>Ein festgehaltenes Ziel wiederholt den Rettungswurf am Ende jedes seiner Züge. Wenn ihm der Wurf dreimal gelingt, endet der Zauber. Misslingen die Würfe dreimal, wird es dauerhaft in Stein verwandelt und erhält den Zustand <b>'Versteinert'</b>. Die Erfolge und Misserfolge müssen nicht aufeinanderfolgend sein. Hältst du die <b>Konzentration</b> über die volle Dauer aufrecht, bleibt das Ziel versteinert, bis der Zustand durch <i>Genesung</i> oder ähnliche Magie beendet wird.<br><br><b>Material:</b> Eine Cockatrice-Feder.",
    "forbiddanceD": "Du erschaffst einen Schutz gegen magisches Reisen, der bis zu 3.700 qm Bodenfläche bis zu einer Höhe von 9 m schützt. Für die Dauer können Kreaturen nicht in den Bereich teleportieren oder Portale (wie durch <i>Tor</i>) nutzen. Der Bereich ist gegen planares Reisen geschützt (Astralebene, Ätherebene, Feenwild, Schattenfell oder <i>Ebenenwechsel</i>).<br><br>Zusätzlich fügt der Zauber gewählten Kreaturenarten Schaden zu. Wähle: Aberrationen, Celestials, Elementare, Fey, Fiends oder Untote. Wenn ein solches Wesen den Bereich betritt oder seinen Zug dort beendet, erleidet es 5W10 Strahlungs- oder nekrotischen Schaden (deine Wahl). Ein Passwort kann den Schaden verhindern. Wirkst du den Zauber 30 Tage lang am selben Ort, wird er permanent.<br><br><b>Material:</b> Rubinstaub im Wert von 1.000+ GM.",
    "globeOfInvulnerabilityD": "Eine unbewegliche, schimmernde Barriere erscheint in einer 3-m-Emanation um dich herum. Jeder Zauber des 5. <b>Zaubergrads</b> oder niedriger, der von außerhalb gewirkt wird, kann nichts innerhalb der Kugel beeinflussen. Der Bereich ist zudem von Flächeneffekten solcher Zauber ausgeschlossen.<br><br><b>Höherer Zaubergrad:</b> Die Barriere blockt Zauber, die einen Grad höher sind, für jeden Zaubergrad über 6.<br><br><b>Material:</b> Eine Glasperle.",
    "guardsAndWardsD": "Du erschaffst einen Schutz für bis zu 230 qm Bodenfläche (bis zu 6 m hoch). Du gestaltest den Bereich als 15-m-Quadrat oder als zusammenhängende 1,5-m- oder 3-m-Quadrate. Du kannst Personen bestimmen, die immun sind, oder ein Passwort festlegen.<br><br>Der Zauber erzeugt folgende Effekte:<ul><li><b>Korridore:</b> Nebel verursacht den Zustand <b>'Stark verdunkelt'</b>. An Kreuzungen besteht eine 50-Prozent-Chance, dass Kreaturen glauben, in die entgegengesetzte Richtung zu gehen.</li><li><b>Türen:</b> Alle Türen sind magisch verschlossen (wie <i>Arkanes Schloss</i>). Zehn Türen können als Wand getarnt werden.</li><li><b>Treppen:</b> Gefüllt mit Spinnweben (wie <i>Netz</i>), die nach 10 Min. nachwachsen.</li><li><b>Zusatzeffekt:</b> Wähle einen: <i>Tanzende Lichter</i>, <i>Magischer Mund</i>, <i>Stinkende Wolke</i>, <i>Windstoß</i> oder <i>Einflüsterung</i>.</li></ul><br><b>Material:</b> Ein Silberstab im Wert von 10+ GM.",
    "harmD": "Du entfesselst bösartige Magie. Das Ziel muss einen <b>Konstitutionsrettungswurf</b> ablegen. Bei Misserfolg erleidet es 14W6 nekrotischen Schaden und sein Trefferpunktemaximum sinkt um diesen Betrag. Bei Erfolg wird nur der halbe Schaden verursacht. Das Maximum kann nicht unter 1 sinken.",
    "healD": "Positive Energie durchströmt ein Ziel in Reichweite und stellt 70 Trefferpunkte wieder her. Der Zauber beendet zudem die Zustände <b>'Blind'</b>, <b>'Taub'</b> und <b>'Vergiftet'</b>.<br><br><b>Höherer Zaubergrad:</b> Die Heilung erhöht sich um 10 für jeden Zaubergrad über 6.",
    "magicJarD": "Dein Körper wird katatonisch, während deine Seele in einen Behälter fährt. Du nimmst deine Umgebung aus der Sicht des Behälters wahr. Du kannst deine Seele bis zu 30 m weit projizieren, um in deinen Körper zurückzukehren oder einen Humanoiden zu besessen (<b>Charismarettungswurf</b>). Bei Erfolg kontrollierst du den Körper und nutzt dessen physische Werte (TP, Stärke, Geschick, Konstitution), behältst aber deine geistigen Werte. Stirbt der Wirtskörper oder wird der Behälter zerstört, riskierst du den Tod, falls dein eigener Körper zu weit weg oder bereits tot ist.<br><br><b>Material:</b> Ein Edelstein oder Reliquienschrein im Wert von 500+ GM.",
    "massSuggestionD": "Du schlägst eine Handlungsweise (max. 25 Wörter) für bis zu zwölf Kreaturen vor. Der Vorschlag muss vernünftig klingen. Ziele müssen einen <b>Weisheitsrettungswurf</b> bestehen oder werden für die Dauer <b>bezaubert</b> und folgen der Anweisung.<br><br><b>Höherer Zaubergrad:</b> Die Dauer verlängert sich: Grad 7 (10 Tage), Grad 8 (30 Tage), Grad 9 (366 Tage).<br><br><b>Material:</b> Eine Schlangenzunge.",
    "moveEarhtD": "Wähle ein Geländeareal (max. 12 m Seitenlänge). Du kannst Erde, Sand oder Ton beliebig umformen (Erhöhen, Gräben, Wände). Die Änderungen dauern 10 Minuten und sind zu langsam, um Kreaturen zu fangen. Natürlicher Stein kann nicht bewegt werden. Nach 10 Minuten Konzentration kannst du einen neuen Bereich wählen.<br><br><b>Material:</b> Eine Miniaturschaufel.",
    "planarAllyD": "Du bittest eine mächtige Entität um Hilfe. Diese sendet einen Celestial, Elementar oder Fiend. Das Wesen ist nicht zum Gehorsam verpflichtet; du musst über eine Bezahlung verhandeln. Übliche Preise sind 100 GM/Min, 1.000 GM/Std oder 10.000 GM/Tag. Nach dem Dienst kehrt das Wesen in seine Heimat zurück.",
    "programmedIllusionD": "Du erschaffst eine Illusion (max. 9-m-Würfel), die bei einem Auslöser aktiviert wird. Die Vorführung dauert bis zu 5 Minuten. Danach ruht sie für 10 Minuten. Der Auslöser muss auf Bedingungen innerhalb von 9 m basieren. Eine <b>Studieren-Aktion</b> kann die Illusion enttarnen.<br><br><b>Material:</b> Jadestaub im Wert von 25+ GM.",
    "summonFiendD": "Du rufst einen unholdischen Geist herbei. Wähle: <b>Dämon, Teufel oder Yugoloth</b>. Die Kreatur ist ein Verbündeter, teilt deine Initiative und folgt deinen Befehlen.<br><br><b>Höherer Zaubergrad:</b> Nutze den Zaubergrad für den Statistikblock.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">Unholdischer Geist</span><br><br><b>Material:</b> Ein blutiges Fläschchen im Wert von 600+ GM.",
    "sunbeamD": "Du feuerst einen Sonnenstrahl in einer 1,5 m breiten und 18 m langen Linie ab. Jede Kreatur dort muss einen <b>Konstitutionsrettungswurf</b> ablegen oder erleidet 6W8 Strahlungsschaden und den Zustand <b>'Blind'</b>. Du kannst in jeder Runde eine neue Linie erschaffen. Über dir leuchtet ein Funken (9 m helles Sonnenlicht).<br><br><b>Material:</b> Ein Vergrößerungsglas.",
    "tasha'sBubblingCauldronD": "Du beschwörst einen Kessel mit brodelnder Flüssigkeit, die die Wirkung eines gewöhnlichen oder ungewöhnlichen Tranks kopiert. Als <b>Bonusaktion</b> können du oder Verbündete Tränke entnehmen (Anzahl gleich Zauber-Modifikator).<br><br><b>Material:</b> Eine vergoldete Schöpfkelle im Wert von 500+ GM.",
    "transportViaPlantsD": "Erstellt eine magische Verbindung zwischen zwei <b>großen</b> Pflanzen auf derselben Ebene. Kreaturen können eine Pflanze betreten und für 1,5 m Bewegung aus der anderen heraustreten.",
    "trueSeeingD": "Die berührte willige Kreatur erhält für die Dauer <b>Wahren Blick</b> mit einer Reichweite von 36 m.<br><br><b>Material:</b> Pilzpulver im Wert von 25+ GM, das verbraucht wird.",
    "wallOfIceD": "Du erschaffst eine Wand aus Eis (Kuppel mit 3 m Radius oder Paneele). Beim Erscheinen müssen Kreaturen einen <b>Geschicklichkeitsrettungswurf</b> gegen 10W6 Kälteschaden ablegen. Zerstörte Abschnitte hinterlassen eisige Luft (5W6 Kälteschaden bei Durchquerung).<br><br><b>Höherer Zaubergrad:</b> Schaden erhöht sich um 2W6 (Wand) und 1W6 (Luft) pro Grad über 6.<br><br><b>Material:</b> Ein Stück Quarz.",
    "wallOfThornsD": "Du erschaffst eine Wand aus dornigem Gestrüpp (18 m lang oder 6 m Ring), die die Sicht blockiert. Kreaturen im Bereich erleiden 7W8 Stichschaden (Geschicklichkeitswurf). Bewegung kostet 6 m pro 1,5 m Weg und verursacht 7W8 Hiebschaden.<br><br><b>Höherer Zaubergrad:</b> Beide Schadensarten +1W8 pro Grad über 6.<br><br><b>Material:</b> Eine Handvoll Dornen.",
    "windWalkD": "Du und bis zu zehn Kreaturen werdet zu Wolkenfetzen. Ihr erhaltet eine Fluggeschwindigkeit von 90 m, <b>Resistenz</b> gegen physischen Schaden und Immunität gegen <b>'Liegend'</b>. Das Zurückverwandeln dauert 1 Minute (Zustand <b>'Betäubt'</b>).<br><br><b>Material:</b> Eine Kerze.",
    "wordOfRecallD": "Du und bis zu fünf willige Kreaturen teleportieren sich sofort zu einem zuvor geweihten Zufluchtsort. Du musst den Ort zuvor durch Wirken dieses Zaubers dort als Heiligtum festgelegt haben.",
    "conjureCelestialD": "Du beschwörst einen Geist der oberen Ebenen als Lichtsäule (3 m Radius, 12 m Höhe). Wähle für Kreaturen im Bereich: <b>Heilendes Licht</b> (4W12 + Modifikator Heilung) oder <b>Sengendes Licht</b> (6W12 Strahlungsschaden, Geschicklichkeitswurf). Die Säule kann 9 m pro Zug bewegt werden.<br><br><b>Höherer Zaubergrad:</b> Effekt +1W12 pro Grad über 7.",
    "delayedBlastFireballD": "Ein Strahl kondensiert zu einer Perle, die am Ende der Dauer explodiert (6 m Radius). Basisschaden 12W6 Feuer, +1W6 pro Runde. Kreaturen können versuchen, die Perle zu fangen und wegzuzufordern (40 feet / 12 m).<br><br><b>Höherer Zaubergrad:</b> Basisschaden +1W6 pro Grad über 7.<br><br><b>Material:</b> Eine Kugel aus Fledermausguano und Schwefel.",
    "divineWordD": "Du sprichst ein Wort göttlicher Macht. Gewählte Kreaturen in Reichweite legen einen <b>Charismarettungswurf</b> ab. Ziele mit 50 oder weniger TP erleiden Effekte:<br><br><table class=\"spell-table\"><caption>Effekte des Göttlichen Wortes</caption><tr><th>Trefferpunkte</th><th>Effekt</th></tr><tr><td>0–20</td><td>Das Ziel stirbt sofort.</td></tr><tr><td>21–30</td><td>Das Ziel ist blind, taub und betäubt für 1 Stunde.</td></tr><tr><td>31–40</td><td>Das Ziel ist blind und taub für 10 Minuten.</td></tr><tr><td>41–50</td><td>Das Ziel ist taub für 1 Minute.</td></tr></table><br>Planare Wesen (Celestials, Elementare, Fey, Fiends) werden bei Misserfolg zudem auf ihre Heimatebene verbannt.",
"etherealnessD": "Du begibst dich in die Grenzregionen der Ätherebene, wo sie deine aktuelle Existenzebene überschneidet. Du verbleibst für die Dauer des Zaubers im Grenzäther. Während dieser Zeit kannst du dich in jede Richtung bewegen. Wenn du dich nach oben oder unten bewegst, kostet jeder Meter Bewegung einen zusätzlichen Meter. Du nimmst die Ebene, die du verlassen hast, in Graustufen wahr und kannst nichts sehen, was weiter als 18 m entfernt ist.<br><br>Während du dich auf der Ätherebene befindest, kannst du nur von Kreaturen, Objekten und Effekten auf dieser Ebene beeinflusst werden oder diese beeinflussen. Kreaturen, die nicht auf der Ätherebene sind, können dich weder wahrnehmen noch mit dir interagieren, es sei denn, ein besonderes Merkmal verleiht ihnen diese Fähigkeit.<br><br>Wenn der Zauber endet, kehrst du auf die Ebene zurück, die du verlassen hast, und zwar an den Ort, der deinem Platz im Grenzäther entspricht. Falls du in einem besetzten Bereich erscheinst, wirst du auf den nächsten freien Platz verdrängt und erleidest Wuchtschaden in Höhe des Doppelten der Distanz in Metern, um die du bewegt wurdest.<br><br>Dieser Zauber endet sofort, wenn du ihn wirkst, während du dich bereits auf der Ätherebene oder einer Ebene befindest, die nicht an diese grenzt.<br><br><b>Höherer Zaubergrad:</b> Du kannst bis zu drei willige Kreaturen (einschließlich dir selbst) für jeden Zaubergrad über 7 als Ziel wählen. Die Kreaturen müssen sich beim Wirken innerhalb von 3 m um dich befinden.",
    "fingerOfDeathD": "Du entfesselst negative Energie gegen eine Kreatur, die du in Reichweite sehen kannst. Das Ziel muss einen <b>Konstitutionsrettungswurf</b> ablegen. Bei einem misslungenen Rettungswurf erleidet es 7W8 + 30 nekrotischen Schaden, bei einem erfolgreichen nur halb so viel Schaden.<br><br>Ein Humanoid, der durch diesen Zauber getötet wird, erhebt sich zu Beginn deines nächsten Zuges als <b>Zombie</b>, der deinen verbalen Befehlen folgt.",
    "fireStormD": "Ein Feuersturm erscheint in Reichweite. Der Bereich des Sturms besteht aus bis zu zehn 3-m-Würfeln, die du nach Belieben anordnen kannst. Jeder Würfel muss an mindestens einen anderen Würfel angrenzen. Jede Kreatur im Bereich muss einen <b>Geschicklichkeitsrettungswurf</b> ablegen. Sie erleidet 7W10 Feuerschaden bei einem misslungenen Rettungswurf oder halb so viel bei einem erfolgreichen.<br><br>Entflammbare Objekte im Bereich, die nicht getragen oder gehalten werden, fangen Feuer.",
    "forceageD": "Ein unbewegliches, <b>unsichtbares</b>, würfelförmiges Gefängnis aus magischer Kraft entsteht um einen Bereich in Reichweite. Das Gefängnis kann entweder ein <b>Käfig</b> oder eine <b>feste Box</b> sein.<br><br>Ein Käfig kann eine Seitenlänge von bis zu 6 m haben und besteht aus Stäben mit 1,2 cm Durchmesser. Eine Box kann eine Seitenlänge von bis zu 3 m haben und bildet eine feste Barriere, die keine Materie durchlässt und Zauber blockiert.<br><br>Jede Kreatur, die sich beim Wirken vollständig im Bereich befindet, ist gefangen. Kreaturen, die zu groß sind, werden aus dem Bereich gestoßen. Eine Kreatur im Inneren kann das Gefängnis nicht mit nichtmagischen Mitteln verlassen. Versucht sie Teleportation oder interplanare Reise, muss sie zuerst einen <b>Charismarettungswurf</b> bestehen. Bei Misserfolg bleibt sie gefangen und verbraucht den Effekt wirkungslos. Das Gefängnis blockiert auch Reisen durch die Ätherebene. Dieser Zauber kann nicht durch <b>Magie bannen</b> aufgehoben werden.<br><br><b>Material:</b> Rubinstaub im Wert von 1.500+ GM, den der Zauber verbraucht.",
    "mirageArcaneD": "Du gestaltest Gelände in einem Bereich von bis zu 1,6 km im Quadrat um. Es sieht nicht nur anders aus, sondern klingt, riecht und fühlt sich auch so an. Offene Felder können wie ein Sumpf oder unwegsames Gebirge erscheinen, ein Teich wie eine Wiese oder ein Abgrund wie ein sanfter Hang. Künstliche Strukturen und Kreaturen werden nicht verändert.<br><br>Du kannst das Aussehen von Gebäuden ändern oder neue hinzufügen. Die Illusion umfasst visuelle, auditive, taktile und olfaktorische Elemente und kann Gelände in <b>schwieriges Gelände</b> verwandeln. Jedes Teil des illusorischen Geländes, das aus dem Bereich entfernt wird, verschwindet sofort. Kreaturen mit <b>Wahrer Blick</b> können die wahre Form des Geländes sehen, interagieren aber dennoch physisch mit der Illusion.",
    "planeShiftD": "Du und bis zu acht willige Kreaturen, die sich im Kreis an den Händen halten, werden auf eine andere Existenzebene transportiert. Du kannst einen Zielort allgemein angeben, und ihr erscheint an oder nahe diesem Ort (SL-Entscheidung).<br><br>Alternativ kannst du die Glyphensequenz eines Teleportationskreises auf einer anderen Ebene nutzen, um direkt dorthin zu reisen. Ist der Kreis zu klein, erscheinen die übrigen Kreaturen auf den nächsten freien Plätzen daneben.<br><br><b>Material:</b> Ein gegabelter Metallstab im Wert von 250+ GM, der auf eine Existenzebene abgestimmt ist.",
    "powerWordFortifyD": "Du stärkst bis zu sechs Kreaturen, die du in Reichweite sehen kannst. Der Zauber gewährt insgesamt 120 <b>temporäre Trefferpunkte</b>, die du unter den Empfängern aufteilst.",
    "prismaticSprayD": "Acht Lichtstrahlen schießen in einem 18-m-Kegel von dir aus. Jede Kreatur im Kegel muss einen <b>Geschicklichkeitsrettungswurf</b> ablegen. Würfle für jedes Ziel 1W8:<br><br><table class=\"spell-table\"><caption>Regenbogenspray</caption><tr><th>1W8</th><th>Strahl & Effekt</th></tr><tr><td>1</td><td><b>Rot:</b> 12W6 Feuerschaden (Hälfte bei Erfolg).</td></tr><tr><td>2</td><td><b>Orange:</b> 12W6 Säureschaden (Hälfte bei Erfolg).</td></tr><tr><td>3</td><td><b>Gelb:</b> 12W6 Blitzschaden (Hälfte bei Erfolg).</td></tr><tr><td>4</td><td><b>Grün:</b> 12W6 Giftschaden (Hälfte bei Erfolg).</td></tr><tr><td>5</td><td><b>Blau:</b> 12W6 Kälteschaden (Hälfte bei Erfolg).</td></tr><tr><td>6</td><td><b>Indigo:</b> Ziel ist <b>festgehalten</b> (Konstitutions-RW). Nach 3 Erfolgen endet der Effekt, nach 3 Fehlschlägen wird es permanent <b>versteinert</b>.</td></tr><tr><td>7</td><td><b>Violett:</b> Ziel ist <b>blind</b> (Weisheits-RW). Bei Misserfolg wird es auf eine andere Ebene versetzt.</td></tr><tr><td>8</td><td><b>Spezial:</b> Das Ziel wird von zwei Strahlen getroffen. Würfle zweimal (ignoriere eine 8).</td></tr></table>",
    "projectImageD": "Du erschaffst eine illusorische Kopie deiner selbst an einem Ort in Reichweite, den du bereits gesehen hast. Die Illusion sieht aus und klingt wie du, ist aber unstofflich. Du nimmst durch ihre Augen und Ohren wahr. Als <b>Magie-Aktion</b> kannst du sie bis zu 18 m weit bewegen und sie gestikulieren oder sprechen lassen. Physische Interaktion enthüllt sie als Illusion. Eine Kreatur kann sie mit einer <b>Studieren-Aktion</b> (Intelligenz gegen Zauber-SG) entlarven; dann kann sie hindurchsehen und Geräusche klingen hohl.<br><br><b>Material:</b> Eine Statuette deiner selbst im Wert von 5+ GM.",
    "regenerateD": "Eine Kreatur, die du berührst, erhält 4W8 + 15 Trefferpunkte zurück. Für die Dauer des Zaubers regeneriert das Ziel zu Beginn jedes seiner Züge 1 Trefferpunkt, und alle abgetrennten Körperteile wachsen nach 2 Minuten nach.<br><br><b>Material:</b> Ein Gebetsrad.",
    "resurrectionD": "Du berührst eine tote Kreatur (max. 100 Jahre tot, nicht an Altersschwäche gestorben, kein Untoter). Sie kehrt mit allen Trefferpunkten zurück. Gifte werden neutralisiert und Wunden geschlossen. Die Rückkehr ist beschwerlich: Das Ziel erhält einen Malus von -4 auf <b>D20-Tests</b>, der nach jeder langen Rast um 1 sinkt. Das Wiederbeleben einer Kreatur, die seit 365 Tagen oder länger tot ist, zehrt an deinen Kräften: Du kannst bis zur nächsten langen Rast keine Zauber mehr wirken und hast <b>Nachteil</b> auf alle D20-Tests.<br><br><b>Material:</b> Ein Diamant im Wert von 1.000+ GM, den der Zauber verbraucht.",
    "reverseGravityD": "Dieser Zauber kehrt die Schwerkraft in einem Zylinder mit 15 m Radius und 30 m Höhe um. Alle Kreaturen und Objekte im Bereich fallen nach oben bis zur Decke des Zylinders. Ein <b>Geschicklichkeitsrettungswurf</b> erlaubt das Festhalten an festen Objekten. Trifft man beim Aufwärtssturz auf ein Hindernis, erleidet man Schaden wie bei einem normalen Sturz. Wird die Oberseite ohne Hindernis erreicht, schwebt man dort. Wenn der Zauber endet, fallen alle wieder nach unten.<br><br><b>Material:</b> Ein Magnetstein und Eisenfeilspäne.",
    "sequesterD": "Durch Berührung sonderst du ein Objekt oder eine willige Kreatur magisch ab. Das Ziel wird <b>unsichtbar</b> und kann nicht durch Erkenntniszauber geortet werden. Eine Kreatur tritt in Scheintod ein (<b>bewusstlos</b>, kein Altern, kein Bedarf an Luft/Nahrung). Du kannst eine Endbedingung festlegen, die innerhalb von 1,6 km eintreten muss. Der Zauber endet auch bei jeglichem Schaden.<br><br><b>Material:</b> Edelsteinstaub im Wert von 5.000+ GM, den der Zauber verbraucht.",
    "simulacrumD": "Du erschaffst ein Simulakrum eines Tieres oder Humanoiden aus Eis oder Schnee. Das Simulakrum ist ein Konstrukt mit der Hälfte der maximalen Trefferpunkte des Originals und kann diesen Zauber nicht selbst wirken. Es handelt direkt nach dir im Kampf und folgt deinen Befehlen. Es kann keine Stufen aufsteigen oder Rasten nutzen. Die Heilung erfordert eine Reparatur während einer langen Rast (100 GM pro TP). Ein erneutes Wirken zerstört das vorherige Simulakrum sofort.<br><br><b>Material:</b> Rubinstaub im Wert von 1.500+ GM, den der Zauber verbraucht.",
    "symbolD": "Du zeichnest eine Glyphe (max. 3 m Durchmesser) auf eine Fläche oder in ein Objekt. Ein <b>Weisheitswurf (Wahrnehmung)</b> ist nötig, um sie zu bemerken. Wähle einen Effekt: <b>Tod</b> (10W10 nekrotisch), <b>Zwietracht</b> (Streit), <b>Furcht</b>, <b>Schmerz</b> (handlungsunfähig), <b>Schlaf</b> oder <b>Betäubung</b>. Einmal ausgelöst, füllt die Glyphe eine 18-m-Sphäre für 10 Minuten mit dämmrigem Licht und betrifft jede Kreatur darin einmal pro Zug.<br><br><b>Material:</b> Diamantstaub im Wert von 1.000+ GM, den der Zauber verbraucht.",
    "teleportD": "Du transportierst dich und bis zu acht willige Kreaturen (oder ein großes Objekt) an einen Ort auf derselben Ebene. Der Erfolg hängt von deiner Vertrautheit ab:<br><br><table class=\"spell-table\"><caption>Teleportations-Ergebnis</caption><tr><th>Vertrautheit</th><th>Patzer</th><th>Ähnlicher Bereich</th><th>Ziel verfehlt</th><th>Ziel getroffen</th></tr><tr><td>Permanenter Kreis</td><td>—</td><td>—</td><td>—</td><td>01–00</td></tr><tr><td>Verknüpftes Objekt</td><td>—</td><td>—</td><td>—</td><td>01–00</td></tr><tr><td>Sehr vertraut</td><td>01–05</td><td>06–13</td><td>14–24</td><td>25–00</td></tr><tr><td>Flüchtig gesehen</td><td>01–33</td><td>34–43</td><td>44–53</td><td>54–00</td></tr><tr><td>Einmal gesehen/beschrieben</td><td>01–43</td><td>44–53</td><td>54–73</td><td>74–00</td></tr><tr><td>Falsches Ziel</td><td>01–50</td><td>51–00</td><td>—</td><td>—</td></tr></table><br><b>Patzer:</b> Jeder Reisende erleidet 3W10 Wuchtschaden. <b>Ziel verfehlt:</b> Ihr landet 2W12 Meilen entfernt in einer zufälligen Richtung.",
    "animalShapesD": "Beliebig viele willige Kreaturen verwandeln sich in <b>Tiere</b> (Größe Groß oder kleiner, HG 4 oder niedriger). Spielwerte werden ersetzt, aber Trefferpunkte, Gesinnung und geistige Werte bleiben erhalten. Aktionen sind durch die Anatomie begrenzt. Ziele erhalten <b>temporäre Trefferpunkte</b> der neuen Form. Die Verwandlung endet bei 0 TP oder als Bonusaktion.",
    "antimagicFieldD": "Ein unsichtbares Feld (3-m-Emanation) unterdrückt alle Magie. Zauber können nicht gewirkt werden, magische Gegenstände funktionieren nicht und Teleportation ist unmöglich. Laufende Zauber werden unterdrückt, die Dauer läuft jedoch weiter. Artefakte und Gottheiten sind ausgenommen.<br><br><b>Material:</b> Eisenfeilspäne.",
    "antipath_SympathyD": "Wähle Antipathie (Furcht & Flucht) oder Sympathie (Bezauberung & Annäherung) gegenüber einer Kreaturenart. Ziele legen einen <b>Weisheitsrettungswurf</b> ab, wenn sie sich auf 36 m nähern. Endet der Zug mehr als 36 m entfernt, kann der Rettungswurf wiederholt werden. Bei Erfolg ist das Wesen für 1 Minute immun.<br><br><b>Material:</b> Eine Mischung aus Essig und Honig.",
    "cloneD": "Du berührst eine Kreatur (oder mindestens 1.5 cm Fleisch). Ein inerter Doppelgänger wächst in einem Gefäß und ist nach 120 Tagen fertig. Stirbt das Original danach, wandert die Seele in den Klon, sofern sie frei und bereit ist. Der Klon ist physisch identisch und besitzt alle Erinnerungen und Fähigkeiten. Die Überreste des Originals werden inert und können nicht mehr wiederbelebt werden.<br><br><b>Material:</b> Ein Diamant (1.000+ GM), der verbraucht wird, und ein verschließbares Gefäß (2.000+ GM).",
"controlWeatherD": "Du übernimmst für die Dauer des Zaubers die Kontrolle über das Wetter in einem Umkreis von 8 km um dich herum. Du musst dich im Freien befinden, um diesen Zauber zu wirken; er endet vorzeitig, wenn du dich in ein Gebäude begibst.<br><br>Wenn du den Zauber wirkst, änderst du die aktuellen Wetterbedingungen, die vom SL festgelegt werden. Du kannst Niederschlag, Temperatur und Wind beeinflussen. Es dauert 1W4 × 10 Minuten, bis die neuen Bedingungen eintreten. Sobald dies geschehen ist, kannst du die Bedingungen erneut ändern. Wenn der Zauber endet, kehrt das Wetter schrittweise zum Normalzustand zurück.<br><br>Um die Wetterbedingungen zu ändern, wähle eine aktuelle Bedingung aus den folgenden Tabellen und ändere ihre Stufe um eins nach oben oder unten. Wenn du den Wind änderst, kannst du auch dessen Richtung anpassen.<br><br><table class=\"spell-table\"><caption>Niederschlag</caption><tr><th>Stufe</th><th>Bedingung</th></tr><tr><td>1</td><td>Klar</td></tr><tr><td>2</td><td>Leichte Bewölkung</td></tr><tr><td>3</td><td>Bedeckt oder Bodennebel</td></tr><tr><td>4</td><td>Regen, Hagel oder Schnee</td></tr><tr><td>5</td><td>Sintflutartiger Regen, Schlagregen oder Blizzard</td></tr></table><br><table class=\"spell-table\"><caption>Temperatur</caption><tr><th>Stufe</th><th>Bedingung</th></tr><tr><td>1</td><td>Hitzewelle</td></tr><tr><td>2</td><td>Heiß</td></tr><tr><td>3</td><td>Warm</td></tr><tr><td>4</td><td>Kühl</td></tr><tr><td>5</td><td>Kalt</td></tr><tr><td>6</td><td>Frost</td></tr></table><br><table class=\"spell-table\"><caption>Wind</caption><tr><th>Stufe</th><th>Bedingung</th></tr><tr><td>1</td><td>Windstill</td></tr><tr><td>2</td><td>Mäßiger Wind</td></tr><tr><td>3</td><td>Starker Wind</td></tr><tr><td>4</td><td>Sturm</td></tr><tr><td>5</td><td>Orkan</td></tr></table><br><b>Material:</b> Brennendes Räucherwerk.",
    "demiplaneD": "Du erschaffst eine schattige, <b>mittelgroße</b> Tür auf einer flachen, festen Oberfläche, die du in Reichweite sehen kannst. Diese Tür kann geöffnet und geschlossen werden und führt zu einer Halbebene, die aus einem leeren, quadratischen Raum mit 9 m Seitenlänge besteht und aus Holz oder Stein (deine Wahl) gefertigt ist.<br><br>Wenn der Zauber endet, verschwindet die Tür. Alle Gegenstände im Inneren bleiben dort. Kreaturen im Inneren bleiben ebenfalls dort, es sei denn, sie entscheiden sich, beim Verschwinden der Tür ausgestoßen zu werden. In diesem Fall landen sie mit dem Zustand <b>'Liegend'</b> auf den nächstgelegenen unbesetzten Plätzen vor der ehemaligen Tür.<br><br>Jedes Mal, wenn du diesen Zauber wirkst, kannst du eine neue Halbebene erschaffen oder die schattige Tür mit einer Halbebene verbinden, die du mit einem früheren Wirken dieses Zaubers erschaffen hast. Wenn du die Beschaffenheit und den Inhalt einer Halbebene kennst, die von einer anderen Kreatur erschaffen wurde, kannst du die Tür stattdessen mit dieser verbinden.",
    "dominateMonsterD": "Eine Kreatur, die du in Reichweite sehen kannst, muss einen <b>Weisheitsrettungswurf</b> bestehen oder erhält für die Dauer den Zustand <b>'Bezaubert'</b>. Das Ziel hat <b>Vorteil</b> bei diesem Rettungswurf, wenn du oder deine Verbündeten gegen es kämpfen. Wann immer das Ziel Schaden erleidet, wiederholt es den Rettungswurf und beendet den Effekt bei einem Erfolg.<br><br>Du hast eine telepathische Verbindung zum bezauberten Ziel, solange ihr euch auf derselben Existenzebene befindet. In deinem Zug kannst du diese Verbindung nutzen, um dem Ziel Befehle zu erteilen (keine Aktion erforderlich), wie z. B. „Greif diese Kreatur an“ oder „Hol jenen Gegenstand“. Das Ziel tut sein Bestes, um den Befehlen in seinem Zug zu gehorchen. Wenn es einen Befehl ausgeführt hat und keine weiteren Anweisungen erhält, handelt und bewegt es sich nach eigenem Ermessen und konzentriert sich darauf, sich selbst zu schützen.<br><br>Du kannst dem Ziel befehlen, eine <b>Reaktion</b> auszuführen, musst dafür aber deine eigene Reaktion aufwenden.<br><br><b>Höherer Zaubergrad:</b> Deine Konzentration hält bei Verwendung eines Zaubergrads von 9 länger an (bis zu 8 Stunden).",
    "earthquakeD": "Wähle einen Punkt auf dem Boden, den du in Reichweite sehen kannst. Für die Dauer des Zaubers erschüttert ein intensives Beben den Boden in einem Kreis mit 30 m Radius um diesen Punkt. Der Boden dort gilt als <b>schwieriges Gelände</b>.<br><br>Wenn du diesen Zauber wirkst und am Ende jedes deiner Züge während der Wirkungsdauer muss jede Kreatur, die sich am Boden in diesem Bereich befindet, einen <b>Geschicklichkeitsrettungswurf</b> ablegen. Bei einem Misserfolg erhält die Kreatur den Zustand <b>'Liegend'</b> und ihre <b>Konzentration</b> wird unterbrochen.<br><br>Zusätzlich kannst du folgende Effekte hervorrufen:<ul><li><b>Spalten:</b> Insgesamt 1W6 Spalten öffnen sich am Ende des Zuges, in dem du den Zauber wirkst. Du wählst die Orte der Spalten, die sich nicht unter Gebäuden befinden dürfen. Jede Spalte ist (1W10 × 3) m tief und 3 m breit und erstreckt sich von einem Rand des Zauberbereichs zum anderen. Eine Kreatur im Bereich einer Spalte muss einen <b>Geschicklichkeitsrettungswurf</b> bestehen oder stürzt hinein.</li><li><b>Strukturen:</b> Das Beben fügt jedem Gebäude, das in Kontakt mit dem Boden im Bereich steht, beim Wirken und am Ende jedes deiner Züge 50 Wuchtschaden zu. Wenn ein Gebäude 0 Trefferpunkte erreicht, stürzt es ein. Eine Kreatur innerhalb einer Distanz zur Einsturzstelle, die der halben Gebäudehöhe entspricht, muss einen <b>Geschicklichkeitsrettungswurf</b> ablegen. Bei einem Misserfolg erleidet sie 12W6 Wuchtschaden, wird hingestreckt und unter Trümmern begraben (Entkommen erfordert eine Aktion und einen SG 20 Wurf auf Stärke (Athletik)). Bei einem Erfolg erleidet sie nur halb so viel Schaden.</li></ul><br><b>Material:</b> Ein zerbrochener Stein.",
    "glibnessD": "Bis der Zauber endet, kannst du bei jedem Charismawurf das gewürfelte Ergebnis durch eine 15 ersetzen. Zudem zeigt Magie, die feststellen soll, ob du die Wahrheit sagst, ungeachtet deiner Worte immer an, dass du wahrheitsgemäß antwortest.",
    "holyAuraD": "Für die Dauer des Zaubers strahlst du eine Aura in einer 9-m-Emanation aus. Während sie sich in der Aura befinden, haben von dir gewählte Kreaturen <b>Vorteil</b> bei allen Rettungswürfen, und andere Kreaturen haben <b>Nachteil</b> bei Angriffswürfen gegen sie. Wenn ein Unhold (Fiend) oder ein Untoter eine betroffene Kreatur mit einem Nahkampfangriff trifft, muss der Angreifer zudem einen <b>Konstitutionsrettungswurf</b> bestehen oder erhält bis zum Ende seines nächsten Zuges den Zustand <b>'Blind'</b>.<br><br><b>Material:</b> Ein Reliquienschrein im Wert von mindestens 1.000 GM.",
    "incendiaryCloudD": "Eine wirbelnde Wolke aus Glut und Rauch füllt eine Sphäre mit 6 m Radius, zentriert auf einen Punkt in Reichweite. Der Bereich der Wolke ist <b>stark verdunkelt</b>. Sie hält für die Dauer an oder bis ein starker Wind sie zerstreut.<br><br>Wenn die Wolke erscheint, muss jede Kreatur darin einen <b>Geschicklichkeitsrettungswurf</b> ablegen und erleidet 10W8 Feuerschaden bei einem Misserfolg (Hälfte bei Erfolg). Eine Kreatur muss diesen Rettungswurf auch ablegen, wenn sich die Sphäre in ihren Bereich bewegt oder wenn sie die Sphäre betritt oder ihren Zug dort beendet. Eine Kreatur erleidet diesen Schaden nur einmal pro Zug.<br><br>Die Wolke bewegt sich zu Beginn jedes deiner Züge 3 m weit weg von dir in eine von dir gewählte Richtung.",
    "mazeD": "Du verbannst eine Kreatur, die du in Reichweite sehen kannst, in eine labyrinthartige Halbebene. Das Ziel bleibt dort für die Dauer des Zaubers oder bis es aus dem Labyrinth entkommt.<br><br>Das Ziel kann eine <b>Studieren-Aktion</b> verwenden, um zu entkommen. Dabei legt es einen Wurf auf <b>Intelligenz (Nachforschung) gegen SG 20</b> ab. Bei einem Erfolg entkommt es und der Zauber endet.<br><br>Wenn der Zauber endet, erscheint das Ziel wieder an dem Platz, den es verlassen hat, oder auf dem nächstgelegenen unbesetzten Platz.",
    "mindBlankD": "Bis der Zauber endet, besitzt eine willige Kreatur, die du berührst, <b>Immunität gegen psychischen Schaden</b> und den Zustand <b>'Bezaubert'</b>. Das Ziel ist zudem unempfänglich gegen jegliche Effekte, die seine Emotionen oder Gesinnung spüren, seine Gedanken lesen oder seinen Standort magisch aufspüren würden. Kein Zauber – nicht einmal <i>Wunsch</i> – kann Informationen über das Ziel sammeln, es aus der Ferne beobachten oder seinen Verstand kontrollieren.",
    "powerWordStunD": "Du überwältigst den Verstand einer Kreatur, die du in Reichweite sehen kannst. Wenn das Ziel 150 Trefferpunkte oder weniger hat, erhält es den Zustand <b>'Betäubt'</b>. Andernfalls wird seine Bewegungsrate bis zum Beginn deines nächsten Zuges auf 0 reduziert.<br><br>Ein betäubtes Ziel legt am Ende jedes seiner Züge einen <b>Konstitutionsrettungswurf</b> ab und beendet den Zustand bei einem Erfolg.",
    "sunburstD": "Gleißendes Sonnenlicht blitzt in einer Sphäre mit 18 m Radius auf, zentriert auf einen Punkt in Reichweite. Jede Kreatur in der Sphäre muss einen <b>Konstitutionsrettungswurf</b> ablegen. Bei einem Misserfolg erleidet sie 12W6 Strahlungsschaden und erhält für 1 Minute den Zustand <b>'Blind'</b>. Bei einem Erfolg wird nur der halbe Schaden verursacht.<br><br>Eine durch diesen Zauber erblindete Kreatur wiederholt den Rettungswurf am Ende jedes ihrer Züge und beendet den Effekt bei einem Erfolg. Dieser Zauber bannt jede magische Dunkelheit in seinem Bereich.<br><br><b>Material:</b> Ein Stück Sonnenstein.",
    "telepathyD": "Du erschaffst eine telepathische Verbindung zwischen dir und einer willigen Kreatur, mit der du vertraut bist. Die Kreatur kann sich an jedem Ort auf derselben Existenzebene wie du befinden. Der Zauber endet, wenn du oder das Ziel euch nicht mehr auf derselben Ebene befindet.<br><br>Bis der Zauber endet, können du und das Ziel sofort Wörter, Bilder, Töne und andere sensorische Botschaften über die Verbindung teilen. Das Ziel erkennt dich dabei als die Kreatur, mit der es kommuniziert. Der Zauber ermöglicht es einer Kreatur, die Bedeutung deiner Worte und aller gesendeten sensorischen Botschaften zu verstehen.<br><br><b>Material:</b> Ein Paar verbundene Silberringe.",
    "tsunamiD": "Eine Wand aus Wasser schießt an einem von dir gewählten Punkt in Reichweite empor. Du kannst die Wand bis zu 90 m lang, 90 m hoch und 15 m dick machen. Die Wand bleibt für die Dauer des Zaubers bestehen.<br><br>Wenn die Wand erscheint, muss jede Kreatur in ihrem Bereich einen <b>Stärkerettungswurf</b> ablegen. Bei einem Misserfolg erleidet sie 6W10 Wuchtschaden, bei einem Erfolg nur halb so viel.<br><br>Zu Beginn jedes deiner Züge nach dem Erscheinen bewegt sich die Wand zusammen mit allen darin befindlichen Kreaturen 15 m von dir weg. Jede Kreatur der Größe Riesig oder kleiner, die sich in der Wand befindet oder deren Bereich die Wand bei der Bewegung betritt, muss einen <b>Stärkerettungswurf</b> bestehen oder erleidet 5W10 Wuchtschaden (einmal pro Runde). Am Ende des Zuges verringert sich die Höhe der Wand um 15 m und der Schaden in Folgerunden sinkt um 1W10. Erreicht die Wand eine Höhe von 0 m, endet der Zauber.<br><br>Gefangene Kreaturen können versuchen zu schwimmen, müssen aber einen Wurf auf <b>Stärke (Athletik)</b> gegen deinen Zauber-SG bestehen, um sich überhaupt bewegen zu können.",
    "astralProjectionD": "Du und bis zu acht willige Kreaturen in Reichweite projizieren eure Astralkörper in die Astralebene (der Zauber endet sofort, wenn du dich bereits auf dieser Ebene befindest). Die Körper der Ziele bleiben in einem Zustand des Scheintods zurück; sie sind <b>bewusstlos</b>, benötigen weder Nahrung noch Luft und altern nicht.<br><br>Die Astralgestalt eines Ziels gleicht seinem Körper in fast jeder Hinsicht und übernimmt dessen Spielwerte und Besitztümer. Der Hauptunterschied ist eine silberne Schnur, die zwischen den Schulterblättern der Astralgestalt verläuft und nach 30 cm unsichtbar wird. Wenn die Schnur durchtrennt wird – was nur geschieht, wenn ein Effekt dies explizit besagt – sterben sowohl der Körper als auch die Astralgestalt des Ziels.<br><br>Eine Astralgestalt kann durch die Astralebene reisen. Sobald sie diese Ebene verlässt, reisen der Körper und die Besitztümer entlang der silbernen Schnur nach, sodass das Ziel auf der neuen Ebene wieder in seinen Körper eintritt. Schaden an der Astralgestalt hat keinen Einfluss auf den physischen Körper und umgekehrt. Sinkt eine Gestalt auf 0 TP, endet der Zauber für dieses Ziel. Du kannst den Zauber für alle Ziele als Magie-Aktion beenden.<br><br><b>Material:</b> Für jedes Ziel ein Hyazinth im Wert von 1.000+ GM und ein Silberbarren im Wert von 100+ GM, die verbraucht werden.",
    "foresightD": "Du berührst eine willige Kreatur und verleihst ihr die begrenzte Fähigkeit, in die unmittelbare Zukunft zu sehen. Für die Dauer des Zaubers hat das Ziel <b>Vorteil</b> bei allen <b>D20-Tests</b>, und andere Kreaturen haben <b>Nachteil</b> bei Angriffswürfen gegen es. Der Zauber endet vorzeitig, wenn du ihn erneut wirkst.<br><br><b>Material:</b> Eine Kolibrifeder.",
"gateD": "Du beschwörst ein Portal, das einen unbesetzten Platz in Reichweite mit einem präzisen Ort auf einer anderen Existenzebene verbindet. Das Portal ist eine kreisförmige Öffnung mit einem Durchmesser von 1,5 m bis 6 m. Du kannst das Portal in jede beliebige Richtung ausrichten. Es bleibt für die Dauer des Zaubers bestehen und das Ziel ist durch das Portal sichtbar.<br><br>Das Portal hat auf jeder Ebene eine Vorder- und eine Rückseite. Reisen ist nur durch die Vorderseite möglich. Wer hindurchtritt, wird sofort auf die andere Ebene transportiert. Gottheiten und andere Herrscher können verhindern, dass sich solche Portale in ihrer Gegenwart oder Domäne öffnen.<br><br>Beim Wirken kannst du den Namen einer spezifischen Kreatur aussprechen (Titel oder Spitznamen funktionieren nicht). Befindet sich diese auf einer anderen Ebene, öffnet sich das Portal direkt neben ihr und zieht sie auf deine Seite. Du erhältst keine Macht über die Kreatur; sie kann frei handeln (fliehen, angreifen oder helfen).<br><br><b>Material:</b> Ein Diamant im Wert von mindestens 5.000 GM.",
    "imprisonmentD": "Du erschaffst eine magische Fessel, um eine Kreatur in Reichweite festzuhalten. Das Ziel muss einen <b>Weisheitsrettungswurf</b> ablegen. Bei Erfolg ist es unbetroffen und für 24 Stunden immun gegen diesen Zauber. Bei Misserfolg wird es gefangen. Währenddessen muss es nicht atmen, essen oder trinken und altert nicht. Erkenntniszauber können das Ziel nicht orten.<br><br>Wähle einen der folgenden Effekte:<ul><li><b>Bestattung:</b> Das Ziel wird tief unter der Erde in einer hohlen Kugel aus magischer Kraft eingeschlossen. Nichts kann die Kugel durchdringen.</li><li><b>Verkettung:</b> Fest im Boden verwurzelte Ketten halten das Ziel fest. Es erhält den Zustand <b>'Festgehalten'</b> und kann nicht bewegt werden.</li><li><b>Labyrinth-Gefängnis:</b> Das Ziel wird in eine gegen Teleportation geschützte Halbebene (Labyrinth, Turm etc.) versetzt.</li><li><b>Minimierung:</b> Das Ziel wird 2,5 cm groß und in einem unzerstörbaren Edelstein gefangen. Nur Licht kann den Stein durchdringen.</li><li><b>Schlummer:</b> Das Ziel erhält den Zustand <b>'Bewusstlos'</b> und kann nicht geweckt werden.</li></ul><br>Bestimme beim Wirken einen Auslöser, der den Zauber beendet (z. B. 'wenn die Tarrasque erwacht'). Ein <i>Magie bannen</i> kann diesen Zauber nur beenden, wenn es mit einem Zaubergrad von 9 gewirkt wird.<br><br><b>Material:</b> Eine Statuette des Ziels im Wert von mindestens 5.000 GM.",
    "massHealD": "Eine Flut heilender Energie geht von dir aus. Du stellst insgesamt 700 Trefferpunkte wieder her, die du nach Belieben auf eine beliebige Anzahl von Kreaturen in Reichweite aufteilst. Zudem werden bei den geheilten Zielen die Zustände <b>'Blind'</b>, <b>'Taub'</b> und <b>'Vergiftet'</b> beendet.",
    "meteorSwarmD": "Gleißende Feuerkugeln schlagen an vier verschiedenen Punkten in Reichweite ein. Jede Kreatur in einer Sphäre mit 12 m Radius um diese Punkte muss einen <b>Geschicklichkeitsrettungswurf</b> ablegen. Bei Misserfolg erleidet sie 20W6 Feuerschaden und 20W6 Wuchtschaden (Hälfte bei Erfolg). Eine Kreatur im Bereich mehrerer Sphären wird nur einmal betroffen. Nichtmagische, brennbare Objekte fangen Feuer.",
    "powerWordHealD": "Eine Welle heilender Energie überflutet eine Kreatur in Reichweite. Das Ziel erhält alle seine Trefferpunkte zurück. Zudem enden die Zustände <b>'Bezaubert'</b>, <b>'Verängstigt'</b>, <b>'Gelähmt'</b>, <b>'Vergiftet'</b> oder <b>'Betäubt'</b>. Ein liegendes Ziel kann seine Reaktion nutzen, um aufzustehen.",
    "powerWordKillD": "Du zwingst eine Kreatur in Reichweite zu sterben. Hat das Ziel 100 Trefferpunkte oder weniger, stirbt es sofort. Andernfalls erleidet es 12W12 psychischen Schaden.",
    "prismaticWallD": "Eine schimmernde, mehrfarbige Wand aus Licht entsteht (bis zu 27 m lang, 9 m hoch). Alternativ bildest du eine Kugel mit 9 m Durchmesser. Die Wand strahlt helles Licht (30 m) aus. Du und von dir bestimmte Wesen können sie gefahrlos passieren. Andere Kreaturen, die sich auf 6 m nähern, müssen einen <b>Konstitutionsrettungswurf</b> bestehen oder werden für 1 Minute <b>blind</b>.<br><br>Die Wand besteht aus sieben Schichten. Wer hindurchgreift, wird von jeder Schicht einzeln betroffen (Geschicklichkeitsrettungswurf):<br><br><table class=\"spell-table\"><caption>Regenbogenwand</caption><tr><th>Schicht</th><th>Effekt</th></tr><tr><td>1. Rot</td><td>12W6 Feuerschaden. Blockt nichtmagische Fernangriffe. Zerstört durch 25 Kälteschaden.</td></tr><tr><td>2. Orange</td><td>12W6 Säureschaden. Blockt magische Fernangriffe. Zerstört durch <i>Windstoß</i>.</td></tr><tr><td>3. Gelb</td><td>12W6 Blitzschaden. Zerstört durch 60 Wuchtschaden.</td></tr><tr><td>4. Grün</td><td>12W6 Giftschaden. Zerstört durch <i>Passwall</i>.</td></tr><tr><td>5. Blau</td><td>12W6 Kälteschaden. Zerstört durch 25 Feuerschaden.</td></tr><tr><td>6. Indigo</td><td>Zustand <b>'Festgehalten'</b>, bei 3 Fehlschlägen <b>'Versteinert'</b>. Zerstört durch <i>Tageslicht</i>.</td></tr><tr><td>7. Violett</td><td>Zustand <b>'Blind'</b>, bei Fehlschlag Teleportation auf andere Ebene. Zerstört durch <i>Magie bannen</i>.</td></tr></table><br>Antimagische Felder haben keinen Effekt; nur <i>Magie bannen</i> auf die violette Schicht wirkt.",
    "shapechangeD": "Du verwandelst dich für die Dauer in eine andere Kreatur (HG maximal gleich deiner Stufe). Die Form kann kein Konstrukt oder Untoter sein. Du erhältst die Trefferpunkte der Form als <b>temporäre Trefferpunkte</b>. Deine geistigen Werte, Gesinnung und die Fähigkeit zu zaubern (falls vorhanden) bleiben erhalten. Deine Ausrüstung kann zu Boden fallen oder mit der neuen Form verschmelzen. Du kannst die Form während der Dauer als Magie-Aktion wechseln.<br><br><b>Material:</b> Ein Jade-Haarreif im Wert von mindestens 1.500 GM.",
    "stormOfVengeanceD": "Eine gewaltige Gewitterwolke (90 m Radius) bildet sich über dir. Kreaturen darunter müssen einen <b>Konstitutionsrettungswurf</b> bestehen oder erleiden 2W6 Schallschaden und werden <b>taub</b>. In Folgerunden treten weitere Effekte ein:<ul><li><b>Runde 2:</b> Saurer Regen (4W6 Säureschaden).</li><li><b>Runde 3:</b> Sechs Blitze (je 10W6 Blitzschaden, Geschicklichkeitswurf).</li><li><b>Runde 4:</b> Hagel (2W6 Wuchtschaden).</li><li><b>Runde 5-10:</b> Gefrierender Regen (1W6 Kälteschaden). Bereich ist <b>stark verdunkelt</b> und <b>schwieriges Gelände</b>.</li></ul>",
    "timeStopD": "Du hältst den Fluss der Zeit für alle außer dich selbst an. Du erhältst 1W4 + 1 Züge hintereinander, in denen du dich normal bewegen und handeln kannst. Der Zauber endet sofort, wenn eine deiner Handlungen eine andere Kreatur oder ein getragenes Objekt beeinflusst oder wenn du dich mehr als 300 m von deinem Startpunkt entfernst.",
    "truePolymorphD": "Du verwandelst eine Kreatur oder ein Objekt. Hältst du die <b>Konzentration</b> über die volle Stunde aufrecht, wird der Effekt permanent (bis er gebannt wird).<ul><li><b>Kreatur in Kreatur:</b> Neue Form bis HG des Ziels. Es erhält <b>temporäre Trefferpunkte</b> der neuen Form.</li><li><b>Objekt in Kreatur:</b> Objekt (bis zu seiner Größe) wird zu einer Kreatur (max. HG 9), die dir gegenüber freundlich ist.</li><li><b>Kreatur in Objekt:</b> Kreatur samt Ausrüstung wird zu einem Objekt ihrer Größe. Sie hat keine Erinnerung an diese Zeit.</li></ul><br><b>Material:</b> Quecksilber, Gummiarabikum und ein Rauchwölkchen.",
    "trueResurrectionD": "Du berührst eine Kreatur, die seit höchstens 200 Jahren tot ist und nicht an Altersschwäche starb. Sie kehrt mit allen Trefferpunkten zurück. Alle Wunden heilen, Gifte und Flüche werden entfernt und fehlende Körperteile ersetzt. War die Kreatur ein Untoter, wird sie in ihre ursprüngliche Form zurückversetzt. Der Zauber kann einen neuen Körper erschaffen, wenn du den Namen des Ziels aussprichst.<br><br><b>Material:</b> Diamanten im Wert von mindestens 25.000 GM.",
    "weirdD": "Du erschaffst illusionäre Schrecken im Geist deiner Feinde. Jede gewählte Kreatur in einer Sphäre mit 9 m Radius muss einen <b>Weisheitsrettungswurf</b> ablegen. Bei Misserfolg erleidet sie 10W10 psychischen Schaden und den Zustand <b>'Verängstigt'</b>. Der Rettungswurf wird am Ende jedes ihrer Züge wiederholt, bei einem weiteren Misserfolg erleidet sie 5W10 psychischen Schaden.",
    "wishD": "<i>Wunsch</i> ist der mächtigste Zauber, den ein Sterblicher wirken kann. Die Basisnutzung erlaubt es, jeden Zauber des 8. <b>Zaubergrads</b> oder niedriger zu kopieren, ohne Kosten oder Komponenten.<br><br>Alternativ wähle einen Effekt:<ul><li><b>Objektschöpfung:</b> Ein Gegenstand bis 25.000 GM Wert (kein magischer Gegenstand, max. 90 m groß).</li><li><b>Sofortige Gesundheit:</b> Du und bis zu 20 Wesen erhalten alle TP zurück und alle Effekte von <i>Genesung</i> enden.</li><li><b>Resistenz:</b> 10 Wesen erhalten permanente Resistenz gegen eine Schadensart.</li><li><b>Zauberimmunität:</b> 10 Wesen werden für 8 Stunden immun gegen einen Zauber.</li><li><b>Plötzliches Lernen:</b> Du ersetzt eines deiner Talente durch ein anderes.</li><li><b>Wurf wiederholen:</b> Du machst ein Ereignis der letzten Runde rückgängig, indem du einen Wurf neu erzwingst.</li><li><b>Die Realität umschreiben:</b> Ein freier Wunsch an den SL. Je größer der Wunsch, desto gefährlicher die Folgen.</li></ul>Die Nutzung abseits des Kopierens von Zaubern schwächt dich massiv: Du erleidest beim Zaubern nekrotischen Schaden, deine Stärke sinkt für Tage auf 3 und es besteht eine 33-Prozent-Chance, dass du <i>Wunsch</i> nie wieder wirken kannst."
       	});

Object.assign(translations.en, {
        // Spells: Descriptions
        "acidSplashD": "You create an acidic bubble at a point within range, where it explodes in a 5-foot-radius Sphere. Each creature in that Sphere must succeed on a Dexterity saving throw or take 1d6 Acid damage.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).",
        "bladeWardD": "Whenever a creature makes an attack roll against you before the spell ends, the attacker subtracts 1d4 from the attack roll.",
        "chillTouchD": "Channeling the chill of the grave, make a melee spell attack against a target within reach. On a hit, the target takes 1d10 Necrotic damage, and it can’t regain Hit Points until the end of your next turn.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d10 when you reach levels 5 (2d10), 11 (3d10), and 17 (4d10).",
        "dancingLightsD": "You create up to four torch-size lights within range, making them appear as torches, lanterns, or glowing orbs that hover for the duration. Alternatively, you combine the four lights into one glowing Medium form that is vaguely humanlike. Whichever form you choose, each light sheds Dim Light in a 10-foot radius.<br><br>As a Bonus Action, you can move the lights up to 60 feet to a space within range. A light must be within 20 feet of another light created by this spell, and a light vanishes if it exceeds the spell’s range.<br><br><b>Material:</b> a bit of phosphorus",
        "druidcraftD": "Whispering to the spirits of nature, you create one of the following effects within range.<ul><li><b>Weather Sensor:</b> You create a Tiny, harmless sensory effect that predicts what the weather will be at your location for the next 24 hours. The effect might manifest as a golden orb for clear skies, a cloud for rain, falling snowflakes for snow, and so on. This effect persists for 1 round.</li><li><b>Bloom:</b> You instantly make a flower blossom, a seed pod open, or a leaf bud bloom.</li><li><b>Sensory Effect:</b> You create a harmless sensory effect, such as falling leaves, spectral dancing fairies, a gentle breeze, the sound of an animal, or the faint odor of skunk. The effect must fit in a 5-foot Cube.</li><li><b>Fire Play:</b> You light or snuff out a candle, a torch, or a campfire.</li></ul>",
        "eldritchBlastD": "You hurl a beam of crackling energy. Make a ranged spell attack against one creature or object in range. On a hit, the target takes 1d10 Force damage.<br><br><b>Cantrip Upgrade:</b> The spell creates two beams at level 5, three beams at level 11, and four beams at level 17. You can direct the beams at the same target or at different ones. Make a separate attack roll for each beam.",
        "elementalismD": "You exert control over the elements, creating one of the following effects within range.<ul><li><b>Beckon Air:</b> You create a breeze strong enough to ripple cloth, stir dust, rustle leaves, and close open doors and shutters, all in a 5-foot Cube. Doors and shutters being held open by someone or something aren’t affected.</li><li><b>Beckon Earth:</b> You create a thin shroud of dust or sand that covers surfaces in a 5-foot-square area, or you cause a single word to appear in your handwriting in a patch of dirt or sand.</li><li><b>Beckon Fire:</b> You create a thin cloud of harmless embers and colored, scented smoke in a 5-foot Cube. You choose the color and scent, and the embers can light candles, torches, or lamps in that area. The smoke’s scent lingers for 1 minute.</li><li><b>Beckon Water:</b> You create a spray of cool mist that lightly dampens creatures and objects in a 5-foot Cube. Alternatively, you create 1 cup of clean water either in an open container or on a surface, and the water evaporates in 1 minute.</li><li><b>Sculpt Element:</b> You cause dirt, sand, fire, smoke, mist, or water that can fit in a 1-foot Cube to assume a crude shape (such as that of a creature) for 1 hour.</li></ul>",
        "fireBoltD": "You hurl a mote of fire at a creature or an object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 Fire damage. A flammable object hit by this spell starts burning if it isn’t being worn or carried.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d10 when you reach levels 5 (2d10), 11 (3d10), and 17 (4d10).",
        "friendsD": "You magically emanate a sense of friendship toward one creature you can see within range. The target must succeed on a Wisdom saving throw or have the Charmed condition for the duration. The target succeeds automatically if it isn’t a Humanoid, if you’re fighting it, or if you have cast this spell on it within the past 24 hours.<br><br>The spell ends early if the target takes damage or if you make an attack roll, deal damage, or force anyone to make a saving throw. When the spell ends, the target knows it was Charmed by you.<br><br><b>Material:</b> some makeup",
        "guidanceD": "You touch a willing creature and choose a skill. Until the spell ends, the creature adds 1d4 to any ability check using the chosen skill.",
        "lightD": "You touch one Large or smaller object that isn’t being worn or carried by someone else. Until the spell ends, the object sheds Bright Light in a 20-foot radius and Dim Light for an additional 20 feet. The light can be colored as you like.<br><br>Covering the object with something opaque blocks the light. The spell ends if you cast it again.<br><br><b>Material:</b> a firefly or phosphorescent moss",
        "mageHandD": "A spectral, floating hand appears at a point you choose within range. The hand lasts for the duration. The hand vanishes if it is ever more than 30 feet away from you or if you cast this spell again.<br><br>When you cast the spell, you can use the hand to manipulate an object, open an unlocked door or container, stow or retrieve an item from an open container, or pour the contents out of a vial.<br><br>As a Magic action on your later turns, you can control the hand thus again. As part of that action, you can move the hand up to 30 feet.<br><br>The hand can’t attack, activate magic items, or carry more than 10 pounds.",
        "mendingD": "This spell repairs a single break or tear in an object you touch, such as a broken chain link, two halves of a broken key, a torn cloak, or a leaking wineskin. As long as the break or tear is no larger than 1 foot in any dimension, you mend it, leaving no trace of the former damage.<br><br>This spell can physically repair a magic item, but it can’t restore magic to such an object.<br><br><b>Material:</b> two lodestones",
        "messageD": "You point at a creature within range and whisper a message. The target (and only the target) hears the message and can whisper a short message back that only you can hear.<br><br>You can cast this spell through solid objects if you are familiar with the target and know it is behind the barrier. A 1-foot thick layer of stone, 1 inch of common metal, or a thin sheet of lead block the spell.<br><br><b>Material:</b> a copper wire",
        "mindSliverD": "You try to temporarily sliver the mind of one creature you can see within range. The target must succeed on an Intelligence saving throw or take 1d6 Psychic damage and subtract 1d4 from the next saving throw it makes before the end of your next turn.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).",
        "minorIllusionD": "You create a sound or an image of an object within range that lasts for the duration. The illusion ends if you cast this spell again.<br><br>If a creature takes a Study action to examine the sound or image, the creature can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the illusion becomes faint to the creature.<br><br><ul><li><b>Sound:</b> If you create a sound, its volume can range from a whisper to a scream. It can be your voice, someone else’s voice, a lion’s roar, a beating of drums, or any other sound you choose. The sound continues unabated throughout the duration, or you can make discrete sounds at different times before the spell ends.</li><li><b>Image:</b> If you create an image of an object - such as a chair, muddy footprints, or a small chest—it must be no larger than a 5-foot Cube. The image can’t create sound, light, smell, or any other sensory effect. Physical interaction with the image reveals it to be an illusion, since things can pass through it.</li></ul><br><b>Material:</b> a bit of fleece",
        "poisonSprayD": "You spray toxic mist at a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 1d12 Poison damage.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d12 when you reach levels 5 (2d12), 11 (3d12), and 17 (4d12).",
        "prestidigitationD": "You create a magical effect within range. Choose the effect from the options below. If you cast this spell multiple times, you can have up to three of its non-instantaneous effects active at a time.<ul><li><b>Sensory Effect:</b> You create an instantaneous, harmless sensory effect, such as a shower of sparks, a puff of wind, faint musical notes, or an odd odor.</li><li><b>Fire Play:</b> You instantaneously light or snuff out a candle, a torch, or a small campfire.</li><li><b>Clean or Soil:</b> You instantaneously clean or soil an object no larger than 1 cubic foot.</li><li><b>Minor Sensation:</b> You chill, warm, or flavor up to 1 cubic foot of nonliving material for 1 hour.</li><li><b>Magic Mark:</b> You make a color, a small mark, or a symbol appear on an object or a surface for 1 hour.</li><li><b>Minor Creation:</b> You create a nonmagical trinket or an illusory image that can fit in your hand. It lasts until the end of your next turn. A trinket can deal no damage and has no monetary worth.</li></ul>",
        "produceFlameD": "A flickering flame appears in your hand and remains there for the duration. While there, the flame emits no heat and ignites nothing, and it sheds Bright Light in a 20-foot radius and Dim Light for an additional 20 feet. The spell ends if you cast it again.<br><br>Until the spell ends, you can take a Magic action to hurl fire at a creature or an object within 60 feet of you. Make a ranged spell attack. On a hit, the target takes 1d8 Fire damage.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).",
        "rayOfFrostD": "A frigid beam of blue-white light streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, it takes 1d8 Cold damage, and its Speed is reduced by 10 feet until the start of your next turn.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).",
        "resistanceD": "You touch a willing creature and choose a damage type: Acid, Bludgeoning, Cold, Fire, Lightning, Necrotic, Piercing, Poison, Radiant, Slashing, or Thunder. When the creature takes damage of the chosen type before the spell ends, the creature reduces the total damage taken by 1d4. A creature can benefit from this spell only once per turn.",
        "sacredFlameD": "Flame-like radiance descends on a creature that you can see within range. The target must succeed on a Dexterity saving throw or take 1d8 Radiant damage. The target gains no benefit from Half Cover or Three-Quarters Cover for this save.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).",
        "shillelaghD": "A Club or Quarterstaff you are holding is imbued with nature’s power. For the duration, you can use your spellcasting ability instead of Strength for the attack and damage rolls of melee attacks using that weapon, and the weapon’s damage die becomes a d8. If the attack deals damage, it can be Force damage or the weapon’s normal damage type (your choice).<br><br>The spell ends early if you cast it again or if you let go of the weapon.<br><br><b>Cantrip Upgrade:</b> The damage die changes when you reach levels 5 (d10), 11 (d12), and 17 (2d6).<br><br><b>Material:</b> mistletoe",
        "shockingGraspD": "Lightning springs from you to a creature that you try to touch. Make a melee spell attack against the target. On a hit, the target takes 1d8 Lightning damage, and it can’t make Opportunity Attacks until the start of its next turn.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).",
        "sorcerousBurstD": "You cast sorcerous energy at one creature or object within range. Make a ranged attack roll against the target. On a hit, the target takes 1d8 damage of a type you choose: Acid, Cold, Fire, Lightning, Poison, Psychic, or Thunder.<br><br>If you roll an 8 on a d8 for this spell, you can roll another d8, and add it to the damage. When you cast this spell, the maximum number of these d8s you can add to the spell’s damage equals your spellcasting ability modifier.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).",
        "spareTheDyingD": "Choose a creature within range that has 0 Hit Points and isn’t dead. The creature becomes Stable.<br><br><b>Cantrip Upgrade:</b> The range doubles when you reach levels 5 (30 feet), 11 (60 feet), and 17 (120 feet).",
        "starryWispD": "You launch a mote of light at one creature or object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d8 Radiant damage, and until the end of your next turn, it emits Dim Light in a 10-foot radius and can’t benefit from the Invisible condition.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).",
        "thaumaturgyD": "You manifest a minor wonder within range. You create one of the effects below within range. If you cast this spell multiple times, you can have up to three of its 1-minute effects active at a time.<br><ul><li><b>Altered Eyes:</b> You alter the appearance of your eyes for 1 minute.</li><li><b>Booming Voice:</b> Your voice booms up to three times as loud as normal for 1 minute. For the duration, you have Advantage on Charisma (Intimidation) checks.</li><li><b>Fire Play:</b> You cause flames to flicker, brighten, dim, or change color for 1 minute.</li><li><b>Invisible Hand:</b> You instantaneously cause an unlocked door or window to fly open or slam shut.</li><li><b>Phantom Sound:</b> You create an instantaneous sound that originates from a point of your choice within range, such as a rumble of thunder, the cry of a raven, or ominous whispers.</li><li><b>Tremors:</b> You cause harmless tremors in the ground for 1 minute.</li></ul>",
        "thornWhipD": "You create a vine-like whip covered in thorns that lashes out at your command toward a creature in range. Make a melee spell attack against the target. On a hit, the target takes 1d6 Piercing damage, and if it is Large or smaller, you can pull it up to 10 feet closer to you.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).<br><br><b>Material:</b> the stem of a plant with thorns",
        "thunderclapD": "Each creature in a 5-foot Emanation originating from you must succeed on a Constitution saving throw or take 1d6 Thunder damage. The spell’s thunderous sound can be heard up to 100 feet away.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).",
        "tollTheDeadD": "You point at one creature you can see within range, and the single chime of a dolorous bell is audible within 10 feet of the target. The target must succeed on a Wisdom saving throw or take 1d8 Necrotic damage. If the target is missing any of its Hit Points, it instead takes 1d12 Necrotic damage.<br><br><b>Cantrip Upgrade:</b> The damage increases by one die when you reach levels 5 (2d8 or 2d12), 11 (3d8 or 3d12), and 17 (4d8 or 4d12).",
        "trueStrikeD": "Guided by a flash of magical insight, you make one attack with the weapon used in the spell’s casting. The attack uses your spellcasting ability for the attack and damage rolls instead of using Strength or Dexterity. If the attack deals damage, it can be Radiant damage or the weapon’s normal damage type (your choice).<br><br><b>Cantrip Upgrade:</b> Whether you deal Radiant damage or the weapon’s normal damage type, the attack deals extra Radiant damage when you reach levels 5 (1d6), 11 (2d6), and 17 (3d6).<br><br><b>Material:</b> a weapon with which you have proficiency and that is worth 1+ CP",
        "viciousMockeryD": "You unleash a string of insults laced with subtle enchantments at one creature you can see or hear within range. The target must succeed on a Wisdom saving throw or take 1d6 Psychic damage and have Disadvantage on the next attack roll it makes before the end of its next turn.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).",
        "wordOfRadianceD": "Burning radiance erupts from you in a 5-foot Emanation. Each creature of your choice that you can see in it must succeed on a Constitution saving throw or take 1d6 Radiant damage.<br><br><b>Cantrip Upgrade:</b> The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).<br><br><b>Material:</b> a sunburst token",
        "alarmD": "You set an alarm against intrusion. Choose a door, a window, or an area within range that is no larger than a 20-foot Cube. Until the spell ends, an alarm alerts you whenever a creature touches or enters the warded area. When you cast the spell, you can designate creatures that won’t set off the alarm. You also choose whether the alarm is audible or mental:<ul><li><b>Audible Alarm:</b> The alarm produces the sound of a handbell for 10 seconds within 60 feet of the warded area.</li><li><b>Mental Alarm:</b> You are alerted by a mental ping if you are within 1 mile of the warded area. This ping awakens you if you’re asleep.</li></ul><br><b>Material:</b> a bell and silver wire",
        "animalFriendshipD": "Target a Beast that you can see within range. The target must succeed on a Wisdom saving throw or have the Charmed condition for the duration. If you or one of your allies deals damage to the target, the spells ends.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional Beast for each spell slot level above 1.<br><br><b>Material:</b> a morsel of food",
        "armorOfAgathysD": "Protective magical frost surrounds you. You gain 5 Temporary Hit Points. If a creature hits you with a melee attack roll before the spell ends, the creature takes 5 Cold damage. The spell ends early if you have no Temporary Hit Points.<br><br><b>Using a Higher-Level Spell Slot:</b> The Temporary Hit Points and the Cold damage both increase by 5 for each spell slot level above 1.<br><br><b>Material:</b> a shard of blue glass",
        "armsOfHadarD": "Invoking Hadar, you cause tendrils to erupt from yourself. Each creature in a 10-foot Emanation originating from you makes a Strength saving throw. On a failed save, a target takes 2d6 Necrotic damage and can’t take Reactions until the start of its next turn. On a successful save, a target takes half as much damage only.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d6 for each spell slot level above 1.",
        "baneD": "Up to three creatures of your choice that you can see within range must each make a Charisma saving throw. Whenever a target that fails this save makes an attack roll or a saving throw before the spell ends, the target must subtract 1d4 from the attack roll or save.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional creature for each spell slot level above 1.<br><br><b>Material:</b> a drop of blood",
        "blessD": "You bless up to three creatures within range. Whenever a target makes an attack roll or a saving throw before the spell ends, the target adds 1d4 to the attack roll or save.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional creature for each spell slot level above 1.<br><br><b>Material:</b> a Holy Symbol worth 5+ GP",
        "burningHandsD": "A thin sheet of flames shoots forth from you. Each creature in a 15-foot Cone makes a Dexterity saving throw, taking 3d6 Fire damage on a failed save or half as much damage on a successful one.<br><br>Flammable objects in the Cone that aren’t being worn or carried start burning.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d6 for each spell slot level above 1.",
        "charmPersonD": "One Humanoid you can see within range makes a Wisdom saving throw. It does so with Advantage if you or your allies are fighting it. On a failed save, the target has the Charmed condition until the spell ends or until you or your allies damage it. The Charmed creature is Friendly to you. When the spell ends, the target knows it was Charmed by you.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional creature for each spell slot level above 1.",
        "chromaticOrbD": "You hurl an orb of energy at a target within range. Choose Acid, Cold, Fire, Lightning, Poison, or Thunder for the type of orb you create, and then make a ranged spell attack against the target. On a hit, the target takes 3d8 damage of the chosen type.<br><br>If you roll the same number on two or more of the d8s, the orb leaps to a different target of your choice within 30 feet of the target. Make an attack roll against the new target, and make a new damage roll. The orb can’t leap again unless you cast the spell with a level 2+ spell slot.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 1. The orb can leap a maximum number of times equal to the level of the slot expended, and a creature can be targeted only once by each casting of this spell.<br><br><b>Material:</b> a diamond worth 50+ GP",
        "colorSprayD": "You launch a dazzling array of flashing, colorful light. Each creature in a 15-foot Cone originating from you must succeed on a Constitution saving throw or have the Blinded condition until the end of your next turn.<br><br><b>Material:</b> a pinch of colorful sand",
        "commandD": "You speak a one-word command to a creature you can see within range. The target must succeed on a Wisdom saving throw or follow the command on its next turn. Choose the command from these options:<ul><li><b>Approach:</b> The target moves toward you by the shortest and most direct route, ending its turn if it moves within 5 feet of you.</li><li><b>Drop:</b> The target drops whatever it is holding and then ends its turn.</li><li><b>Flee:</b> The target spends its turn moving away from you by the fastest available means.</li><li><b>Grovel:</b> The target has the Prone condition and then ends its turn.</li><li><b>Halt:</b> On its turn, the target doesn’t move and takes no action or Bonus Action.</li></ul><br><b>Using a Higher-Level Spell Slot:</b> You can affect one additional creature for each spell slot level above 1.",
        "compelledDuelD": "You try to compel a creature into a duel. One creature that you can see within range makes a Wisdom saving throw. On a failed save, the target has Disadvantage on attack rolls against creatures other than you, and it can’t willingly move to a space that is more than 30 feet away from you.<br><br>The spell ends if you make an attack roll against a creature other than the target, if you cast a spell on an enemy other than the target, if an ally of yours damages the target, or if you end your turn more than 30 feet away from the target.",
        "comprehendLanguagesD": "For the duration, you understand the literal meaning of any language that you hear or see signed. You also understand any written language that you see, but you must be touching the surface on which the words are written. It takes about 1 minute to read one page of text. This spell doesn’t decode symbols or secret messages.<br><br><b>Material:</b> a pinch of soot and salt",
        "createOrDestroyWaterD": "You do one of the following:<ul><li><b>Create Water:</b> You create up to 10 gallons of clean water within range in an open container. Alternatively, the water falls as rain in a 30-foot Cube within range, extinguishing exposed flames there.</li><li><b>Destroy Water:</b> You destroy up to 10 gallons of water in an open container within range. Alternatively, you destroy fog in a 30-foot Cube within range.</li></ul><br><b>Using a Higher-Level Spell Slot:</b> You create or destroy 10 additional gallons of water, or the size of the Cube increases by 5 feet, for each spell slot level above 1.<br><br><b>Material:</b> a mix of water and sand",
        "cureWoundsD": "A creature you touch regains a number of Hit Points equal to 2d8 plus your spellcasting ability modifier.<br><br><b>Using a Higher-Level Spell Slot:</b> The healing increases by 2d8 for each spell slot level above 1.",
        "detectEvilAndGoodD": "For the duration, you sense the location of any Aberration, Celestial, Elemental, Fey, Fiend, or Undead within 30 feet of yourself. You also sense whether the Hallow spell is active there and, if so, where.<br><br>The spell is blocked by 1 foot of stone, dirt, or wood; 1 inch of metal; or a thin sheet of lead.",
        "detectMagicD": "For the duration, you sense the presence of magical effects within 30 feet of yourself. If you sense such effects, you can take the Magic action to see a faint aura around any visible creature or object in the area that bears the magic, and if an effect was created by a spell, you learn the spell’s school of magic.<br><br>The spell is blocked by 1 foot of stone, dirt, or wood; 1 inch of metal; or a thin sheet of lead.",
        "detectPoisonAndDiseaseD": "For the duration, you sense the location of poisons, poisonous or venomous creatures, and magical contagions within 30 feet of yourself. You sense the kind of poison, creature, or contagion in each case.<br><br>The spell is blocked by 1 foot of stone, dirt, or wood; 1 inch of metal; or a thin sheet of lead.<br><br><b>Material:</b> a yew leaf",
        "disguiseSelfD": "You make yourself—including your clothing, armor, weapons, and other belongings on your person—look different until the spell ends. You can seem 1 foot shorter or taller and can appear heavier or lighter. You must adopt a form that has the same basic arrangement of limbs as you have. Otherwise, the extent of the illusion is up to you.<br><br>The changes wrought by this spell fail to hold up to physical inspection. For example, if you use this spell to add a hat to your outfit, objects pass through the hat, and anyone who touches it would feel nothing.<br><br>To discern that you are disguised, a creature must take the Study action to inspect your appearance and succeed on an Intelligence (Investigation) check against your spell save DC.",
        "dissonantWhispersD": "One creature of your choice that you can see within range hears a discordant melody in its mind. The target makes a Wisdom saving throw. On a failed save, it takes 3d6 Psychic damage and must immediately use its Reaction, if available, to move as far away from you as it can, using the safest route. On a successful save, the target takes half as much damage only.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d6 for each spell slot level above 1.",
        "divineFavorD": "Until the spell ends, your attacks with weapons deal an extra 1d4 Radiant damage on a hit.",
        "divineSmiteD": "The target takes an extra 2d8 Radiant damage from the attack. The damage increases by 1d8 if the target is a Fiend or an Undead.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 1.<br><br><b>Bonus Action:</b> Which you take immediately after hitting a target with a Melee weapon or an Unarmed Strike.",
        "ensnaringStrikeD": "As you hit the target, grasping vines appear on it, and it makes a Strength saving throw. A Large or larger creature has Advantage on this save. On a failed save, the target has the Restrained condition until the spell ends. On a successful save, the vines shrivel away, and the spell ends.<br><br>While Restrained, the target takes 1d6 Piercing damage at the start of each of its turns. The target or a creature within reach of it can take an action to make a Strength (Athletics) check against your spell save DC. On a success, the spell ends.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d6 for each spell slot level above 1.<br><br><b>Bonus Action:</b> which you take immediately after hitting a creature with a weapon.",
	"faerieFireD": "Objects in a 20-foot Cube within range are outlined in blue, green, or violet light (your choice). Each creature in the Cube is also outlined if it fails a <b>Dexterity saving throw</b>. For the duration, objects and affected creatures shed <b>Dim Light</b> in a 10-foot radius and can’t benefit from the <b>Invisible</b> condition.<br><br>Attack rolls against an affected creature or object have <b>Advantage</b> if the attacker can see it.",
        "falseLifeD": "You gain 2d4 + 4 Temporary Hit Points.<br><br><b>Using a Higher-Level Spell Slot:</b> You gain 5 additional Temporary Hit Points for each spell slot level above 1.<br><br><b>Material:</b> a drop of alcohol",
        "featherFallD": "Choose up to five falling creatures within range. A falling creature’s rate of descent slows to 60 feet per round until the spell ends. If a creature lands before the spell ends, the creature takes no damage from the fall, and the spell ends for that creature.<br><br><b>Reaction:</b> which you take when you or a creature you can see within 60 feet of you falls.<br><br><b>Material:</b> a small feather or piece of down",
        "findFamiliarD": "You gain the service of a familiar, a spirit that takes an animal form you choose: Bat, Cat, Frog, Hawk, Lizard, Octopus, Owl, Rat, Raven, Spider, Weasel, or another Beast that has a Challenge Rating of 0. Appearing in an unoccupied space within range, the familiar has the statistics of the chosen form, though it is a Celestial, Fey, or Fiend (your choice) instead of a Beast. Your familiar acts independently of you, but it obeys your commands.<br><br><b>Telepathic Connection:</b> While your familiar is within 100 feet of you, you can communicate with it telepathically. Additionally, as a Bonus Action, you can see through the familiar’s eyes and hear what it hears until the start of your next turn, gaining the benefits of any special senses it has.<br><br><b>Deliver Spells:</b> Finally, when you cast a spell with a range of touch, your familiar can deliver the touch. Your familiar must be within 100 feet of you, and it must take a Reaction to deliver the touch when you cast the spell.<br><br><b>Combat:</b> The familiar is an ally to you and your allies. It rolls its own Initiative and acts on its own turn. A familiar can’t attack, but it can take other actions as normal.<br><br><b>Disappearance of the Familiar:</b> When the familiar drops to 0 Hit Points, it disappears. It reappears after you cast this spell again. As a Magic action, you can temporarily dismiss the familiar to a pocket dimension. Alternatively, you can dismiss it forever. As a Magic action while it is temporarily dismissed, you can cause it to reappear in an unoccupied space within 30 feet of you. Whenever the familiar drops to 0 Hit Points or disappears into the pocket dimension, it leaves behind in its space anything it was wearing or carrying.<br><br><b>One Familiar Only:</b> You can’t have more than one familiar at a time. If you cast this spell while you have a familiar, you instead cause it to adopt a new eligible form.<br><br><b>Material:</b> burning incense worth 10+ GP, which the spell consumes",
        "frogCloudD": "You create a 20-foot-radius Sphere of fog centered on a point within range. The Sphere is Heavily Obscured. It lasts for the duration or until a strong wind (such as one created by Gust of Wind) disperses it.<br><br><b>Using a Higher-Level Spell Slot:</b> The fog’s radius increases by 20 feet for each spell slot level above 1.",
        "goodberryD": "Ten berries appear in your hand and are infused with magic for the duration. A creature can take a Bonus Action to eat one berry. Eating a berry restores 1 Hit Point, and the berry provides enough nourishment to sustain a creature for one day.<br><br>Uneaten berries disappear when the spell ends.<br><br><b>Material:</b> a sprig of mistletoe",
        "greaseD": "Nonflammable grease covers the ground in a 10-foot square centered on a point within range and turns it into Difficult Terrain for the duration.<br><br>When the grease appears, each creature standing in its area must succeed on a Dexterity saving throw or have the Prone condition. A creature that enters the area or ends its turn there must also succeed on that save or fall Prone.<br><br><b>Material:</b> a bit of pork rind or butter",
        "guidingBoltD": "You hurl a bolt of light toward a creature within range. Make a ranged spell attack against the target. On a hit, it takes 4d6 Radiant damage, and the next attack roll made against it before the end of your next turn has Advantage.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d6 for each spell slot level above 1.",
        "hailOfThornsD": "As you hit the creature, this spell creates a rain of thorns that sprouts from your Ranged weapon or ammunition. The target of the attack and each creature within 5 feet of it make a Dexterity saving throw, taking 1d10 Piercing damage on a failed save or half as much damage on a successful one.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d10 for each spell slot level above 1.<br><br><b>Bonus Action:</b> which you take immediately after hitting a creature with a Ranged weapon.",
        "healingWordD": "A creature of your choice that you can see within range regains Hit Points equal to 2d4 plus your spellcasting ability modifier.<br><br><b>Using a Higher-Level Spell Slot:</b> The healing increases by 2d4 for each spell slot level above 1.",
        "hellishRebukeD": "The creature that damaged you is momentarily surrounded by green flames. It makes a Dexterity saving throw, taking 2d10 Fire damage on a failed save or half as much damage on a successful one.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d10 for each spell slot level above 1.<br><br><b>Reaction:</b> which you take in response to taking damage from a creature that you can see within 60 feet of yourself.",
        "heroismD": "A willing creature you touch is imbued with bravery. Until the spell ends, the creature is immune to the Frightened condition and gains Temporary Hit Points equal to your spellcasting ability modifier at the start of each of its turns.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional creature for each spell slot level above 1.",
        "hexD": "You place a curse on a creature that you can see within range. Until the spell ends, you deal an extra 1d6 Necrotic damage to the target whenever you hit it with an attack roll. Also, choose one ability when you cast the spell. The target has Disadvantage on ability checks made with the chosen ability.<br><br>If the target drops to 0 Hit Points before this spell ends, you can take a Bonus Action on a later turn to curse a new creature.<br><br><b>Using a Higher-Level Spell Slot:</b> Your Concentration can last longer with a spell slot of level 2 (up to 4 hours), 3–4 (up to 8 hours), or 5+ (24 hours).<br><br><b>Material:</b> the petrified eye of a newt",
        "huntersMarkD": "You magically mark one creature you can see within range as your quarry. Until the spell ends, you deal an extra 1d6 Force damage to the target whenever you hit it with an attack roll. You also have Advantage on any Wisdom (Perception or Survival) check you make to find it.<br><br>If the target drops to 0 Hit Points before this spell ends, you can take a Bonus Action to move the mark to a new creature you can see within range.<br><br><b>Using a Higher-Level Spell Slot:</b> Your Concentration can last longer with a spell slot of level 3–4 (up to 8 hours) or 5+ (up to 24 hours).",
        "iceKnifeD": "You create a shard of ice and fling it at one creature within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 Piercing damage. Hit or miss, the shard then explodes. The target and each creature within 5 feet of it must succeed on a Dexterity saving throw or take 2d6 Cold damage.<br><br><b>Using a Higher-Level Spell Slot:</b> The Cold damage increases by 1d6 for each spell slot level above 1.<br><br><b>Material:</b> (a drop of water or a piece of ice)",
        "identifyD": "You touch an object throughout the spell’s casting. If the object is a magic item or some other magical object, you learn its properties and how to use them, whether it requires Attunement, and how many charges it has, if any. You learn whether any ongoing spells are affecting the item and what they are. If the item was created by a spell, you learn that spell’s name.<br><br>If you instead touch a creature throughout the casting, you learn which ongoing spells, if any, are currently affecting it.<br><br><b>Material:</b> a pearl worth 100+ GP",
        "illusoryScriptD": "You write on parchment, paper, or another suitable material and imbue it with an illusion that lasts for the duration. To you and any creatures you designate when you cast the spell, the writing appears normal, seems to be written in your hand, and conveys whatever meaning you intended when you wrote the text. To all others, the writing appears as if it were written in an unknown or magical script that is unintelligible. Alternatively, the illusion can alter the meaning, handwriting, and language of the text, though the language must be one you know.<br><br>If the spell is dispelled, the original script and the illusion both disappear.<br><br>A creature that has Truesight can read the hidden message.<br><br><b>Material:</b> ink worth 10+ GP, which the spell consumes",
        "inflictWoundsD": "A creature you touch makes a Constitution saving throw, taking 2d10 Necrotic damage on a failed save or half as much damage on a successful one.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d10 for each spell slot level above 1.",
        "jumpD": "You touch a willing creature. Once on each of its turns until the spell ends, that creature can jump up to 30 feet by spending 10 feet of movement.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional creature for each spell slot level above 1.<br><br><b>Material:</b> a grasshopper’s hind leg",
        "longstriderD": "You touch a creature. The target’s Speed increases by 10 feet until the spell ends.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional creature for each spell slot level above 1.<br><br><b>Material:</b> a pinch of dirt",
        "mageArmorD": "You touch a willing creature who isn’t wearing armor. Until the spell ends, the target’s base AC becomes 13 plus its Dexterity modifier. The spell ends early if the target dons armor.<br><br><b>Material:</b> a piece of cured leather",
        "magicMissileD": "You create three glowing darts of magical force. Each dart strikes a creature of your choice that you can see within range. A dart deals 1d4 + 1 Force damage to its target. The darts all strike simultaneously, and you can direct them to hit one creature or several.<br><br><b>Using a Higher-Level Spell Slot:</b> The spell creates one more dart for each spell slot level above 1.",
        "protectionFromEvilAndGoodD": "Until the spell ends, one willing creature you touch is protected against creatures that are Aberrations, Celestials, Elementals, Fey, Fiends, or Undead. The protection grants several benefits. Creatures of those types have Disadvantage on attack rolls against the target. The target also can’t be possessed by or gain the Charmed or Frightened conditions from them. If the target is already possessed, Charmed, or Frightened by such a creature, the target has Advantage on any new saving throw against the relevant effect.<br><br><b>Material:</b> a flask of Holy Water worth 25+ GP, which the spell consumes",
        "purifyFoodAndDrinkD": "You remove poison and rot from nonmagical food and drink in a 5-foot-radius Sphere centered on a point within range.",
        "rayOfSicknessD": "You shoot a greenish ray at a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 2d8 Poison damage and has the Poisoned condition until the end of your next turn.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 1.",
        "sanctuaryD": "You ward a creature within range. Until the spell ends, any creature who targets the warded creature with an attack roll or a damaging spell must succeed on a Wisdom saving throw or either choose a new target or lose the attack or spell. This spell doesn’t protect the warded creature from areas of effect.<br><br>The spell ends if the warded creature makes an attack roll, casts a spell, or deals damage.<br><br><b>Material:</b> a shard of glass from a mirror",
        "searingSmiteD": "As you hit the target, it takes an extra 1d6 Fire damage from the attack. At the start of each of its turns until the spell ends, the target takes 1d6 Fire damage and then makes a Constitution saving throw. On a failed save, the spell continues. On a successful save, the spell ends.<br><br><b>Using a Higher-Level Spell Slot:</b> All the damage increases by 1d6 for each spell slot level above 1.<br><br><b>Bonus Action:</b> which you take immediately after hitting a target with a Melee weapon or an Unarmed Strike.",
        "shieldD": "An imperceptible barrier of magical force protects you. Until the start of your next turn, you have a +5 bonus to AC, including against the triggering attack, and you take no damage from Magic Missile.<br><br><b>Reaction:</b> which you take when you are hit by an attack roll or targeted by the Magic Missile spell.",
        "shieldOfFaithD": "A shimmering field surrounds a creature of your choice within range, granting it a +2 bonus to AC for the duration.<br><br><b>Material:</b> a prayer scroll",
        "silentImageD": "You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 15-foot Cube. The image appears at a spot within range and lasts for the duration. The image is purely visual; it isn’t accompanied by sound, smell, or other sensory effects.<br><br>As a Magic action, you can cause the image to move to any spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking.<br><br>Physical interaction with the image reveals it to be an illusion, since things can pass through it. A creature that takes a Study action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image.<br><br><b>Material:</b> a bit of fleece",
        "sleepD": "Each creature of your choice in a 5-foot-radius Sphere centered on a point within range must succeed on a Wisdom saving throw or have the Incapacitated condition until the end of its next turn, at which point it must repeat the save. If the target fails the second save, the target has the Unconscious condition for the duration. The spell ends on a target if it takes damage or someone within 5 feet of it takes an action to shake it out of the spell’s effect.<br><br>Creatures that don’t sleep, such as elves, or that have Immunity to the Exhaustion condition automatically succeed on saves against this spell.<br><br><b>Material:</b> a pinch of sand or rose petals",
        "speakWithAnimalsD": "For the duration, you can comprehend and verbally communicate with Beasts, and you can use any of the Influence action’s skill options with them.<br><br>Most Beasts have little to say about topics that don’t pertain to survival or companionship, but at minimum, a Beast can give you information about nearby locations and monsters, including whatever it has perceived within the past day.",
        "thounderousSmiteD": "Your strike rings with thunder that is audible within 300 feet of you, and the target takes an extra 2d6 Thunder damage from the attack. Additionally, if the target is a creature, it must succeed on a Strength saving throw or be pushed 10 feet away from you and have the Prone condition.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d6 for each spell slot level above 1.<br><br><b>Bonus Action:</b> which you take immediately after hitting a target with a Melee weapon or an Unarmed Strike.",
        "thunderwaveD": "You unleash a wave of thunderous energy. Each creature in a 15-foot Cube originating from you makes a Constitution saving throw. On a failed save, a creature takes 2d8 Thunder damage and is pushed 10 feet away from you. On a successful save, a creature takes half as much damage only.<br><br>In addition, unsecured objects that are entirely within the Cube are pushed 10 feet away from you, and a thunderous boom is audible within 300 feet.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 1.",
        "unseenServantD": "This spell creates an Invisible, mindless, shapeless, Medium force that performs simple tasks at your command until the spell ends. The servant springs into existence in an unoccupied space on the ground within range. It has AC 10, 1 Hit Point, and a Strength of 2, and it can’t attack. If it drops to 0 Hit Points, the spell ends.<br><br>Once on each of your turns as a Bonus Action, you can mentally command the servant to move up to 15 feet and interact with an object. The servant can perform simple tasks that a human could do, such as fetching things, cleaning, mending, folding clothes, lighting fires, serving food, and pouring drinks. Once you give the command, the servant performs the task to the best of its ability until it completes the task, then waits for your next command.<br><br>If you command the servant to perform a task that would move it more than 60 feet away from you, the spell ends.<br><br><b>Material:</b> a bit of string and of wood",
        "witchBoltD": "A beam of crackling energy lances toward a creature within range, forming a sustained arc of lightning between you and the target. Make a ranged spell attack against it. On a hit, the target takes 2d12 Lightning damage.<br><br>On each of your subsequent turns, you can take a Bonus Action to deal 1d12 Lightning damage to the target automatically, even if the first attack missed.<br><br>The spell ends if the target is ever outside the spell’s range or if it has Total Cover from you.<br><t><b>Using a Higher-Level Spell Slot:</b> The initial damage increases by 1d12 for each spell slot level above 1.<br><br><b>Material:</b> a twig struck by lightning",
        "wrathfulSmiteD": "The target takes an extra 1d6 Necrotic damage from the attack, and it must succeed on a Wisdom saving throw or have the Frightened condition until the spell ends. At the end of each of its turns, the Frightened target repeats the save, ending the spell on itself on a success.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d6 for each spell slot level above 1.<br><br><b>Bonus Action:</b> which you take immediately after hitting a creature with a Melee weapon or an Unarmed Strike.",
        "aidD": "Choose up to three creatures within range. Each target’s Hit Point maximum and current Hit Points increase by 5 for the duration.<br><br><b>Using a Higher-Level Spell Slot:</b> Each target’s Hit Points increase by 5 for each spell slot level above 2.<br><br><b>Material:</b> a strip of white cloth",
        "alterSelfD": "You alter your physical form. Choose one of the following options. Its effects last for the duration, during which you can take a Magic action to replace the option you chose with a different one.<br><ul><li><b>Aquatic Adaptation:</b> You sprout gills and grow webs between your fingers. You can breathe underwater and gain a Swim Speed equal to your Speed.</li><li><b>Change Appearance:</b> You alter your appearance. You decide what you look like, including your height, weight, facial features, sound of your voice, hair length, coloration, and other distinguishing characteristics. You can make yourself appear as a member of another species, though none of your statistics change. You can’t appear as a creature of a different size, and your basic shape stays the same; if you’re bipedal, you can’t use this spell to become quadrupedal, for instance. For the duration, you can take a Magic action to change your appearance in this way again.</li><li><b>Natural Weapons:</b> You grow claws (Slashing), fangs (Piercing), horns (Piercing), or hooves (Bludgeoning). When you use your Unarmed Strike to deal damage with that new growth, it deals 1d6 damage of the type in parentheses instead of dealing the normal damage for your Unarmed Strike, and you use your spellcasting ability modifier for the attack and damage rolls rather than using Strength.</li></ul>",
        "animalMessnengerD": "A Tiny Beast of your choice that you can see within range must succeed on a Charisma saving throw, or it attempts to deliver a message for you (if the target’s Challenge Rating isn’t 0, it automatically succeeds). You specify a location you have visited and a recipient who matches a general description, such as “a person dressed in the uniform of the town guard” or “a red-haired dwarf wearing a pointed hat.” You also communicate a message of up to twenty-five words. The Beast travels for the duration toward the specified location, covering about 25 miles per 24 hours or 50 miles if the Beast can fly.<br><br>When the Beast arrives, it delivers your message to the creature that you described, mimicking your communication. If the Beast doesn’t reach its destination before the spell ends, the message is lost, and the Beast returns to where you cast the spell.<br><br><b>Using a Higher-Level Spell Slot:</b> The spell’s duration increases by 48 hours for each spell slot level above 2.<br><br><b>Material:</b> a morsel of food",
        "arcaneLockD": "You touch a closed door, window, gate, container, or hatch and magically lock it for the duration. This lock can’t be unlocked by any nonmagical means. You and any creatures you designate when you cast the spell can open and close the object despite the lock. You can also set a password that, when spoken within 5 feet of the object, unlocks it for 1 minute.<br><br><b>Material:</b> gold dust worth 25+ GP, which the spell consumes",
        "arcaneVigorD": "You tap into your life force to heal yourself. Roll one or two of your unexpended Hit Point Dice, and regain a number of Hit Points equal to the roll’s total plus your spellcasting ability modifier. Those dice are then expended.<br><br><b>Using a Higher-Level Spell Slot:</b> The number of unexpended Hit Dice you can roll increases by one for each spell slot level above 2.",
"auguryD": "You receive an omen from an otherworldly entity about the results of a course of action that you plan to take within the next 30 minutes. The DM chooses the omen from the Omens table.<br><br><table class=\"spell-table\"><caption>Omens</caption><tr><th>Omen</th><th>For Results That Will Be...</th></tr><tr><td>Weal</td><td>Good</td></tr><tr><td>Woe</td><td>Bad</td></tr><tr><td>Weal and woe</td><td>Good and bad</td></tr><tr><td>Indifference</td><td>Neither good nor bad</td></tr></table><br>The spell doesn’t account for circumstances, such as other spells, that might change the results.<br><br>If you cast the spell more than once before finishing a Long Rest, there is a cumulative 25 percent chance for each casting after the first that you get no answer.<br><br><b>Material:</b> specially marked sticks, bones, cards, or other divinatory tokens worth 25+ GP",
        "barkskinD": "You touch a willing creature. Until the spell ends, the target’s skin assumes a bark-like appearance, and the target has an Armor Class of 17 if its AC is lower than that.<br><br><b>Material:</b> a handful of oak bark",
        "beastSenseD": "You touch a willing Beast. For the duration, you can perceive through the Beast’s senses as well as your own. When perceiving through the Beast’s senses, you benefit from any special senses it has.",
        "blindness_DeafnessD": "One creature that you can see within range must succeed on a Constitution saving throw, or it has the Blinded or Deafened condition (your choice) for the duration. At the end of each of its turns, the target repeats the save, ending the spell on itself on a success.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional creature for each spell slot level above 2.",
        "blurD": "Your body becomes blurred. For the duration, any creature has Disadvantage on attack rolls against you. An attacker is immune to this effect if it perceives you with Blindsight or Truesight.",
        "calmEmotionsD": "Each Humanoid in a 20-foot-radius Sphere centered on a point you choose within range must succeed on a Charisma saving throw or be affected by one of the following effects (choose for each creature):<br><ul><li>The creature has Immunity to the Charmed and Frightened conditions until the spell ends. If the creature was already Charmed or Frightened, those conditions are suppressed for the duration.</li><li>The creature becomes Indifferent about creatures of your choice that it’s Hostile toward. This indifference ends if the target takes damage or witnesses its allies taking damage. When the spell ends, the creature’s attitude returns to normal.</li></ul>",
        "cloudOfDaggersD": "You conjure spinning daggers in a 5-foot Cube centered on a point within range. Each creature in that area takes 4d4 Slashing damage. A creature also takes this damage if it enters the Cube or ends its turn there or if the Cube moves into its space. A creature takes this damage only once per turn.<br><br>On your later turns, you can take a Magic action to teleport the Cube up to 30 feet.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 2d4 for each spell slot level above 2.<br><br><b>Material:</b> a sliver of glass",
        "continualFlameD": "A flame springs from an object that you touch. The effect casts Bright Light in a 20-foot radius and Dim Light for an additional 20 feet. It looks like a regular flame, but it creates no heat and consumes no fuel. The flame can be covered or hidden but not smothered or quenched.<br><br><b>Material:</b> ruby dust worth 50+ GP, which the spell consumes",
	"darknessD": "For the duration, magical Darkness spreads from a point within range and fills a 15-foot-radius Sphere. Darkvision can’t see through it, and nonmagical light can’t illuminate it.<br><br>Alternatively, you cast the spell on an object that isn’t being worn or carried, causing the Darkness to fill a 15-foot Emanation originating from that object. Covering that object with something opaque, such as a bowl or helm, blocks the Darkness.<br><br>If any of this spell’s area overlaps with an area of Bright Light or Dim Light created by a spell of level 2 or lower, that other spell is dispelled.<br><br><b>Material:</b> bat fur and a piece of coal",
        "darkvisionD": "For the duration, a willing creature you touch has Darkvision with a range of 150 feet.<br><br><b>Material:</b> a dried carrot",
        "detectThoughtsD": "You activate one of the effects below. Until the spell ends, you can activate either effect as a Magic action on your later turns.<br><ul><li><b>Sense Thoughts:</b> You sense the presence of thoughts within 30 feet of yourself that belong to creatures that know languages or are telepathic. You don’t read the thoughts, but you know that a thinking creature is present. The spell is blocked by 1 foot of stone, dirt, or wood; 1 inch of metal; or a thin sheet of lead.</li><li><b>Read Thoughts:</b> Target one creature you can see within 30 feet of yourself or one creature within 30 feet of yourself that you detected with the Sense Thoughts option. You learn what is most on the target’s mind right now. If the target doesn’t know any languages and isn’t telepathic, you learn nothing.<br><br>As a Magic action on your next turn, you can try to probe deeper into the target’s mind. If you probe deeper, the target makes a Wisdom saving throw. On a failed save, you discern the target’s reasoning, emotions, and something that looms large in its mind (such as a worry, love, or hate). On a successful save, the spell ends. Either way, the target knows that you are probing into its mind, and until you shift your attention away from the target’s mind, the target can take an action on its turn to make an Intelligence (Arcana) check against your spell save DC, ending the spell on a success.</li></ul><br><b>Material:</b> 1 Copper Piece",
        "dragonsBreathD": "You touch one willing creature, and choose Acid, Cold, Fire, Lightning, or Poison. Until the spell ends, the target can take a Magic action to exhale a 15-foot Cone. Each creature in that area makes a Dexterity saving throw, taking 3d6 damage of the chosen type on a failed save or half as much damage on a successful one.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d6 for each spell slot level above 2.<br><br><b>Material:</b> a hot pepper",
        "enhanceAbilityD": "You touch a creature and choose Strength, Dexterity, Intelligence, Wisdom, or Charisma. For the duration, the target has Advantage on ability checks using the chosen ability.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional creature for each spell slot level above 2. You can choose a different ability for each target.<br><br><b>Material:</b> fur or a feather",
        "enlarge_ReduceD": "For the duration, the spell enlarges or reduces a creature or an object you can see within range (see the chosen effect below). A targeted object must be neither worn nor carried. If the target is an unwilling creature, it can make a Constitution saving throw. On a successful save, the spell has no effect.<br><br>Everything that a targeted creature is wearing and carrying changes size with it. Any item it drops returns to normal size at once. A thrown weapon or piece of ammunition returns to normal size immediately after it hits or misses a target.<br><ul><li><b>Enlarge:</b> The target’s size increases by one category—from Medium to Large, for example. The target also has Advantage on Strength checks and Strength saving throws. The target’s attacks with its enlarged weapons or Unarmed Strikes deal an extra 1d4 damage on a hit.</li><li><b>Reduce:</b> The target’s size decreases by one category—from Medium to Small, for example. The target also has Disadvantage on Strength checks and Strength saving throws. The target’s attacks with its reduced weapons or Unarmed Strikes deal 1d4 less damage on a hit (this can’t reduce the damage below 1).</li></ul><br><b>Material:</b> a pinch of powdered iron",
        "enthrallD": "You weave a distracting string of words, causing creatures of your choice that you can see within range to make a Wisdom saving throw. Any creature you or your companions are fighting automatically succeeds on this save. On a failed save, a target has a −10 penalty to Wisdom (Perception) checks and Passive Perception until the spell ends.",
        "findSteedD": "You summon an otherworldly being that appears as a loyal steed in an unoccupied space of your choice within range. This creature uses the Otherworldly Steed stat block. If you already have a steed from this spell, the steed is replaced by the new one.<br><br>The steed resembles a Large, rideable animal of your choice, such as a horse, a camel, a dire wolf, or an elk. Whenever you cast the spell, choose the steed’s creature type—Celestial, Fey, or Fiend - which determines certain traits in the stat block.<br><br><b>Combat:</b> The steed is an ally to you and your allies. In combat, it shares your Initiative count, and it functions as a controlled mount while you ride it (as defined in the rules on mounted combat). If you have the Incapacitated condition, the steed takes its turn immediately after yours and acts independently, focusing on protecting you.<br><br><b>Disappearance of the Steed:</b> The steed disappears if it drops to 0 Hit Points or if you die. When it disappears, it leaves behind anything it was wearing or carrying. If you cast this spell again, you decide whether you summon the steed that disappeared or a different one.<br><br><b>Using a Higher-Level Spell Slot:</b> Use the spell slot’s level for the spell’s level in the stat block.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">Otherworldly Steed</span>",
        "findTrapsD": "You sense any trap within range that is within line of sight. A trap, for the purpose of this spell, includes any object or mechanism that was created to cause damage or other danger. Thus, the spell would sense the Alarm or Glyph of Warding spell or a mechanical pit trap, but it wouldn’t reveal a natural weakness in the floor, an unstable ceiling, or a hidden sinkhole.<br><br>This spell reveals that a trap is present but not its location. You do learn the general nature of the danger posed by a trap you sense.",
        "flameBladeD": "You evoke a fiery blade in your free hand. The blade is similar in size and shape to a scimitar, and it lasts for the duration. If you let go of the blade, it disappears, but you can evoke it again as a Bonus Action.<br><br>As a Magic action, you can make a melee spell attack with the fiery blade. On a hit, the target takes Fire damage equal to 3d6 plus your spellcasting ability modifier.<br><br>The flaming blade sheds Bright Light in a 10-foot radius and Dim Light for an additional 10 feet.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d6 for each spell slot level above 2.<br><br><b>Material:</b> a sumac leaf",
        "flamingSphereD": "You create a 5-foot-diameter sphere of fire in an unoccupied space on the ground within range. It lasts for the duration. Any creature that ends its turn within 5 feet of the sphere makes a Dexterity saving throw, taking 2d6 Fire damage on a failed save or half as much damage on a successful one.<br><br>As a Bonus Action, you can move the sphere up to 30 feet, rolling it along the ground. If you move the sphere into a creature’s space, that creature makes the save against the sphere, and the sphere stops moving for the turn.<br><br>When you move the sphere, you can direct it over barriers up to 5 feet tall and jump it across pits up to 10 feet wide. Flammable objects that aren’t being worn or carried start burning if touched by the sphere, and it sheds Bright Light in a 20-foot radius and Dim Light for an additional 20 feet.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d6 for each spell slot level above 2.<br><br><b>Material:</b> a ball of wax",
        "gentleReposeD": "You touch a corpse or other remains. For the duration, the target is protected from decay and can’t become Undead.<br><br>The spell also effectively extends the time limit on raising the target from the dead, since days spent under the influence of this spell don’t count against the time limit of spells such as Raise Dead.<br><br><b>Material:</b> 2 Copper Pieces, which the spell consumes",
        "gustOfWindD": "A Line of strong wind 60 feet long and 10 feet wide blasts from you in a direction you choose for the duration. Each creature in the Line must succeed on a Strength saving throw or be pushed 15 feet away from you in a direction following the Line. A creature that ends its turn in the Line must make the same save.<br><br>Any creature in the Line must spend 2 feet of movement for every 1 foot it moves when moving closer to you.<br><br>The gust disperses gas or vapor, and it extinguishes candles and similar unprotected flames in the area. It causes protected flames, such as those of lanterns, to dance wildly and has a 50 percent chance to extinguish them.<br><br>As a Bonus Action on your later turns, you can change the direction in which the Line blasts from you.<br><br><b>Material:</b> a legume seed",
        "heatMetalD": "Choose a manufactured metal object, such as a metal weapon or a suit of Heavy or Medium metal armor, that you can see within range. You cause the object to glow red-hot. Any creature in physical contact with the object takes 2d8 Fire damage when you cast the spell. Until the spell ends, you can take a Bonus Action on each of your later turns to deal this damage again if the object is within range.<br><br>If a creature is holding or wearing the object and takes the damage from it, the creature must succeed on a Constitution saving throw or drop the object if it can. If it doesn’t drop the object, it has Disadvantage on attack rolls and ability checks until the start of your next turn.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 2.<br><br><b>Material:</b> a piece of iron and a flame",
        "holdPersonD": "Choose a Humanoid that you can see within range. The target must succeed on a Wisdom saving throw or have the Paralyzed condition for the duration. At the end of each of its turns, the target repeats the save, ending the spell on itself on a success.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional Humanoid for each spell slot level above 2.<br><br><b>Material:</b> a straight piece of iron",
        "invisibilityD": "A creature you touch has the Invisible condition until the spell ends. The spell ends early immediately after the target makes an attack roll, deals damage, or casts a spell.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional creature for each spell slot level above 2.<br><br><b>Material:</b> an eyelash in gum arabic",
        "knockD": "Choose an object that you can see within range. The object can be a door, a box, a chest, a set of manacles, a padlock, or another object that contains a mundane or magical means that prevents access.<br><br>A target that is held shut by a mundane lock or that is stuck or barred becomes unlocked, unstuck, or unbarred. If the object has multiple locks, only one of them is unlocked.<br><br>If the target is held shut by Arcane Lock, that spell is suppressed for 10 minutes, during which time the target can be opened and closed.<br><br>When you cast the spell, a loud knock, audible up to 300 feet away, emanates from the target.",
        "lesserRestorationD": "You touch a creature and end one condition on it: Blinded, Deafened, Paralyzed, or Poisoned.",
        "LevitateD": "One creature or loose object of your choice that you can see within range rises vertically up to 20 feet and remains suspended there for the duration. The spell can levitate an object that weighs up to 500 pounds. An unwilling creature that succeeds on a Constitution saving throw is unaffected.<br><br>The target can move only by pushing or pulling against a fixed object or surface within reach (such as a wall or a ceiling), which allows it to move as if it were climbing. You can change the target’s altitude by up to 20 feet in either direction on your turn. If you are the target, you can move up or down as part of your move. Otherwise, you can take a Magic action to move the target, which must remain within the spell’s range.<br><br>When the spell ends, the target floats gently to the ground if it is still aloft.<br><br><b>Material:</b> a metal spring",
        "locateAnimalsOrPlantsD": "Describe or name a specific kind of Beast, Plant creature, or nonmagical plant. You learn the direction and distance to the closest creature or plant of that kind within 5 miles, if any are present.<br><br><b>Material:</b> fur from a bloodhound",
        "locateObjectD": "Describe or name an object that is familiar to you. You sense the direction to the object’s location if that object is within 1,000 feet of you. If the object is in motion, you know the direction of its movement.<br><br>The spell can locate a specific object known to you if you have seen it up close—within 30 feet—at least once. Alternatively, the spell can locate the nearest object of a particular kind, such as a certain kind of apparel, jewelry, furniture, tool, or weapon.<br><br>This spell can’t locate an object if any thickness of lead blocks a direct path between you and the object.<br><br><b>Material:</b> a forked twig",
        "magicMouthD": "You implant a message within an object in range—a message that is uttered when a trigger condition is met. Choose an object that you can see and that isn’t being worn or carried by another creature. Then speak the message, which must be 25 words or fewer, though it can be delivered over as long as 10 minutes. Finally, determine the circumstance that will trigger the spell to deliver your message.<br><br>When that trigger occurs, a magical mouth appears on the object and recites the message in your voice and at the same volume you spoke. If the object you chose has a mouth or something that looks like a mouth (for example, the mouth of a statue), the magical mouth appears there, so the words appear to come from the object’s mouth. When you cast this spell, you can have the spell end after it delivers its message, or it can remain and repeat its message whenever the trigger occurs.<br><br>The trigger can be as general or as detailed as you like, though it must be based on visual or audible conditions that occur within 30 feet of the object. For example, you could instruct the mouth to speak when any creature moves within 30 feet of the object or when a silver bell rings within 30 feet of it.<br><br><b>Material:</b> jade dust worth 10+ GP, which the spell consumes",
        "magicWeaponD": "You touch a nonmagical weapon. Until the spell ends, that weapon becomes a magic weapon with a +1 bonus to attack rolls and damage rolls. The spell ends early if you cast it again.<br><br><b>Using a Higher-Level Spell Slot:</b> The bonus increases to +2 with a level 3–5 spell slot. The bonus increases to +3 with a level 6+ spell slot.",
        "mindSpikeD": "You drive a spike of psionic energy into the mind of one creature you can see within range. The target makes a Wisdom saving throw, taking 3d8 Psychic damage on a failed save or half as much damage on a successful one. On a failed save, you also always know the target’s location until the spell ends, but only while the two of you are on the same plane of existence. While you have this knowledge, the target can’t become hidden from you, and if it has the Invisible condition, it gains no benefit from that condition against you.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 2.",
        "mirrorImageD": "Three illusory duplicates of yourself appear in your space. Until the spell ends, the duplicates move with you and mimic your actions, shifting position so it’s impossible to track which image is real.<br><br>Each time a creature hits you with an attack roll during the spell’s duration, roll a d6 for each of your remaining duplicates. If any of the d6s rolls a 3 or higher, one of the duplicates is hit instead of you, and the duplicate is destroyed. The duplicates otherwise ignore all other damage and effects. The spell ends when all three duplicates are destroyed.<br><g>A creature is unaffected by this spell if it has the Blinded condition, Blindsight, or Truesight.",
        "mistyStepD": "Briefly surrounded by silvery mist, you teleport up to 30 feet to an unoccupied space you can see.",
        "moonbeamD": "A silvery beam of pale light shines down in a 5-foot-radius, 40-foot-high Cylinder centered on a point within range. Until the spell ends, Dim Light fills the Cylinder, and you can take a Magic action on later turns to move the Cylinder up to 60 feet.<br><br>When the Cylinder appears, each creature in it makes a Constitution saving throw. On a failed save, a creature takes 2d10 Radiant damage, and if the creature is shape-shifted (as a result of the Polymorph spell, for example), it reverts to its true form and can’t shape-shift until it leaves the Cylinder. On a successful save, a creature takes half as much damage only. A creature also makes this save when the spell’s area moves into its space and when it enters the spell’s area or ends its turn there. A creature makes this save only once per turn.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d10 for each spell slot level above 2.<br><br><b>Material:</b> a moonseed leaf",
        "passWithoutTreceD": "You radiate a concealing aura in a 30-foot Emanation for the duration. While in the aura, you and each creature you choose have a +10 bonus to Dexterity (Stealth) checks and leave no tracks.<br><br><b>Material:</b> ashes from burned mistletoe",
        "phantasmalForceD": "You attempt to craft an illusion in the mind of a creature you can see within range. The target makes an Intelligence saving throw. On a failed save, you create a phantasmal object, creature, or other phenomenon that is no larger than a 10-foot Cube and that is perceivable only to the target for the duration. The phantasm includes sound, temperature, and other stimuli.<br><br>The target can take a Study action to examine the phantasm with an Intelligence (Investigation) check against your spell save DC. If the check succeeds, the target realizes that the phantasm is an illusion, and the spell ends.<br><br>While affected by the spell, the target treats the phantasm as if it were real and rationalizes any illogical outcomes from interacting with it. For example, if the target steps through a phantasmal bridge and survives the fall, it believes the bridge exists and something else caused it to fall.<br><br>An affected target can even take damage from the illusion if the phantasm represents a dangerous creature or hazard. On each of your turns, such a phantasm can deal 2d8 Psychic damage to the target if it is in the phantasm’s area or within 5 feet of the phantasm. The target perceives the damage as a type appropriate to the illusion.<br><br><b>Material:</b> a bit of fleece",
        "prayerOfHealingD": "Up to five creatures of your choice who remain within range for the spell’s entire casting gain the benefits of a Short Rest and also regain 2d8 Hit Points. A creature can’t be affected by this spell again until that creature finishes a Long Rest.<br><br><b>Using a Higher-Level Spell Slot:</b> The healing increases by 1d8 for each spell slot level above 2.",
        "protectionFromPoisonD": "You touch a creature and end the Poisoned condition on it. For the duration, the target has Advantage on saving throws to avoid or end the Poisoned condition, and it has Resistance to Poison damage.",
        "rayOfEnfeeblementD": "A beam of enervating energy shoots from you toward a creature within range. The target must make a Constitution saving throw. On a successful save, the target has Disadvantage on the next attack roll it makes until the start of your next turn.<br><br>On a failed save, the target has Disadvantage on Strength-based D20 Tests for the duration. During that time, it also subtracts 1d8 from all its damage rolls. The target repeats the save at the end of each of its turns, ending the spell on a success.",
        "ropeTrickD": "You touch a rope. One end of it hovers upward until the rope hangs perpendicular to the ground or the rope reaches a ceiling. At the rope’s upper end, an Invisible 3-foot-by-5-foot portal opens to an extradimensional space that lasts until the spell ends. That space can be reached by climbing the rope, which can be pulled into or dropped out of it.<br><br>The space can hold up to eight Medium or smaller creatures. Attacks, spells, and other effects can’t pass into or out of the space, but creatures inside it can see through the portal. Anything inside the space drops out when the spell ends.<br><br><b>Material:</b> a segment of rope",
        "scorchingRayD": "You hurl three fiery rays. You can hurl them at one target within range or at several. Make a ranged spell attack for each ray. On a hit, the target takes 2d6 Fire damage.<br><br><b>Using a Higher-Level Spell Slot:</b> You create one additional ray for each spell slot level above 2.",
        "seeInvisibilityD": "For the duration, you see creatures and objects that have the Invisible condition as if they were visible, and you can see into the Ethereal Plane. Creatures and objects there appear ghostly.<br><br><b>Material:</b> a pinch of talc",
        "shatterD": "A loud noise erupts from a point of your choice within range. Each creature in a 10-foot-radius Sphere centered there makes a Constitution saving throw, taking 3d8 Thunder damage on a failed save or half as much damage on a successful one. A Construct has Disadvantage on the save.<br><br>A nonmagical object that isn’t being worn or carried also takes the damage if it’s in the spell’s area.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 2.<br><br><b>Material:</b> a chip of mica",
        "silenceD": "For the duration, no sound can be created within or pass through a 20-foot-radius Sphere centered on a point you choose within range. Any creature or object entirely inside the Sphere has Immunity to Thunder damage, and creatures have the Deafened condition while entirely inside it. Casting a spell that includes a Verbal component is impossible there.",
        "spiderClimbD": "Until the spell ends, one willing creature you touch gains the ability to move up, down, and across vertical surfaces and along ceilings, while leaving its hands free. The target also gains a Climb Speed equal to its Speed.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional creature for each spell slot level about 2.<br><br><b>Material:</b> a drop of bitumen and a spider",
        "spikeGrowthD": "The ground in a 20-foot-radius Sphere centered on a point within range sprouts hard spikes and thorns. The area becomes Difficult Terrain for the duration. When a creature moves into or within the area, it takes 2d4 Piercing damage for every 5 feet it travels.<br><br>The transformation of the ground is camouflaged to look natural. Any creature that can’t see the area when the spell is cast must take a Search action and succeed on a Wisdom (Perception or Survival) check against your spell save DC to recognize the terrain as hazardous before entering it.<br><br><b>Material:</b> seven thorns",
        "spiritualWeaponD": "You create a floating, spectral force that resembles a weapon of your choice and lasts for the duration. The force appears within range in a space of your choice, and you can immediately make one melee spell attack against one creature within 5 feet of the force. On a hit, the target takes Force damage equal to 1d8 plus your spellcasting ability modifier.<br><br>As a Bonus Action on your later turns, you can move the force up to 20 feet and repeat the attack against a creature within 5 feet of it.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for every slot level above 2.",
        "suggestionD": "You suggest a course of activity—described in no more than 25 words—to one creature you can see within range that can hear and understand you. The suggestion must sound achievable and not involve anything that would obviously deal damage to the target or its allies.<br><br>The target must succeed on a Wisdom saving throw or have the Charmed condition for the duration or until you or your allies deal damage to the target. The Charmed target pursues the suggestion to the best of its ability. The suggested activity can continue for the entire duration, but if the suggested activity can be completed in a shorter time, the spell ends for the target upon completing it.<br><br><b>Material:</b> a drop of honey",
        "summonBeastD": "You call forth a bestial spirit. It manifests in an unoccupied space that you can see within range and uses the Bestial Spirit stat block. When you cast the spell, choose an environment: Air, Land, or Water. The creature resembles an animal of your choice that is native to the chosen environment, which determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends.<br><br>The creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the Dodge action and uses its movement to avoid danger.<br><br><b>Using a Higher-Level Spell Slot:</b> Use the spell slot’s level for the spell’s level in the stat block.<br><br><b>Material:</b> a feather, tuft of fur, and fish tail inside a gilded acorn worth 200+ GP<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">bestial spirit</span>",
        "wardingBondD": "You touch another creature that is willing and create a mystic connection between you and the target until the spell ends. While the target is within 60 feet of you, it gains a +1 bonus to AC and saving throws, and it has Resistance to all damage. Also, each time it takes damage, you take the same amount of damage.<br><br>The spell ends if you drop to 0 Hit Points or if you and the target become separated by more than 60 feet. It also ends if the spell is cast again on either of the connected creatures.<br><br><b>Material:</b> a pair of platinum rings worth 50+ GP each, which you and the target must wear for the duration",
        "webD": "You conjure a mass of sticky webbing at a point within range. The webs fill a 20-foot Cube there for the duration. The webs are Difficult Terrain, and the area within them is Lightly Obscured.<br><br>If the webs aren’t anchored between two solid masses (such as walls or trees) or layered across a floor, wall, or ceiling, the web collapses on itself, and the spell ends at the start of your next turn. Webs layered over a flat surface have a depth of 5 feet.<br><br>The first time a creature enters the webs on a turn or starts its turn there, it must succeed on a Dexterity saving throw or have the Restrained condition while in the webs or until it breaks free.<br><br>A creature Restrained by the webs can take an action to make a Strength (Athletics) check against your spell save DC. If it succeeds, it is no longer Restrained.<br><br>The webs are flammable. Any 5-foot Cube of webs exposed to fire burns away in 1 round, dealing 2d4 Fire damage to any creature that starts its turn in the fire.<br><br><b>Material:</b> a bit of spiderweb",
        "zoneOfTruthD": "You create a magical zone that guards against deception in a 15-foot-radius Sphere centered on a point within range. Until the spell ends, a creature that enters the spell’s area for the first time on a turn or starts its turn there makes a Charisma saving throw. On a failed save, a creature can’t speak a deliberate lie while in the radius. You know whether a creature succeeds or fails on this save.<br><br>An affected creature is aware of the spell and can avoid answering questions to which it would normally respond with a lie. Such a creature can be evasive yet must be truthful.",
        "animateDeadD": "Choose a pile of bones or a corpse of a Medium or Small Humanoid within range. The target becomes an Undead creature: a Skeleton if you chose bones or a Zombie if you chose a corpse.<br><br>On each of your turns, you can take a Bonus Action to mentally command any creature you made with this spell if the creature is within 60 feet of you. You decide what action the creature will take and where it will move on its next turn. If you issue no commands, the creature takes the Dodge action and moves only to avoid harm. Once given an order, the creature continues to follow it until its task is complete.<br><br>The creature is under your control for 24 hours. To maintain control, you must cast this spell again before the current 24-hour period ends. This reasserts your control over up to four creatures rather than animating a new one.<br><br><b>Using a Higher-Level Spell Slot:</b> You animate or reassert control over two additional Undead creatures for each spell slot level above 3.<br><br><b>Material:</b> a drop of blood, a piece of flesh, and a pinch of bone dust",
        "auraOfVitalityD": "An aura radiates from you in a 30-foot Emanation for the duration. When you create the aura and at the start of each of your turns while it persists, you can restore 2d6 Hit Points to one creature in it.",
        "beaconOfHopeD": "Choose any number of creatures within range. For the duration, each target has Advantage on Wisdom saving throws and Death Saving Throws and regains the maximum number of Hit Points possible from any healing.",
        "bestowCurseD": "You touch a creature, which must succeed on a Wisdom saving throw or become cursed for the duration. Until the curse ends, the target suffers one of choice:<ul><li>Choose one ability. The target has Disadvantage on ability checks and saving throws made with that ability.</li><li>The target has Disadvantage on attack rolls against you.</li><li>In combat, the target must succeed on a Wisdom saving throw at the start of each of its turns or be forced to take the Dodge action on that turn.</li><li>If you deal damage to the target with an attack roll or a spell, the target takes an extra 1d8 Necrotic damage.</li></ul><br><b>Using a Higher-Level Spell Slot:</b> If you cast this spell using a level 4 spell slot, you can maintain Concentration on it for up to 10 minutes. If you use a level 5+ spell slot, the spell doesn’t require Concentration, and the duration becomes 8 hours (level 5–6 slot) or 24 hours (level 7–8 slot). If you use a level 9 spell slot, the spell lasts until dispelled.",
        "blindingSmiteD": "The target hit by the strike takes an extra 3d8 Radiant damage from the attack, and the target has the Blinded condition until the spell ends. At the end of each of its turns, the Blinded target makes a Constitution saving throw, ending the spell on itself on a success.<br><br><b>Using a Higher-Level Spell Slot:</b> The extra damage increases by 1d8 for each spell slot level above 3.<br><br><b>Bonus Action:</b> which you take immediately after hitting a creature with a Melee weapon or an Unarmed Strike.",
        "blinkD": "Roll 1d6 at the end of each of your turns for the duration. On a roll of 4–6, you vanish from your current plane of existence and appear in the Ethereal Plane. While on the Ethereal Plane, you can perceive the plane you left in shades of gray, but you can’t see anything there more than 60 feet away. You return to the other plane at the start of your next turn at an unoccupied space within 10 feet of the space you left.",
        "callLightningD": "A storm cloud appears at a point within range above you (Cylinder, 10 feet tall, 60-foot radius). Choose a point under the cloud: a lightning bolt shoots to that point. Each creature within 5 feet makes a Dexterity saving throw, taking 3d10 Lightning damage on a failed save (half on success). You can take a Magic action to call down lightning again. Outdoors in a storm, damage increases by 1d10.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d10 for each spell slot level above 3.",
        "clairvoyanceD": "You create an Invisible sensor within range. When you cast the spell, choose seeing or hearing. You can use the chosen sense through the sensor. As a Bonus Action, you can switch between seeing and hearing. A creature that sees the sensor sees a luminous orb about the size of your fist.<br><br><b>Material:</b> a focus worth 100+ GP, either a jeweled horn for hearing or a glass eye for seeing",
        "conjureAnimalsD": "You conjure nature spirits as a Large pack of spectral animals in an unoccupied space within range. You have Advantage on Strength saving throws within 5 feet of the pack. You can move the pack up to 30 feet in your turn. Creatures within 10 feet of the pack must make a Dexterity saving throw or take 3d10 Slashing damage.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d10 for each spell slot level above 3.",
        "conjureBarrageD": "You brandish the weapon used to cast the spell and conjure similar spectral weapons that launch forward. Each creature of your choice in a 60-foot Cone makes a Dexterity saving throw, taking 5d8 Force damage on a failed save or half as much on a successful one.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 3.<br><br><b>Material:</b> a Melee or Ranged weapon worth at least 1 CP",
        "counterspellD": "You attempt to interrupt a creature in the process of casting a spell. The creature makes a Constitution saving throw. On a failed save, the spell dissipates with no effect. The slot isn’t expended.<br><br><b>Reaction:</b> which you take when you see a creature within 60 feet of yourself casting a spell.",
        "createFoodAndWaterD": "You create 45 pounds of food and 30 gallons of fresh water on the ground or in containers. The food is bland but nourishing and spoils after 24 hours.",
        	"crusader'sMantleD": "You radiate a magical aura in a 30-foot Emanation. While in the aura, you and your allies each deal an extra 1d4 Radiant damage when hitting with a weapon or an Unarmed Strike.",
        "daylightD": "Sunlight spreads from a point and fills a 60-foot-radius Sphere. Bright Light (further 60 feet Dim Light). Alternatively, an object emits the light (60-foot Emanation). Covering the object blocks it. If it overlaps with *Darkness* (level 3 or lower), that spell is dispelled.",
        "dispelMagicD": "Choose one creature, object, or magical effect. Any ongoing spell of level 3 or lower ends. For each spell of level 4+, make an ability check (DC 10 + spell level).<br><br><b>Using a Higher-Level Spell Slot:</b> You automatically end a spell if its level is equal to or less than the level of the spell slot you use.",
        "elementalWeaponD": "A nonmagical weapon you touch becomes a magic weapon. Choose: Acid, Cold, Fire, Lightning, or Thunder. The weapon has +1 to attack rolls and deals an extra 1d4 damage of the chosen type.<br><br><b>Using a Higher-Level Spell Slot:</b> With a level 5–6 slot, bonus increases to +2 (2d4 damage). Level 7+ increases to +3 (3d4 damage).",
        "fearD": "Each creature in a 30-foot Cone must succeed on a Wisdom saving throw or drop whatever it is holding and have the Frightened condition. Frightened creatures must use the Dash action to move away from you. If they lose line of sight, they repeat the save.<br><br><b>Material:</b> a white feather",
        "feignDeathD": "You put a willing creature into a cataleptic state. The target appears dead, is blinded, incapacitated, and has a Speed of 0. It has Resistance to all damage (except Psychic) and Immunity to 'Poisoned'.<br><br><b>Material:</b> a pinch of graveyard dirt",
        "fireballD": "A bright streak flashes to a point and explodes in a 20-foot-radius Sphere. Each creature makes a Dexterity saving throw: 8d6 Fire damage on failure, half on success. Flammable objects burn.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d6 for each spell slot level above 3.<br><br><b>Material:</b> a ball of bat guano and sulfur",
        "flyD": "A willing creature gains a Fly Speed of 60 feet and can hover. If aloft when the spell ends, the target falls.<br><br><b>Using a Higher-Level Spell Slot:</b> One additional creature for each spell slot level above 3.<br><br><b>Material:</b> a feather",
        "gaseousFormD": "A willing creature transforms into a misty cloud. Fly Speed 10 feet (hover). Resistance to physical damage, Immunity to 'Prone', and Advantage on physical saving throws. Can't attack, cast spells, or use objects.<br><br><b>Using a Higher-Level Spell Slot:</b> One additional creature for each level above 3.<br><br><b>Material:</b> a bit of gauze",
        "glyphOfWardingD": "You inscribe a glyph on a surface or in an object (max 10 feet diameter). Moving it more than 10 feet breaks the spell. You set the trigger and effect:<ul><li><b>Explosive Rune:</b> 20-foot Sphere, 5d8 damage (Acid, Cold, Fire, Lightning, or Thunder), Dexterity save for half.</li><li><b>Spell Glyph:</b> Stores a spell up to level 3, which targets the intruder when triggered.</li></ul><br><b>Using a Higher-Level Spell Slot:</b> Rune damage increases by 1d8 per level above 3. Spell glyph max level equals the slot level.<br><br><b>Material:</b> powdered diamond worth 200+ GP, which the spell consumes",
        "hasteD": "Choose a willing creature. Speed is doubled, +2 to AC, Advantage on Dexterity saves, and one additional action (Attack (one only), Dash, Disengage, Hide, or Utilize). When the spell ends, the target is Incapacitated for 1 turn.<br><br><b>Material:</b> a shaving of licorice root",
   	"hungerOfHadarD": "You open a gateway to the Far Realm, a region infested with unspeakable horrors. A 20-foot-radius Sphere of Darkness appears, centered on a point with range and lasting for the duration. The Sphere is Difficult Terrain, and it is filled with strange whispers and slurping noises, which can be heard up to 30 feet away. No light, magical or otherwise, can illuminate the area, and creatures fully within it have the Blinded condition.<br><br>Any creature that starts its turn in the area takes 2d6 Cold damage. Any creature that ends its turn there must succeed on a Dexterity saving throw or take 2d6 Acid damage from otherworldly tentacles.<br><br><b>Using a Higher-Level Spell Slot:</b> The Cold or Acid damage (your choice) increases by 1d6 for each spell slot level above 3.<br><br><b>Material:</b> a pickled tentacle",
        "hypnoticPatternD": "You create a twisting pattern of colors in a 30-foot Cube within range. The pattern appears for a moment and vanishes. Each creature in the area who can see the pattern must succeed on a Wisdom saving throw or have the Charmed condition for the duration. While Charmed, the creature has the Incapacitated condition and a Speed of 0.<br><br>The spell ends for an affected creature if it takes any damage or if someone else uses an action to shake the creature out of its stupor.<br><br><b>Material:</b> a pinch of confetti",
        "lightningArrowD": "As your attack hits or misses the target, the weapon or ammunition you’re using transforms into a lightning bolt. Instead of taking any damage or other effects from the attack, the target takes 4d8 Lightning damage on a hit or half as much damage on a miss. Each creature within 10 feet of the target then makes a Dexterity saving throw, taking 2d8 Lightning damage on a failed save or half as much damage on a successful one.<br><br>The weapon or ammunition then returns to its normal form.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage for both effects of the spell increases by 1d8 for each spell slot level above 3.<br><br><b>Reaction:</b> which you take immediately after hitting or missing a target with a ranged attack using a weapon.",
	"lightningBoltD": "A stroke of lightning forming a 100-foot-long, 5-foot-wide Line blasts out from you in a direction you choose. Each creature in the Line makes a <b>Dexterity saving throw</b>, taking 8d6 Lightning damage on a failed save or half as much damage on a successful one.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d6 for each spell slot level above 3.<br><br><b>Material:</b> a bit of fur and a crystal rod",
    	"magicCircleD": "You create a 10-foot-radius, 20-foot-tall Cylinder of magical energy centered on a point on the ground that you can see within range. Glowing runes appear wherever the Cylinder intersects with the floor or other surface.<br><br>Choose one or more of the following types of creatures: Celestials, Elementals, Fey, Fiends, or Undead. The circle affects a creature of the chosen type in the following ways:<ul><li>The creature can’t willingly enter the Cylinder by nonmagical means. If the creature tries to use teleportation or interplanar travel to do so, it must first succeed on a <b>Charisma saving throw</b>.</li><li>The creature has <b>Disadvantage</b> on attack rolls against targets within the Cylinder.</li><li>Targets within the Cylinder can’t be possessed by or gain the <b>Charmed</b> or <b>Frightened</b> condition from the creature.</li></ul><br>Each time you cast this spell, you can cause its magic to operate in the reverse direction, preventing a creature of the specified type from leaving the Cylinder and protecting targets outside it.<br><br><b>Using a Higher-Level Spell Slot:</b> The duration increases by 1 hour for each spell slot level above 3.<br><br><b>Material:</b> salt and powdered silver worth 100+ GP, which the spell consumes",
    	"majorImageD": "You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 20-foot Cube. The image appears at a spot that you can see within range and lasts for the duration. It seems real, including sounds, smells, and temperature appropriate to the thing depicted, but it can’t deal damage or cause conditions.<br><br>If you are within range of the illusion, you can take a <b>Magic action</b> to cause the image to move to any other spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking. Similarly, you can cause the illusion to make different sounds at different times, even making it carry on a conversation, for example.<br><br>Physical interaction with the image reveals it to be an illusion, for things can pass through it. A creature that takes a <b>Study action</b> to examine the image can determine that it is an illusion with a successful <b>Intelligence (Investigation)</b> check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and its other sensory qualities become faint to the creature.<br><br><b>Using a Higher-Level Spell Slot:</b> The spell lasts until dispelled, without requiring <b>Concentration</b>, if cast with a level 4+ spell slot.<br><br><b>Material:</b> a bit of fleece",
    	"massHealingWordD": "Up to six creatures of your choice that you can see within range regain <b>Hit Points</b> equal to 2d4 plus your spellcasting ability modifier.<br><br><b>Using a Higher-Level Spell Slot:</b> The healing increases by 1d4 for each spell slot level above 3.",
    	"meldIntoStoneD": "You step into a stone object or surface large enough to fully contain your body, merging yourself and your equipment with the stone for the duration. You must touch the stone to do so. Nothing of your presence remains visible or otherwise detectable by nonmagical senses.<br><br>While merged with the stone, you can’t see what occurs outside it, and any <b>Wisdom (Perception)</b> checks you make to hear sounds outside it are made with <b>Disadvantage</b>. You remain aware of the passage of time and can cast spells on yourself while merged in the stone. You can use 5 feet of movement to leave the stone where you entered it, which ends the spell. You otherwise can’t move.<br><br>Minor physical damage to the stone doesn’t harm you, but its partial destruction or a change in its shape (to the extent that you no longer fit within it) expels you and deals 6d6 <b>Force damage</b> to you. The stone’s complete destruction (or transmutation into a different substance) expels you and deals 50 <b>Force damage</b> to you. If expelled, you move into an unoccupied space closest to where you first entered and have the <b>Prone</b> condition.",
    	"nondetectionD": "For the duration, you hide a target that you touch from <b>Divination</b> spells. The target can be a willing creature, or it can be a place or an object no larger than 10 feet in any dimension. The target can’t be targeted by any Divination spell or perceived through magical scrying sensors.<br><br><b>Material:</b> a pinch of diamond dust worth 25+ GP, which the spell consumes",
    	"phantomSteedD": "A Large, quasi-real, horselike creature appears on the ground in an unoccupied space of your choice within range. You decide the creature’s appearance, and it is equipped with a saddle, bit, and bridle. Any of the equipment created by the spell vanishes in a puff of smoke if it is carried more than 10 feet away from the steed.<br><br>For the duration, you or a creature you choose can ride the steed. The steed uses the <b>Riding Horse</b> stat block, except it has a Speed of 100 feet and can travel 13 miles in an hour. When the spell ends, the steed gradually fades, giving the rider 1 minute to dismount. The spell ends early if the steed takes any damage.",
    	"plantGrowthD": "This spell channels vitality into plants. The casting time you use determines whether the spell has the <b>Overgrowth</b> or the <b>Enrichment</b> effect below:<ul><li><b>Overgrowth:</b> Choose a point within range. All normal plants in a 100-foot-radius Sphere centered on that point become thick and overgrown. A creature moving through that area must spend 4 feet of movement for every 1 foot it moves. You can exclude one or more areas of any size within the spell’s area from being affected.</li><li><b>Enrichment:</b> All plants in a half-mile radius centered on a point within range become enriched for 365 days. The plants yield twice the normal amount of food when harvested. They can benefit from only one Plant Growth per year.</li></ul><br><b>Special:</b> Action (Overgrowth) or 8 hours (Enrichment)",
    	"protectionFromEnergyD": "For the duration, the willing creature you touch has <b>Resistance</b> to one damage type of your choice: Acid, Cold, Fire, Lightning, or Thunder.",
    	"removeCurseD": "At your touch, all curses affecting one creature or object end. If the object is a cursed magic item, its curse remains, but the spell breaks its owner’s <b>Attunement</b> to the object so it can be removed or discarded.",
    	"revivifyD": "You touch a creature that has died within the last minute. That creature revives with 1 <b>Hit Point</b>. This spell can’t revive a creature that has died of old age, nor does it restore any missing body parts.<br><br><b>Material:</b> a diamond worth 300+ GP, which the spell consumes",
    	"sendingD": "You send a short message of 25 words or fewer to a creature you have met or a creature described to you by someone who has met it. The target hears the message in its mind, recognizes you as the sender if it knows you, and can answer in a like manner immediately. The spell enables targets to understand the meaning of your message.<br><br>You can send the message across any distance and even to other planes of existence, but if the target is on a different plane than you, there is a 5 percent chance that the message doesn’t arrive. You know if the delivery fails.<br><br>Upon receiving your message, a creature can block your ability to reach it again with this spell for 8 hours. If you try to send another message during that time, you learn that you are blocked, and the spell fails.<br><br><b>Material:</b> a copper wire",
    	"sleetStormD": "Until the spell ends, sleet falls in a 40-foot-tall, 20-foot-radius Cylinder centered on a point you choose within range. The area is <b>Heavily Obscured</b>, and exposed flames in the area are doused.<br><br>Ground in the Cylinder is <b>Difficult Terrain</b>. When a creature enters the Cylinder for the first time on a turn or starts its turn there, it must succeed on a <b>Dexterity saving throw</b> or have the <b>Prone</b> condition and lose <b>Concentration</b>.<br><br><b>Material:</b> a miniature umbrella",
    	"slowD": "You alter time around up to six creatures of your choice in a 40-foot Cube within range. Each target must succeed on a <b>Wisdom saving throw</b> or be affected by this spell for the duration.<br><br>An affected target’s Speed is halved, it takes a −2 penalty to AC and <b>Dexterity saving throws</b>, and it can’t take <b>Reactions</b>. On its turns, it can take either an action or a <b>Bonus Action</b>, not both, and it can make only one attack if it takes the Attack action. If it casts a spell with a Somatic component, there is a 25 percent chance the spell fails as a result of the target making the spell’s gestures too slowly.<br><br>An affected target repeats the save at the end of each of its turns, ending the spell on itself on a success.<br><br><b>Material:</b> a drop of molasses",
    	"speakWithDeadD": "You grant the semblance of life to a corpse of your choice within range, allowing it to answer questions you pose. The corpse must have a mouth, and this spell fails if the deceased creature was <b>Undead</b> when it died. The spell also fails if the corpse was the target of this spell within the past 10 days.<br><br>Until the spell ends, you can ask the corpse up to five questions. The corpse knows only what it knew in life, including the languages it knew. Answers are usually brief, cryptic, or repetitive, and the corpse is under no compulsion to offer a truthful answer if you are antagonistic toward it or it recognizes you as an enemy. This spell doesn’t return the creature’s soul to its body, only its animating spirit. Thus, the corpse can’t learn new information, doesn’t comprehend anything that has happened since it died, and can’t speculate about future events.<br><br><b>Material:</b> burning incense",
    	"speakWithPlantsD": "You imbue plants in an immobile 30-foot <b>Emanation</b> with limited sentience and animation, giving them the ability to communicate with you and follow your simple commands. You can question plants about events in the spell’s area within the past day, gaining information about creatures that have passed, weather, and other circumstances.<br><br>You can also turn <b>Difficult Terrain</b> caused by plant growth (such as thickets and undergrowth) into ordinary terrain that lasts for the duration. Or you can turn ordinary terrain where plants are present into Difficult Terrain that lasts for the duration.<br><br>The spell doesn’t enable plants to uproot themselves and move about, but they can move their branches, tendrils, and stalks for you.<br><br>If a <b>Plant creature</b> is in the area, you can communicate with it as if you shared a common language.",
    	"spiritGuardiansD": "Protective spirits flit around you in a 15-foot <b>Emanation</b> for the duration. If you are good or neutral, their spectral form appears angelic or fey (your choice). If you are evil, they appear fiendish.<br><br>When you cast this spell, you can designate creatures to be unaffected by it. Any other creature’s Speed is halved in the Emanation, and whenever the Emanation enters a creature’s space and whenever a creature enters the Emanation or ends its turn there, the creature must make a <b>Wisdom saving throw</b>. On a failed save, the creature takes 3d8 <b>Radiant damage</b> (if you are good or neutral) or 3d8 <b>Necrotic damage</b> (if you are evil). On a successful save, the creature takes half as much damage. A creature makes this save only once per turn.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 3.<br><br><b>Material:</b> a prayer scroll",
    	"stinkingClaudD": "You create a 20-foot-radius Sphere of yellow, nauseating gas centered on a point within range. The cloud is <b>Heavily Obscured</b>. The cloud lingers in the air for the duration or until a strong wind (such as the one created by <b>Gust of Wind</b>) disperses it.<br><br>Each creature that starts its turn in the Sphere must succeed on a <b>Constitution saving throw</b> or have the <b>Poisoned</b> condition until the end of the current turn. While Poisoned in this way, the creature can’t take an action or a <b>Bonus Action</b>.<br><br><b>Material:</b> a rotten egg",
    	"summonFeyD": "You call forth a Fey spirit. It manifests in an unoccupied space that you can see within range and uses the <b>Fey Spirit</b> stat block. When you cast the spell, choose a mood: Fuming, Mirthful, or Tricksy. The creature resembles a Fey creature of your choice marked by the chosen mood, which determines certain details in its stat block. The creature disappears when it drops to 0 <b>Hit Points</b> or when the spell ends.<br><br>The creature is an ally to you and your allies. In combat, the creature shares your <b>Initiative count</b>, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the <b>Dodge action</b> and uses its movement to avoid danger.<br><br><b>Using a Higher-Level Spell Slot:</b> Use the spell slot’s level for the spell’s level in the stat block.<br><br><b>Material:</b> a gilded flower worth 300+ GP<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">small fey</span>",
    	"summonUndeadD": "You call forth an <b>Undead spirit</b>. It manifests in an unoccupied space that you can see within range and uses the <b>Undead Spirit</b> stat block. When you cast the spell, choose the creature’s form: Ghostly, Putrid, or Skeletal. The spirit resembles an Undead creature with the chosen form, which determines certain details in its stat block. The creature disappears when it drops to 0 <b>Hit Points</b> or when the spell ends.<br><br>The creature is an ally to you and your allies. In combat, the creature shares your <b>Initiative count</b>, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the <b>Dodge action</b> and uses its movement to avoid danger.<br><br><b>Using a Higher-Level Spell Slot:</b> Use the spell slot’s level for the spell’s level in the stat block.<br><br><b>Material:</b> a gilded skull worth 300+ GP<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">undead spirit</span>",
    	"tonguesD": "This spell grants the creature you touch the ability to understand any spoken or signed language that it hears or sees. Moreover, when the target communicates by speaking or signing, any creature that knows at least one language can understand it if that creature can hear the speech or see the signing.<br><br><b>Material:</b> a miniature ziggurat",
    	"vampiricTouchD": "The touch of your shadow-wreathed hand can siphon life force from others to heal your wounds. Make a <b>melee spell attack</b> against one creature within reach. On a hit, the target takes 3d6 <b>Necrotic damage</b>, and you regain <b>Hit Points</b> equal to half the amount of Necrotic damage dealt.<br><br>Until the spell ends, you can make the attack again on each of your turns as a <b>Magic action</b>, targeting the same creature or a different one.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d6 for each spell slot level above 3.",
    	"waterBreathingD": "This spell grants up to ten willing creatures of your choice within range the ability to breathe underwater until the spell ends. Affected creatures also retain their normal mode of respiration.<br><br><b>Material:</b> a short reed",
    	"waterWalkD": "This spell grants the ability to move across any liquid surface—such as water, acid, mud, snow, quicksand, or lava—as if it were harmless solid ground. Up to ten willing creatures of your choice within range gain this ability for the duration.<br><br>An affected target must take a <b>Bonus Action</b> to pass from the liquid’s surface into the liquid itself and vice versa, but if the target falls into the liquid, the target passes through the surface into the liquid below.<br><br><b>Material:</b> a piece of cork",
    	"windWallD": "A wall of strong wind rises from the ground at a point you choose within range. You can make the wall up to 50 feet long, 15 feet high, and 1 foot thick. You can shape the wall in any way you choose so long as it makes one continuous path along the ground. The wall lasts for the duration.<br><br>When the wall appears, each creature in its area makes a <b>Strength saving throw</b>, taking 4d8 <b>Bludgeoning damage</b> on a failed save or half as much damage on a successful one.<br><br>Small or smaller flying creatures or objects can’t pass through the wall. Arrows, bolts, and other ordinary projectiles launched at targets behind the wall are deflected upward and miss automatically. Creatures in <b>gaseous form</b> can’t pass through it.<br><br><b>Material:</b> a fan and a feather",
    	"arcaneEyeD": "You create an <b>Invisible</b>, invulnerable eye within range that hovers for the duration. You mentally receive visual information from the eye, which can see in every direction. It also has <b>Darkvision</b> with a range of 30 feet.<br><br>As a <b>Bonus Action</b>, you can move the eye up to 30 feet in any direction. A solid barrier blocks the eye’s movement, but the eye can pass through an opening as small as 1 inch in diameter.<br><br><b>Material:</b> a bit of bat fur",
    	"auraOfLifeD": "An aura radiates from you in a 30-foot <b>Emanation</b> for the duration. While in the aura, you and your allies have <b>Resistance</b> to <b>Necrotic damage</b>, and your <b>Hit Point maximums</b> can’t be reduced. If an ally with 0 Hit Points starts its turn in the aura, that ally regains 1 Hit Point.",
    	"auraOfPurityD": "An aura radiates from you in a 30-foot <b>Emanation</b> for the duration. While in the aura, you and your allies have <b>Resistance</b> to <b>Poison damage</b> and <b>Advantage</b> on saving throws to avoid or end effects that include the Blinded, Charmed, Deafened, Frightened, Paralyzed, Poisoned, or Stunned condition.",
    	"banishmentD": "One creature that you can see within range must succeed on a <b>Charisma saving throw</b> or be transported to a harmless demiplane for the duration. While there, the target has the <b>Incapacitated</b> condition. When the spell ends, the target reappears in the space it left.<br><br>If the target is an Aberration, a Celestial, an Elemental, a Fey, or a Fiend, the target doesn’t return if the spell lasts for 1 minute. The target is instead transported to a random location on a plane associated with its creature type.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional creature for each spell slot level above 4.<br><br><b>Material:</b> a pentacle",
    	"blightD": "A creature that you can see within range makes a <b>Constitution saving throw</b>, taking 8d8 <b>Necrotic damage</b> on a failed save or half as much damage on a successful one. A <b>Plant creature</b> automatically fails the save.<br><br>Alternatively, target a nonmagical plant that isn’t a creature, such as a tree or shrub. It doesn’t make a save; it simply withers and dies.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 4.",
    	"charmMonsterD": "One creature you can see within range makes a <b>Wisdom saving throw</b>. It does so with <b>Advantage</b> if you or your allies are fighting it. On a failed save, the target has the <b>Charmed</b> condition until the spell ends or until you or your allies damage it. The Charmed creature is Friendly to you.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional creature for each spell slot level above 4.",
    	"compulsionD": "Each creature of your choice that you can see within range must succeed on a <b>Wisdom saving throw</b> or have the <b>Charmed</b> condition until the spell ends.<br><br>For the duration, you can take a <b>Bonus Action</b> to designate a direction that is horizontal to you. Each Charmed target must use as much of its movement as possible to move in that direction on its next turn. After moving in this way, a target repeats the save.",
    	"confusionD": "Each creature in a 10-foot-radius Sphere centered on a point you choose within range must succeed on a <b>Wisdom saving throw</b>, or that target can’t take Bonus Actions or Reactions and must roll 1d10 at the start of each of its turns to determine its behavior:<br><br><table class=\"spell-table\"><caption>Confusion</caption><tr><th>1d10</th><th>Behavior</th></tr><tr><td>1</td><td>The target doesn’t take an action and uses all its movement to move in a random direction (1d4: 1 north; 2 east; 3 south; or 4 west).</td></tr><tr><td>2–6</td><td>The target doesn’t move or take actions.</td></tr><tr><td>7–8</td><td>The target doesn’t move and takes the Attack action to make one melee attack against a random creature within reach.</td></tr><tr><td>9–10</td><td>The target chooses its behavior.</td></tr></table><br>At the end of each of its turns, an affected target repeats the save.<br><br><b>Using a Higher-Level Spell Slot:</b> The Sphere’s radius increases by 5 feet for each spell slot level above 4.<br><br><b>Material:</b> three nut shells",
    	"conjureMinorElementalsD": "You conjure spirits from the <b>Elemental Planes</b> that flit around you in a 15-foot <b>Emanation</b> for the duration. Until the spell ends, any attack you make deals an extra 2d8 damage when you hit a creature in the Emanation (Acid, Cold, Fire, or Lightning).<br><br>In addition, the ground in the Emanation is <b>Difficult Terrain</b> for your enemies.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 2d8 for each spell slot level above 4.",
    	"conjureWoodlandBeingsD": "You conjure nature spirits that flit around you in a 10-foot <b>Emanation</b> for the duration. Creatures in the area must make a <b>Wisdom saving throw</b> or take 5d8 <b>Force damage</b> (half on success).<br><br>In addition, you can take the <b>Disengage action</b> as a Bonus Action for the spell’s duration.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 4.",
    	"controlWaterD": "Until the spell ends, you control water inside a Cube up to 100 feet on a side using one of the following effects:<ul><li><b>Flood:</b> Water level rises by as much as 20 feet. Large waves repeat on subsequent turns.</li><li><b>Part Water:</b> Create a trench across the area.</li><li><b>Redirect Flow:</b> Flowing water moves in a direction you choose.</li><li><b>Whirlpool:</b> Create a whirlpool in an area at least 50 feet square. Creatures are pulled toward it and take 2d8 <b>Bludgeoning damage</b> on a failed <b>Strength save</b>.</li></ul><br><b>Material:</b> a mixture of water and dust",
    	"deathWardD": "You touch a creature and grant it a measure of protection from death. The first time the target would drop to 0 <b>Hit Points</b>, it instead drops to 1 Hit Point, and the spell ends.<br><br>If subjected to an effect that would kill it instantly without damage, the effect is negated and the spell ends.",
    	"dimensionDoorD": "You teleport to a location within range. You arrive at exactly the spot desired. You can also teleport one willing creature within 5 feet of you.<br><br>If you arrive in a space occupied by a creature or object, you and any traveler each take 4d6 <b>Force damage</b>, and the teleportation fails.",
    	"divinationD": "Ask one question about a specific goal or event to occur within 7 days. The DM offers a truthful reply.<br><br>There is a cumulative 25 percent chance of no answer for subsequent castings before a <b>Long Rest</b>.<br><br><b>Material:</b> incense worth 25+ GP, which the spell consumes",
    	"dominateBeastD": "One Beast must succeed on a <b>Wisdom saving throw</b> or be <b>Charmed</b>. You have a telepathic link to issue commands (no action required). You can command it to take a Reaction if you spend your own.<br><br><b>Using a Higher-Level Spell Slot:</b> Your <b>Concentration</b> can last longer: level 5 (up to 10 min.), level 6 (up to 1 hr.), or 7+ (up to 8 hrs.).",
	"fabricateD": "You convert raw materials into products of the same material. For example, you can fabricate a wooden bridge from a clump of trees, a rope from a patch of hemp, or clothes from flax or wool.<br><br>Choose raw materials that you can see within range. You can fabricate a <b>Large</b> or smaller object (contained within a 10-foot Cube or eight connected 5-foot Cubes) given a sufficient quantity of material. If you’re working with metal, stone, or another mineral substance, however, the fabricated object can be no larger than <b>Medium</b> (contained within a 5-foot Cube). The quality of any fabricated objects is based on the quality of the raw materials.<br><br>Creatures and magic items can’t be created by this spell. You also can’t use it to create items that require a high degree of skill—such as weapons and armor—unless you have <b>proficiency</b> with the type of <b>Artisan’s Tools</b> used to craft such objects.",
        	"fireShieldD": "Wispy flames wreathe your body for the duration, shedding <b>Bright Light</b> in a 10-foot radius and <b>Dim Light</b> for an additional 10 feet.<br><br>The flames provide you with a warm shield or a chill shield, as you choose. The warm shield grants you <b>Resistance to Cold damage</b>, and the chill shield grants you <b>Resistance to Fire damage</b>.<br><br>In addition, whenever a creature within 5 feet of you hits you with a melee attack roll, the shield erupts with flame. The attacker takes 2d8 Fire damage from a warm shield or 2d8 Cold damage from a chill shield.<br><br><b>Material:</b> a bit of phosphorus or a firefly.",
        	"fountOfMoonlightD": "A cool light wreathes your body for the duration, emitting <b>Bright Light</b> in a 20-foot radius and <b>Dim Light</b> for an additional 20 feet.<br><br>Until the spell ends, you have <b>Resistance to Radiant damage</b>, and your melee attacks deal an extra 2d6 Radiant damage on a hit.<br><br>In addition, immediately after you take damage from a creature you can see within 60 feet of yourself, you can take a <b>Reaction</b> to force the creature to make a <b>Constitution saving throw</b>. On a failed save, the creature has the <b>Blinded</b> condition until the end of your next turn.",
        	"freedomOfMovementD": "You touch a willing creature. For the duration, the target’s movement is unaffected by <b>Difficult Terrain</b>, and spells and other magical effects can neither reduce the target’s Speed nor cause the target to have the <b>Paralyzed</b> or <b>Restrained</b> conditions. The target also has a <b>Swim Speed</b> equal to its Speed.<br><br>In addition, the target can spend 5 feet of movement to automatically escape from nonmagical restraints, such as manacles or a creature imposing the <b>Grappled</b> condition on it.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target one additional creature for each spell slot level above 4.<br><br><b>Material:</b> a leather strap.",
        	"giantInsectD": "You summon a giant centipede, spider, or wasp (chosen when you cast the spell). It manifests in an unoccupied space you can see within range and uses the Giant Insect stat block. The form you choose determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends.<br><br>The creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the <b>Dodge action</b> and uses its movement to avoid danger.<br><br><b>Using a Higher-Level Spell Slot:</b> Use the spell slot’s level for the spell’s level in the stat block.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">giant insect</span>",
       	 "graspingVineD": "You conjure a vine that sprouts from a surface in an unoccupied space that you can see within range. The vine lasts for the duration.<br><br>Make a melee spell attack against a creature within 30 feet of the vine. On a hit, the target takes 4d8 Bludgeoning damage and is pulled up to 30 feet toward the vine; if the target is <b>Huge</b> or smaller, it has the <b>Grappled</b> condition (escape DC equal to your spell save DC). The vine can grapple only one creature at a time, and you can cause the vine to release a Grappled creature (no action required).<br><br>As a <b>Bonus Action</b> on your later turns, you can repeat the attack against a creature within 30 feet of the vine.<br><br><b>Using a Higher-Level Spell Slot:</b> The number of creatures the vine can grapple increases by one for each spell slot level above 4.",
        	"greaterInvisibilityD": "A creature you touch has the <b>Invisible</b> condition until the spell ends.",
        	"guardianOfFaithD": "A <b>Large</b> spectral guardian appears and hovers for the duration in an unoccupied space that you can see within range. The guardian occupies that space and is invulnerable, and it appears in a form appropriate for your deity or pantheon.<br><br>Any enemy that moves to a space within 10 feet of the guardian for the first time on a turn or starts its turn there makes a <b>Dexterity saving throw</b>, taking 20 Radiant damage on a failed save or half as much damage on a successful one. The guardian vanishes when it has dealt a total of 60 damage.",
        	"hallucinatoryTerrainD": "You make natural terrain in a 150-foot Cube in range look, sound, and smell like another sort of natural terrain. Thus, open fields or a road can be made to resemble a swamp, hill, crevasse, or some other difficult or impassable terrain. Manufactured structures, equipment, and creatures within the area aren’t changed.<br><br>The tactile characteristics of the terrain are unchanged, so creatures entering the area are likely to notice the illusion. If the difference isn’t obvious by touch, a creature examining the illusion can take the <b>Study action</b> to make an <b>Intelligence (Investigation)</b> check against your spell save DC to disbelieve it. If a creature discerns that the terrain is illusory, the creature sees a vague image superimposed on the real terrain.<br><br><b>Material:</b> a mushroom.",
        	"iceStormD": "Hail falls in a 20-foot-radius, 40-foot-high Cylinder centered on a point within range. Each creature in the Cylinder makes a <b>Dexterity saving throw</b>. A creature takes 2d10 Bludgeoning damage and 4d6 Cold damage on a failed save or half as much damage on a successful one.<br><br>Hailstones turn ground in the Cylinder into <b>Difficult Terrain</b> until the end of your next turn.<br><br><b>Using a Higher-Level Spell Slot:</b> The Bludgeoning damage increases by 1d10 for each spell slot level above 4.<br><br><b>Material:</b> a mitten.",
        	"locateCreatureD": "Describe or name a creature that is familiar to you. You sense the direction to the creature’s location if that creature is within 1,000 feet of you. If the creature is moving, you know the direction of its movement.<br><br>The spell can locate a specific creature known to you or the nearest creature of a specific kind (such as a human or a unicorn) if you have seen such a creature up close—within 30 feet—at least once. If the creature you described or named is in a different form, such as under the effects of a Flesh to Stone or Polymorph spell, this spell doesn’t locate the creature.<br><br>This spell can’t locate a creature if any thickness of lead blocks a direct path between you and the creature.<br><br><b>Material:</b> fur from a bloodhound.",
        	"phantasmalKillerD": "You tap into the nightmares of a creature you can see within range and create an illusion of its deepest fears, visible only to that creature. The target makes a <b>Wisdom saving throw</b>. On a failed save, the target takes 4d10 Psychic damage and has <b>Disadvantage</b> on ability checks and attack rolls for the duration. On a successful save, the target takes half as much damage, and the spell ends.<br><br>For the duration, the target makes a Wisdom saving throw at the end of each of its turns. On a failed save, it takes the Psychic damage again. On a successful save, the spell ends.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d10 for each spell slot level above 4.",
        	"polymorphD": "You attempt to transform a creature that you can see within range into a <b>Beast</b>. The target must succeed on a <b>Wisdom saving throw</b> or shape-shift into Beast form for the duration. That form can be any Beast you choose that has a <b>Challenge Rating</b> equal to or less than the target’s (or the target’s level if it doesn’t have a Challenge Rating). The target’s game statistics are replaced by the stat block of the chosen Beast, but the target retains its alignment, personality, creature type, Hit Points, and Hit Point Dice.<br><br>The target gains a number of <b>Temporary Hit Points</b> equal to the Hit Points of the Beast form. The spell ends early on the target if it has no Temporary Hit Points left.<br><br>The target is limited in the actions it can perform by the anatomy of its new form, and it can’t speak or cast spells. The target’s gear melds into the new form.<br><br><b>Material:</b> a caterpillar cocoon.",
        	"staggeringSmiteD": "The target takes an extra 4d6 Psychic damage from the attack, and the target must succeed on a <b>Wisdom saving throw</b> or have the <b>Stunned</b> condition until the end of your next turn.<br><br><b>Using a Higher-Level Spell Slot:</b> The extra damage increases by 1d6 for each spell slot level above 4.<br><br><b>Bonus Action:</b> which you take immediately after hitting a creature with a Melee weapon or an Unarmed Strike.",
        	"stoneShapeD": "You touch a stone object of <b>Medium</b> size or smaller or a section of stone no more than 5 feet in any dimension and form it into any shape you like. For example, you could shape a large rock into a weapon, statue, or coffer, or you could make a small passage through a wall that is 5 feet thick. The object you create can have up to two hinges and a latch, but finer mechanical detail isn’t possible.<br><br><b>Material:</b> soft clay.",
        	"stoneskinD": "Until the spell ends, one willing creature you touch has <b>Resistance</b> to Bludgeoning, Piercing, and Slashing damage.<br><br><b>Material:</b> diamond dust worth 100+ GP, which the spell consumes.",
       	"summonAberrationD": "You call forth an aberrant spirit. It manifests in an unoccupied space that you can see within range and uses the Aberrant Spirit stat block. When you cast the spell, choose <b>Beholderkin, Mind Flayer, or Slaad</b>. The creature resembles an Aberration of that kind, which determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends.<br><br>The creature is an ally to you and your allies. In combat, it shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the <b>Dodge action</b> and uses its movement to avoid danger.<br><br><b>Using a Higher-Level Spell Slot:</b> Use the spell slot’s level for the spell’s level in the stat block.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">aberrant spirit</span><br><br><b>Material:</b> a pickled tentacle and an eyeball in a platinum-inlaid vial worth 400+ GP.",
       	 "summonConstructD": "You call forth the spirit of a <b>Construct</b>. It manifests in an unoccupied space that you can see within range and uses the Construct Spirit stat block. When you cast the spell, choose a material: <b>Clay, Metal, or Stone</b>. The creature resembles an animate statue (you determine the appearance) made of the chosen material, which determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends.<br><br>The creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the <b>Dodge action</b> and uses its movement to avoid danger.<br><br><b>Using a Higher-Level Spell Slot:</b> Use the spell slot’s level for the spell’s level in the stat block.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">construct spirit</span><br><br><b>Material:</b> a lockbox worth 400+ GP.",
       	"summonElementalD": "You call forth an <b>Elemental spirit</b>. It manifests in an unoccupied space that you can see within range and uses the Elemental Spirit stat block. When you cast the spell, choose an element: <b>Air, Earth, Fire, or Water</b>. The creature resembles a bipedal form wreathed in the chosen element, which determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends.<br><br>The creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the <b>Dodge action</b> and uses its movement to avoid danger.<br><br><b>Using a Higher-Level Spell Slot:</b> Use the spell slot’s level for the spell’s level in the stat block.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">elemental spirit</span><br><br><b>Material:</b> air, a pebble, ash, and water inside a gold-inlaid vial worth 400+ GP.",
        "vitriolicSphereD": "You point at a location within range, and a glowing, 1-foot-diameter ball of acid streaks there and explodes in a 20-foot-radius Sphere. Each creature in that area makes a <b>Dexterity saving throw</b>. On a failed save, a creature takes 10d4 Acid damage and another 5d4 Acid damage at the end of its next turn. On a successful save, a creature takes half the initial damage only.<br><br><b>Using a Higher-Level Spell Slot:</b> The initial damage increases by 2d4 for each spell slot level above 4.<br><br><b>Material:</b> a drop of bile.",
        	"wallOfFireD": "You create a wall of fire on a solid surface within range. You can make the wall up to 60 feet long, 20 feet high, and 1 foot thick, or a ringed wall up to 20 feet in diameter, 20 feet high, and 1 foot thick. The wall is opaque and lasts for the duration.<br><br>When the wall appears, each creature in its area makes a <b>Dexterity saving throw</b>, taking 5d8 Fire damage on a failed save or half as much damage on a successful one.<br><br>One side of the wall, selected by you when you cast this spell, deals 5d8 Fire damage to each creature that ends its turn within 10 feet of that side or inside the wall. The other side of the wall deals no damage.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 4.<br><br><b>Material:</b> a piece of charcoal.",
        	"animateObjectsD": "Objects animate at your command. Choose a number of nonmagical objects within range that aren’t being worn or carried, aren’t fixed to a surface, and aren’t Gargantuan. The maximum number of objects is equal to your spellcasting ability modifier; for this number, a <b>Medium</b> or smaller target counts as one object, a <b>Large</b> target counts as two, and a <b>Huge</b> target counts as three.<br><br>Each target animates, sprouts legs, and becomes a Construct that uses the <b>Animated Object</b> stat block; this creature is under your control until the spell ends or until it is reduced to 0 Hit Points. Each creature you make with this spell is an ally to you and your allies. In combat, it shares your Initiative count and takes its turn immediately after yours.<br><br>Until the spell ends, you can take a <b>Bonus Action</b> to mentally command any creature you made with this spell if the creature is within 500 feet of you. If you issue no commands, the creature takes the <b>Dodge action</b> and moves only to avoid harm.<br><br><b>Using a Higher-Level Spell Slot:</b> The creature’s Slam damage increases by 1d4 (Medium or smaller), 1d6 (Large), or 1d12 (Huge) for each spell slot level above 5.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">animated object</span>",
        	"antilifeShellD": "An aura extends from you in a 10-foot <b>Emanation</b> for the duration. The aura prevents creatures other than Constructs and Undead from passing or reaching through it. An affected creature can cast spells or make attacks with Ranged or Reach weapons through the barrier.<br><br>If you move so that an affected creature is forced to pass through the barrier, the spell ends.",
        	"awakenD": "You spend the casting time tracing magical pathways within a precious gemstone, and then touch the target. The target must be either a <b>Beast or Plant creature</b> with an Intelligence of 3 or less or a natural plant that isn’t a creature. The target gains an Intelligence of 10 and the ability to speak one language you know. If the target is a natural plant, it becomes a Plant creature and gains the ability to move its limbs and gains senses similar to a human’s.<br><br>The awakened target has the <b>Charmed</b> condition for 30 days or until you or your allies deal damage to it. When that condition ends, the awakened creature chooses its attitude toward you.<br><br><b>Material:</b> an agate worth 1,000+ GP, which the spell consumes.",
        	"banishingSmiteD": "The target hit by the attack roll takes an extra 5d10 <b>Force damage</b> from the attack. If the attack reduces the target to 50 Hit Points or fewer, the target must succeed on a <b>Charisma saving throw</b> or be transported to a harmless demiplane for the duration. While there, the target has the <b>Incapacitated</b> condition. When the spell ends, the target reappears in the space it left.<br><br><b>Bonus Action:</b> which you take immediately after hitting a creature with a Melee weapon or an Unarmed Strike.",
        	"circleOfPowerD": "An aura radiates from you in a 30-foot <b>Emanation</b> for the duration. While in the aura, you and your allies have <b>Advantage</b> on saving throws against spells and other magical effects. When an affected creature makes a saving throw against a spell or magical effect that allows a save to take only half damage, it takes no damage if it succeeds on the save.",
        	"cloudkillD": "You create a 20-foot-radius Sphere of yellow-green fog centered on a point within range. The fog lasts for the duration or until strong wind disperses it. Its area is <b>Heavily Obscured</b>.<br><br>Each creature in the Sphere makes a <b>Constitution saving throw</b>, taking 5d8 Poison damage on a failed save or half as much damage on a successful one. A creature must also make this save when the Sphere moves into its space and when it enters the Sphere or ends its turn there. The Sphere moves 10 feet away from you at the start of each of your turns.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 5.",
       	"communeD": "You contact a deity or a divine proxy and ask up to three questions that can be answered with <b>yes or no</b>. You must ask your questions before the spell ends. You receive a correct answer for each question.<br><br>If you cast the spell more than once before finishing a <b>Long Rest</b>, there is a cumulative 25 percent chance for each casting after the first that you get no answer.<br><br><b>Material:</b> incense.",
        	"communeWithNatureD": "You commune with nature spirits and gain knowledge of the surrounding area. In the outdoors, the spell gives you knowledge of the area within 3 miles of you. In caves, the radius is limited to 300 feet. The spell doesn’t function where nature has been replaced by construction.<br><br>Choose three of the following facts: settlement locations, portal locations, location of a <b>CR 10+</b> creature, prevalent kind of plant/mineral/Beast, or locations of bodies of water.",
        	"coneOfColdD": "You unleash a blast of cold air. Each creature in a 60-foot <b>Cone</b> originating from you makes a <b>Constitution saving throw</b>, taking 8d8 Cold damage on a failed save or half as much damage on a successful one. A creature killed by this spell becomes a frozen statue until it thaws.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 1d8 for each spell slot level above 5.<br><br><b>Material:</b> a small crystal or glass cone.",
        	"conjureElementalD": "You conjure a <b>Large</b>, intangible spirit from the Elemental Planes. Choose the spirit’s element: <b>air (Lightning), earth (Thunder), fire (Fire), or water (Cold)</b>.<br><br>Whenever a creature enters the spirit’s space or starts its turn within 5 feet of it, you can force it to make a <b>Dexterity saving throw</b>. On failed save, the target takes 8d8 damage of the spirit’s type, and the target has the <b>Restrained</b> condition until the spell ends. At the start of each of its turns, the Restrained target repeats the save, taking 4d8 damage on a failure.<br><br><b>Using a Higher-Level Spell Slot:</b> The damage increases by 2d8 for each spell slot level above 5.",
        	"conjureVollerD": "You brandish the weapon used to cast the spell and choose a point within range. Hundreds of similar spectral weapons fall in a volley. Each creature of your choice in a 40-foot-radius, 20-foot-high Cylinder centered on that point makes a <b>Dexterity saving throw</b>, taking 8d8 <b>Force damage</b> on a failed save or half as much damage on a successful one.<br><br><b>Material:</b> a Melee or Ranged weapon worth at least 1 CP.",
        	"contactOtherPlaneD": "You mentally contact a demigod or other knowledgeable entity. Make a <b>DC 15 Intelligence saving throw</b>. On a success, you can ask the entity up to five questions. The DM answers each question with one word.<br><br>On a failed save, you take 6d6 Psychic damage and have the <b>Incapacitated</b> condition until you finish a <b>Long Rest</b>.<br><br><b>Material:</b> a Greater Restoration spell cast on you ends this effect.",
        	"contagionD": "Your touch inflicts a magical contagion. The target must succeed on a <b>Constitution saving throw</b> or take 11d8 <b>Necrotic damage</b> and have the <b>Poisoned</b> condition. While Poisoned, the target has Disadvantage on saving throws made with one chosen ability.<br><br>The target repeats the saving throw at the end of each of its turns until it gets three successes or failures. If it fails three, the spell lasts for 7 days.",
        	"creationD": "You pull wisps of shadow material from the <b>Shadowfell</b> to create an object within range. It is either vegetable matter or mineral matter. The object must be no larger than a 5-foot Cube.<br><br>The spell’s duration depends on the material:<br><br><table class=\"spell-table\"><caption>Shadow Material</caption><tr><th>Material</th><th>Duration</th></tr><tr><td>Vegetable matter</td><td>24 hours</td></tr><tr><td>Stone or crystal</td><td>12 hours</td></tr><tr><td>Precious metals</td><td>1 hour</td></tr><tr><td>Gems</td><td>10 minutes</td></tr><tr><td>Adamantine or mithral</td><td>1 minute</td></tr></table><br><b>Using a Higher-Level Spell Slot:</b> The Cube increases by 5 feet for each spell slot level above 5.<br><br><b>Material:</b> a paintbrush.",
    "destructiveWaveD": "Destructive energy ripples outward from you in a 30-foot Emanation. Each chosen creature must make a <b>Constitution saving throw</b>. On a failed save, a target takes 5d6 Thunder damage and 5d6 Radiant or Necrotic damage (your choice) and has the <b>Prone</b> condition. On a successful save, a target takes half as much damage only.",
    "dispelEvilAndGoodD": "For the duration, Celestials, Elementals, Fey, Fiends, and Undead have <b>Disadvantage</b> on attack rolls against you. You can end the spell early to use:<ul><li><b>Break Enchantment:</b> As a Magic action, touch a creature possessed, Charmed, or Frightened by such beings to end those conditions.</li><li><b>Dismissal:</b> As a Magic action, target a creature within 5 feet. It must succeed on a <b>Charisma saving throw</b> or be sent back to its home plane.</li></ul><br><b>Material:</b> powdered silver and iron.",
    "dominatePersonD": "One Humanoid must succeed on a <b>Wisdom saving throw</b> or have the <b>Charmed</b> condition. The target has Advantage on the save if you are fighting it. It repeats the save whenever it takes damage. You have a telepathic link to issue commands (no action required). You can command it to take a Reaction, but must spend your own to do so.<br><br><b>Using a Higher-Level Spell Slot:</b> Concentration lasts longer: level 6 (10 mins), 7 (1 hr), or 8+ (8 hrs).",
    "dreamD": "You target a creature you know. You or a willing creature enter a trance to act as a dream messenger. While in the trance, the messenger is <b>Incapacitated</b> and has a Speed of 0. If the target is asleep, the messenger appears in its dreams. You can make the messenger terrifying: the target makes a <b>Wisdom saving throw</b>; on a failure, it gains no benefit from rest and takes 3d6 Psychic damage.<br><br><b>Material:</b> a handful of sand.",
    "flameStrikeD": "A vertical column of brilliant fire roars down. Each creature in a 10-foot-radius, 40-foot-high Cylinder must make a <b>Dexterity saving throw</b>, taking 5d6 Fire damage and 5d6 Radiant damage on a failure (half on success).<br><br><b>Using a Higher-Level Spell Slot:</b> Fire and Radiant damage increase by 1d6 each per level above 5.<br><br><b>Material:</b> a pinch of sulfur.",
    "geasD": "You give a verbal command ordering a service or refraining from action. The target must succeed on a <b>Wisdom saving throw</b> or have the <b>Charmed</b> condition. While Charmed, it takes 5d10 Psychic damage if it acts counter to your command (max once per day). Suicidal commands end the spell.<br><br><b>Using a Higher-Level Spell Slot:</b> Level 7-8 duration is 365 days. Level 9 lasts until dispelled.",
    "greaterRestorationD": "You touch a creature and magically remove one effect: 1 exhaustion level, Charmed or Petrified condition, a curse (including attunement), ability score reduction, or HP maximum reduction.<br><br><b>Material:</b> diamond dust worth 100+ GP, which the spell consumes.",
    "hallowD": "You infuse an area (up to 60-foot radius) with holy or unholy power.<br><br><b>Hallowed Ward:</b> Specific creature types cannot enter, and possession/Charm/Fear from them is suppressed.<br><br><b>Extra Effect:</b> Bind an effect like Courage, Darkness, Daylight, Peaceful Rest, Interference, Fear, Resistance, Silence, Tongues, or Vulnerability.<br><br><b>Material:</b> incense worth 1,000+ GP, which the spell consumes.",
    "holdMonsterD": "Choose a creature within range. The target must succeed on a <b>Wisdom saving throw</b> or have the <b>Paralyzed</b> condition. At the end of each of its turns, the target repeats the save.<br><br><b>Using a Higher-Level Spell Slot:</b> Target one additional creature for each level above 5.<br><br><b>Material:</b> a straight piece of iron.",
    "insectPlagueD": "Swarming locusts fill a 20-foot-radius Sphere. Area is <b>Lightly Obscured</b> and <b>Difficult Terrain</b>. Each creature makes a <b>Constitution saving throw</b>, taking 4d10 Piercing damage on a failure (half on success).<br><br><b>Using a Higher-Level Spell Slot:</b> Damage increases by 1d10 per level above 5.<br><br><b>Material:</b> a locust.",
    "jallarzisStormOfRadianceD": "A storm of light and thunder in a 10-foot-radius, 40-foot Cylinder. Creatures have <b>Blinded</b> and <b>Deafened</b> conditions and can't cast Verbal spells. Each creature makes a <b>Constitution saving throw</b>, taking 2d10 Radiant and 2d10 Thunder damage.<br><br><b>Using a Higher-Level Spell Slot:</b> Damage increases by 1d10 each per level above 5.<br><br><b>Material:</b> a pinch of phosphorus.",
    "legendLoreD": "Name or describe a famous person, place, or object. The spell brings to mind significant lore. Accurate but potentially figurative. Fails if the subject isn't actually famous.<br><br><b>Material:</b> incense (250+ GP) and four ivory strips (50+ GP each).",
    "massCureWoundsD": "A wave of healing energy in a 30-foot-radius Sphere. Up to six creatures each regain <b>Hit Points</b> equal to 5d8 plus your spellcasting ability modifier.<br><br><b>Using a Higher-Level Spell Slot:</b> Healing increases by 1d8 per level above 5.",
    "misleadD": "You gain the <b>Invisible</b> condition and an illusory double appears. Invisibility ends if you attack or cast. As a Magic action, move the double up to twice your Speed and see/hear through it.",
    "modifyMemoryD": "Reshape a creature's memories (Wisdom save). Target is <b>Charmed</b> and <b>Incapacitated</b>. You can alter an event from the last 24 hours that lasted no more than 10 minutes.<br><br><b>Using a Higher-Level Spell Slot:</b> Memories from up to 7 days (lvl 6), 30 days (lvl 7), 365 days (lvl 8), or any time (lvl 9).",
    "passwallD": "A passage appears in wood, plaster, or stone (up to 5x8x20 feet). No instability is caused. Creatures are safely ejected when it ends.<br><br><b>Material:</b> a pinch of sesame seeds.",
    "planarBindingD": "Bind a Celestial, Elemental, Fey, or Fiend to your service (Charisma save). Must stay in range for the 1-hour casting. Bound creatures follow commands but Hostile ones may twist them.<br><br><b>Using a Higher-Level Spell Slot:</b> Duration: 10 days (lvl 6), 30 days (lvl 7), 180 days (lvl 8), or 366 days (lvl 9).<br><br><b>Material:</b> a jewel worth 1,000+ GP, which the spell consumes.",
    "raiseDeadD": "Revive a creature dead no longer than 10 days. Returns with 1 HP. Neutralizes poisons and closes wounds (no limb restoration). Target takes <b>−4 penalty</b> to D20 Tests, reducing by 1 per Long Rest.<br><br><b>Material:</b> a diamond worth 500+ GP, which the spell consumes.",
    "rarysTelepathicBondD": "Forge a telepathic link among up to eight willing creatures. They can communicate telepathically as long as they are on the same plane.",
    "reincarnateD": "Form a new body for a dead Humanoid (< 10 days dead). Soul enters and retains memories but gains new traits:<br><br><table class=\"spell-table\"><caption>Reincarnations</caption><tr><th>1d10</th><th>Species</th></tr><tr><td>1</td><td>Aasimar</td></tr><tr><td>2</td><td>Dragonborn</td></tr><tr><td>3</td><td>Dwarf</td></tr><tr><td>4</td><td>Elf</td></tr><tr><td>5</td><td>Gnome</td></tr><tr><td>6</td><td>Goliath</td></tr><tr><td>7</td><td>Halfling</td></tr><tr><td>8</td><td>Human</td></tr><tr><td>9</td><td>Orc</td></tr><tr><td>10</td><td>Tiefling</td></tr></table><br><b>Material:</b> rare oils worth 1,000+ GP, which the spell consumes.",
    "scryingD": "See and hear a creature on the same plane (Wisdom save).<br><br><table class=\"spell-table\"><caption>Knowledge</caption><tr><th>Familiarity</th><th>Save Modifier</th></tr><tr><td>Secondhand</td><td>+5</td></tr><tr><td>Firsthand</td><td>+0</td></tr><tr><td>Extensive</td><td>−5</td></tr></table><br><table class=\"spell-table\"><caption>Physical Connection</caption><tr><th>Connection</th><th>Save Modifier</th></tr><tr><td>Picture/Likeness</td><td>−2</td></tr><tr><td>Possession</td><td>−4</td></tr><tr><td>Body part/Hair</td><td>−10</td></tr></table><br>On failure, an Invisible sensor appears within 10 feet of the target.<br><br><b>Material:</b> focus worth 1,000+ GP.",
"seemingD": "You give an illusory appearance to each creature of your choice that you can see within range. An unwilling target can make a <b>Charisma saving throw</b> to be unaffected. You can give the same appearance or different ones. The spell can change bodies and equipment, including height by up to 1 foot. The changes fail physical inspection. A creature can take a <b>Study action</b> (Intelligence (Investigation) check) to discern the disguise.",
    "steelWindStrikeD": "You flourish your weapon and strike like the wind. Choose up to five creatures within range and make a melee spell attack against each. On a hit, a target takes 6d10 Force damage. Then, teleport to an unoccupied space within 5 feet of one target.<br><br><b>Material:</b> a Melee weapon worth 1+ SP.",
    "summonCelestialD": "You call forth a Celestial spirit in an angelic form. It manifests in an unoccupied space and uses the <b>Celestial Spirit</b> stat block. Choose <b>Avenger or Defender</b>. The creature is an ally and shares your Initiative. It obeys your verbal commands or takes the Dodge action.<br><br><b>Using a Higher-Level Spell Slot:</b> Use the spell slot’s level for the stat block.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">celestial spirit</span><br><br><b>Material:</b> a reliquary worth 500+ GP.",
    "summonDragonD": "You call forth a Dragon spirit. It manifests in an unoccupied space and uses the <b>Draconic Spirit</b> stat block. The creature is an ally and shares your Initiative. It obeys your verbal commands (no action required) or takes the Dodge action.<br><br><b>Using a Higher-Level Spell Slot:</b> Use the spell slot’s level for the stat block.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">dragon spirit</span><br><br><b>Material:</b> a dragon-engraved object worth 500+ GP.",
    "swiftQuiverD": "When you cast the spell and as a <b>Bonus Action</b> until it ends, you can make two attacks with a weapon that fires Arrows or Bolts. The spell magically creates the ammunition, which disintegrates after hitting or missing.<br><br><b>Material:</b> a Quiver worth 1+ GP.",
    "synapticStaticD": "Psychic energy erupts in a 20-foot-radius Sphere. Each creature must make an <b>Intelligence saving throw</b>, taking 8d6 Psychic damage on a failure. On a failed save, a target's thoughts are muddled for 1 minute, subtracting 1d6 from attack rolls, ability checks, and Concentration saves.",
    "telekinesisD": "Manipulate creatures or objects by thought. As a <b>Magic action</b>, you can exert your will: <b>Creature:</b> Move a Huge or smaller target up to 30 feet (Strength save) and it becomes <b>Restrained</b>. <b>Object:</b> Move a Huge or smaller object up to 30 feet. You can exert fine control on objects like tools or vials.",
    "teleportationCircleD": "Draw a 5-foot-radius circle that links your location to a permanent teleportation circle. A portal opens until the end of your next turn. You can create a permanent circle by casting this spell in the same location every day for 365 days.<br><br><b>Material:</b> rare inks worth 50+ GP.",
    "treeStrideD": "You gain the ability to enter a tree and move to another of the same kind within 500 feet. Entering costs 5 feet of movement. You appear within 5 feet of the destination tree. You can use this once per turn and must end your turn outside a tree.",
    "wallOfForceD": "An Invisible wall of force springs into existence. It can be a hemispherical dome (10-foot radius) or ten 10-foot-square panels. It is 1/4 inch thick and immune to all damage. It blocks ethereal travel and cannot be dispelled, though <i>Disintegrate</i> destroys it.<br><br><b>Material:</b> a shard of glass.",
    "wallOfStoneD": "A nonmagical stone wall appears (ten 10x10-foot panels, 6 inches thick; or 10x20-foot panels, 3 inches thick). It must be supported by existing stone. Concentration for 10 minutes makes it permanent. Panels have AC 15 and 30 HP per inch of thickness.<br><br><b>Material:</b> a cube of granite.",
    "yolandesRegalPresenceD": "Surround yourself with unearthly majesty in a 10-foot <b>Emanation</b>. Each chosen creature must make a <b>Wisdom saving throw</b> or take 4d6 Psychic damage, be pushed 10 feet, and have the <b>Prone</b> condition.<br><br><b>Material:</b> a miniature tiara.",
    "arcaneGateD": "Create linked teleportation portals in two Large spaces (one in range, one within 10 feet of you). Mist-filled rings hover near the ground. Entry to one side leads to exit from the other. Use a <b>Bonus Action</b> to change facing.",
    "bladeBarrierD": "Create a wall of whirling blades (100 feet long or 60-foot diameter). Provides <b>Three-Quarters Cover</b> and <b>Difficult Terrain</b>. Creatures in the area make a <b>Dexterity saving throw</b> or take 6d10 Force damage.",
    "chainLightningD": "Launch a lightning bolt at a target; three bolts then leap to other targets within 30 feet. Each target makes a <b>Dexterity saving throw</b> and takes 10d8 Lightning damage.<br><br><b>Using a Higher-Level Spell Slot:</b> One additional bolt per level above 6.<br><br><b>Material:</b> three silver pins.",
    "circleOfDeathD": "Negative energy ripples in a 60-foot-radius Sphere. Each creature makes a <b>Constitution saving throw</b>, taking 8d8 Necrotic damage on a failure.<br><br><b>Using a Higher-Level Spell Slot:</b> Damage increases by 2d8 per level above 6.<br><br><b>Material:</b> crushed black pearl powder (500+ GP).",
    "conjureFeyD": "Conjure a Medium spirit from the Feywild. When it appears, make a melee spell attack against a creature within 5 feet (3d12 + mod Psychic damage and <b>Frightened</b> condition). Teleport the spirit 30 feet as a <b>Bonus Action</b> to repeat the attack.<br><br><b>Using a Higher-Level Spell Slot:</b> Damage increases by 2d12 per level above 6.",
    "contingencyD": "Choose a spell of level 5 or lower (1 action casting time, targets you). Cast it as part of Contingency; it takes effect only when a specified trigger occurs. Only one Contingency can be active at a time.<br><br><b>Material:</b> a gem-encrusted statuette of yourself (1,500+ GP).",
    "createUndeadD": "Cast at night only. Choose up to three corpses to become <b>Ghouls</b> under your control. Command them as a <b>Bonus Action</b>. Re-cast within 24 hours to maintain control.<br><br><b>Using a Higher-Level Spell Slot:</b> Higher levels allow for more Ghouls or more powerful undead like Ghasts, Wights, or Mummies.<br><br><b>Material:</b> one black onyx (150+ GP) per corpse.",
    "disintegrateD": "Launch a green ray. Target makes a <b>Dexterity saving throw</b>, taking 10d6 + 40 Force damage. If reduced to 0 HP, it is disintegrated. Nonmagical objects (Large or smaller) are automatically disintegrated; larger objects lose a 10-foot-Cube portion.<br><br><b>Using a Higher-Level Spell Slot:</b> Damage increases by 3d6 per level above 6.<br><br><b>Material:</b> a lodestone and dust.",
"eyebiteD": "For the duration, your eyes become an inky void. One creature of your choice within 60 feet of you that you can see must succeed on a <b>Wisdom saving throw</b> or be affected by one of the following effects of your choice for the duration.<br><br>On each of your turns until the spell ends, you can take a <b>Magic action</b> to target another creature but can’t target a creature again if it has succeeded on a save against this casting of the spell.<ul><li><b>Asleep:</b> The target has the <b>Unconscious</b> condition. It wakes up if it takes any damage or if another creature takes an action to shake it awake.</li><li><b>Panicked:</b> The target has the <b>Frightened</b> condition. On each of its turns, the Frightened target must take the <b>Dash action</b> and move away from you by the safest and shortest route available. If the target moves to a space at least 60 feet away from you where it can’t see you, this effect ends.</li><li><b>Sickened:</b> The target has the <b>Poisoned</b> condition.</li></ul>",
    "findThePathD": "You magically sense the most direct physical route to a location you name. You must be familiar with the location, and the spell fails if you name a destination on another plane of existence, a moving destination, or an unspecific destination.<br><br>For the duration, as long as you are on the same plane of existence as the destination, you know how far it is and in what direction it lies. Whenever you face a choice of paths along the way there, you know which path is the most direct.<br><br><b>Material:</b> a set of divination tools—such as cards or runes—worth 100+ GP.",
    "fleshToStoneD": "You attempt to turn one creature that you can see within range into stone. The target makes a <b>Constitution saving throw</b>. On a failed save, it has the <b>Restrained</b> condition for the duration. On a successful save, its Speed is 0 until the start of your next turn. Constructs automatically succeed on the save.<br><br>A Restrained target makes another Constitution saving throw at the end of each of its turns. If it successfully saves three times, the spell ends. If it fails three times, it is turned to stone and has the <b>Petrified</b> condition for the duration. If you maintain your <b>Concentration</b> for the entire possible duration, the target is Petrified until the condition is ended by magic.<br><br><b>Material:</b> a cockatrice feather.",
    "forbiddanceD": "You create a ward against magical travel that protects up to 40,000 square feet of floor space to a height of 30 feet above the floor. Creatures can’t teleport into the area or use portals to enter. The spell proofs the area against planar travel.<br><br>In addition, the spell damages chosen creature types (Aberrations, Celestials, Elementals, Fey, Fiends, or Undead). Affected creatures take 5d10 Radiant or Necrotic damage when they enter or end their turn there. A password can prevent this. Casting it for 30 days makes it permanent.<br><br><b>Material:</b> ruby dust worth 1,000+ GP.",
    "globeOfInvulnerabilityD": "An immobile, shimmering barrier appears in a 10-foot <b>Emanation</b> around you. Any spell of level 5 or lower cast from outside can’t affect anything within it. The area within the barrier is excluded from areas of effect created by such spells.<br><br><b>Using a Higher-Level Spell Slot:</b> The barrier blocks spells of 1 level higher for each spell slot level above 6.<br><br><b>Material:</b> a glass bead.",
    "guardsAndWardsD": "You create a ward that protects up to 2,500 square feet of floor space. The warded area can be up to 20 feet tall. You shape it as one 50-foot square or contiguous 5-foot/10-foot squares.<br><br>The spell creates these effects:<ul><li><b>Corridors:</b> Fog makes them <b>Heavily Obscured</b>. 50% chance creatures believe they are going in the opposite direction.</li><li><b>Doors:</b> Magically locked (Arcane Lock). Up to ten doors can be hidden by illusions.</li><li><b>Stairs:</b> Webs fill stairs and regrow in 10 minutes.</li><li><b>Other Spell Effect:</b> Place one: Dancing Lights, Magic Mouth, Stinking Cloud, Gust of Wind, or Suggestion.</li></ul><br><b>Material:</b> a silver rod worth 10+ GP.",
    "harmD": "You unleash virulent magic. The target makes a <b>Constitution saving throw</b>. On a failed save, it takes 14d6 Necrotic damage, and its Hit Point maximum is reduced by that amount. On a success, it takes half as much damage only. HP maximum cannot be reduced below 1.",
    "healD": "Choose a creature in range. Positive energy restores 70 Hit Points and ends the <b>Blinded</b>, <b>Deafened</b>, and <b>Poisoned</b> conditions.<br><br><b>Using a Higher-Level Spell Slot:</b> The healing increases by 10 for each level above 6.",
    "magicJarD": "Your body falls catatonic as your soul enters a container. You can project your soul up to 100 feet to possess a Humanoid (<b>Charisma saving throw</b>). On success, you control the body, replacing physical stats but keeping mental ones. If the host dies or the container is destroyed, you risk death if your body is too far or dead.<br><br><b>Material:</b> a gem, crystal, or reliquary worth 500+ GP.",
    "massSuggestionD": "You suggest a course of activity (max 25 words) to up to twelve creatures. Targets must succeed on a <b>Wisdom saving throw</b> or have the <b>Charmed</b> condition and follow the suggestion.<br><br><b>Using a Higher-Level Spell Slot:</b> Duration is longer: lvl 7 (10 days), lvl 8 (30 days), lvl 9 (366 days).<br><br><b>Material:</b> a snake’s tongue.",
    "moveEarhtD": "Choose terrain (max 40-foot square). You reshape dirt, sand, or clay for the duration (raise elevation, trenches, etc.). Changes take 10 minutes to complete. Does not affect natural stone. You can choose a new area every 10 minutes.<br><br><b>Material:</b> a miniature shovel.",
    "planarAllyD": "Beseech an otherworldly entity for aid. It sends a Celestial, Elemental, or Fiend. You must bargain for its services. Standard rates are 100 GP/min, 1,000 GP/hr, or 10,000 GP/day. The creature returns home after the task.",
    "programmedIllusionD": "Create an illusion (max 30-foot Cube) that activates on a trigger. Scripted performance lasts up to 5 minutes, then goes dormant for 10 minutes. <b>Study action</b> can discern it as an illusion.<br><br><b>Material:</b> jade dust worth 25+ GP.",
    "summonFiendD": "You call forth a fiendish spirit. Choose <b>Demon, Devil, or Yugoloth</b>. The creature is an ally, shares your Initiative, and obeys your verbal commands.<br><br><b>Using a Higher-Level Spell Slot:</b> Use the spell slot’s level for the stat block.<br><br><b>Summonable creature:</b> <span class=\"spell-summon-link\">fiendish spirit</span><br><br><b>Material:</b> a bloody vial worth 600+ GP.",
    "sunbeamD": "You launch a sunbeam in a 5-foot-wide, 60-foot-long Line. Creatures make a <b>Constitution saving throw</b> or take 6d8 Radiant damage and the <b>Blinded</b> condition. You can create a new Line as a <b>Magic action</b>. Brilliant sunlight shines above you (30-foot radius).<br><br><b>Material:</b> a magnifying glass.",
    "tasha'sBubblingCauldronD": "You conjure a cauldron filled with liquid that duplicates a <b>Common or Uncommon</b> potion. As a <b>Bonus Action</b>, you or an ally can withdraw potions (limit equal to spellcasting modifier).<br><br><b>Material:</b> a gilded ladle worth 500 + GP.",
    "transportViaPlantsD": "Create a magical link between two <b>Large</b> inanimate plants on the same plane. Creatures can step into one and exit the other using 5 feet of movement.",
    "trueSeeingD": "Grant a willing creature <b>Truesight</b> with a range of 120 feet.<br><br><b>Material:</b> mushroom powder worth 25+ GP, which the spell consumes.",
    "wallOfIceD": "Create a wall of ice (dome or panels). On appearance, creatures make a <b>Dexterity saving throw</b> against 10d6 Cold damage. Destroyed sections leave frigid air (5d6 Cold damage on a <b>Constitution save</b>).<br><br><b>Using a Higher-Level Spell Slot:</b> Damage increases by 2d6/1d6 per level above 6.<br><br><b>Material:</b> a piece of quartz.",
    "wallOfThornsD": "Create a wall of thorns blocking line of sight. Deals 7d8 Piercing damage (Dexterity save) on appearance. Movement costs 4 feet per 1 foot. Entry or ending turn in the wall deals 7d8 Slashing damage.<br><br><b>Using a Higher-Level Spell Slot:</b> Both damage types increase by 1d8 per level above 6.<br><br><b>Material:</b> a handful of thorns.",
    "windWalkD": "You and ten creatures assume gaseous forms. <b>Fly Speed of 300 feet</b>, hover, and damage resistance. Reverting takes 1 minute (<b>Stunned</b> condition).<br><br><b>Material:</b> a candle.",
    "wordOfRecallD": "You and up to five willing creatures teleport to a previously designated sanctuary. You must prepare the location by casting this spell there beforehand.",
    "conjureCelestialD": "Conjure a spirit as a pillar of light (10-foot radius). Choose for each creature: <b>Healing Light</b> (4d12 + mod HP) or <b>Searing Light</b> (6d12 Radiant damage, Dexterity save). Move the pillar 30 feet per turn.<br><br><b>Using a Higher-Level Spell Slot:</b> Healing and damage increase by 1d12 per level above 7.",
    "delayedBlastFireballD": "A yellow beam condenses into a bead, exploding at the end of the duration (20-foot radius). Base damage 12d6 Fire, +1d6 per turn. Creatures can catch and throw the bead (40 feet) with a <b>Dexterity save</b>.<br><br><b>Using a Higher-Level Spell Slot:</b> Base damage increases by 1d6 per level above 7.<br><br><b>Material:</b> a ball of bat guano and sulfur.",
    "divineWordD": "You utter a word of power. Chosen creatures make a <b>Charisma saving throw</b>. Targets with 50 HP or fewer suffer effects:<br><br><table class=\"spell-table\"><caption>Divine Word Effects</caption><tr><th>Hit Points</th><th>Effect</th></tr><tr><td>0–20</td><td>The target dies.</td></tr><tr><td>21–30</td><td>Blinded, Deafened, and Stunned for 1 hour.</td></tr><tr><td>31–40</td><td>Blinded and Deafened for 10 minutes.</td></tr><tr><td>41–50</td><td>Deafened for 1 minute.</td></tr></table><br>Planar creatures failing the save are banished.",
"etherealnessD": "You step into the border regions of the Ethereal Plane, where it overlaps with your current plane. You remain in the Border Ethereal for the duration. During this time, you can move in any direction. If you move up or down, every foot of movement costs an extra foot. You can perceive the plane you left, which looks gray, and you can’t see anything there more than 60 feet away.<br><br>While on the Ethereal Plane, you can affect and be affected only by creatures, objects, and effects on that plane. Creatures that aren’t on the Ethereal Plane can’t perceive or interact with you unless a feature gives them the ability to do so.<br><br>When the spell ends, you return to the plane you left in the spot that corresponds to your space in the Border Ethereal. If you appear in an occupied space, you are shunted to the nearest unoccupied space and take Force damage equal to twice the number of feet you are moved.<br><br>This spell ends instantly if you cast it while you are on the Ethereal Plane or a plane that doesn’t border it, such as one of the Outer Planes.<br><br><b>Using a Higher-Level Spell Slot:</b> You can target up to three willing creatures (including yourself) for each spell slot level above 7. The creatures must be within 10 feet of you when you cast the spell.",
    "fingerOfDeathD": "You unleash negative energy toward a creature you can see within range. The target makes a <b>Constitution saving throw</b>, taking 7d8 + 30 Necrotic damage on a failed save or half as much damage on a successful one.<br><br>A Humanoid killed by this spell rises at the start of your next turn as a <b>Zombie</b> that follows your verbal orders.",
    "fireStormD": "A storm of fire appears within range. The area of the storm consists of up to ten 10-foot Cubes, which you arrange as you like. Each Cube must be contiguous with at least one other Cube. Each creature in the area makes a <b>Dexterity saving throw</b>, taking 7d10 Fire damage on a failed save or half as much damage on a successful one.<br><br>Flammable objects in the area that aren’t being worn or carried start burning.",
    "forceageD": "An immobile, <b>Invisible</b>, Cube-shaped prison composed of magical force springs into existence around an area you choose within range. The prison can be a <b>cage</b> or a <b>solid box</b>, as you choose.<br><br>A prison in the shape of a cage can be up to 20 feet on a side and is made from 1/2-inch diameter bars. A prison in the shape of a box can be up to 10 feet on a side, creating a solid barrier that prevents matter from passing and blocks spells.<br><br>When you cast the spell, any creature completely inside is trapped. Creatures only partially within are pushed away. A creature inside can’t leave by nonmagical means. If it tries to use teleportation, it must first succeed on a <b>Charisma saving throw</b>. On a failed save, the creature doesn’t exit and wastes the spell. The cage extends into the Ethereal Plane, blocking ethereal travel. This spell can’t be dispelled by <b>Dispel Magic</b>.<br><br><b>Material:</b> ruby dust worth 1,500+ GP, which the spell consumes.",
    "mirageArcaneD": "You make terrain in an area up to 1 mile square look, sound, smell, and even feel like some other sort of terrain. Open fields can be made to resemble a swamp or hills. Manufactured structures and creatures aren’t changed. You can alter the appearance of structures or add them where none are present. The illusion includes audible, visual, tactile, and olfactory elements, so it can turn clear ground into <b>Difficult Terrain</b>. Any piece removed from the area disappears. Creatures with <b>Truesight</b> see through the illusion but can still physically interact with it.",
    "planeShiftD": "You and up to eight willing creatures who link hands in a circle are transported to a different plane of existence. You can specify a target destination in general terms and you appear in or near that destination, as determined by the DM. Alternatively, if you know the sigil sequence of a teleportation circle on another plane, this spell can take you to that circle.<br><br><b>Material:</b> a forked, metal rod worth 250+ GP and attuned to a plane of existence.",
    "powerWordFortifyD": "You fortify up to six creatures you can see within range. The spell bestows 120 <b>Temporary Hit Points</b>, which you divide among the spell’s recipients.",
    "prismaticSprayD": "Eight rays of light flash from you in a 60-foot Cone. Each creature in the Cone makes a <b>Dexterity saving throw</b>. For each target, roll 1d8 to determine the effect:<br><br><table class=\"spell-table\"><caption>Prismatic Rays</caption><tr><th>1d8</th><th>Ray & Effect</th></tr><tr><td>1</td><td><b>Red:</b> 12d6 Fire damage (half on success).</td></tr><tr><td>2</td><td><b>Orange:</b> 12d6 Acid damage (half on success).</td></tr><tr><td>3</td><td><b>Yellow:</b> 12d6 Lightning damage (half on success).</td></tr><tr><td>4</td><td><b>Green:</b> 12d6 Poison damage (half on success).</td></tr><tr><td>5</td><td><b>Blue:</b> 12d6 Cold damage (half on success).</td></tr><tr><td>6</td><td><b>Indigo:</b> Target is <b>Restrained</b> and makes a Constitution save each turn. 3 successes ends it; 3 failures results in <b>Petrified</b>.</td></tr><tr><td>7</td><td><b>Violet:</b> Target is <b>Blinded</b> (Wisdom save). On failure, it is teleported to another plane.</td></tr><tr><td>8</td><td><b>Special:</b> Struck by two rays. Roll twice, rerolling any 8.</td></tr></table>",
    "projectImageD": "You create an illusory copy of yourself at any location within range that you have seen before. The illusion looks and sounds like you but is intangible. You can see through its eyes and hear through its ears. As a <b>Magic action</b>, you can move it up to 60 feet. Physical interaction reveals it to be illusory. A creature can take a <b>Study action</b> (Investigation check) to determine it is an illusion; then it can see through the image and noises sound hollow.<br><br><b>Material:</b> a statuette of yourself worth 5+ GP.",
    "regenerateD": "A creature you touch regains 4d8 + 15 Hit Points. For the duration, the target regains 1 Hit Point at the start of each of its turns, and any severed body parts regrow after 2 minutes.<br><br><b>Material:</b> a prayer wheel.",
    "resurrectionD": "With a touch, you revive a dead creature (< 100 years, not died of old age, not Undead). The creature returns with all its Hit Points. Poison is neutralized and wounds closed. Coming back is an ordeal: the target takes a <b>−4 penalty to D20 Tests</b>, reduced by 1 after each Long Rest. Reviving a creature dead for 365+ days taxes you, preventing spellcasting and giving <b>Disadvantage</b> on D20 Tests until your next Long Rest.<br><br><b>Material:</b> a diamond worth 1,000+ GP, which the spell consumes.",
    "reverseGravityD": "This spell reverses gravity in a 50-foot-radius, 100-foot high Cylinder. All creatures and objects in that area fall upward to the top. A <b>Dexterity saving throw</b> allows grabbing a fixed object. If a ceiling is encountered, strike damage applies. When the spell ends, affected objects and creatures fall downward.<br><br><b>Material:</b> a lodestone and iron filings.",
    "sequesterD": "With a touch, you magically sequester an object or willing creature. The target is <b>Invisible</b> and can’t be targeted by Divination spells. Creatures enter suspended animation (<b>Unconscious</b>, no aging/needs). You can set an ending condition that occurs within 1 mile. Damage ends the spell.<br><br><b>Material:</b> gem dust worth 5,000+ GP, which the spell consumes.",
    "simulacrumD": "You create a duplicate of one Beast or Humanoid within 10 feet out of ice or snow. The simulacrum is a <b>Construct</b> with half the original's HP maximum. It acts on your turn and obeys commands. It can't gain levels or rests. Restoring HP requires repairs during a Long Rest (100 GP per HP). Casting again destroys previous simulacrums.<br><br><b>Material:</b> powdered ruby worth 1,500+ GP, which the spell consumes.",
    "symbolD": "You inscribe a harmful glyph (10-ft diameter). Choose an effect: <b>Death</b> (10d10 Necrotic), <b>Discord</b>, <b>Fear</b>, <b>Pain</b>, <b>Sleep</b>, or <b>Stunning</b>. A successful <b>Wisdom (Perception) check</b> is required to notice it. Once triggered, it fills a 60-foot Sphere for 10 minutes, affecting each creature once per turn.<br><br><b>Material:</b> powdered diamond worth 1,000+ GP, which the spell consumes.",
    "teleportD": "This spell instantly transports you and up to eight willing creatures to a destination on the same plane. Success depends on familiarity:<br><br><table class=\"spell-table\"><caption>Teleportation Outcome</caption><tr><th>Familiarity</th><th>Mishap</th><th>Similar Area</th><th>Off Target</th><th>On Target</th></tr><tr><td>Permanent circle</td><td>—</td><td>—</td><td>—</td><td>01–00</td></tr><tr><td>Linked object</td><td>—</td><td>—</td><td>—</td><td>01–00</td></tr><tr><td>Very familiar</td><td>01–05</td><td>06–13</td><td>14–24</td><td>25–00</td></tr><tr><td>Seen casually</td><td>01–33</td><td>34–43</td><td>44–53</td><td>54–00</td></tr><tr><td>Viewed once</td><td>01–43</td><td>44–53</td><td>54–73</td><td>74–00</td></tr><tr><td>False destination</td><td>01–50</td><td>51–00</td><td>—</td><td>—</td></tr></table><br><b>Mishap:</b> Each traveler takes 3d10 Force damage. <b>Off Target:</b> You appear 2d12 miles away.",
    "animalShapesD": "Choose any number of willing creatures. Each target shape-shifts into a <b>Large</b> or smaller Beast (CR 4 or lower). Game statistics are replaced, but Hit Points, alignment, and mental scores are retained. Targets gain <b>Temporary Hit Points</b> equal to the form’s HP. Transformation ends at 0 TP or as a Bonus Action.",
    "antimagicFieldD": "An aura of antimagic surrounds you in 10-foot <b>Emanation</b>. No spells can be cast and magic items don't work inside. Ongoing spells are suppressed but duration continues. Artifacts and deities are unaffected. <b>Dispel Magic</b> has no effect.<br><br><b>Material:</b> iron filings.",
    "antipath_SympathyD": "Choose Antipathy (Fear & movement away) or Sympathy (Charmed & movement toward) for a creature type. Targets make a <b>Wisdom saving throw</b> when within 120 feet. If it ends its turn 120+ feet away, it can repeat the save. Success grants 1 minute immunity.<br><br><b>Material:</b> a mix of vinegar and honey.",
    "cloneD": "You touch a creature or its flesh. An inert duplicate forms inside a vessel and finishes growing after 120 days. If the original creature dies, its soul transfers to the clone if free and willing. The clone is physically identical and has the same personality and memories. The original remains become inert.<br><br><b>Material:</b> a diamond worth 1,000+ GP and a sealable vessel worth 2,000+ GP.",
"controlWeatherD": "You take control of the weather within 5 miles of you for the duration. You must be outdoors to cast this spell, and it ends early if you go indoors.<br><br>When you cast the spell, you change the current weather conditions, which are determined by the DM. You can change precipitation, temperature, and wind. It takes 1d4 × 10 minutes for the new conditions to take effect. Once they do so, you can change the conditions again. When the spell ends, the weather gradually returns to normal.<br><br>When you change the weather conditions, find a current condition on the following tables and change its stage by one, up or down. When changing the wind, you can change its direction.<br><br><table class=\"spell-table\"><caption>Precipitation</caption><tr><th>Stage</th><th>Condition</th></tr><tr><td>1</td><td>Clear</td></tr><tr><td>2</td><td>Light clouds</td></tr><tr><td>3</td><td>Overcast or ground fog</td></tr><tr><td>4</td><td>Rain or hail or snow</td></tr><tr><td>5</td><td>Torrential rain or driving hail or blizzard</td></tr></table><br><table class=\"spell-table\"><caption>Temperature</caption><tr><th>Stage</th><th>Condition</th></tr><tr><td>1</td><td>Heat wave</td></tr><tr><td>2</td><td>Hot</td></tr><tr><td>3</td><td>Warm</td></tr><tr><td>4</td><td>Cool</td></tr><tr><td>5</td><td>Cold</td></tr><tr><td>6</td><td>Freezing</td></tr></table><br><table class=\"spell-table\"><caption>Wind</caption><tr><th>Stage</th><th>Condition</th></tr><tr><td>1</td><td>Calm</td></tr><tr><td>2</td><td>Moderate wind</td></tr><tr><td>3</td><td>Strong wind</td></tr><tr><td>4</td><td>Gale</td></tr><tr><td>5</td><td>Storm</td></tr></table><br><b>Material:</b> burning incense.",
    "demiplaneD": "You create a shadowy Medium door on a flat solid surface that you can see within range. This door can be opened and closed, and it leads to a demiplane that is an empty room 30 feet in each dimension, made of wood or stone (your choice).<br><br>When the spell ends, the door vanishes, and any objects inside the demiplane remain there. Any creatures inside also remain unless they opt to be shunted through the door as it vanishes, landing with the <b>Prone</b> condition in the unoccupied spaces closest to the door’s former space.<br><br>Each time you cast this spell, you can create a new demiplane or connect the shadowy door to a demiplane you created with a previous casting of this spell. Additionally, if you know the nature and contents of a demiplane created by a casting of this spell by another creature, you can connect the shadowy door to that demiplane instead.",
    "dominateMonsterD": "One creature you can see within range must succeed on a <b>Wisdom saving throw</b> or have the <b>Charmed</b> condition for the duration. The target has <b>Advantage</b> on the save if you or your allies are fighting it. Whenever the target takes damage, it repeats the save, ending the spell on itself on a success.<br><br>You have a telepathic link with the Charmed target while the two of you are on the same plane of existence. On your turn, you can use this link to issue commands to the target (no action required). The target does its best to obey on its turn. If it completes an order and doesn’t receive further direction from you, it acts and moves as it likes, focusing on protecting itself.<br><br>You can command the target to take a <b>Reaction</b> but must take your own Reaction to do so.<br><br><b>Using a Higher-Level Spell Slot:</b> Your Concentration can last longer with a level 9 spell slot (up to 8 hours).",
    "earthquakeD": "Choose a point on the ground that you can see within range. For the duration, an intense tremor rips through the ground in a 100-foot-radius circle centered on that point. The ground there is <b>Difficult Terrain</b>.<br><br>When you cast this spell and at the end of each of your turns for the duration, each creature on the ground in the area makes a <b>Dexterity saving throw</b>. On a failed save, a creature has the <b>Prone</b> condition, and its <b>Concentration</b> is broken.<br><br>You can also cause the effects below:<ul><li><b>Fissures:</b> A total of 1d6 fissures open in the spell’s area at the end of the turn you cast it. Each fissure is 1d10 × 10 feet deep and 10 feet wide. A creature in the same space as a fissure must succeed on a <b>Dexterity saving throw</b> or fall in.</li><li><b>Structures:</b> The tremor deals 50 <b>Bludgeoning damage</b> to any structure in contact with the ground at the start and end of your turns. If a structure drops to 0 Hit Points, it collapses. Creatures nearby make a Dexterity save or take 12d6 Bludgeoning damage and are buried (DC 20 Strength (Athletics) check to escape).</li></ul><br><b>Material:</b> a fractured rock.",
    "glibnessD": "Until the spell ends, when you make a <b>Charisma check</b>, you can replace the number you roll with a 15. Additionally, no matter what you say, magic that would determine if you are telling the truth indicates that you are being truthful.",
    "holyAuraD": "For the duration, you emit an aura in a 30-foot <b>Emanation</b>. While in the aura, creatures of your choice have <b>Advantage</b> on all saving throws, and other creatures have <b>Disadvantage</b> on attack rolls against them. In addition, when a Fiend or an Undead hits an affected creature with a melee attack roll, the attacker must succeed on a <b>Constitution saving throw</b> or have the <b>Blinded</b> condition until the end of its next turn.<br><br><b>Material:</b> a reliquary worth 1,000+ GP.",
    "incendiaryCloudD": "A swirling cloud of embers and smoke fills a 20-foot-radius Sphere. The cloud’s area is <b>Heavily Obscured</b>. It lasts for the duration or until a strong wind disperses it.<br><br>When the cloud appears, each creature in it makes a <b>Dexterity saving throw</b>, taking 10d8 Fire damage on a failed save (half on success). A creature also makes this save when the Sphere moves into its space or when it enters/ends turn there. The cloud moves 10 feet away from you each turn.<br><br><b>Material:</b> a rotten egg.",
    "mazeD": "You banish a creature that you can see within range into a labyrinthine demiplane. The target remains there for the duration or until it escapes the maze.<br><br>The target can take a <b>Study action</b> to try to escape. When it does so, it makes a <b>DC 20 Intelligence (Investigation) check</b>. If it succeeds, it escapes, and the spell ends.<br><br>When the spell ends, the target reappears in the space it left or in the nearest unoccupied space.",
    "mindBlankD": "Until the spell ends, one willing creature you touch has <b>Immunity to Psychic damage</b> and the <b>Charmed</b> condition. The target is also unaffected by anything that would sense its emotions or alignment, read its thoughts, or magically detect its location, and no spell—not even <i>Wish</i>—can gather information about the target, observe it remotely, or control its mind.",
    "powerWordStunD": "You overwhelm the mind of one creature you can see within range. If the target has 150 Hit Points or fewer, it has the <b>Stunned</b> condition. Otherwise, its Speed is 0 until the start of your next turn.<br><br>The Stunned target makes a <b>Constitution saving throw</b> at the end of each of its turns, ending the condition on itself on a success.",
    "sunburstD": "Brilliant sunlight flashes in a 60-foot-radius Sphere. Each creature in the Sphere makes a <b>Constitution saving throw</b>. On a failed save, a creature takes 12d6 <b>Radiant damage</b> and has the <b>Blinded</b> condition for 1 minute (half damage on success).<br><br>A creature erblinded by this spell makes another Constitution saving throw at the end of each of its turns. This spell dispels Darkness in its area.<br><br><b>Material:</b> a piece of sunstone.",
    "telepathyD": "You create a telepathic link between yourself and a willing creature with which you are familiar. The creature can be anywhere on the same plane of existence. The spell ends if you or the target are no longer on the same plane.<br><br>Until the spell ends, you and the target can instantly share words, images, sounds, and other sensory messages, and the target recognizes you. The spell enables a creature to understand the meaning of your words and sensory messages.<br><br><b>Material:</b> a pair of linked silver rings.",
    "tsunamiD": "A wall of water springs into existence. You can make the wall up to 300 feet long, 300 feet high, and 50 feet thick. When the wall appears, each creature in its area makes a <b>Strength saving throw</b>, taking 6d10 Bludgeoning damage on a failed save.<br><br>At the start of your turns, the wall moves 50 feet away. Any Huge or smaller creature inside must succeed on a Strength save or take 5d10 Bludgeoning damage. Wall height reduces by 50 feet each turn. Moving within the wall requires a <b>Strength (Athletics) check</b> against your spell save DC.",
    "astralProjectionD": "You and up to eight willing creatures project your astral bodies into the Astral Plane. Your bodies are left behind in suspended animation (<b>Unconscious</b>, no food/air/aging).<br><br>A silvery cord trails from the astral form. If cut, both body and form die. The moment the form leaves the plane, you re-enter your body. Damage to the form doesn't affect the body. Dismissing the spell returns all non-dead targets to their bodies.<br><br><b>Material:</b> for each target, a jacinth worth 1,000+ GP and a silver bar worth 100+ GP, which the spell consumes.",
    "foresightD": "You touch a willing creature and bestow a limited ability to see into the immediate future. For the duration, the target has <b>Advantage</b> on <b>D20 Tests</b>, and other creatures have <b>Disadvantage</b> on attack rolls against it. The spell ends early if you cast it again.<br><br><b>Material:</b> a hummingbird feather.",
"gateD": "You conjure a portal linking an unoccupied space within range to a precise location on a different plane. The portal is a circular opening, 5 to 20 feet in diameter. It lasts for the duration and the destination is visible through it. Travel is possible only through the front. Planar rulers can prevent portals from opening in their domains. You can name a specific creature to pull it through the portal, but you gain no special power over it.<br><br><b>Material:</b> a diamond worth 5,000+ GP.",
    "imprisonmentD": "You create a magical restraint for a creature. Target makes a <b>Wisdom saving throw</b>; on failure, it is imprisoned. It doesn't need to breathe, eat, or drink and doesn't age. Choose an effect:<ul><li><b>Burial:</b> Entombed beneath the earth in a force globe.</li><li><b>Chaining:</b> Chains grant the <b>Restrained</b> condition.</li><li><b>Hedged Prison:</b> Trapped in a warded demiplane.</li><li><b>Minimus Containment:</b> Target becomes 1 inch tall inside a gemstone.</li><li><b>Slumber:</b> Target has the <b>Unconscious</b> condition.</li></ul>Define a trigger to end the spell. <i>Dispel Magic</i> only works if cast with a level 9 slot.<br><br><b>Material:</b> a statuette of the target worth 5,000+ GP.",
    "massHealD": "A flood of healing energy restores up to 700 Hit Points, divided among any number of creatures. It also removes <b>Blinded</b>, <b>Deafened</b>, and <b>Poisoned</b> conditions.",
    "meteorSwarmD": "Blazing fire orbs strike four points. Each creature in a 40-foot-radius Sphere makes a <b>Dexterity saving throw</b>, taking 20d6 Fire and 20d6 Bludgeoning damage on failure (half on success). Affected only once per area. Flammable objects ignite.",
    "powerWordHealD": "A wave of healing restores all Hit Points to a creature and ends <b>Charmed</b>, <b>Frightened</b>, <b>Paralyzed</b>, <b>Poisoned</b>, or <b>Stunned</b> conditions. Prone targets can use their Reaction to stand up.",
    "powerWordKillD": "Compel a creature to die. If it has 100 HP or fewer, it dies instantly. Otherwise, it takes 12d12 Psychic damage.",
    "prismaticWallD": "A shimmering multicolored wall (90 ft long, 30 ft high) or globe (30 ft diameter). Sheds Bright Light. Chosen creatures are safe; others within 20 feet make a <b>Constitution save</b> or become <b>Blinded</b>.<br><br><table class=\"spell-table\"><caption>Prismatic Layers</caption><tr><th>Order</th><th>Effects</th></tr><tr><td>1. Red</td><td>12d6 Fire damage. Blocks nonmagical ranged attacks. Destroyed by 25 Cold damage.</td></tr><tr><td>2. Orange</td><td>12d6 Acid damage. Blocks magical ranged attacks. Destroyed by <i>Gust of Wind</i>.</td></tr><tr><td>3. Yellow</td><td>12d6 Lightning damage. Destroyed by 60 Force damage.</td></tr><tr><td>4. Green</td><td>12d6 Poison damage. Destroyed by <i>Passwall</i>.</td></tr><tr><td>5. Blue</td><td>12d6 Cold damage. Destroyed by 25 Fire damage.</td></tr><tr><td>6. Indigo</td><td><b>Restrained</b>, then <b>Petrified</b>. Destroyed by <i>Daylight</i>.</td></tr><tr><td>7. Violet</td><td><b>Blinded</b>, then teleported. Destroyed by <i>Dispel Magic</i>.</td></tr></table><br>Immune to Antimagic Field; only <i>Dispel Magic</i> on the violet layer works.",
    "shapechangeD": "You shape-shift into another creature (max CR = your level). Cannot be a Construct or Undead. Gain <b>Temporary Hit Points</b> equal to the form's HP. You retain mental stats, alignment, and Spellcasting. Equipment can drop or merge. You can change forms as a <b>Magic action</b>.<br><br><b>Material:</b> a jade circlet worth 1,500+ GP.",
    "stormOfVengeanceD": "A 300-foot-radius storm cloud forms. Creatures under it make a <b>Constitution save</b> or take 2d6 Thunder damage and become <b>Deafened</b>. Turn effects: Runde 2 (Acid rain), Runde 3 (Lightning bolts), Runde 4 (Hail), Runde 5-10 (Freezing rain). Area becomes <b>Heavily Obscured</b> and <b>Difficult Terrain</b>.",
    "timeStopD": "Briefly stop time for 1d4 + 1 turns in a row. You can move and act normally. Ends if you affect another creature or carried object, or move more than 1,000 feet away.",
    "truePolymorphD": "Transform a creature or object. Permanent if <b>Concentration</b> held for 1 hour.<ul><li><b>Creature to Creature:</b> New form up to target's CR. Gain <b>Temporary Hit Points</b>.</li><li><b>Object to Creature:</b> Becomes a creature (max CR 9) Friendly to you.</li><li><b>Creature to Object:</b> Becomes an object of its size; no memory of this time.</li></ul><br><b>Material:</b> mercury, gum arabic, and a wisp of smoke.",
    "trueResurrectionD": "Revive a creature dead < 200 years. Restores all HP, heals all wounds, neutralizes poisons, and replaces missing organs. Can provide a new body if original is gone. Restores Undead to non-Undead form.<br><br><b>Material:</b> diamonds worth 25,000+ GP.",
    "weirdD": "Create illusory terrors. Chosen creatures in a 30-foot-radius Sphere make a <b>Wisdom saving throw</b>, taking 10d10 Psychic damage and becoming <b>Frightened</b>. Repeat save each turn; failure deals 5d10 Psychic damage.",
    "wishD": "The mightiest spell. Basic use: duplicate any level 8 or lower spell. Alternative effects:<ul><li><b>Object Creation:</b> Up to 25,000 GP value.</li><li><b>Instant Health:</b> Restore all HP for 20 creatures and end <i>Greater Restoration</i> effects.</li><li><b>Resistance:</b> Permanent resistance for 10 creatures.</li><li><b>Spell Immunity:</b> 8 hours immunity for 10 creatures.</li><li><b>Sudden Learning:</b> Replace a feat.</li><li><b>Roll Redo:</b> Undo a recent event by rerolling.</li><li><b>Reshape Reality:</b> A custom wish with DM discretion.</li></ul>Causes extreme stress and 33% chance to never cast <i>Wish</i> again."
        	});